 SET mysqlDatatype = 'DATE';

 ELSEIF conceptDatatype = 'Datetime' THEN
 SET mysqlDatatype = 'DATETIME';

 ELSEIF conceptDatatype = 'Numeric' THEN
 SET mysqlDatatype = 'DOUBLE';

 ELSE
 SET mysqlDatatype = 'TEXT';

 END IF;

 RETURN mysqlDatatype;
END //

