 END AS num,
 @prev_flat_table_name := flat_table_name,
 @prev_concept_id := concept_id
 FROM mamba_concept_metadata
 -- WHERE incremental_record = 1
 ORDER BY flat_table_name, concept_id, id) m ON md.id = m.id
SET md.row_num = num
WHERE md.incremental_record = 1;

-- $END
