    RESIGNAL;
END;

-- $BEGIN

-- Insert only new Records
INSERT INTO mamba_dim_concept_name (concept_name_id,
 concept_id,
 name,
 locale,
 locale_preferred,
 voided,
 concept_name_type,
 date_created,
 date_changed,
