-- ---------------------------------------------------------------------------------------------
-- fn_get_ti_status
--

DROP FUNCTION IF EXISTS fn_get_ti_status;

DELIMITER //

~
CREATE FUNCTION fn_get_ti_status(TI_CLIENT_ID INT, START_DATE DATE, END_DATE DATE) RETURNS NVARCHAR(10)
    DETERMINISTIC
BEGIN

    DECLARE TI_RESULT NVARCHAR(10);
    DECLARE min_date_val DATE;

    SET min_date_val = (
        SELECT MIN(follow_up_date_followup_) AS min_follow_up_date
        FROM mamba_flat_encounter_follow_up follow_up
                 LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                           ON follow_up.encounter_id = follow_up_1.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                           ON follow_up.encounter_id = follow_up_2.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                           ON follow_up.encounter_id = follow_up_3.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                           ON follow_up.encounter_id = follow_up_4.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                           ON follow_up.encounter_id = follow_up_5.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                           ON follow_up.encounter_id = follow_up_6.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                           ON follow_up.encounter_id = follow_up_7.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                           ON follow_up.encounter_id = follow_up_8.encounter_id
                 LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                           ON follow_up.encounter_id = follow_up_9.encounter_id
        WHERE follow_up_status IS NOT NULL
          AND art_antiretroviral_start_date IS NOT NULL
          AND transferred_in_check_this_for_all_t = 'Yes'
          AND follow_up.client_id = TI_CLIENT_ID
    );

    IF min_date_val BETWEEN START_DATE AND END_DATE THEN
        SET TI_RESULT = 'TI';
    ELSE
        SET TI_RESULT = 'NTI';
    END IF;

    RETURN TI_RESULT;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- fn_gregorian_to_ethiopian_calendar
--

DROP FUNCTION IF EXISTS fn_gregorian_to_ethiopian_calendar;

DELIMITER //
~
CREATE FUNCTION fn_gregorian_to_ethiopian_calendar(_date DATE, _format VARCHAR(100))
    RETURNS VARCHAR(100)  -- Increased size to handle longer formats if needed
    DETERMINISTIC
BEGIN
    DECLARE s INT;
    DECLARE t INT;
    DECLARE n INT;
    DECLARE jdn INT;
    DECLARE era INT DEFAULT 1723856;
    DECLARE r INT;
    DECLARE eth_year INT;
    DECLARE eth_month INT;
    DECLARE eth_day INT;

    DECLARE greg_year INT DEFAULT YEAR(_date);
    DECLARE greg_month INT DEFAULT MONTH(_date);
    DECLARE greg_day INT DEFAULT DAY(_date);

    -- Calculate leap day indicator
    SET s = (greg_year DIV 4) - ((greg_year - 1) DIV 4)
                - (greg_year DIV 100) + ((greg_year - 1) DIV 100)
                + (greg_year DIV 400) - ((greg_year - 1) DIV 400);

    -- Month adjustment
    SET t = (14 - greg_month) DIV 12;

    -- Day of year offset
    SET n = 31 * t * (greg_month - 1)
                + (1 - t) * (59 + s + 30 * (greg_month - 3) + ((3 * greg_month - 7) DIV 5))
                + greg_day - 1;

    -- Julian Day Number
    SET jdn = 1721426
                  + 365 * (greg_year - 1)
                  + ((greg_year - 1) DIV 4)
                  - ((greg_year - 1) DIV 100)
        + ((greg_year - 1) DIV 400)
        + n;

    -- Ethiopian conversion
    SET r = (jdn - era) MOD 1461;
    SET n = r MOD 365 + 365 * (r DIV 1460);
    SET eth_year = 4 * ((jdn - era) DIV 1461) + (r DIV 365) - (r DIV 1460);
    SET eth_month = (n DIV 30) + 1;
    SET eth_day = (n MOD 30) + 1;

    -- Format the output
    SET _format = REPLACE(_format, 'Y', CAST(eth_year AS CHAR));
    SET _format = REPLACE(_format, 'M', LPAD(CAST(eth_month AS CHAR), 2, '0'));
    SET _format = REPLACE(_format, 'D', LPAD(CAST(eth_day AS CHAR), 2, '0'));

    RETURN _format;
END //
DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- fn_ethiopian_to_gregorian_calendar
--

DROP FUNCTION IF EXISTS fn_ethiopian_to_gregorian_calendar;

DELIMITER //
~
CREATE FUNCTION fn_ethiopian_to_gregorian_calendar(ethiopian_date VARCHAR(10))
    RETURNS VARCHAR(10)
    READS SQL DATA
    DETERMINISTIC
BEGIN
    DECLARE ey INT;
    DECLARE em INT;
    DECLARE ed INT;
    DECLARE jd BIGINT;
    DECLARE doy INT;
    DECLARE leap_days INT;
    DECLARE is_leap TINYINT;
    DECLARE l INT;
    DECLARE n INT;
    DECLARE i INT;
    DECLARE j INT;
    DECLARE gy INT;
    DECLARE gm INT;
    DECLARE gd INT;
    DECLARE result VARCHAR(10);

    -- Validate input format
    IF ethiopian_date NOT REGEXP '^[0-9]{4}-[0-1][0-9]-[0-3][0-9]$' THEN
        RETURN NULL;  -- Invalid format
    END IF;

    -- Parse input 'YYYY-MM-DD'
    SET ey = CAST(SUBSTRING(ethiopian_date, 1, 4) AS UNSIGNED);
    SET em = CAST(SUBSTRING(ethiopian_date, 6, 2) AS UNSIGNED);
    SET ed = CAST(SUBSTRING(ethiopian_date, 9, 2) AS UNSIGNED);

    -- Check for Ethiopian leap year (ey % 4 = 3)
    SET is_leap = (ey % 4 = 3);

    -- Validate Ethiopian date
    IF ey < 1 OR ey > 9999 OR
       em < 1 OR em > 13 OR
       ed < 1 OR
       (em <= 12 AND ed > 30) OR
       (em = 13 AND ed > (5 + is_leap)) THEN
        RETURN NULL;  -- Invalid Ethiopian date
    END IF;

    -- Calculate day of year (doy)
    IF em < 13 THEN
        SET doy = 30 * (em - 1) + ed;
    ELSE
        SET doy = 360 + ed;
    END IF;

    -- Calculate leap days adjustment
    SET leap_days = ey DIV 4 - (IF(is_leap, 1, 0));

    -- Calculate Julian Day Number (JDN)
    SET jd = 365 * (ey - 1) + leap_days + doy + 1724220;

    -- Convert JDN to Gregorian date
    SET l = jd + 68569;
    SET n = (4 * l) DIV 146097;
    SET l = l - ((146097 * n) + 3) DIV 4;
    SET i = (4000 * (l + 1)) DIV 1461001;
    SET l = l - (1461 * i) DIV 4 + 31;
    SET j = (80 * l) DIV 2447;
    SET gd = l - (2447 * j) DIV 80;
    SET gm = j + 2 - 12 * (j DIV 11);
    SET gy = 100 * (n - 49) + i + (j DIV 11);

    -- Validate Gregorian date
    IF gy < 1 OR gy > 9999 OR gm < 1 OR gm > 12 OR gd < 1 OR gd > 31 THEN
        RETURN NULL;  -- Invalid Gregorian date
    END IF;

    -- Format output as YYYY-MM-DD
    SET result = CONCAT(
            LPAD(gy, 4, '0'),
            '-',
            LPAD(gm, 2, '0'),
            '-',
            LPAD(gd, 2, '0')
                 );

    RETURN result;
END //

DELIMITER ;


        
