(
    client_id         int                                not null
        primary key,
    patient_name      VARCHAR(255) NULL,
    prefix            VARCHAR(255) NULL,
    given_name        VARCHAR(255) NULL,
    middle_name       VARCHAR(255) NULL,
    family_name       VARCHAR(255) NULL,
