    uan               VARCHAR(50)  NULL,
    patient_uuid      VARCHAR(38),
    current_age       INT,
    mobile_no         VARCHAR(50),
    phone_no         VARCHAR(50),
    date_of_birth     DATE                               NULL,
    sex               VARCHAR(50)  NULL,
