-- $BEGIN
CREATE TABLE IF NOT EXISTS mamba_fact_client
(
    client_id                      INT NOT NULL,
    patient_uuid                   CHAR(38),
    mrn                            VARCHAR(50),

    -- Demographics
    patient_name                   VARCHAR(255),
    sex                            VARCHAR(10),
    birthdate                      DATE,
    age                            INT,

    -- Identifiers
    uan                            VARCHAR(50),
    phrh_code                      VARCHAR(50),
    ncd_code                       VARCHAR(50),
    icd_number                     VARCHAR(50),
    ict_number                     VARCHAR(50),  -- Added

-- Registration & Follow-up Dates
    registration_date              DATE,
    art_start_date                 DATE,         -- Reordered
    months_on_art                  INT,          -- Reordered
    next_appointment_date          DATE,         -- Reordered
    hiv_confirmed_date             DATE,
    transfer_in_date               DATE,

    -- Address
    region                         VARCHAR(255),
    zone                           VARCHAR(255),
    woreda                         VARCHAR(255),
    kebele                         VARCHAR(255),
    house_number                   VARCHAR(255),
    mobile_phone                   VARCHAR(50),
    address_completeness           VARCHAR(20),

    current_status                 VARCHAR(50),
    current_regimen                VARCHAR(255),
    regimen_dose                   VARCHAR(255),
    regimen_line                   VARCHAR(50),
    tx_curr_end_date               DATE,
    nutritional_status             VARCHAR(255),
    pregnancy_status               VARCHAR(50),
    pmtct_status                   VARCHAR(50),
    family_planning_method         VARCHAR(255),
    who_stage                      VARCHAR(50),  -- Added

    last_visit_date                DATE,
    days_overdue                   INT,

    last_vl_date                   DATE,
    last_vl_result                 NUMERIC(10, 2),
    is_suppressed                  BOOLEAN,
    vl_status                      VARCHAR(100),
    vl_eligibility_date            DATE,

    tpt_status                     VARCHAR(50),
    tpt_start_date                 DATE,
    tpt_completed_date             DATE,
    tpt_discontinued_date          DATE,

    active_tb_diagnosis_date       DATE,
    tb_treatment_start_date        DATE,
    tb_treatment_discontinued_date DATE,
    tb_treatment_completed_date    DATE,

    dsd_category                   VARCHAR(100),
    ict_screening_status           VARCHAR(100),
    ncd_screening_status           VARCHAR(100),
    next_ncd_screening_date        DATE,
    cxca_screening_status          VARCHAR(100),
    next_cca_screening_date        DATE,
    systolic_blood_pressure        INT,
    diastolic_blood_pressure       INT,
    target_population              VARCHAR(100),

    last_updated                   TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,

    INDEX idx_uuid (patient_uuid),
    INDEX idx_mrn (mrn),
    INDEX idx_status (current_status)
    );

-- $END
END //

DELIMITER ;

        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_client_insert
--

DROP PROCEDURE IF EXISTS sp_fact_client_insert;

DELIMITER //

~
CREATE PROCEDURE sp_fact_client_insert()
BEGIN

DECLARE EXIT HANDLER FOR SQLEXCEPTION
BEGIN
    GET DIAGNOSTICS CONDITION 1

    @message_text = MESSAGE_TEXT,
    @mysql_errno = MYSQL_ERRNO,
    @returned_sqlstate = RETURNED_SQLSTATE;

    CALL sp_mamba_etl_error_log_insert('sp_fact_client_insert', @message_text, @mysql_errno, @returned_sqlstate);

    UPDATE _mamba_etl_schedule
    SET end_time                   = NOW(),
        completion_status          = 'ERROR',
        transaction_status         = 'COMPLETED',
        success_or_error_message   = CONCAT('sp_fact_client_insert', ', ', @mysql_errno, ', ', @message_text)
        WHERE id = (SELECT last_etl_schedule_insert_id FROM _mamba_etl_user_settings ORDER BY id DESC LIMIT 1);

    RESIGNAL;
END;

-- $BEGIN
INSERT INTO mamba_fact_client
(client_id, patient_uuid, mrn, patient_name, sex, birthdate, age, uan, phrh_code, ncd_code, icd_number, ict_number,
 registration_date, art_start_date, months_on_art, next_appointment_date, hiv_confirmed_date, transfer_in_date,
 region, zone, woreda, kebele, house_number, mobile_phone, address_completeness, current_status,
 current_regimen, regimen_dose, regimen_line, tx_curr_end_date, nutritional_status, pregnancy_status,
 pmtct_status, family_planning_method, who_stage, last_visit_date, days_overdue, last_vl_date, last_vl_result,
 is_suppressed, vl_status, vl_eligibility_date, tpt_status, tpt_start_date, tpt_completed_date,
 tpt_discontinued_date, active_tb_diagnosis_date, tb_treatment_start_date, tb_treatment_discontinued_date,
 tb_treatment_completed_date, dsd_category, ict_screening_status, ncd_screening_status, next_ncd_screening_date,
 cxca_screening_status, next_cca_screening_date, systolic_blood_pressure, diastolic_blood_pressure, target_population)
WITH FollowUp AS (SELECT follow_up.client_id,
                         follow_up.encounter_id,
                         follow_up_date_followup_,
                         next_visit_date,
                         current_who_hiv_stage,
                         follow_up_status,
                         regimen,
                         antiretroviral_art_dispensed_dose_i,
                         treatment_end_date,
                         nutritional_status_of_adult,
                         nutritional_status_of_older_child_a,
                         mid_upper_arm_circumference,
                         hiv_viral_load                                                 AS viral_load_count,
                         pregnancy_status,
                         currently_breastfeeding_child,
                         method_of_family_planning,
                         dsd_category,
                         weight_text_                                                   as weight,
                         date_of_event,
                         transferred_in_check_this_for_all_t                            as transfer_in,
                         art_antiretroviral_start_date                                  as art_start_date,
                         date_of_reported_hiv_viral_load,
                         date_viral_load_results_received,

                         cervical_cancer_screening_status                               as cx_ca_screening_status,
                         cervical_cancer_screening_method_strategy                      as screening_method,
                         via_screening_result,
                         hpv_dna_screening_result,
                         cytology_result,
                         date_visual_inspection_of_the_cervi                            as via_date,
                         hpv_dna_result_received_date                                   as hpv_received_date,
                         date_cytology_result_received                                  as cytology_received_date,

                         eligible_for_cxca_screening,
                         reason_for_not_being_eligible,
                         other_reason_for_not_being_eligible_for_cxca,
                         treatment_start_date                                           as ccs_treat_received_date,
                         colposcopy_of_cervix_findings                                  as colposcopy_exam_finding,
                         biopsy_result_received_date,
                         biopsy_result,
                         date_patient_referred_out,
                         next_follow_up_screening_date,

                         COALESCE(at_3436_weeks_of_gestation,
                                  viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                  viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                  every_six_months_until_mtct_ends,
                                  six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                  three_months_after_delivery, at_the_first_antenatal_care_visit,
                                  annual_viral_load_test,
                                  second_viral_load_test_at_12_months_post_art,
                                  first_viral_load_test_at_6_months_or_longer_post_art,
                                  first_viral_load_test_at_3_months_or_longer_post_art) AS routine_viral_load_test_indication,
                         COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                  suspected_antiretroviral_failure)                     AS targeted_viral_load_test_indication,
                         hiv_viral_load,
                         viral_load_test_status,
                         date_started_on_tuberculosis_prophy,
                         date_completed_tuberculosis_prophyl,
                         date_discontinued_tuberculosis_prop,
                         reason_not_eligible_for_tuberculosi,
                         diagnosis_date,
                         tuberculosis_drug_treatment_start_d,
                         regimen_change,
                         date_active_tbrx_completed,
                         date_active_tbrx_dc
                  FROM mamba_flat_encounter_follow_up follow_up
                           LEFT JOIN mamba_flat_encounter_follow_up_1 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_2 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_3 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_4 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_5 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_6 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_7 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_8 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_9 USING (encounter_id)
                           LEFT JOIN mamba_flat_encounter_follow_up_10 USING (encounter_id)),

     LatestFollowUp AS (SELECT *
                        FROM (SELECT client_id,
                                     follow_up_date_followup_                                                                             as visit_date,
                                     next_visit_date,
                                     follow_up_status,
                                     regimen,
                                     antiretroviral_art_dispensed_dose_i                                                                  as regimen_dose,
                                     treatment_end_date,
                                     nutritional_status_of_adult,
                                     nutritional_status_of_older_child_a,
                                     mid_upper_arm_circumference,
                                     pregnancy_status,
                                     art_start_date,
                                     current_who_hiv_stage                                                                                as who_stage,
                                     currently_breastfeeding_child,
                                     weight,
                                     method_of_family_planning,
                                     dsd_category,
                                     date_of_event                                                                                        as hiv_confirmed_date,
                                     transfer_in,
                                     eligible_for_cxca_screening,
                                     reason_for_not_being_eligible,
                                     other_reason_for_not_being_eligible_for_cxca,
                                     cx_ca_screening_status                                                                               as screening_status,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) as rn
                              FROM FollowUp
                              WHERE follow_up_date_followup_ IS NOT NULL) ranked
                        WHERE rn = 1),

     Medical_Aggregates AS (SELECT client_id,
                                   MIN(CASE
                                           WHEN transfer_in IN ('Yes', 'True', '1') OR
                                                follow_up_status IN ('Transfer in', 'Transfer In', 'TI')
                                               THEN follow_up_date_followup_ END) as transfer_in_date,
                                   MIN(art_start_date)                            as art_start_date,
                                   MAX(date_started_on_tuberculosis_prophy)       as tpt_start_date,
                                   MAX(date_completed_tuberculosis_prophyl)       as tpt_completed_date,
                                   MAX(date_discontinued_tuberculosis_prop)       as tpt_discontinued_date,
                                   MAX(CASE
                                           WHEN reason_not_eligible_for_tuberculosi = 'Contraindication' THEN 1
                                           ELSE 0 END)                            as tpt_is_contraindicated,
                                   MAX(diagnosis_date)                            as active_tb_diagnosis_date,
                                   MAX(tuberculosis_drug_treatment_start_d)       as tb_treatment_start_date,
                                   MAX(date_active_tbrx_dc)                       as tb_treatment_discontinued_date,
                                   MAX(date_active_tbrx_completed)                as tb_treatment_completed_date
                            FROM FollowUp
                            GROUP BY client_id),

     Vl_Events AS (SELECT encounter_id,
                          client_id,
                          follow_up_date_followup_,
                          date_of_reported_hiv_viral_load                                                                                                                                   as viral_load_sent_date,
                          date_viral_load_results_received                                                                                                                                  as viral_load_perform_date,
                          regimen_change,
                          routine_viral_load_test_indication,
                          follow_up_date_followup_                                                                                                                                          as FollowupDate,
                          currently_breastfeeding_child                                                                                                                                     as breastfeeding_status,
                          viral_load_test_status,
                          viral_load_count,
                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY (date_of_reported_hiv_viral_load IS NOT NULL) DESC, date_of_reported_hiv_viral_load DESC, encounter_id DESC)   AS rn_sent,
                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY (regimen_change IS NOT NULL) DESC, follow_up_date_followup_ DESC, encounter_id DESC)                           AS rn_switch,
                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY (date_viral_load_results_received IS NOT NULL) DESC, date_viral_load_results_received DESC, encounter_id DESC) AS rn_perf
                   FROM FollowUp),

     vl_performed AS (SELECT vl_perf.encounter_id,
                             vl_perf.client_id,
                             vl_sent.viral_load_sent_date                                            AS VL_Sent_Date,
                             CASE
                                 WHEN vl_perf.viral_load_perform_date < vl_sent.viral_load_sent_date THEN NULL
                                 ELSE vl_perf.viral_load_perform_date END                            AS viral_load_perform_date,
                             CASE
                                 WHEN vl_perf.viral_load_perform_date < vl_sent.viral_load_sent_date THEN NULL
                                 ELSE vl_perf.viral_load_test_status END                             AS viral_load_status,
                             CASE
                                 WHEN vl_perf.viral_load_count >= 0 AND
                                      vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date
                                     THEN CAST(vl_perf.viral_load_count AS DECIMAL(12, 2))
                                 ELSE NULL END                                                       AS viral_load_count,
                             CASE
                                 WHEN vl_perf.viral_load_test_status IS NULL AND
                                      vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date THEN NULL
                                 WHEN vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date AND
                                      (vl_perf.viral_load_test_status LIKE 'Det%' OR
                                       vl_perf.viral_load_test_status LIKE 'Uns%' OR
                                       vl_perf.viral_load_test_status LIKE 'High VL%' OR
                                       vl_perf.viral_load_test_status LIKE 'Low Level Viremia%') THEN 'U'
                                 WHEN vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date AND
                                      (vl_perf.viral_load_test_status LIKE 'Su%' OR
                                       vl_perf.viral_load_test_status LIKE 'Undet%') THEN 'S'
                                 WHEN vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date AND
                                      (COALESCE(vl_perf.viral_load_count, 0) > 50) THEN 'U'
                                 WHEN vl_perf.viral_load_perform_date >= vl_sent.viral_load_sent_date AND
                                      (COALESCE(vl_perf.viral_load_count, 0) <= 50) THEN 'S'
                                 ELSE NULL
                                 END                                                                 AS viral_load_status_inferred,
                             COALESCE(vl_sent.viral_load_sent_date,
                                      vl_perf.viral_load_perform_date)                               AS viral_load_ref_date,
                             vl_perf.routine_viral_load_test_indication
                      FROM Vl_Events vl_perf
                               LEFT JOIN Vl_Events vl_sent
                                         ON vl_perf.client_id = vl_sent.client_id AND vl_sent.rn_sent = 1 AND
                                            vl_sent.viral_load_sent_date IS NOT NULL
                      WHERE vl_perf.rn_perf = 1),

     vl_scenario AS (SELECT f_case.client_id,
                            f_case.art_start_date,
                            f_case.visit_date,
                            f_case.follow_up_status,
                            sub_switch_date.FollowupDate as switchDate,
                            vlperfdate.VL_Sent_Date,
                            vlperfdate.viral_load_perform_date,
                            vlperfdate.viral_load_status_inferred,
                            CASE
                                WHEN vlperfdate.VL_Sent_Date IS NULL AND f_case.follow_up_status = 'Restart medication'
                                    THEN 'RESTART_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NULL AND sub_switch_date.FollowupDate IS NOT NULL
                                    THEN 'SWITCH_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NULL AND f_case.pregnancy_status = 'Yes' AND
                                     TIMESTAMPDIFF(DAY, f_case.art_start_date, CURDATE()) > 90 THEN 'PREG_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NULL AND
                                     TIMESTAMPDIFF(DAY, f_case.art_start_date, CURDATE()) <= 180 THEN 'INELIGIBLE_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NULL AND
                                     TIMESTAMPDIFF(DAY, f_case.art_start_date, CURDATE()) > 180 THEN 'FIRST_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL AND
                                     vlperfdate.VL_Sent_Date < f_case.visit_date AND
                                     f_case.follow_up_status = 'Restart medication' THEN 'RESTART_NOT_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL AND
                                     vlperfdate.VL_Sent_Date < sub_switch_date.FollowupDate AND
                                     sub_switch_date.FollowupDate IS NOT NULL THEN 'SWITCH_NOT_NULL'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL AND vlperfdate.viral_load_status_inferred = 'U'
                                    THEN 'UNSUPPRESSED'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL AND (f_case.pregnancy_status = 'Yes' OR
                                                                              f_case.currently_breastfeeding_child =
                                                                              'Yes') AND
                                     vlperfdate.routine_viral_load_test_indication IN
                                     ('First viral load test at 6 months or longer post ART',
                                      'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                      'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml')
                                    THEN 'PMTCT_EARLY'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL AND (f_case.pregnancy_status = 'Yes' OR
                                                                              f_case.currently_breastfeeding_child =
                                                                              'Yes') AND
                                     vlperfdate.routine_viral_load_test_indication IS NOT NULL THEN 'PMTCT_LATE'
                                WHEN vlperfdate.VL_Sent_Date IS NOT NULL THEN 'ANNUAL'
                                ELSE 'UNASSIGNED'
                                END                      AS scenario_type,
                            f_case.pregnancy_status,
                            f_case.currently_breastfeeding_child,
                            f_case.hiv_confirmed_date,
                            f_case.weight,
                            f_case.regimen_dose,
                            f_case.regimen,
                            f_case.next_visit_date,
                            f_case.treatment_end_date,
                            vlperfdate.viral_load_count,
                            vlperfdate.viral_load_status
                     FROM LatestFollowUp f_case
                              LEFT JOIN vl_performed as vlperfdate ON vlperfdate.client_id = f_case.client_id
                              LEFT JOIN Vl_Events as sub_switch_date ON sub_switch_date.client_id = f_case.client_id AND
                                                                        sub_switch_date.rn_switch = 1 AND
                                                                        sub_switch_date.regimen_change IS NOT NULL
                     WHERE f_case.rn = 1),

     vl_eligibility AS (SELECT *,
                               CASE scenario_type
                                   WHEN 'RESTART_NULL' THEN DATE_ADD(visit_date, INTERVAL 91 DAY)
                                   WHEN 'SWITCH_NULL' THEN DATE_ADD(switchDate, INTERVAL 181 DAY)
                                   WHEN 'PREG_NULL' THEN DATE_ADD(art_start_date, INTERVAL 91 DAY)
                                   WHEN 'INELIGIBLE_NULL' THEN NULL
                                   WHEN 'FIRST_NULL' THEN DATE_ADD(art_start_date, INTERVAL 181 DAY)
                                   WHEN 'RESTART_NOT_NULL' THEN DATE_ADD(visit_date, INTERVAL 91 DAY)
                                   WHEN 'SWITCH_NOT_NULL' THEN DATE_ADD(switchDate, INTERVAL 181 DAY)
                                   WHEN 'UNSUPPRESSED' THEN DATE_ADD(VL_Sent_Date, INTERVAL 91 DAY)
                                   WHEN 'PMTCT_EARLY' THEN DATE_ADD(VL_Sent_Date, INTERVAL 91 DAY)
                                   WHEN 'PMTCT_LATE' THEN DATE_ADD(VL_Sent_Date, INTERVAL 181 DAY)
                                   WHEN 'ANNUAL' THEN DATE_ADD(VL_Sent_Date, INTERVAL 365 DAY)
                                   ELSE DATE_ADD(CURDATE(), INTERVAL 100 YEAR)
                                   END AS eligiblityDate,
                               CASE scenario_type
                                   WHEN 'RESTART_NULL' THEN 'client restarted ART'
                                   WHEN 'SWITCH_NULL' THEN 'Regimen Change'
                                   WHEN 'PREG_NULL' THEN 'First VL for Pregnant'
                                   WHEN 'INELIGIBLE_NULL' THEN 'N/A'
                                   WHEN 'FIRST_NULL' THEN 'First VL'
                                   WHEN 'RESTART_NOT_NULL' THEN 'client restarted ART'
                                   WHEN 'SWITCH_NOT_NULL' THEN 'Regimen Change'
                                   WHEN 'UNSUPPRESSED' THEN 'Repeat/Confirmatory Viral Load test'
                                   WHEN 'PMTCT_EARLY' THEN 'Pregnant/Breastfeeding and needs retesting'
                                   WHEN 'PMTCT_LATE' THEN 'Pregnant/Breastfeeding and needs retesting'
                                   WHEN 'ANNUAL' THEN 'Annual Viral Load Test'
                                   ELSE 'Unassigned'
                                   END AS vl_status_final
                        FROM vl_scenario),

     Identifiers AS (SELECT patient_id,
                            MAX(CASE WHEN pit.name = 'PHRH' THEN pi.identifier END) as phrh_code,
                            MAX(CASE WHEN pit.name = 'NCD' THEN pi.identifier END)  as ncd_code,
                            MAX(CASE WHEN pit.name = 'ICD' THEN pi.identifier END)  as icd_number
                     FROM mamba_dim_patient_identifier pi
                              JOIN mamba_dim_patient_identifier_type pit
                                   ON pi.identifier_type = pit.patient_identifier_type_id
                     WHERE pit.name IN ('PHRH', 'NCD', 'ICD')
                     GROUP BY patient_id),

     ICT_Events AS (SELECT *
                    FROM (SELECT client_id,
                                 CASE
                                     WHEN accepted = 'Yes' THEN 'Accepted'
                                     WHEN accepted = 'No' THEN 'Refused'
                                     ELSE 'Offered' END                                                as ict_status,
                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY offered_date DESC) as rn
                          FROM mamba_flat_encounter_ict_offer
                          WHERE offered_date IS NOT NULL) ranked
                    WHERE rn = 1),

     ICT_General_Events AS (SELECT *
                            FROM (SELECT client_id,
                                         ict_serial_number                                                                              as ict_number,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY encounter_datetime DESC, encounter_id DESC) as rn
                                  FROM mamba_flat_encounter_ict_general
                                  WHERE ict_serial_number IS NOT NULL
                                    AND ict_serial_number != '') ranked
                            WHERE rn = 1),

     NCD_Screening_Events AS (SELECT *
                              FROM (SELECT client_id,
                                           baseline_diagnosis,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY screening_date DESC) as rn
                                    FROM mamba_flat_encounter_ncd_screening
                                    WHERE screening_date IS NOT NULL) ranked
                              WHERE rn = 1),

     NCD_FollowUp_Events AS (SELECT *
                             FROM (SELECT f.client_id,
                                          return_visit_date                                                                              as next_screening_date,
                                          systolic_blood_pressure,
                                          diastolic_blood_pressure,
                                          ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY follow_up_date DESC, f.encounter_id DESC) as rn
                                   FROM mamba_flat_encounter_ncd_followup f
                                            LEFT JOIN mamba_flat_encounter_ncd_followup_1 f1
                                                      on f.encounter_id = f1.encounter_id
                                   WHERE return_visit_date IS NOT NULL
                                      OR systolic_blood_pressure IS NOT NULL
                                      OR diastolic_blood_pressure IS NOT NULL) ranked
                             WHERE rn = 1),

     CXCA_PrevScreening AS (SELECT *
                            FROM (SELECT client_id,
                                         follow_up_date_followup_                                                                             as follow_up_date,
                                         via_screening_result                                                                                 as ccs_via_result,
                                         via_date                                                                                             as via_date,
                                         ccs_treat_received_date,
                                         date_patient_referred_out,
                                         biopsy_result,
                                         hpv_dna_screening_result                                                                             as ccs_hpv_result,
                                         hpv_received_date                                                                                    as hpv_dna_result_received_date,
                                         cytology_result,
                                         cytology_received_date                                                                               as cytology_result_date,
                                         colposcopy_exam_finding,
                                         biopsy_result_received_date,
                                         next_follow_up_screening_date,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) as rn
                                  FROM FollowUp
                                  WHERE cx_ca_screening_status = 'Cervical cancer screening performed') ranked
                            WHERE rn = 1),

     CXCA_Eligibility_Base AS (SELECT lf.client_id,
                                      lf.visit_date,
                                      lf.follow_up_status                             as final_follow_up_status,
                                      lf.eligible_for_cxca_screening,
                                      lf.reason_for_not_being_eligible,
                                      lf.other_reason_for_not_being_eligible_for_cxca,
                                      lf.screening_status,
                                      lf.art_start_date,
                                      ps.follow_up_date                               AS previous_screening_follow_up_date,
                                      ps.ccs_via_result,
                                      ps.via_date,
                                      ps.ccs_treat_received_date,
                                      ps.date_patient_referred_out,
                                      ps.biopsy_result,
                                      ps.ccs_hpv_result,
                                      ps.hpv_dna_result_received_date,
                                      ps.cytology_result,
                                      ps.cytology_result_date,
                                      ps.colposcopy_exam_finding,
                                      ps.biopsy_result_received_date,
                                      ps.next_follow_up_screening_date,
                                      c.sex,
                                      TIMESTAMPDIFF(YEAR, c.date_of_birth, CURDATE()) AS Age,

                                      CASE
                                          WHEN ps.client_id IS NULL AND lf.eligible_for_cxca_screening = 'No'
                                              THEN CONCAT('Not Eligible ',
                                                          COALESCE(lf.reason_for_not_being_eligible,
                                                                   lf.other_reason_for_not_being_eligible_for_cxca))
                                          WHEN (ps.biopsy_result = 'Carcinoma in situ' OR
                                                ps.biopsy_result = 'Invasive cervical cancer' OR
                                                ps.biopsy_result = 'Other')
                                              AND (ps.ccs_treat_received_date <= CURDATE() OR
                                                   ps.date_patient_referred_out <= CURDATE())
                                              THEN 'Not Eligible Confirmed Cirvical Cancer'
                                          WHEN ps.client_id IS NULL AND
                                               lf.screening_status != 'Cervical cancer screening performed' AND
                                               lf.eligible_for_cxca_screening = 'Yes'
                                              THEN 'Eligible Labeled by User'
                                          WHEN ps.client_id IS NULL AND lf.eligible_for_cxca_screening IS NULL
                                              THEN 'Eligible Never Screened/Assessed'
                                          WHEN ps.ccs_via_result = 'Unknown'
                                              THEN 'Eligible Unknown VIA Screening Result'
                                          WHEN (TIMESTAMPDIFF(DAY, ps.via_date, CURDATE())) > 730 AND
                                               ps.ccs_via_result = 'VIA negative'
                                              THEN 'Eligible Needs Re-Screening'
                                          WHEN ps.ccs_via_result = 'VIA positive: eligible for cryo/thermo-coagula'
                                              THEN CASE
                                                       WHEN
                                                           ((TIMESTAMPDIFF(DAY, ps.ccs_treat_received_date, CURDATE())) >
                                                            365 OR
                                                            (TIMESTAMPDIFF(DAY, ps.date_patient_referred_out, CURDATE())) >
                                                            365) AND
                                                           ps.biopsy_result IS NULL
                                                           THEN 'Eligible Post Treatment/Referral Follow-Up'
                                                       WHEN ps.ccs_treat_received_date IS NULL AND
                                                            ps.date_patient_referred_out IS NULL
                                                           THEN 'Eligible Treatment Not Received or Not Referred'
                                                       ELSE 'Not Eligible (Screening Up-to-Date)'
                                              END
                                          WHEN (ps.ccs_via_result =
                                                'VIA positive: non-eligible for cryo/thermo-coagula' OR
                                                ps.ccs_via_result = 'suspected cervical cancer') AND
                                               ps.biopsy_result IS NULL
                                              THEN 'Eligible Biopsy Test Not Done'
                                          WHEN ps.ccs_hpv_result = 'Negative result' AND
                                               TIMESTAMPDIFF(DAY, ps.hpv_dna_result_received_date, CURDATE()) > 1095
                                              THEN 'Eligible Needs Re-Screening'
                                          WHEN ps.ccs_via_result IS NULL AND ps.ccs_hpv_result = 'Positive'
                                              THEN 'Eligible Needs VIA Triage'
                                          WHEN ps.cytology_result = 'Negative result' AND
                                               TIMESTAMPDIFF(DAY, ps.cytology_result_date, CURDATE()) > 1095
                                              THEN 'Eligible Needs Re-Screening'
                                          WHEN (ps.cytology_result =
                                                'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear' OR
                                                ps.cytology_result = '> Ascus')
                                              THEN CASE
                                                       WHEN ps.hpv_dna_result_received_date IS NULL
                                                           THEN 'Eligible Needs HPV Triage'
                                                       WHEN ps.ccs_hpv_result = 'Negative result' AND
                                                            TIMESTAMPDIFF(DAY, ps.hpv_dna_result_received_date, CURDATE()) >
                                                            730
                                                           THEN 'Eligible Needs Re-Screening'
                                                       WHEN ps.ccs_hpv_result = 'Positive' AND ps.colposcopy_exam_finding IS NULL
                                                           THEN 'Eligible Needs Colposcopy Test'
                                                       ELSE 'Not Eligible (Screening Up-to-Date)'
                                              END
                                          WHEN (ps.biopsy_result = 'CIN (1-3)' OR ps.biopsy_result = 'CIN-2') AND
                                               TIMESTAMPDIFF(DAY, ps.biopsy_result_received_date, CURDATE()) > 365
                                              THEN 'Eligible Needs Re-Screening'
                                          ELSE 'Not Eligible (Screening Up-to-Date)'
                                          END                                         AS EligibilityStatus
                               FROM LatestFollowUp lf
                                        LEFT JOIN CXCA_PrevScreening ps ON lf.client_id = ps.client_id
                                        JOIN mamba_dim_client c ON lf.client_id = c.client_id),

     CXCA_Status AS (SELECT base.*,
                            CASE
                                WHEN base.sex = 'Male' OR Age < 25 OR Age > 65 OR
                                     base.final_follow_up_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                    THEN 'Not Applicable (Blue)'
                                WHEN base.art_start_date IS NULL
                                    THEN 'ART Not Started (Black)'
                                WHEN base.EligibilityStatus = 'Not Eligible Confirmed Cirvical Cancer'
                                    THEN 'Confirmed CXCA (RED)'
                                WHEN base.EligibilityStatus = 'Not Eligible (Screening Up-to-Date)'
                                    THEN 'Previously Screened (Green)'
                                WHEN base.EligibilityStatus LIKE 'Eligible%'
                                    THEN 'Eligible (Yellow)'
                                WHEN base.EligibilityStatus LIKE 'Not Eligible%'
                                    THEN 'Not Eligible (White)'
                                ELSE 'Unknown Status'
                                END AS cxca_screening_status
                     FROM CXCA_Eligibility_Base AS base),

     PMTCT_CTE AS (SELECT client_id,
                          MAX(date_of_enrollment_or_booking) as pmtct_start_date
                   FROM mamba_flat_encounter_pmtct_enrollment
                   WHERE date_of_enrollment_or_booking IS NOT NULL
                   GROUP BY client_id),

     PMTCT_Discharge_CTE AS (SELECT client_id,
                                    MAX(discharge_date) as pmtct_discharge_date
                             FROM mamba_flat_encounter_pmtct_discharge
                             WHERE discharge_date IS NOT NULL
                             GROUP BY client_id),

     Registration AS (SELECT client_id,
                             MIN(registration_date) as registration_date
                      FROM mamba_flat_encounter_registration
                      WHERE registration_date IS NOT NULL
                      GROUP BY client_id),

     PHRH_Target_Population AS (SELECT *
                                FROM (SELECT client_id,
                                             target_population,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY followup_date DESC, encounter_id DESC) as rn
                                      FROM mamba_flat_encounter_phrh_followup
                                      WHERE target_population IS NOT NULL
                                        AND target_population != '') ranked
                                WHERE rn = 1),

     FamilyPlanning AS (SELECT *
                        FROM (SELECT client_id,
                                     method_of_family_planning,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) as rn
                              FROM FollowUp
                              WHERE method_of_family_planning IS NOT NULL
                                AND method_of_family_planning != ''
                                AND method_of_family_planning != '-') ranked
                        WHERE rn = 1)


SELECT c.client_id,
       c.patient_uuid,
       COALESCE(c.mrn, '-')                                                                                          as mrn,
       COALESCE(c.patient_name, '-')                                                                                 as patient_name,
       c.sex,
       c.date_of_birth                                                                                               as birthdate,
       TIMESTAMPDIFF(YEAR, c.date_of_birth, CURDATE())                                                               as age,

       COALESCE(c.uan, '-')                                                                                          as uan,
       COALESCE(id.phrh_code, '-')                                                                                   as phrh_code,
       COALESCE(id.ncd_code, '-')                                                                                    as ncd_code,
       COALESCE(id.icd_number, '-')                                                                                  as icd_number,
       COALESCE(ict_gen.ict_number, '-')                                                                             as ict_number,

       reg.registration_date                                                                                         as registration_date,
       ma.art_start_date                                                                                             as art_start_date,
       TIMESTAMPDIFF(MONTH, ma.art_start_date, CURDATE())                                                            as months_on_art,
       lfu.next_visit_date                                                                                           as next_appointment_date,

       lfu.hiv_confirmed_date                                                                                        as hiv_confirmed_date,
       ma.transfer_in_date                                                                                           as transfer_in_date,

       COALESCE(c.state_province, '-')                                                                               as region,
       COALESCE(c.county_district, '-')                                                                              as zone,
       COALESCE(c.city_village, '-')                                                                                 as woreda,
       COALESCE(c.kebele, '-')                                                                                       as kebele,
       COALESCE(c.house_number, '-')                                                                                 as house_number,
       COALESCE(c.mobile_no, '-')                                                                                    as mobile_phone,
       CASE
           WHEN (c.patient_name IS NOT NULL AND c.state_province IS NOT NULL AND c.mobile_no IS NOT NULL) THEN 'GREEN'
           ELSE 'YELLOW' END                                                                                         as address_completeness,

       CASE
           WHEN lfu.visit_date IS NULL THEN '-'
           WHEN lfu.follow_up_status IN ('Dead', 'Died') THEN 'Dead'
           WHEN lfu.follow_up_status IN ('Transferred out', 'TO') THEN 'Transferred Out'
           WHEN lfu.treatment_end_date >= CURDATE() THEN 'Active'
           ELSE COALESCE(lfu.follow_up_status, '-')
           END                                                                                                       as current_status,

       COALESCE(lfu.regimen, '-')                                                                                    as current_regimen,
       COALESCE(lfu.regimen_dose, '-')                                                                               as regimen_dose,

       CASE
           WHEN lfu.regimen IS NULL THEN '-'
           WHEN lfu.regimen LIKE '1%' THEN 'First Line'
           WHEN lfu.regimen LIKE '2%' THEN 'Second Line'
           ELSE 'Other'
           END                                                                                                       as regimen_line,

       lfu.treatment_end_date                                                                                        as tx_curr_end_date,
       CASE COALESCE(lfu.nutritional_status_of_adult, lfu.nutritional_status_of_older_child_a)
           WHEN 'normal' THEN 'Normal'
           WHEN 'Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)' THEN 'Mild Malnutrition'
           WHEN 'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)'
               THEN 'Moderate Malnutrition'
           WHEN 'Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)'
               THEN 'Severe Malnutrition'
           WHEN 'Overweight' THEN 'Overweight'
           WHEN 'Obese Abdomen' THEN 'Obese'
           ELSE COALESCE(lfu.nutritional_status_of_adult, lfu.nutritional_status_of_older_child_a, '-')
           END                                                                                                       AS nutritional_status,
       COALESCE(lfu.pregnancy_status, '-')                                                                           as pregnancy_status,
       CASE
           WHEN (pmtct.pmtct_start_date IS NOT NULL AND
                 (pmtct_dis.pmtct_discharge_date IS NULL OR pmtct_dis.pmtct_discharge_date < pmtct.pmtct_start_date))
               THEN 'Currently on PMTCT'
           ELSE 'Not Applicable'
           END                                                                                                       as pmtct_status,
       COALESCE(fp.method_of_family_planning, '-')                                                                   as family_planning_method,
       COALESCE(lfu.who_stage, '-')                                                                                  as who_stage,

       lfu.visit_date                                                                                                as last_visit_date,
       CASE
           WHEN DATEDIFF(CURDATE(), COALESCE(lfu.next_visit_date, lfu.visit_date)) > 0 THEN DATEDIFF(CURDATE(),
                                                                                                     COALESCE(lfu.next_visit_date, lfu.visit_date))
           ELSE 0 END                                                                                                as days_overdue,

       lab.viral_load_perform_date                                                                                   as last_vl_date,
       lab.viral_load_count                                                                                          as last_vl_result,
       CASE
           WHEN lab.viral_load_status_inferred = 'S' THEN 1
           WHEN lab.viral_load_status_inferred = 'U' THEN 0
           ELSE NULL
           END                                                                                                       as is_suppressed,

       CASE
           WHEN lfu.visit_date IS NULL THEN '-'
           WHEN lab.vl_status_final = 'N/A' THEN 'Not Applicable'
           WHEN lab.eligiblityDate <= CURDATE() THEN 'Eligible for Viral Load'
           WHEN lab.eligiblityDate > CURDATE() THEN 'Viral Load Done (Currently not Eligible)'
           WHEN lab.art_start_date IS NULL AND lab.follow_up_status IS NULL THEN 'Not Started ART'
           ELSE '-'
           END                                                                                                       as vl_status,

       lab.eligiblityDate                                                                                            as vl_eligibility_date,

       CASE
           WHEN ma.tpt_completed_date IS NOT NULL THEN 'Gold (TPT Completed)'
           WHEN ma.tpt_start_date IS NOT NULL AND ma.tpt_completed_date IS NULL AND ma.tpt_discontinued_date IS NULL
               THEN 'On TPT'
           WHEN ma.tpt_is_contraindicated = 1 THEN 'Contraindicated'
           ELSE 'Not Started'
           END                                                                                                       as tpt_status,

       ma.tpt_start_date                                                                                             as tpt_start_date,
       ma.tpt_completed_date                                                                                         as tpt_completed_date,
       ma.tpt_discontinued_date                                                                                      as tpt_discontinued_date,

       ma.active_tb_diagnosis_date                                                                                   as active_tb_diagnosis_date,
       ma.tb_treatment_start_date                                                                                    as tb_treatment_start_date,
       ma.tb_treatment_discontinued_date                                                                             as tb_treatment_discontinued_date,
       ma.tb_treatment_completed_date                                                                                as tb_treatment_completed_date,

       COALESCE(lfu.dsd_category, '-')                                                                               as dsd_category,

       COALESCE(ict.ict_status, 'Not Screened')                                                                      as ict_screening_status,
       COALESCE(ncd.baseline_diagnosis, CASE
                                            WHEN ncd.client_id IS NOT NULL THEN 'Screened'
                                            ELSE 'Not Screened' END)                                                 as ncd_screening_status,
       ncd_fu.next_screening_date                                                                                    as next_ncd_screening_date,

       COALESCE(cxca.cxca_screening_status, 'Not Applicable')                                                        as cxca_screening_status,
       cxca.next_follow_up_screening_date                                                                            as next_cca_screening_date,
       ncd_fu.systolic_blood_pressure                                                                                as systolic_blood_pressure,
       ncd_fu.diastolic_blood_pressure                                                                               as diastolic_blood_pressure,

       COALESCE(phrh.target_population, c.key_population, '-')                                                       as target_population

FROM mamba_dim_client c
         LEFT JOIN LatestFollowUp lfu ON c.client_id = lfu.client_id
         LEFT JOIN Medical_Aggregates ma ON c.client_id = ma.client_id
         LEFT JOIN vl_eligibility lab ON c.client_id = lab.client_id
         LEFT JOIN Identifiers id ON c.client_id = id.patient_id
         LEFT JOIN ICT_Events ict ON c.client_id = ict.client_id
         LEFT JOIN ICT_General_Events ict_gen ON c.client_id = ict_gen.client_id
         LEFT JOIN NCD_Screening_Events ncd ON c.client_id = ncd.client_id
         LEFT JOIN NCD_FollowUp_Events ncd_fu ON c.client_id = ncd_fu.client_id
         LEFT JOIN CXCA_Status cxca ON c.client_id = cxca.client_id
         LEFT JOIN PMTCT_CTE pmtct ON c.client_id = pmtct.client_id
         LEFT JOIN PMTCT_Discharge_CTE pmtct_dis ON c.client_id = pmtct_dis.client_id
         LEFT JOIN Registration reg ON c.client_id = reg.client_id
         LEFT JOIN PHRH_Target_Population phrh ON c.client_id = phrh.client_id
         LEFT JOIN FamilyPlanning fp ON c.client_id = fp.client_id;
-- $END
END //

DELIMITER ;

        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_client_update
--

DROP PROCEDURE IF EXISTS sp_fact_client_update;

DELIMITER //

~
CREATE PROCEDURE sp_fact_client_update()
BEGIN

DECLARE EXIT HANDLER FOR SQLEXCEPTION
BEGIN
    GET DIAGNOSTICS CONDITION 1

    @message_text = MESSAGE_TEXT,
    @mysql_errno = MYSQL_ERRNO,
    @returned_sqlstate = RETURNED_SQLSTATE;

    CALL sp_mamba_etl_error_log_insert('sp_fact_client_update', @message_text, @mysql_errno, @returned_sqlstate);

    UPDATE _mamba_etl_schedule
    SET end_time                   = NOW(),
        completion_status          = 'ERROR',
        transaction_status         = 'COMPLETED',
        success_or_error_message   = CONCAT('sp_fact_client_update', ', ', @mysql_errno, ', ', @message_text)
        WHERE id = (SELECT last_etl_schedule_insert_id FROM _mamba_etl_user_settings ORDER BY id DESC LIMIT 1);

    RESIGNAL;
END;

-- $BEGIN
-- $END
END //

DELIMITER ;

        
-- ---------------------------------------------------------------------------------------------
-- sp_data_processing_derived_client
--

DROP PROCEDURE IF EXISTS sp_data_processing_derived_client;

DELIMITER //

~
CREATE PROCEDURE sp_data_processing_derived_client()
BEGIN

DECLARE EXIT HANDLER FOR SQLEXCEPTION
BEGIN
    GET DIAGNOSTICS CONDITION 1

    @message_text = MESSAGE_TEXT,
    @mysql_errno = MYSQL_ERRNO,
    @returned_sqlstate = RETURNED_SQLSTATE;

    CALL sp_mamba_etl_error_log_insert('sp_data_processing_derived_client', @message_text, @mysql_errno, @returned_sqlstate);

    UPDATE _mamba_etl_schedule
    SET end_time                   = NOW(),
        completion_status          = 'ERROR',
        transaction_status         = 'COMPLETED',
        success_or_error_message   = CONCAT('sp_data_processing_derived_client', ', ', @mysql_errno, ', ', @message_text)
        WHERE id = (SELECT last_etl_schedule_insert_id FROM _mamba_etl_user_settings ORDER BY id DESC LIMIT 1);

    RESIGNAL;
END;

-- $BEGIN
CALL sp_dim_client();
CALL sp_fact_client();
-- $END
END //

DELIMITER ;

        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_cxca_scrn_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_cxca_scrn_datim_query;

~
CREATE PROCEDURE sp_dim_cxca_scrn_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN

    DECLARE age_group_cols TEXT;
    DECLARE cxca_scrn_query TEXT;
    DECLARE cxca_visit_condition TEXT;
    DECLARE group_query TEXT;

    SET session group_concat_max_len = 20000;

    IF REPORT_TYPE = 'FIRST_TIME_SCREENING' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Initial visit'' ';
    ELSEIF REPORT_TYPE = 'RE_SCREENING' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Re-screening for cervical cancer after 5 year'' OR visit_type = ''Re-screening for cervical cancer after 3 year'' OR visit_type = ''Re-screening for cervical cancer after 2 year'' OR visit_type = ''Re-screening for cervical cancer after 1 year'' ';
    ELSEIF REPORT_TYPE = 'POST_TREATMENT' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Post-treatment follow-up other'' OR visit_type = ''Post-treatment follow-up at 1 year'' OR visit_type =''Post-treatment follow-up to 6 weeks'' ';
    ELSE
        SET cxca_visit_condition = '1=1';
    END IF;

    SET cxca_scrn_query = CONCAT('WITH FollowUp as (select encounter_id,
                         client_id,
                         cervical_cancer_screening_status          as cx_ca_screening_status,
                         cervical_cancer_screening_method_strategy as screening_method,
                         via_screening_result,
                         hpv_dna_screening_result,
                         follow_up_date_followup_                  as follow_up_date,
                         date_hpv_test_was_done                    as hpv_date,
                         date_visual_inspection_of_the_cervi       as via_date,
                         cytology_sample_collection_date           as cytology_date,
                         follow_up_status,
                         treatment_end_date,
                         antiretroviral_art_dispensed_dose_i       as dose_days,
                         art_antiretroviral_start_date             as art_start_date,
                         cytology_result,
                         purpose_for_visit_cervical_screening      as visit_type,
                         hpv_dna_result_received_date              as hpv_received_date,
                         date_cytology_result_received             as cytology_received_date,
                         is_the_client_screened_in_this_facility
                  FROM mamba_fact_followup),
     tmp_latest_follow_up AS (SELECT client_id,
                                     follow_up_date,
                                     encounter_id,
                                     follow_up_status,
                                     treatment_end_date,
                                     dose_days,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
     ),

     currently_on_art AS (select *
                          from tmp_latest_follow_up
                          where row_num = 1
                          --  AND follow_up_status in (''Alive'', ''Restart medication'')
                          ),
     tmp_cx_screened as (select FollowUp.*,
                                ROW_NUMBER() over (PARTITION BY FollowUp.client_id ORDER BY via_date DESC,hpv_received_date DESC,cytology_received_date DESC , FollowUp.encounter_id DESC) as row_num
                         from FollowUp
                                  join currently_on_art on FollowUp.client_id = currently_on_art.client_id
                         where cx_ca_screening_status = ''Cervical cancer screening performed''
                           and is_the_client_screened_in_this_facility = ''Yes''
                           and ((via_date BETWEEN ''',REPORT_START_DATE,'''  AND ''',REPORT_END_DATE,'''
                               ) OR
                                (hpv_received_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,
                                 ''' ) OR (cytology_received_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ))),
     cx_screened as (select tmp_cx_screened.*,
                            CASE


                                #  WHEN screening_method=''Human Papillomavirus test'' and hpv_dna_screening_result =''Unknown'' then ''Cervical Cancer screen: Suspected Cancer''
                                WHEN screening_method = ''Human Papillomavirus test'' and
                                     hpv_dna_screening_result = ''Negative result''
                                    then ''Cervical Cancer screen: Negative''
                                WHEN screening_method = ''Visual Inspection of the Cervix with Acetic Acid (VIA)'' and
                                     via_screening_result = ''VIA negative'' then ''Cervical Cancer screen: Negative''
                                WHEN screening_method = ''Visual Inspection of the Cervix with Acetic Acid (VIA)'' and
                                     (via_screening_result = ''VIA positive: eligible for cryo/thermo-coagulation'' or
                                      via_screening_result = ''VIA positive: eligible for cryo/thermo-coagula'' or
                                      via_screening_result = ''VIA positive: non-eligible for cryo/thermo-coagulation'' or
                                      via_screening_result = ''VIA positive: non-eligible for cryo/thermo-coagula'')
                                    then ''Cervical Cancer screen: Positive''
                                WHEN screening_method = ''Visual Inspection of the Cervix with Acetic Acid (VIA)'' and
                                     via_screening_result = ''Suspicious for cervical cancer'' or via_screening_result = ''suspected cervical cancer''
                                    then ''Cervical Cancer screen: Suspected Cancer''

                                WHEN screening_method = ''Human Papillomavirus test'' and
                                     hpv_dna_screening_result = ''Positive''
                                    and
                                     (via_screening_result = ''VIA positive: eligible for cryo/thermo-coagulation'' or
                                      via_screening_result = ''VIA positive: eligible for cryo/thermo-coagula'' or
                                      via_screening_result = ''VIA positive: non-eligible for cryo/thermo-coagulation'')
                                    then ''Cervical Cancer screen: Positive''
                                WHEN screening_method = ''Human Papillomavirus test'' and
                                     hpv_dna_screening_result = ''Positive''
                                    and via_screening_result = ''VIA negative'' then ''Cervical Cancer screen: Negative''
                                WHEN screening_method = ''Cytology'' and
                                     (cytology_result = ''Negative'' OR cytology_result = ''ASCUS'')
                                    THEN ''Cervical Cancer screen: Negative''
                                WHEN screening_method = ''Cytology'' and cytology_result = ''> Ascus''
                                    THEN ''Cervical Cancer screen: Positive''
                                END                                             AS screening_result,
                            client.uan,
                            client.mrn,
                            client.sex,
                            client.date_of_birth,
                            (SELECT datim_agegroup
                             from mamba_dim_agegroup
                             where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as fine_age_group,
                            (SELECT normal_agegroup
                             from mamba_dim_agegroup
                             where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as coarse_age_group
                     from tmp_cx_screened
                              join mamba_dim_client client
                                   on tmp_cx_screened.client_id = client.client_id
                     where row_num = 1
                       and TIMESTAMPDIFF(YEAR, date_of_birth, follow_up_date) >= 15
                       and not (screening_method = ''Human Papillomavirus test'' and
                                hpv_dna_screening_result = ''Positive'' and via_screening_result is null)
     ) ');
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
                and mamba_dim_agegroup.datim_age_val <= 12
              group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group ',
                                   CASE

                                       WHEN datim_agegroup IN ('50-54', '55-59', '60-64', '65+') THEN
                                           'IN (''50-54'', ''55-59'', ''60-64'', ''65+'')'
                                       ELSE
                                           CONCAT(' = ', '''', datim_agegroup, '''')
                                       END,
                                   ' THEN count ELSE 0 END) AS `',
                                   REPLACE(
                                           CASE
                                               WHEN datim_agegroup IN ('50-54', '55-59', '60-64', '65+') THEN '50+'
                                               ELSE datim_agegroup
                                               END,
                                           '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
                and mamba_dim_agegroup.datim_age_val <= 12
              group by datim_agegroup) as order_query;
    END IF;
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM cx_screened';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM cx_screened';
    ELSE
        SET group_query = CONCAT('
        SELECT
        CASE
        WHEN screening_result=''Cervical Cancer screen: Negative'' THEN ''Cervical Cancer screen: Negative''
        WHEN screening_result=''Cervical Cancer screen: Positive'' THEN ''Cervical Cancer screen: Positive''
        WHEN screening_result=''Cervical Cancer screen: Suspected Cancer'' THEN ''Cervical Cancer screen: Suspected Cancer'' END AS screening_result,
        SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            screening_result,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM cx_screened WHERE ', cxca_visit_condition, '
          GROUP BY screening_result, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Cervical Cancer screen: Negative'' AS screening_result
                     UNION SELECT ''Cervical Cancer screen: Positive''
                     UNION SELECT ''Cervical Cancer screen: Suspected Cancer'') AS screening_result
        USING (screening_result)
        GROUP BY screening_result
        ');
    END IF;
    SET @sql = CONCAT(cxca_scrn_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_cxca_tx_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_cxca_tx_datim_query;

~
CREATE PROCEDURE sp_dim_cxca_tx_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)

)
BEGIN

    DECLARE age_group_cols VARCHAR(5000);
    DECLARE cxca_tx_query text;
    DECLARE cxca_visit_condition VARCHAR(1000);
    DECLARE group_query TEXT;

    SET session group_concat_max_len = 20000;

    IF REPORT_TYPE = 'FIRST_TIME_SCREENING' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Initial visit'' ';
    ELSEIF REPORT_TYPE = 'RE_SCREENING' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Re-screening for cervical cancer after 5 year'' OR visit_type = ''Re-screening for cervical cancer after 3 year'' OR visit_type = ''Re-screening for cervical cancer after 1 year'' ';
    ELSEIF REPORT_TYPE = 'POST_TREATMENT' THEN
        SET cxca_visit_condition =
                ' visit_type = ''Post-treatment follow-up other'' OR visit_type = ''Post-treatment follow-up at 1 year'' OR visit_type =''Post-treatment follow-up to 6 weeks'' ';
    ELSE
        SET  cxca_visit_condition = '1=1';
    END IF;

    SET cxca_tx_query = CONCAT('WITH FollowUp as (select encounter_id,
                         client_id,
                         cervical_cancer_screening_status          as cx_ca_screening_status,
                         cervical_cancer_screening_method_strategy as screening_type,
                         via_screening_result,
                         hpv_dna_screening_result,
                         follow_up_date_followup_                  as follow_up_date,
                         date_hpv_test_was_done                    as hpv_date,
                         date_visual_inspection_of_the_cervi       as via_date,
                         treatment_of_precancerous_lesions_of_the_cervix as treatment,
                         treatment_start_date,
                         art_antiretroviral_start_date as art_start_date,
                         purpose_for_visit_cervical_screening as visit_type
                  FROM mamba_fact_followup),
     tmp_cx_rx as (select *,
                          ROW_NUMBER() over (PARTITION BY client_id ORDER BY treatment_start_date DESC, encounter_id DESC) as row_num
                   from FollowUp
                   where treatment_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' and art_start_date is not null),

     cx_rx as (select tmp_cx_rx.*,
                      client.date_of_birth,
                      client.sex,
                      (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                      (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group
               from tmp_cx_rx
                        left join mamba_dim_client client on tmp_cx_rx.client_id = client.client_id
               where row_num = 1 and current_age >= 15 ) ');
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup where mamba_dim_agegroup.datim_age_val > 4 group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup where mamba_dim_agegroup.datim_age_val > 4 group by datim_agegroup) as order_query;
    END IF;
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM cx_rx';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM cx_rx';
    ELSE
    SET group_query = CONCAT('
        SELECT
        CASE
        WHEN treatment=''Cryosurgery of lesion of cervix'' THEN ''Cryotherapy''
        WHEN treatment=''Loop electrosurgical excision procedure of cervix'' THEN ''LEEP''
        WHEN treatment=''Thermocauterization of cervix'' THEN ''Thermocoagulation'' END AS treatment,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            treatment,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM cx_rx WHERE ', cxca_visit_condition, '
          GROUP BY treatment, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Cryosurgery of lesion of cervix'' AS treatment
                     UNION SELECT ''Loop electrosurgical excision procedure of cervix''
                     UNION SELECT ''Thermocauterization of cervix'') AS treatment
        USING (treatment)
        GROUP BY treatment
        ');
    END IF;
    SET @sql = CONCAT(cxca_tx_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_ict_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_ict_datim_query;

~
CREATE PROCEDURE sp_dim_ict_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    DECLARE age_group_cols VARCHAR(5000);
    DECLARE ict_query VARCHAR(6000);
    DECLARE filter_condition VARCHAR(200);
    DECLARE group_query TEXT;
    DECLARE source_cte VARCHAR(100);
    SET session group_concat_max_len = 20000;


    IF REPORT_TYPE = 'TESTING_OFFERED' THEN
        SET filter_condition = ' offer.offered_date is not null ';
    ELSEIF REPORT_TYPE = 'TESTING_ACCEPTED' THEN
        SET filter_condition = ' accepted = ''Yes'' ';
    ELSEIF REPORT_TYPE = 'ELICITED' THEN
        SET filter_condition = CONCAT(' elicited_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
    ELSEIF REPORT_TYPE = 'KNOWN_POSITIVE' THEN
        SET filter_condition =
               CONCAT(' prior_hiv_test_result = ''Positive'' and elicited_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' AND hiv_test_result IS NULL ');
    ELSEIF REPORT_TYPE = 'DOCUMENTED_NEGATIVE' THEN
        SET filter_condition =
               CONCAT( ' prior_hiv_test_result = ''Negative result'' and hiv_test_result != ''Positive'' and age < 15 and elicited_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
    ELSEIF REPORT_TYPE = 'NEW_POSITIVE' THEN
        SET filter_condition =
              CONCAT( ' hiv_test_result = ''Positive'' and coalesce(hiv_test_date,date_of_case_closure,elicited_date) BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
    ELSEIF REPORT_TYPE = 'NEW_NEGATIVE' THEN
        SET filter_condition =
                CONCAT(' hiv_test_result = ''Negative result'' and coalesce(hiv_test_date,date_of_case_closure,elicited_date) BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' AND age > 14 ');
    ELSEIF REPORT_TYPE = 'ICT_TOTAL' THEN
        SET filter_condition = CONCAT(' hiv_test_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' and hiv_test_result is not null ');
    ELSE
        SET filter_condition = ' 1=1 ';
    END IF;
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSEIF REPORT_TYPE = 'DOCUMENTED_NEGATIVE' THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup
              from mamba_dim_agegroup
              where datim_age_val between 2 and 4
              group by datim_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;
    IF REPORT_TYPE = 'TESTING_OFFERED' OR REPORT_TYPE = 'TESTING_ACCEPTED' THEN
        SET source_cte = ' offer ';
    ELSE
        SET source_cte = ' contact_list ';
    END IF;
    SET ict_query =CONCAT( ' With offer_list as (select client.client_id,
                           client.mrn,
                           client.uan,
                           (SELECT datim_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE ,''' ) = age) as fine_age_group,
                                     (SELECT normal_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as coarse_age_group,
                           TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) as age,
                           client.sex,
                           offer.offered_date,
                           offered,
                           offer.yes,
                           offer.no,
                           accepted,
                           accepted_date,
                           number_of_male_contacts_above_the_age_of_15,
                           number_of_male_contacts_below_the_age_of_15,
                           number_of_female_contacts_above_the_age_of_15,
                           number_of_female_contacts_below_the_age_of_15,
                           ROW_NUMBER() over (PARTITION BY client.client_id ORDER BY offered_date DESC ) as row_num
                    from mamba_flat_encounter_ict_general ict_general
                             join mamba_flat_encounter_ict_offer offer on ict_general.client_id = offer.client_id
                             join mamba_dim_client client on ict_general.client_id = client.client_id
                    where offered_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE ,''' ),
                 offer as (select * from offer_list where row_num = 1),
                      contact_list as (select contact.client_id,
       contact.elicited_date,
       contact.hiv_test_date,
       contact.hiv_test_result,
       prior_hiv_test_result,
       prior_test_date_estimated,
       date_of_case_closure,
       encounter.encounter_id,
       encounter.uuid,
       coalesce(contact_birthdate,index_contact.date_of_birth) as birthdate,

       CASE
           WHEN COALESCE(index_contact.sex, contact_1.respondent_gender) IN
                (''F'', ''Female gender'') THEN ''Female''
           WHEN COALESCE(index_contact.sex, contact_1.respondent_gender) IN
                (''M'', ''Male gender'') THEN ''Male''
           ELSE COALESCE(index_contact.sex, contact_1.respondent_gender)
           END AS sex,

       (SELECT datim_agegroup
        from mamba_dim_agegroup
        where TIMESTAMPDIFF(YEAR, coalesce(contact_birthdate,index_contact.date_of_birth), ''',REPORT_END_DATE,''' ) = age) as fine_age_group,
       (SELECT normal_agegroup
        from mamba_dim_agegroup
        where TIMESTAMPDIFF(YEAR, coalesce(contact_birthdate,index_contact.date_of_birth), ''',REPORT_END_DATE,''' ) = age) as coarse_age_group,
       TIMESTAMPDIFF(YEAR, coalesce(contact_birthdate,index_contact.date_of_birth), ''',REPORT_END_DATE,''' ) as age
from mamba_flat_encounter_index_contact_followup contact
         left join mamba_flat_encounter_index_contact_followup_1 contact_1
                   on contact.encounter_id = contact_1.encounter_id
         left join mamba_flat_encounter_ict_general g on contact.client_id = g.client_id
         left join mamba_dim_client index_client on contact.client_id = index_client.client_id
         left join mamba_dim_encounter encounter on contact.encounter_id = encounter.encounter_id
         left join mamba_dim_person_attribute attribute on encounter.uuid = attribute.value
         left join mamba_dim_client index_contact on attribute.person_id = index_contact.client_id) ');

    IF REPORT_TYPE = 'ICT_TOTAL' THEN
        SET group_query = CONCAT('SELECT COUNT(*) as Numerator FROM contact_list WHERE ', filter_condition);
    ELSEIF REPORT_TYPE = 'ELICITED' THEN
        SET IS_COURSE_AGE_GROUP = 1;
        SET group_query = CONCAT('
            SELECT
              sex,
              SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
              ', age_group_cols, ' ,
              SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
            FROM (
              SELECT
                sex,
                ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
                COUNT(*) AS count
              FROM ', source_cte, ' WHERE ', filter_condition, ' GROUP BY sex, ',
                                 IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
            ) AS subquery
            RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
            USING (sex)
            GROUP BY sex
            ');
    ELSE
        SET group_query = CONCAT('
            SELECT
              sex,
              SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
              ', age_group_cols, ' ,
              SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
            FROM (
              SELECT
                sex,
                ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
                COUNT(*) AS count
              FROM ', source_cte, ' WHERE ', filter_condition, ' GROUP BY sex, ',
                                 IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
            ) AS subquery
            RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
            USING (sex)
            GROUP BY sex
            ');
    END IF;
    SET @sql = CONCAT(ict_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //
DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_pmtct_eid_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_pmtct_eid_datim_query;

~
CREATE PROCEDURE sp_dim_pmtct_eid_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    -- DSD: PMTCT_EID - Early Infant Diagnosis Report
    -- Numerator: HIV-exposed infants who had a virologic HIV test by 12 months during reporting period
    -- Disaggregated by: infant age at test (0<=2 months, 2-12 months) and test sequence (First test, Second test or more)

    DECLARE base_query TEXT;
    DECLARE final_query TEXT;

    SET session group_concat_max_len = 30000;

    SET base_query = CONCAT(
            'WITH tmp_hei_test AS ( ',
            '    SELECT ',
            '        hiv_test.client_id, ',
            '        hiv_test_date, ',
            '        date_of_birth, ',
            '        hiv_test_result, ',
            '        test_round, ',
            '        dna_pcr_sample_collection_date, ',
            '        TIMESTAMPDIFF(MONTH, date_of_birth, dna_pcr_sample_collection_date) as age_in_months, ',
            '        ROW_NUMBER() OVER (PARTITION BY hiv_test.client_id ORDER BY dna_pcr_sample_collection_date ASC, encounter_id ASC) as test_sequence, ',
            '        ROW_NUMBER() OVER (PARTITION BY hiv_test.client_id ORDER BY dna_pcr_sample_collection_date DESC, encounter_id DESC) as row_num ',
            '    FROM mamba_flat_encounter_hei_hiv_test hiv_test ',
            '    JOIN mamba_dim_client client ON hiv_test.client_id = client.client_id ',
            '    WHERE dna_pcr_sample_collection_date BETWEEN ''', REPORT_START_DATE, ''' AND ''', REPORT_END_DATE, ''' ',
            '), ',
            'hei_test AS ( ',
            '    SELECT *, ',
            '           CASE WHEN test_sequence = 1 THEN ''First Test'' ELSE ''Second Test or More'' END as test_category, ',
            '           CASE WHEN age_in_months <= 2 THEN ''0<=2 Months'' ELSE ''2-12 Months'' END as age_category ',
            '    FROM tmp_hei_test ',
            '    WHERE age_in_months <= 12 ',
            '      AND row_num = 1 ',
            '), ',
            'categories AS ( ',
            '    SELECT ''First Test'' as test_category, 1 as sort_order ',
            '    UNION ALL ',
            '    SELECT ''Second Test or More'', 2 ',
            ') '
                     );

    IF REPORT_TYPE = 'NUMERATOR' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT COALESCE(COUNT(*), 0) AS Numerator FROM hei_test'
                          );

    ELSEIF REPORT_TYPE = 'DISAGGREGATED' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT ',
                                 '    c.test_category, ',
                                 '    COALESCE(SUM(CASE WHEN h.age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `0<=2 Months`, ',
                                 '    COALESCE(SUM(CASE WHEN h.age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `2-12 Months` ',
                                 'FROM categories c ',
                                 'LEFT JOIN hei_test h ON c.test_category = h.test_category ',
                                 'GROUP BY c.test_category, c.sort_order ',
                                 'ORDER BY c.sort_order'
                          );

    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT ',
                                 '    (SELECT COALESCE(COUNT(*), 0) FROM hei_test) AS Numerator, ',
                                 '    COALESCE(SUM(CASE WHEN test_category = ''First Test'' AND age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `First_Test_0_2_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN test_category = ''First Test'' AND age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `First_Test_2_12_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN test_category = ''Second Test or More'' AND age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `Second_Test_0_2_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN test_category = ''Second Test or More'' AND age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `Second_Test_2_12_Months` ',
                                 'FROM hei_test'
                          );

    ELSE
        -- DEBUG mode
        SET final_query = CONCAT(base_query,
                                 'SELECT client_id AS Client, test_category AS Test_Category, age_category AS Age_Category, age_in_months AS Age_Months, dna_pcr_sample_collection_date FROM hei_test'
                          );
    END IF;

    SET @sql = final_query;
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_pmtct_fo_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_pmtct_fo_datim_query;

~
CREATE PROCEDURE sp_dim_pmtct_fo_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    -- DSD: PMTCT_FO - Final Outcome Report
    -- Denominator: HIV-exposed infants born 24 months prior to reporting period and registered in birth cohort
    -- Numerator: HIV-exposed infants with documented outcome by 18 months of age
    -- Disaggregated by: HIV-infected, HIV-uninfected, HIV-final status unknown, Died without status known

    DECLARE base_query TEXT;
    DECLARE final_query TEXT;
    
    -- Build base CTE query
    SET base_query = CONCAT(
        'WITH tmp_birth_cohort AS ( ',
        '    SELECT e.client_id, c.date_of_birth, e.encounter_datetime as enrollment_date, ',
        '           ROW_NUMBER() OVER (PARTITION BY e.client_id ORDER BY e.encounter_datetime DESC, e.encounter_id DESC) as row_num ',
        '    FROM mamba_flat_encounter_hei_enrollment e ',
        '    JOIN mamba_dim_client c ON e.client_id = c.client_id ',
        '    WHERE c.date_of_birth BETWEEN DATE_SUB(''', REPORT_START_DATE, ''', INTERVAL 24 MONTH) ',
        '          AND DATE_SUB(''', REPORT_END_DATE, ''', INTERVAL 24 MONTH) ',
        '), ',
        'birth_cohort AS ( ',
        '    SELECT * FROM tmp_birth_cohort WHERE row_num = 1 ',
        '), ',
        'tmp_final_outcome AS ( ',
        '    SELECT fo.client_id, fo.date_when_final_outcome_was_known, fo.positive, fo.negative_result, ',
        '           fo.still_on_bfexposed, fo.lost_to_followup, fo.died, fo.transferred_out, bc.date_of_birth, ',
        '           TIMESTAMPDIFF(MONTH, bc.date_of_birth, fo.date_when_final_outcome_was_known) as age_at_outcome_months, ',
        '           ROW_NUMBER() OVER (PARTITION BY fo.client_id ORDER BY fo.date_when_final_outcome_was_known DESC, fo.encounter_id DESC) as row_num ',
        '    FROM mamba_flat_encounter_hei_final_outcome fo ',
        '    JOIN birth_cohort bc ON fo.client_id = bc.client_id ',
        '    WHERE fo.date_when_final_outcome_was_known IS NOT NULL ',
        '), ',
        'final_outcome AS ( ',
        '    SELECT * FROM tmp_final_outcome WHERE row_num = 1 AND age_at_outcome_months <= 18 ',
        '), ',
        'outcome_categorized AS ( ',
        '    SELECT fo.*, ',
        '           CASE WHEN fo.positive IS NOT NULL THEN ''HIV-infected'' ',
        '                WHEN fo.negative_result IS NOT NULL THEN ''HIV-uninfected'' ',
        '                WHEN fo.died IS NOT NULL THEN ''Died without status known'' ',
        '                WHEN fo.still_on_bfexposed IS NOT NULL OR fo.lost_to_followup IS NOT NULL OR fo.transferred_out IS NOT NULL THEN ''HIV-final status unknown'' ',
        '                ELSE ''HIV-final status unknown'' ',
        '           END AS outcome_type ',
        '    FROM final_outcome fo ',
        ') '
    );
    
    -- Build final SELECT based on REPORT_TYPE
    IF REPORT_TYPE = 'DENOMINATOR' THEN
        SET final_query = CONCAT(base_query, 
            'SELECT COALESCE(COUNT(*), 0) AS Denominator FROM birth_cohort'
        );
    
    ELSEIF REPORT_TYPE = 'NUMERATOR' THEN
        SET final_query = CONCAT(base_query,
            'SELECT COALESCE(COUNT(*), 0) AS Numerator FROM outcome_categorized'
        );
    
    ELSEIF REPORT_TYPE = 'DISAGGREGATED' THEN
        SET final_query = CONCAT(base_query,
            'SELECT ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-infected'' THEN 1 ELSE 0 END), 0) AS `HIV-infected`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-uninfected'' THEN 1 ELSE 0 END), 0) AS `HIV-uninfected`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-final status unknown'' THEN 1 ELSE 0 END), 0) AS `HIV-final status unknown`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''Died without status known'' THEN 1 ELSE 0 END), 0) AS `Died without status known` ',
            'FROM outcome_categorized'
        );
    
    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET final_query = CONCAT(base_query,
            'SELECT ',
            '    (SELECT COALESCE(COUNT(*), 0) FROM birth_cohort) AS Denominator, ',
            '    (SELECT COALESCE(COUNT(*), 0) FROM outcome_categorized) AS Numerator, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-infected'' THEN 1 ELSE 0 END), 0) AS `HIV-infected`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-uninfected'' THEN 1 ELSE 0 END), 0) AS `HIV-uninfected`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''HIV-final status unknown'' THEN 1 ELSE 0 END), 0) AS `HIV-final status unknown`, ',
            '    COALESCE(SUM(CASE WHEN outcome_type = ''Died without status known'' THEN 1 ELSE 0 END), 0) AS `Died without status known` ',
            'FROM outcome_categorized'
        );
    
    ELSE
        -- DEBUG mode
        SET final_query = CONCAT(base_query,
            'SELECT client_id AS Client, outcome_type AS Outcome FROM outcome_categorized'
        );
    END IF;
    
    -- Prepare and execute the dynamic query
    SET @sql = final_query;
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_pmtct_hei_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_pmtct_hei_datim_query;

~
CREATE PROCEDURE sp_dim_pmtct_hei_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    -- DSD: PMTCT_HEI - HEI Positivity Report
    -- Numerator: Infants who had a first virologic HIV test (sample collected) by 12 months
    -- Disaggregated by: Result (Positive, Negative) and Age (0<=2 months, 2-12 months)

    DECLARE base_query TEXT;
    DECLARE final_query TEXT;

    SET session group_concat_max_len = 30000;

    SET base_query = CONCAT(
            'WITH tmp_hei_test AS ( ',
            '    SELECT ',
            '        hiv_test.client_id, ',
            '        hiv_test_date, ',
            '        date_of_birth, ',
            '        hiv_test_result, ',
            '        dna_pcr_sample_collection_date, ',
            '        TIMESTAMPDIFF(MONTH, date_of_birth, dna_pcr_sample_collection_date) as age_in_months, ',
            '        ROW_NUMBER() OVER (PARTITION BY hiv_test.client_id ORDER BY dna_pcr_sample_collection_date DESC, encounter_id DESC) as row_num ',
            '    FROM mamba_flat_encounter_hei_hiv_test hiv_test ',
            '    JOIN mamba_dim_client client ON hiv_test.client_id = client.client_id ',
            '    WHERE test_type = ''HIV DNA polymerase chain reaction, dried blood spot (DBS)'' ',
            '      AND (test_round = ''Initial test'' OR hiv_test_result = ''Positive'') ',
            '      AND dna_pcr_sample_collection_date BETWEEN ''', REPORT_START_DATE, ''' AND ''', REPORT_END_DATE, ''' ',
            '), ',
            'hei_test AS ( ',
            '    SELECT *, ',
            '           CASE WHEN hiv_test_result = ''Positive'' THEN ''Positive'' ELSE ''Negative'' END as result_category, ',
            '           CASE WHEN age_in_months <= 2 THEN ''0<=2 Months'' ELSE ''2-12 Months'' END as age_category ',
            '    FROM tmp_hei_test ',
            '    WHERE row_num = 1 ',
            '      AND age_in_months <= 12 ', -- Ensure age filter applies to the calculated sample date age
            '), ',
            'categories AS ( ',
            '    SELECT ''Positive'' as result_category, 1 as sort_order ',
            '    UNION ALL ',
            '    SELECT ''Negative'', 2 ',
            ') '
                     );

    IF REPORT_TYPE = 'NUMERATOR' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT COALESCE(COUNT(*), 0) AS Numerator FROM hei_test'
                          );

    ELSEIF REPORT_TYPE = 'DISAGGREGATED' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT ',
                                 '    c.result_category, ',
                                 '    COALESCE(SUM(CASE WHEN h.age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `0<=2 Months`, ',
                                 '    COALESCE(SUM(CASE WHEN h.age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `2-12 Months` ',
                                 'FROM categories c ',
                                 'LEFT JOIN hei_test h ON c.result_category = h.result_category ',
                                 'GROUP BY c.result_category, c.sort_order ',
                                 'ORDER BY c.sort_order'
                          );

    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET final_query = CONCAT(base_query,
                                 'SELECT ',
                                 '    (SELECT COALESCE(COUNT(*), 0) FROM hei_test) AS Numerator, ',
                                 '    COALESCE(SUM(CASE WHEN result_category = ''Positive'' AND age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `Positive_0_2_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN result_category = ''Positive'' AND age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `Positive_2_12_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN result_category = ''Negative'' AND age_category = ''0<=2 Months'' THEN 1 ELSE 0 END), 0) AS `Negative_0_2_Months`, ',
                                 '    COALESCE(SUM(CASE WHEN result_category = ''Negative'' AND age_category = ''2-12 Months'' THEN 1 ELSE 0 END), 0) AS `Negative_2_12_Months` ',
                                 'FROM hei_test'
                          );

    ELSE
        -- DEBUG mode
        SET final_query = CONCAT(base_query,
                                 'SELECT client_id AS Client, result_category AS Result, age_category AS Age_Category, age_in_months AS Age_Months, dna_pcr_sample_collection_date FROM hei_test'
                          );
    END IF;

    SET @sql = final_query;
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_prep_ct_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_prep_ct_datim_query;

~
CREATE PROCEDURE sp_dim_prep_ct_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN

    DECLARE age_group_cols VARCHAR(5000);
    DECLARE prep_query VARCHAR(6278);
    DECLARE group_query TEXT;

    SET session group_concat_max_len = 20000;


    SET prep_query = CONCAT('WITH PreExposure AS (select screening.client_id,
                            screening.encounter_id,
                            screening.encounter_datetime,
                            screening.sex_worker,
                            screening.prep_started,
                            screening.type_of_client,
                            screening_1.treatment_start_date,
                            screening_1.do_you_have_an_hiv_positive_partner,
                            screening_1.antiretroviral_art_dispensed_dose_in_days as dose_dispensed,
                            follow_up.follow_up_status,
                            follow_up.pregnancy_status                            as f_pregnancy_status,
                            follow_up_1.prep_dose_end_date,
                            follow_up_1.followup_date_followup_1,
                            preexposure_prophylaxis_prep_regimen as regimen,
                            screening.screening_date,
                            final_hiv_test_result,
                            currently_breastfeeding_child
                     FROM mamba_flat_encounter_pre_exposure_scree screening
                              left join mamba_flat_encounter_pre_exposure_scree_1 screening_1
                                        on screening.encounter_id = screening_1.encounter_id
                              LEFT JOIN mamba_flat_encounter_pre_exposure_follo follow_up
                                        on screening.client_id = follow_up.client_id
                              LEFT JOIN mamba_flat_encounter_pre_exposure_follo_1 follow_up_1
                                        on follow_up.encounter_id = follow_up_1.encounter_id),
     tmp_latest_follow_up as (select prep_dose_end_date,
                                     prep_started,
                                     date_of_birth,
                                     sex,
                                     client.uan,
                                     client.mrn,
                                     (SELECT datim_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as fine_age_group,   -- Param 1 @end_date
                                     (SELECT normal_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''') = age) as coarse_age_group, -- Param 2 @end_date
                                     do_you_have_an_hiv_positive_partner,
                                     sex_worker,
                                     treatment_start_date,
                                     follow_up_status,
                                     type_of_client,
                                     regimen,
                                     client.client_id,
                                     followup_date_followup_1,
                                     dose_dispensed,
                                     final_hiv_test_result,
                                     f_pregnancy_status,
                                     currently_breastfeeding_child,
                                     ROW_NUMBER() OVER (
                                         PARTITION BY PreExposure.client_id
                                         ORDER BY
                                             PreExposure.followup_date_followup_1 DESC,
                                             PreExposure.encounter_id DESC
                                         )                                               AS row_num
                              from PreExposure
                                       join mamba_dim_client client on PreExposure.client_id = client.client_id
                              where (followup_date_followup_1 <= ''',REPORT_END_DATE,'''
                                  or followup_date_followup_1 is null)),
     prep_new as (select *
                  from tmp_latest_follow_up
                  WHERE treatment_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,'''
                    AND type_of_client = ''New client''
                    AND row_num = 1),
     prep as (select *
              from tmp_latest_follow_up
              where row_num = 1
                  and ((prep_dose_end_date >= ''',REPORT_END_DATE,''' or
                        DATE_ADD(treatment_start_date, INTERVAL dose_dispensed DAY) >=
                        ''',REPORT_END_DATE,''')
                        )
                 or (followup_date_followup_1 BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' AND
                     (final_hiv_test_result = ''Positive'' OR follow_up_status = ''Restart medication'' OR
                      follow_up_status = ''Alive'')) -- Param 8 @end_date, Param 9 @end_date
                  and prep_started = ''Yes''
                  and client_id not in (select client_id from prep_new)) ');
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
              group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
              group by datim_agegroup) as order_query;
    END IF;
    IF REPORT_TYPE = 'AGE_SEX' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
          SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prep
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM prep';
    ELSEIF REPORT_TYPE= 'DEBUG' THEN
        SET group_query = 'SELECT * FROM prep';
    ELSEIF REPORT_TYPE = 'TEST_RESULT' THEN
        SET group_query = 'select ''Positive'' as `Name`, COUNT(*) as count from prep where final_hiv_test_result=''Positive''
        UNION ALL
        select ''Negative'' as `Name`, COUNT(*) from prep where final_hiv_test_result in (''Negative result'',''Negative'')
        UNION ALL
        select ''Other'' as `Name`, COUNT(*) from prep where final_hiv_test_result NOT IN (''Negative result'',''Positive'',''Negative'')';
    ELSEIF REPORT_TYPE = 'PREP_TYPE' THEN
        SET group_query = 'select ''Oral'' as `Name`, COUNT(*) as count from prep where regimen not in (''Cabotegravir'',''Other'') and regimen is not null
        UNION ALL
        select ''Injectable'' as `Name`, COUNT(*) as count from prep where regimen=''Cabotegravir''
        UNION ALL
        select ''Other'' as `Name`, COUNT(*) as count from prep where regimen=''Other''';
    ELSEIF REPORT_TYPE = 'PREGNANT_BF' THEN
        SET group_query = 'select ''Pregnant'' as `Name`, COUNT(*) as count from prep where f_pregnancy_status = ''Yes''
        UNION ALL
        select ''Breastfeeding'' as `Name`, COUNT(*) from prep where currently_breastfeeding_child = ''Yes''';
    ELSEIF REPORT_TYPE = 'FACILITY' THEN
        SET group_query = 'select ''Facility'' as `Name`, COUNT(*) as count from prep
        UNION ALL
        select ''Community (Associated with Facility)'' as `Name`, 0';
    END IF;
    SET @sql = CONCAT(prep_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_prep_new_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_prep_new_datim_query;

~
CREATE PROCEDURE sp_dim_prep_new_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN

    DECLARE age_group_cols VARCHAR(5000);
    DECLARE prep_query VARCHAR(6278);
    DECLARE group_query TEXT;

    SET session group_concat_max_len = 20000;


    SET prep_query = CONCAT('WITH PreExposure AS (select screening.client_id,
                            screening.encounter_id,
                            screening.encounter_datetime,
                            screening.sex_worker,
                            screening.prep_started,
                            screening.type_of_client,
                            screening_1.treatment_start_date,
                            screening_1.do_you_have_an_hiv_positive_partner,
                            screening_1.antiretroviral_art_dispensed_dose_in_days as dose_dispensed,
                            follow_up.follow_up_status,
                            follow_up.pregnancy_status                            as f_pregnancy_status,
                            preexposure_prophylaxis_prep_regimen as regimen,
                            follow_up_1.prep_dose_end_date,
                            follow_up_1.followup_date_followup_1,
                            screening.screening_date,
                            final_hiv_test_result,
                            currently_breastfeeding_child
                     FROM mamba_flat_encounter_pre_exposure_scree screening
                              left join mamba_flat_encounter_pre_exposure_scree_1 screening_1
                                        on screening.encounter_id = screening_1.encounter_id
                              LEFT JOIN mamba_flat_encounter_pre_exposure_follo follow_up
                                        on screening.client_id = follow_up.client_id
                              LEFT JOIN mamba_flat_encounter_pre_exposure_follo_1 follow_up_1
                                        on follow_up.encounter_id = follow_up_1.encounter_id),
     tmp_latest_follow_up as (select prep_dose_end_date,
                                     prep_started,
                                     date_of_birth,
                                     sex,
                                     client.uan,
                                     client.mrn,
                                     (SELECT datim_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as fine_age_group, -- Param 1 @end_date
                                     (SELECT normal_agegroup
                                      from mamba_dim_agegroup
                                      where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as coarse_age_group, -- Param 2 @end_date
                                     do_you_have_an_hiv_positive_partner,
                                     sex_worker,
                                     treatment_start_date,
                                     follow_up_status,
                                     type_of_client,
                                     client.client_id,
                                     regimen,
                                     followup_date_followup_1,
                                     dose_dispensed,
                                     final_hiv_test_result,
                                     f_pregnancy_status,
                                     currently_breastfeeding_child,
                                     ROW_NUMBER() OVER (
                                         PARTITION BY PreExposure.client_id
                                         ORDER BY
                                             PreExposure.followup_date_followup_1 DESC,
                                             PreExposure.encounter_id DESC
                                         )                                               AS row_num
                              from PreExposure
                                       join mamba_dim_client client on PreExposure.client_id = client.client_id
                              where (followup_date_followup_1 <= ''',REPORT_END_DATE,'''
                                  or followup_date_followup_1 is null)),
     prep_new as (select *
                  from tmp_latest_follow_up
                  WHERE treatment_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,'''
                    AND type_of_client = ''New client''
                    AND row_num = 1
         -- AND follow_up_status
     ) ');
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
              group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup
              from mamba_dim_agegroup
              where mamba_dim_agegroup.datim_age_val > 4
              group by datim_agegroup) as order_query;
    END IF;
    IF REPORT_TYPE = 'AGE_SEX' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
          SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prep_new
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSEIF REPORT_TYPE = 'TOTAL' THEN
            SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM prep_new';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM prep_new';
    ELSEIF REPORT_TYPE = 'PREP_TYPE' THEN
        SET group_query = 'select ''Oral'' as `Name`, COUNT(*) as count from prep_new where regimen not in (''Cabotegravir'',''Other'') and regimen is not null
        UNION ALL
        select ''Injectable'' as `Name`, COUNT(*) as count from prep_new where regimen=''Cabotegravir''
        UNION ALL
        select ''Other'' as `Name`, COUNT(*) as count from prep_new where regimen=''Other''';
    ELSEIF REPORT_TYPE = 'PREGNANT_BF' THEN
        SET group_query = 'select ''Pregnant'' as `Name`, COUNT(*) as count from prep_new where f_pregnancy_status = ''Yes''
        UNION ALL
        select ''Breastfeeding'' as `Name`, COUNT(*) from prep_new where currently_breastfeeding_child = ''Yes''';
    ELSEIF REPORT_TYPE = 'FACILITY' THEN
        SET group_query = 'select ''Facility'' as `Name`, COUNT(*) as count from prep_new
        UNION ALL
        select ''Community (Associated with Facility)'' as `Name`, 0';
    END IF;
    SET @sql = CONCAT(prep_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tb_art_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tb_art_datim_query;

~
CREATE PROCEDURE sp_dim_tb_art_datim_query(IN REPORT_START_DATE date,
                                           IN REPORT_END_DATE date,
                                           IN IS_COURSE_AGE_GROUP tinyint(1),
                                           IN REPORT_TYPE varchar(100)
)
BEGIN

    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tx_tb_query VARCHAR(6000);
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(227);
    SET session group_concat_max_len = 20000;

    IF REPORT_TYPE = 'ALREADY_ON_ART' THEN
        SET outcome_condition =
                CONCAT(' art_start_date < ''',REPORT_START_DATE,''' ');
    ELSEIF REPORT_TYPE = 'NEW_ON_ART' THEN
        SET outcome_condition =
                CONCAT(' art_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
    ELSE
        SET outcome_condition = '1=1';
    END IF;

    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;

    SET tx_tb_query = CONCAT('WITH FollowUp AS (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc as tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_started_on_tuberculosis_prophy,
                         screening_test_result_tuberculosis     screening_result,
                         lf_lam_result,
                         patient_diagnosed_with_active_tuber,
                         diagnosis_date as active_tb_diagnosed_date,
                         tuberculosis_drug_treatment_start_d as tb_treatment_start_date,
                         date_active_tbrx_completed,
                         date_active_tbrx_dc,
                         currently_taking_tuberculosis_proph
                  FROM mamba_fact_followup),
     tmp_latest_follow_up as (SELECT client_id,
                                     follow_up_date                                                                             ,
                                     encounter_id,
                                     follow_up_status,
                                     tb_screening_date,
                                     art_start_date,
                                     tb_screened,
                                     screening_result,
                                     lf_lam_result,
                                     patient_diagnosed_with_active_tuber,
                                     active_tb_diagnosed_date,
                                     tb_treatment_start_date,
                                     date_active_tbrx_completed,
                                     date_active_tbrx_dc,
                                     currently_taking_tuberculosis_proph,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND follow_up_date <= ''',REPORT_END_DATE,''' ),
     tb_art as (
         select tmp_latest_follow_up.*,
                sex,
                date_of_birth,
                mrn,
                uan,
                (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group
         from tmp_latest_follow_up
                  join mamba_dim_client client on client.client_id=tmp_latest_follow_up.client_id
         where follow_up_status in (''Alive'',''Restart medication'')
           and row_num=1
           and art_start_date <= ''',REPORT_END_DATE,'''
           and (active_tb_diagnosed_date <= ''',REPORT_END_DATE,''' OR tb_treatment_start_date <= ''',REPORT_END_DATE,''' )
           and (
             (date_active_tbrx_dc is null and date_active_tbrx_completed is null and  (DATE_ADD(tb_treatment_start_date, INTERVAL 1 YEAR ) >= ''',REPORT_END_DATE,''' ))
                 OR
             (date_active_tbrx_completed > ''',REPORT_END_DATE,''' OR date_active_tbrx_dc > ''',REPORT_END_DATE,''' )
             )
     ) ');
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM tb_art';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM tb_art';
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM tb_art WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tx_tb_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tb_prev_datim_denominator_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tb_prev_datim_denominator_query;

~
CREATE PROCEDURE sp_dim_tb_prev_datim_denominator_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN, -- expected values: 0 for fine age group, 1 for coarse age group
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tb_prev_query VARCHAR(6000);
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(227);
    SET session group_concat_max_len = 20000;

    SET outcome_condition = ' 1 = 1 ';
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;

    SET tb_prev_query = CONCAT('WITH FollowUp AS (select follow_up.encounter_id,
                         follow_up.client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc as tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_started_on_tuberculosis_prophy as tpt_start_date,
                         screening_test_result_tuberculosis     screening_result,
                         lf_lam_result,
                         patient_diagnosed_with_active_tuber,
                         diagnosis_date as active_tb_diagnosed_date,
                         tuberculosis_drug_treatment_start_d as tb_treatment_start_date

                  FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),

     tmp_tpt_start as (select client_id,
                              tpt_start_date,
                              art_start_date,
                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_start_date DESC, FollowUp.encounter_id DESC) AS row_num
                       from FollowUp
                       where tpt_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH)) AND tpt_start_date < ''',REPORT_START_DATE,''' ),
     tpt as (
         select tmp_tpt_start.*,
                sex,
                date_of_birth,
                (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group
         from tmp_tpt_start
                  join mamba_dim_client client on client.client_id=tmp_tpt_start.client_id
         where row_num=1) ,
     new_art_tpt as ( select * from tpt where art_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH)) AND art_start_date < ''',REPORT_START_DATE,''' ),
     prev_art_tpt as ( select * from tpt where art_start_date < fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH))) ');
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS DENOMINATOR FROM tpt';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM tpt';
    ELSEIF REPORT_TYPE = 'NEW_ART' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM new_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSEIF REPORT_TYPE = 'PREV_ART' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prev_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prev_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tb_prev_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tb_prev_datim_numerator_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tb_prev_datim_numerator_query;

~
CREATE PROCEDURE sp_dim_tb_prev_datim_numerator_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN, -- expected values: 0 for fine age group, 1 for coarse age group
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tb_prev_query VARCHAR(6000);
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(227);
    SET session group_concat_max_len = 20000;

    SET outcome_condition = ' 1 = 1 ';
    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;

    SET tb_prev_query = CONCAT('WITH FollowUp AS (select follow_up.encounter_id,
                         follow_up.client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc as tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_started_on_tuberculosis_prophy as tpt_start_date,
                         date_completed_tuberculosis_prophyl as tpt_completed_date,
                         screening_test_result_tuberculosis     screening_result,
                         lf_lam_result,
                         patient_diagnosed_with_active_tuber,
                         diagnosis_date as active_tb_diagnosed_date,
                         tuberculosis_drug_treatment_start_d as tb_treatment_start_date

                  FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
     tmp_tpt_start as (select client_id,
                              tpt_start_date,
                              art_start_date,
                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_start_date DESC, FollowUp.encounter_id DESC) AS row_num
                       from FollowUp
                       where tpt_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH)) AND tpt_start_date < ''',REPORT_START_DATE,''' ),
     tpt_started as (select tmp_tpt_start.*,
                            sex,
                            date_of_birth,
                            (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                            (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group
                     from tmp_tpt_start
                              join mamba_dim_client client on client.client_id=tmp_tpt_start.client_id
                     where row_num=1),

     tmp_tpt_complete as (select client_id,
                                 tpt_completed_date,
                              art_start_date,
                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_completed_date DESC, FollowUp.encounter_id DESC) AS row_num
                       from FollowUp
                       where tpt_completed_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH)) AND tpt_completed_date < ''',REPORT_END_DATE,''' ),
     tpt_completed as (select tmp_tpt_complete.*,
                              client.sex,
                              client.date_of_birth,
                            (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,client.date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                            (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,client.date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group
                     from tmp_tpt_complete
                              join mamba_dim_client client on client.client_id=tmp_tpt_complete.client_id
                              join tpt_started on tpt_started.client_id=tmp_tpt_complete.client_id
                     where tmp_tpt_complete.row_num=1),

     new_art_tpt as ( select * from tpt_completed where art_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH)) AND art_start_date < ''',REPORT_START_DATE,''' ),
     prev_art_tpt as ( select * from tpt_completed where art_start_date < fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_START_DATE,''' , ''Y-M-D''), INTERVAL -6 MONTH))) ');
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM tpt_completed';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM tpt_completed';
    ELSEIF REPORT_TYPE = 'NEW_ART' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
        -- , SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM new_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSEIF REPORT_TYPE = 'PREV_ART' THEN
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
       -- , SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prev_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, '
      -- , SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM prev_art_tpt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tb_prev_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_curr_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_curr_datim_query;

~
CREATE PROCEDURE sp_dim_tx_curr_datim_query(
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN ARV_GROUP INT,
    IN NUMERATOR BOOLEAN
)
BEGIN


    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tx_curr_query VARCHAR(6000);
    DECLARE group_query VARCHAR(5000);
    DECLARE arv_group_condition VARCHAR(100);
    SET session group_concat_max_len = 20000;


    IF ARV_GROUP = 0 THEN
        SET arv_group_condition = 'dose_days < 90 ';
    ELSEIF ARV_GROUP = 1 THEN
        SET arv_group_condition = 'dose_days BETWEEN 90 AND 150 ';
    ELSEIF ARV_GROUP = 2 THEN
        SET arv_group_condition = 'dose_days >= 180';
    ELSE
        SET arv_group_condition = '1=1';
    END IF;



    IF IS_COURSE_AGE_GROUP THEN
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(normal_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(datim_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;
    SET tx_curr_query = CONCAT('WITH FollowUp AS (select encounter_id,
                             client_id           AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_      AS follow_up_date,
                             art_antiretroviral_start_date AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child   AS breast_feeding_status,
                             pregnancy_status,
                             antiretroviral_art_dispensed_dose_i AS dose_days
                      FROM mamba_fact_followup),
         -- TX curr
         tx_curr_all AS (SELECT PatientId,
                                follow_up_date                                                                             ,
                                encounter_id,
                                follow_up_status,
                                treatment_end_date,
                                dose_days,
                                ROW_NUMBER() OVER (PARTITION BY PatientId ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                         FROM FollowUp
                         WHERE follow_up_status IS NOT NULL
                           AND art_start_date IS NOT NULL
                           AND follow_up_date <= ''',COALESCE(REPORT_END_DATE,NOW()),'''
                         ),

         tx_curr AS (select *
                     from tx_curr_all
                     where row_num = 1
                       AND follow_up_status in (''Alive'', ''Restart medication'')
                       AND treatment_end_date >= ''',COALESCE(REPORT_END_DATE,NOW()),''' ),
         tx_curr_with_client as (select tx_curr.*,
                                        client.sex,
                                        client.date_of_birth,
                                        pregnancy_status,
                                        regimen,
                                        left(regimen, 1) as regimen_line,
                                        client.mrn,
                                        client.uan,
                                        (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',COALESCE(REPORT_END_DATE,NOW()),''' )=age) as fine_age_group,
                                        (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',COALESCE(REPORT_END_DATE,NOW()),''' )=age) as coarse_age_group
                                 from FollowUp
                                          inner join tx_curr on FollowUp.encounter_id = tx_curr.encounter_id
                                          left join mamba_dim_client client on tx_curr.PatientId = client.client_id) ');

IF NUMERATOR THEN
    SET group_query = ' SELECT COUNT(*) AS Subtotal from tx_curr_with_client';
ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM tx_curr_with_client WHERE ',arv_group_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
END IF;
    SET @sql = CONCAT(tx_curr_query,group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_ml_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_ml_datim_query;

~
CREATE PROCEDURE sp_dim_tx_ml_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN

    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tx_ml_query text;
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(150);
    SET session group_concat_max_len = 30000;

    IF REPORT_TYPE = 'DIED' THEN
        SET outcome_condition = ' lost_follow_up_status = ''Dead''';
    ELSEIF REPORT_TYPE = 'LESS_THAN_THREE_MONTHS' THEN
        SET outcome_condition = ' TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
  AND lost_follow_up_status not in (''Transferred out'', ''Stop all'', ''Dead'')';
    ELSEIF REPORT_TYPE = 'THREE_TO_FIVE_MONTHS' THEN
        SET outcome_condition = ' TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) BETWEEN 3 AND 5
  AND lost_follow_up_status not in (''Transferred out'', ''Stop all'', ''Dead'')';
    ELSEIF REPORT_TYPE = 'MORE_THAN_SIX_MONTHS' THEN
        SET outcome_condition = ' TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) > 5
  AND lost_follow_up_status not in (''Transferred out'', ''Stop all'', ''Dead'')';
    ELSEIF REPORT_TYPE = 'TRANSFERRED_OUT' THEN
        SET outcome_condition = ' lost_follow_up_status = ''Transferred out''';
    ELSEIF REPORT_TYPE = 'REFUSED' THEN
        SET outcome_condition = ' lost_follow_up_status = ''Stop all''';
    ELSE
        SET  outcome_condition = '1=1';
    END IF;

    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                    ''' THEN count ELSE 0 END) AS `',
                                    REPLACE(normal_agegroup, '`', '``'),
                                    '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                    ''' THEN count ELSE 0 END) AS `',
                                    REPLACE(datim_agegroup, '`', '``'),
                                    '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;

    SET tx_ml_query = CONCAT('WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             antiretroviral_art_dispensed_dose_i as dose_days,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             adherence
                      FROM mamba_fact_followup),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               regimen,
                                               dose_days,
                                               adherence,
                                               next_visit_date,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= DATE_ADD( ''',REPORT_START_DATE,''' , INTERVAL -1 DAY)),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in (''Alive'', ''Restart medication'')
                             AND treatment_end_date >= DATE_ADD( ''',REPORT_START_DATE,''' , INTERVAL -1 DAY)),
         -- TX curr
         tmp_lost_follow_up AS (SELECT client_id,
                                       follow_up_date,
                                       encounter_id,
                                       follow_up_status,
                                       treatment_end_date,
                                       art_start_date,
                                       regimen,
                                       dose_days,
                                       adherence,
                                       next_visit_date,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                FROM FollowUp
                                WHERE follow_up_status IS NOT NULL
                                  AND art_start_date IS NOT NULL
                                  AND follow_up_date <= ''',REPORT_END_DATE,''' ),
         lost_follow_up as (select *
                            from tmp_lost_follow_up
                            where row_num = 1),
         tx_curr_end AS (select *
                         from tmp_lost_follow_up
                         where row_num = 1
                           AND follow_up_status in (''Alive'', ''Restart medication'')
                           AND treatment_end_date >= ''',REPORT_END_DATE,''' ),

         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select tmp_lost_follow_up.*
                        from tmp_lost_follow_up
                                 join first_follow_up on tmp_lost_follow_up.client_id = first_follow_up.client_id
                        where art_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,'''
                          AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != ''Yes'')
                          AND first_follow_up.follow_up_status in (''Alive'', ''Restart medication'')
                          AND tmp_lost_follow_up.row_num = 1),
         tx_new as (select *
                    from tx_new_tmp),

         on_art as (select *
                    from tx_new
                    union ALL
                    select *
                    from tx_curr_start),
         interrupted_art as (select on_art.*,
                                    client.sex,
                                    client.date_of_birth,
                                    lost_follow_up.follow_up_status                                   as lost_follow_up_status,
                                    lost_follow_up.follow_up_date                                     as lost_follow_up_date,
                                     (SELECT datim_agegroup
                                     from mamba_dim_agegroup
                                     where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as fine_age_group,
                                    (SELECT normal_agegroup
                                     from mamba_dim_agegroup
                                     where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as coarse_age_group
                             from on_art
                                      join mamba_dim_client client on on_art.client_id = client.client_id
                                      join lost_follow_up
                                           on on_art.client_id = lost_follow_up.client_id
                             where on_art.client_id not in (select client_id from tx_curr_end)) ');
    IF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM interrupted_art';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM interrupted_art';
    ELSE
    SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM interrupted_art WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tx_ml_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_new_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_new_datim_query;

-- e.g. CALL sp_dim_tx_new_datim_query('2022-10-02', '2023-10-31', '2023-10-31', 0, 'unknown');
~
CREATE PROCEDURE sp_dim_tx_new_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN, -- expected values: 0 for fine age group, 1 for coarse age group
    IN CD4_COUNT_GROUPAGE VARCHAR(255) -- expected values are: 'all', '>=200', '<200', 'unknown'
)
BEGIN

    DECLARE cd4_count_condition VARCHAR(255);
    DECLARE age_group_cols VARCHAR(5000);
    DECLARE art_start_date_start DATE;
    DECLARE art_start_date_end DATE;
    DECLARE tx_new_query TEXT;
    DECLARE group_query VARCHAR(5000);

    SET art_start_date_start = REPORT_START_DATE;
    SET art_start_date_end = REPORT_END_DATE;

    SET session group_concat_max_len = 20000;

    IF CD4_COUNT_GROUPAGE = 'all' THEN
        SET cd4_count_condition = '1=1';
    ELSEIF CD4_COUNT_GROUPAGE = '>=200' THEN
        SET cd4_count_condition = ' (visitect_cd4_result is null and cd4_count >= 200 AND (age >= 5 or age is null)) or (visitect_cd4_result=''VISITECT <=200 copies/ml'' or visitect_cd4_result=''VISITECT >200 copies/ml'' )';
    ELSEIF CD4_COUNT_GROUPAGE = '<200' THEN
        SET cd4_count_condition = ' (visitect_cd4_result is null and cd4_count < 200 AND (age >= 5 or age is null)) or (visitect_cd4_result=''VISITECT <200 copies/ml'') ';
    ELSEIF CD4_COUNT_GROUPAGE = 'unknown' THEN
        SET cd4_count_condition = ' (cd4_count IS NULL OR age < 5) and (visitect_cd4_result is null)';
    ELSE
        SET cd4_count_condition = '1=1';
    END IF;

    IF IS_COURSE_AGE_GROUP THEN
        IF CD4_COUNT_GROUPAGE = '>=200' OR CD4_COUNT_GROUPAGE = '<200' THEN
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(normal_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select normal_agegroup from mamba_dim_agegroup where datim_age_val > 2 group by normal_agegroup) as order_query;
        ELSE
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(normal_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
        END IF;
    ELSE
        IF CD4_COUNT_GROUPAGE = '>=200' OR CD4_COUNT_GROUPAGE = '<200' THEN
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(datim_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select datim_agegroup from mamba_dim_agegroup where datim_age_val > 2 group by datim_agegroup) as order_query;
        ELSE
            SELECT GROUP_CONCAT( CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                        ''' THEN count ELSE 0 END) AS `',
                                        REPLACE(datim_agegroup, '`', '``'),
                                        '`')
                   )
            INTO age_group_cols
            FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
        END IF;
    END IF;
    SET tx_new_query = CONCAT('WITH FollowUp AS (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         cd4_count,
                         visitect_cd4_result,
                         visitect_cd4_test_date
                  FROM mamba_fact_followup),
     tmp_latest_follow_up as (SELECT client_id,
                                     follow_up_date                                                                             AS FollowupDate,
                                     encounter_id,
                                     follow_up_status,
                                     art_start_date,
                                     cd4_count,
                                     visitect_cd4_result,
                                     breast_feeding_status,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND follow_up_date <= ''',REPORT_END_DATE,''' ),
     tmp_visitect_cd4_result as (SELECT client_id,
                                        encounter_id,
                                        visitect_cd4_result,
                                        ROW_NUMBER() over (PARTITION BY client_id ORDER BY visitect_cd4_test_date DESC, encounter_id DESC) AS row_num
                                 FROM FollowUp
                                 WHERE visitect_cd4_test_date is not null and visitect_cd4_test_date <= ''',REPORT_END_DATE,''' ),
     visitect_cd4_result as ( select * from tmp_visitect_cd4_result where row_num=1),
     latest_follow_up as (SELECT *
                          from tmp_latest_follow_up
                          where row_num = 1),
     tmp_first_follow_up as (SELECT client_id,
                                    follow_up_date                                                                     AS FollowupDate,
                                    encounter_id,
                                    transferred_in,
                                    pregnancy_status,
                                    follow_up_status,
                                    ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                             FROM FollowUp
                             WHERE art_start_date IS NOT NULL),
     first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

     tx_new_tmp as (select latest_follow_up.client_id,
                           latest_follow_up.art_start_date,
                           latest_follow_up.FollowupDate,
                           transferred_in,
                           pregnancy_status,
                           cd4_count,
                           visitect_cd4_result.visitect_cd4_result,
                           breast_feeding_status
                    from latest_follow_up
                             join first_follow_up on latest_follow_up.client_id = first_follow_up.client_id
                             LEFT JOIN visitect_cd4_result on latest_follow_up.client_id = visitect_cd4_result.client_id
                    where art_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,'''
                      AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != ''Yes'')
                      AND first_follow_up.follow_up_status in (''Alive'', ''Restart medication'')),
     tx_new as (select tx_new_tmp.client_id,
                       sex,
                       pregnancy_status,
                       date_of_birth,
                       TIMESTAMPDIFF(YEAR, date_of_birth, FollowupDate)               as age,
                       (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                       (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group,
                       breast_feeding_status,
                       cd4_count,
                       visitect_cd4_result
                from tx_new_tmp
                         join mamba_dim_client client on tx_new_tmp.client_id = client.client_id) ');
    IF CD4_COUNT_GROUPAGE = 'numerator' THEN
        SET group_query = 'SELECT COUNT(*) as Numerator FROM tx_new';
    ELSEIF CD4_COUNT_GROUPAGE = 'breast_feeding' THEN
        SET group_query = 'SELECT COUNT(*) as Breastfeeding from tx_new where breast_feeding_status = ''Yes''';
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
          SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM tx_new
                WHERE ', cd4_count_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tx_new_query,group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_pvls_datim_query
--

-- CALL sp_dim_tx_pvls_datim_query ('2023-10-31',0,1);
DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_pvls_datim_query;

~
CREATE PROCEDURE sp_dim_tx_pvls_datim_query(
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN,
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN


    DECLARE age_group_cols VARCHAR(5000);
    DECLARE pvls_query VARCHAR(6000);
    DECLARE disaggregate_query VARCHAR(6000);
SET session group_concat_max_len = 20000;


IF IS_COURSE_AGE_GROUP THEN
SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                           ''' THEN count ELSE 0 END) AS `',
                           REPLACE(normal_agegroup, '`', '``'),
                           '`')
       )
INTO age_group_cols
FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
ELSE
SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                           ''' THEN count ELSE 0 END) AS `',
                           REPLACE(datim_agegroup, '`', '``'),
                           '`')
       )
INTO age_group_cols
FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
END IF;
    SET pvls_query = CONCAT('WITH FollowUp AS (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_viral_load_results_received    as viral_load_performed_date,
                         hiv_viral_load                      as viral_load_count,
                         viral_load_test_status,
                         viral_load_test_indication,
                         viral_load_received_                as viral_load_performed,
                         date_of_reported_hiv_viral_load     as viral_load_sent_date
                  FROM mamba_fact_followup),
     tmp_latest_follow_up AS (SELECT client_id,
                                     follow_up_date                                                                             ,
                                     encounter_id,
                                     follow_up_status,
                                     treatment_end_date,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND follow_up_date <= ''',REPORT_END_DATE,''' ),
     latest_follow_up AS (select *
                          from tmp_latest_follow_up
                          where row_num = 1),
     tmp_pvls as (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date,
                         viral_load_performed_date,
                         pregnancy_status,
                         viral_load_count,
                         viral_load_test_status,
                         viral_load_sent_date,
                         breast_feeding_status,
                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_performed_date DESC, encounter_id DESC) AS row_num
                  from FollowUp
                  where viral_load_performed_date is not null
                    and viral_load_performed_date > fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar( ''',REPORT_END_DATE,''' , ''Y-M-D''), INTERVAL -12 MONTH))
                    AND viral_load_performed_date <= ''',REPORT_END_DATE,''' ),
     tmp_pvls_2 as (select * from tmp_pvls where row_num = 1),
     pvls as (select client.client_id,
                     pregnancy_status,
                     sex,
                     date_of_birth,
                     viral_load_count,
                     viral_load_test_status,
                     follow_up_date,
                     (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                     (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group,
                     breast_feeding_status
              from tmp_pvls_2
                       inner join mamba_dim_client client on tmp_pvls_2.client_id = client.client_id
                    --   inner join latest_follow_up on tmp_pvls_2.client_id = latest_follow_up.client_id
              ),
     pvls_numerator as (select *
                        from pvls
                        where viral_load_count < 1000 or (viral_load_count  is null and viral_load_test_status in (''Suppressed'',''Low-level viremia''))
                        ) ');
    IF REPORT_TYPE = 'NUMERATOR' THEN
        SET disaggregate_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM pvls_numerator
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
ELSEIF REPORT_TYPE = 'NUMERATOR_TOTAL' THEN
    SET disaggregate_query = 'SELECT COUNT(*) as Subtotal FROM pvls_numerator';
ELSEIF REPORT_TYPE = 'NUMERATOR_DEBUG' THEN
    SET disaggregate_query = 'SELECT * FROM pvls_numerator';
ELSEIF REPORT_TYPE = 'NUMERATOR_BREAST_FEEDING_PREGNANT' THEN
        SET disaggregate_query = 'SELECT COUNT(CASE WHEN pregnancy_status = ''Yes'' THEN 1 ELSE NULL END ) AS Pregnant,
       COUNT(CASE WHEN breast_feeding_status = ''Yes'' THEN 1 ELSE NULL END ) AS Breastfeeding
        FROM pvls_numerator';
ELSEIF REPORT_TYPE = 'DENOMINATOR' THEN
        SET disaggregate_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM pvls
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    ELSEIF REPORT_TYPE = 'DENOMINATOR_TOTAL' THEN
        SET disaggregate_query = 'SELECT COUNT(*) as Subtotal FROM pvls';
    ELSEIF REPORT_TYPE = 'DENOMINATOR_DEBUG' THEN
        SET disaggregate_query = 'SELECT * FROM pvls';
    ELSEIF REPORT_TYPE = 'DENOMINATOR_BREAST_FEEDING_PREGNANT' THEN
        SET disaggregate_query = 'SELECT COUNT(CASE WHEN pregnancy_status = ''Yes'' THEN 1 ELSE NULL END ) AS Pregnant,
       COUNT(CASE WHEN breast_feeding_status = ''Yes'' THEN 1 ELSE NULL END ) AS Breastfeeding
        FROM pvls';
    END IF;
    SET @sql = CONCAT(pvls_query, disaggregate_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

END //
DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_rtt_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_rtt_datim_query;

~
CREATE PROCEDURE sp_dim_tx_rtt_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN, -- expected values: 0 for fine age group, 1 for coarse age group
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    DECLARE age_group_cols VARCHAR(6000);
    DECLARE tx_rtt_query VARCHAR(15000);
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(227);
    SET session group_concat_max_len = 20000;

    IF REPORT_TYPE = 'CD4_LESS_THAN_200' THEN
        SET outcome_condition =
                ' (restart_visitect_cd4_result is null and restart_cd4_count < 200) or (restart_visitect_cd4_result = ''VISITECT <=200 copies/ml'' or restart_visitect_cd4_result = ''VISITECT <200 copies/ml'') ';
    ELSEIF REPORT_TYPE = 'CD4_GREATER_THAN_200' THEN
        SET outcome_condition =
                ' (restart_visitect_cd4_result is null and restart_cd4_count >= 200) or (restart_visitect_cd4_result = ''VISITECT >200 copies/ml'') ';
    ELSEIF REPORT_TYPE = 'CD4_UNKNOWN' THEN
        SET outcome_condition = ' (restart_cd4_count is null AND restart_visitect_cd4_result is null AND datim_age_val > 2 ) OR (datim_age_val <= 2)';
     -- SET outcome_condition = ' (restart_cd4_count is null and interrupted_months >= 6) AND (restart_visitect_cd4_result is null and interrupted_months >= 6)';
    ELSEIF REPORT_TYPE = 'CD4_NOT_ELIGIBLE' THEN
        SET outcome_condition = 'interrupted_months = 5000';
     -- SET outcome_condition = 'interrupted_months < 6';
    ELSE
        SET outcome_condition = '1=1';
    END IF;

    IF IS_COURSE_AGE_GROUP THEN
        IF REPORT_TYPE = 'CD4_LESS_THAN_200' OR REPORT_TYPE = 'CD4_GREATER_THAN_200' OR
           REPORT_TYPE = 'CD4_NOT_ELIGIBLE' OR REPORT_TYPE = 'CD4_UNKNOWN' THEN
            SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                       ''' THEN count ELSE 0 END) AS `',
                                       REPLACE(normal_agegroup, '`', '``'),
                                       '`')
                   )
            INTO age_group_cols
            FROM (select normal_agegroup
                  from mamba_dim_agegroup
                  WHERE datim_age_val > 2
                  group by normal_agegroup) as order_query;
        ELSE
            SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                       ''' THEN count ELSE 0 END) AS `',
                                       REPLACE(normal_agegroup, '`', '``'),
                                       '`')
                   )
            INTO age_group_cols
            FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
        END IF;
    ELSE
        IF REPORT_TYPE = 'CD4_LESS_THAN_200' OR REPORT_TYPE = 'CD4_GREATER_THAN_200' OR
           REPORT_TYPE = 'CD4_NOT_ELIGIBLE'  THEN
            SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                       ''' THEN count ELSE 0 END) AS `',
                                       REPLACE(datim_agegroup, '`', '``'),
                                       '`')
                   )
            INTO age_group_cols
            FROM (select datim_agegroup
                  from mamba_dim_agegroup
                  WHERE datim_age_val > 2
                  group by datim_agegroup) as order_query;
        ELSE
            SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                       ''' THEN count ELSE 0 END) AS `',
                                       REPLACE(datim_agegroup, '`', '``'),
                                       '`')
                   )
            INTO age_group_cols
            FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
        END IF;
    END IF;

    SET tx_rtt_query = CONCAT('WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         transferred_in_check_this_for_all_t AS transferred_in,
                         cd4_count,
                         visitect_cd4_result,
                         visitect_cd4_test_date
                  FROM mamba_fact_followup),
     -- TX curr start
     tmp_latest_follow_up_start AS (SELECT client_id,
                                           follow_up_date,
                                           encounter_id,
                                           follow_up_status,
                                           treatment_end_date,
                                           art_start_date,
                                           cd4_count,
                                           visitect_cd4_result,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                    FROM FollowUp
                                    WHERE follow_up_status IS NOT NULL
                                      AND art_start_date IS NOT NULL
                                      AND follow_up_date <= DATE_ADD( ''',REPORT_START_DATE,''' , INTERVAL -1 DAY)),
     tmp_visitect_cd4_result as (SELECT client_id,
                                        encounter_id,
                                        visitect_cd4_result,
                                        ROW_NUMBER() over (PARTITION BY client_id ORDER BY visitect_cd4_test_date DESC, encounter_id DESC) AS row_num
                                 FROM FollowUp
                                 WHERE visitect_cd4_test_date is not null and visitect_cd4_test_date <= ''',REPORT_END_DATE,''' ),
     latest_follow_up_start as (select *
                                from tmp_latest_follow_up_start
                                where row_num = 1),
     visitect_cd4_result as ( select * from tmp_visitect_cd4_result where row_num=1),
     tx_curr_start AS (select *
                       from tmp_latest_follow_up_start
                       where row_num = 1
                         AND follow_up_status in (''Alive'', ''Restart medication'')
                         AND treatment_end_date >= DATE_ADD( ''',REPORT_START_DATE,''' , INTERVAL -1 DAY)),
     interrupted_at_start AS (select latest_follow_up_start.*
                              from latest_follow_up_start
                                       left join tx_curr_start
                                                 on latest_follow_up_start.client_id = tx_curr_start.client_id
                              where tx_curr_start.client_id is null
                                and latest_follow_up_start.follow_up_status != ''Transferred out''),

     -- TX curr
     tmp_latest_follow_up_end AS (SELECT FollowUp.client_id,
                                         follow_up_date,
                                         FollowUp.encounter_id,
                                         follow_up_status,
                                         treatment_end_date,
                                         art_start_date,
                                         cd4_count,
                                         visitect_cd4_result.visitect_cd4_result,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date DESC, FollowUp.encounter_id DESC) AS row_num
                                  FROM FollowUp
                                           LEFT JOIN visitect_cd4_result on FollowUp.client_id = visitect_cd4_result.client_id
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <=  ''',REPORT_END_DATE,''' ),
     -- TX curr
     tmp_restart_follow_up_end AS (SELECT FollowUp.client_id,
                                          follow_up_date as restart_follow_up_date,
                                          FollowUp.encounter_id,
                                          follow_up_status as restart_status,
                                          treatment_end_date,
                                          art_start_date,
                                          cd4_count as restart_cd4_count,
                                          visitect_cd4_result.visitect_cd4_result as restart_visitect_cd4_result,
                                          ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date , FollowUp.encounter_id ) AS row_num
                                   FROM FollowUp
                                   LEFT JOIN visitect_cd4_result on FollowUp.client_id = visitect_cd4_result.client_id
                                   WHERE follow_up_status IS NOT NULL
                                     AND art_start_date IS NOT NULL
                                     AND follow_up_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ),
     tx_curr_end AS (select *
                     from tmp_latest_follow_up_end
                     where row_num = 1
                       AND follow_up_status in (''Alive'', ''Restart medication'')
                       AND treatment_end_date >= ''',REPORT_END_DATE,''' ),
     restart_follow_up_end as (select tmp_restart_follow_up_end.* from tmp_restart_follow_up_end
                                                                           join tx_curr_end on tmp_restart_follow_up_end.client_id = tx_curr_end.client_id
                               where tmp_restart_follow_up_end.row_num=1),

     tx_rtt as (select tx_curr_end.follow_up_date as latest_follow_up_date,
                       tx_curr_end.encounter_id,
                       tx_curr_end.follow_up_status as latest_follow_up_status,
                       tx_curr_end.treatment_end_date as latest_follow_up_treatment_end_date,
                       tx_curr_end.art_start_date as latest_follow_up_art_start_date,
                       tx_curr_end.cd4_count as latest_follow_up_cd4_count,
                       tx_curr_end.visitect_cd4_result as latest_follow_up_visitect_cd4_result,
                       restart_follow_up_end.restart_cd4_count,
                       restart_follow_up_end.restart_visitect_cd4_result,
                       restart_follow_up_end.restart_status,
                       restart_follow_up_end.restart_follow_up_date,
                       sex,
                       date_of_birth,
                       mrn,
                       uan,
                       (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                       (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group,
                       (SELECT datim_age_val from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as datim_age_val,
                       interrupted_at_start.follow_up_date as interrupted_follow_up_follow_up_date,
                       interrupted_at_start.follow_up_status as interrupted_follow_up_follow_up_status,
                       interrupted_at_start.treatment_end_date as interrupted_follow_up_treatment_end_date,
                       CASE
                           WHEN interrupted_at_start.follow_up_status in (''Alive'', ''Restart medication'')
                               and interrupted_at_start.treatment_end_date <= DATE_ADD( ''',REPORT_START_DATE,''' , INTERVAL -1 DAY) THEN
                               TIMESTAMPDIFF(MONTH, interrupted_at_start.treatment_end_date,
                                             restart_follow_up_end.restart_follow_up_date)
                           ELSE TIMESTAMPDIFF(MONTH, interrupted_at_start.follow_up_date,
                                              restart_follow_up_end.restart_follow_up_date)
                           END AS ''interrupted_months''


                from interrupted_at_start
                         join tx_curr_end
                              on interrupted_at_start.client_id = tx_curr_end.client_id
                         join mamba_dim_client client on interrupted_at_start.client_id= client.client_id
                         join restart_follow_up_end  on tx_curr_end.client_id=restart_follow_up_end.client_id
     ) ');
    IF REPORT_TYPE = 'IIT' THEN
        SET group_query = 'select ''Experienced treatment interruption of <3 months before returning to treatment'' as `IIT`,COUNT(*) as `Value` from tx_rtt where interrupted_months <3
        UNION ALL
        select ''Experienced treatment interruption of 3-5 months before returning to treatment'' ,COUNT(*) from tx_rtt where interrupted_months BETWEEN 3 AND 5
        UNION ALL
        select ''Experienced treatment interruption of 6+ months before returning to treatment'' ,COUNT(*) from tx_rtt where interrupted_months >= 6';
    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'SELECT COUNT(*) AS NUMERATOR FROM tx_rtt';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'SELECT * FROM tx_rtt';
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM tx_rtt WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;
    SET @sql = CONCAT(tx_rtt_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_dim_tx_tb_datim_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_dim_tx_tb_datim_query;

~
CREATE PROCEDURE sp_dim_tx_tb_datim_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN IS_COURSE_AGE_GROUP BOOLEAN, -- expected values: 0 for fine age group, 1 for coarse age group
    IN REPORT_TYPE VARCHAR(100)
)
BEGIN
    DECLARE age_group_cols VARCHAR(5000);
    DECLARE tx_tb_query VARCHAR(8469);
    DECLARE group_query TEXT;
    DECLARE outcome_condition VARCHAR(227);
    DECLARE source_table VARCHAR(50);
    SET session group_concat_max_len = 20000;

    IF REPORT_TYPE = 'NEW_ART_POSITIVE' THEN
        SET outcome_condition =
                CONCAT(' art_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' and screening_result=''Positive'' ');
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'NEW_ART_NEGATIVE' THEN
        SET outcome_condition =
                CONCAT(' art_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,'''  and (screening_result != ''Positive'' OR screening_result IS NULL)  ');
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'PREV_ART_POSITIVE' THEN
        SET outcome_condition =
                CONCAT(' art_start_date < ''',REPORT_START_DATE,''' and follow_up_status in (''Alive'', ''Restart medication'') and screening_result = ''Positive'' ');
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'PREV_ART_NEGATIVE' THEN
        SET outcome_condition =
                CONCAT(' art_start_date < ''',REPORT_START_DATE,''' and follow_up_status in (''Alive'', ''Restart medication'')  and (screening_result != ''Positive'' OR screening_result IS NULL) ');
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'SCREEN_TYPE' THEN
        SET outcome_condition = ' 1=1 ';
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'SPECIMEN_SENT' THEN
        SET outcome_condition = ' 1=1 ';
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'DIAGNOSTIC_TEST' THEN
        SET outcome_condition = ' 1=1 ';
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'POSITIVE_RESULT' THEN
        SET outcome_condition = ' 1=1 ';
        SET source_table = 'tb_screening';
    ELSEIF REPORT_TYPE = 'NUMERATOR_NEW' THEN
        SET outcome_condition = CONCAT(' art_start_date IS NOT NULL AND art_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' and tb_treatment_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
        SET source_table = 'tb_treatment';
    ELSEIF REPORT_TYPE = 'NUMERATOR_TOTAL' THEN
        SET outcome_condition = CONCAT(' art_start_date IS NOT NULL AND art_start_date <= ''',REPORT_END_DATE,''' AND tb_treatment_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
        SET source_table = 'tb_treatment';
    ELSEIF REPORT_TYPE = 'NUMERATOR_PREV' THEN
        SET outcome_condition = CONCAT(' art_start_date IS NOT NULL AND art_start_date < ''',REPORT_START_DATE,''' and tb_treatment_start_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ');
        SET source_table = 'tb_treatment';
    ELSE
        SET outcome_condition = '1=1';
        SET source_table = 'tb_screening';
    END IF;

    IF IS_COURSE_AGE_GROUP THEN
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN coarse_age_group = ''', normal_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(normal_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select normal_agegroup from mamba_dim_agegroup group by normal_agegroup) as order_query;
    ELSE
        SELECT GROUP_CONCAT(CONCAT('SUM(CASE WHEN fine_age_group = ''', datim_agegroup,
                                   ''' THEN count ELSE 0 END) AS `',
                                   REPLACE(datim_agegroup, '`', '``'),
                                   '`')
               )
        INTO age_group_cols
        FROM (select datim_agegroup from mamba_dim_agegroup group by datim_agegroup) as order_query;
    END IF;

    SET tx_tb_query = CONCAT('WITH FollowUp AS (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc as tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_started_on_tuberculosis_prophy,
                         screening_test_result_tuberculosis     screening_result,
                         lf_lam_result,
                         gene_xpert_result,
                         diagnostic_test as other_diagnostic_test,
                         tb_diagnostic_test_result           as         other_tb_diagnostic_result,
                         specimen_sent_to_lab,
                         tuberculosis_drug_treatment_start_d as tb_treatment_start_date,
                         date_active_tbrx_completed as tb_treatment_completed_date
                  FROM mamba_fact_followup
                    ),
                         tmp_latest_follow_up
                             as (select client_id,
                                        encounter_id,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                 from FollowUp
                                 where follow_up_date <= ''',REPORT_END_DATE,''' ),
                         tmp_latest_screeing_follow_up as (SELECT client_id,
                                                                  follow_up_date                                                                                ,
                                                                  encounter_id,
                                                                  follow_up_status,
                                                                  tb_screening_date,
                                                                  art_start_date,
                                                                  tb_screened,
                                                                  screening_result,
                                                                  lf_lam_result,
                                                                  gene_xpert_result,
                                                                  other_diagnostic_test,
                                                                  other_tb_diagnostic_result,
                                                                  specimen_sent_to_lab,
                                                                  tb_treatment_start_date,
                                                                  tb_treatment_completed_date,
                                                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tb_screening_date DESC, encounter_id DESC) AS row_num
                                                           FROM FollowUp
                                                           WHERE follow_up_status IS NOT NULL
                                                             AND tb_screening_date is not null
                                                             and tb_screening_date between ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ),
                         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
                         latest_screeing_follow_up as (select * from tmp_latest_screeing_follow_up where row_num = 1),
                         tb_screening as (SELECT follow_up.*,
                                                 sex,
                                                 date_of_birth,
                                                (SELECT datim_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as fine_age_group,
                                                (SELECT normal_agegroup from mamba_dim_agegroup where TIMESTAMPDIFF(YEAR,date_of_birth, ''',REPORT_END_DATE,''' )=age) as coarse_age_group,
                                                 mrn,
                                                 uan,
                                                 latest_follow_up.follow_up_status as latest_follow_up_staus
                                          from latest_screeing_follow_up follow_up
                                                   inner join mamba_dim_client client on client_id = client.client_id
                                                   left join latest_follow_up on client_id = latest_follow_up.client_id),
                     tmp_tb_treatment as (select *,
                                                     ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY tb_treatment_start_date DESC,
                                                         encounter_id DESC) AS row_num
                                              from FollowUp
                                              WHERE tb_treatment_start_date BETWEEN ''',REPORT_START_DATE,''' AND ''',REPORT_END_DATE,''' ),

                         tb_treatment AS (SELECT tmp_tb_treatment.*,
                                                 sex,
                                                 date_of_birth,
                                                 (SELECT datim_agegroup
                                                  from mamba_dim_agegroup
                                                  where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as fine_age_group,
                                                 (SELECT normal_agegroup
                                                  from mamba_dim_agegroup
                                                  where TIMESTAMPDIFF(YEAR, date_of_birth, ''',REPORT_END_DATE,''' ) = age) as coarse_age_group,
                                                 mrn,
                                                 uan
                                          FROM tmp_tb_treatment
                                          JOIN mamba_dim_client client on client.client_id = tmp_tb_treatment.client_id
                                          where row_num = 1)');
    IF REPORT_TYPE = 'SCREEN_TYPE' THEN
        SET group_query = 'select SUM(CASE WHEN other_diagnostic_test = ''Chest X-Ray'' is not null THEN 1 ELSE 0 END) as `Chest X-Ray` ,
       SUM(CASE WHEN other_diagnostic_test != ''Chest X-Ray'' is null THEN 1 ELSE 0 END) AS ''Symptom Screen Only'',
       0 AS `Molecular WHO-Recommended Diagnostic Test(mWRD)`
 from tb_screening';
    ELSEIF REPORT_TYPE = 'SPECIMEN_SENT' THEN
        SET group_query = ' select  SUM(CASE WHEN other_diagnostic_test = ''Smear microscopy only'' is not null THEN 1 ELSE 0 END) as `Smear Microscopy Only`,
        0 AS `mWRD: Molecular WHO-Recommended Diagnostic PCR (with or without other testing)`,
        SUM(CASE WHEN other_diagnostic_test = ''Additional test other than Gene-Xpert'' is not null THEN 1 ELSE 0 END) as `Additional test other than mWRD`
from tb_screening where specimen_sent_to_lab=''Yes'' ';
    ELSEIF REPORT_TYPE = 'DIAGNOSTIC_TEST' THEN
        SET group_query =
                ' select  ''Number of ART patients who had a specimen sent for bacteriologic diagnosis of active TB disease'' AS `Name`,COUNT(*) AS `Value` from tb_screening where specimen_sent_to_lab=''Yes'' ';
    ELSEIF REPORT_TYPE = 'POSITIVE_RESULT' THEN
        SET group_query =
                ' select  ''Number of ART patients who had a positive result returned for bacteriologic diagnosis of active TB disease'' AS `Name`,COUNT(*) AS `Value` from tb_screening where specimen_sent_to_lab=''Yes'' and (lf_lam_result=''Positive'' or gene_xpert_result=''Positive'') ';
    ELSEIF REPORT_TYPE = 'NUMERATOR_TOTAL' THEN
        SET group_query = CONCAT(' select COUNT(*) as `Subtotal` FROM tb_treatment WHERE ', outcome_condition);
    ELSEIF REPORT_TYPE = 'TOTAL' THEN
        SET group_query = 'select COUNT(*) as `Subtotal` FROM tb_screening';
    ELSEIF REPORT_TYPE = 'DEBUG' THEN
        SET group_query = 'select * FROM tb_screening';
    ELSE
        SET group_query = CONCAT('
        SELECT
          sex,
          SUM(CASE WHEN ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ' is null AND count is not null THEN count ELSE 0 END) AS ''Unknown Age'',
          ', age_group_cols, ' ,
        SUM(CASE WHEN count is not null THEN count ELSE 0 END) as Subtotal
        FROM (
          SELECT
            sex,
            ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), ',
            COUNT(*) AS count
          FROM ',source_table, ' WHERE ', outcome_condition, '
          GROUP BY sex, ', IF(IS_COURSE_AGE_GROUP, 'coarse_age_group', 'fine_age_group'), '
        ) AS subquery
        RIGHT JOIN (SELECT ''Female'' AS sex UNION SELECT ''Male'') AS genders
        USING (sex)
        GROUP BY sex
        ');
    END IF;

    SET @sql = CONCAT(tx_tb_query, group_query);
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_data_processing_derived_follow_up
--

-- Entry point for the follow_up derived domain.
-- Always performs a full rebuild of mamba_fact_followup on every
-- ETL run. The previous incremental/delta-refresh optimization
-- was reverted in favor of full rebuild: simpler, no drift, no
-- reliance on the _mamba_etl_schedule watermark, and matches the
-- user-triggered ETL model where the operator expects a known-
-- correct state after each run.
--
-- Sequence:
--   1. DROP TABLE mamba_fact_followup (always)
--   2. CALL sp_fact_hmis_followup()  -- creates + TRUNCATE+INSERT
--   3. CALL sp_compress_follow_up_flat_tables()  -- apply compression
--      to mamba_fact_followup (via _create) and the 10 source flat
--      tables. Idempotent on already-compressed tables.
--
-- The etl_incremental_mode parameter is kept in the signature for
-- backward compatibility with the call site in
-- sp_mamba_data_processing_etl, but is intentionally ignored.

DELIMITER //

DROP PROCEDURE IF EXISTS sp_data_processing_derived_follow_up;

~
CREATE PROCEDURE sp_data_processing_derived_follow_up(IN etl_incremental_mode INT)
BEGIN
    DROP TABLE IF EXISTS mamba_fact_followup;

    CALL sp_fact_hmis_followup();

    CALL sp_compress_follow_up_flat_tables();
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_compress_follow_up_flat_tables
--

-- Post-create compression for the 10 follow-up source flat tables.
--
-- The core (mamba-core-api, in a separate repo) creates these tables with
-- the default ROW_FORMAT=DYNAMIC via sp_mamba_flat_encounter_table_create.
-- We can't change that from this repo, so we re-apply compression here
-- AFTER the core ETL has (re)built the tables and BEFORE the follow-up
-- materialization reads from them.
--
-- The 10 ALTERs are idempotent: on an already-compressed table MySQL 8
-- performs a metadata-only change (no rewrite). On an uncompressed table
-- (first run, or after a full-rebuild) MySQL rewrites the table with
-- compression. On the incremental path the core's
-- sp_mamba_flat_table_incremental_insert_all updates rows in-place
-- without touching row format, so the tables stay compressed.
--
-- Why KEY_BLOCK_SIZE=8:
--   * ~55% on-disk size reduction
--   * ~10% CPU overhead for (de)compression (negligible on modern x86)
--   * Sweet spot for HDD-backed MySQL 8 deployments
--   * Same buffer pool RAM usage; compressed pages take 8 KB on disk
--     but the 16 KB buffer pool slots are populated from decompressed pages

DELIMITER //

DROP PROCEDURE IF EXISTS sp_compress_follow_up_flat_tables;

~
CREATE PROCEDURE sp_compress_follow_up_flat_tables()
BEGIN
    ALTER TABLE mamba_flat_encounter_follow_up   ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_1 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_2 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_3 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_4 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_5 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_6 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_7 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_8 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;
    ALTER TABLE mamba_flat_encounter_follow_up_9 ROW_FORMAT=COMPRESSED KEY_BLOCK_SIZE=8;

    ANALYZE TABLE mamba_flat_encounter_follow_up,
                mamba_flat_encounter_follow_up_1,
                mamba_flat_encounter_follow_up_2,
                mamba_flat_encounter_follow_up_3,
                mamba_flat_encounter_follow_up_4,
                mamba_flat_encounter_follow_up_5,
                mamba_flat_encounter_follow_up_6,
                mamba_flat_encounter_follow_up_7,
                mamba_flat_encounter_follow_up_8,
                mamba_flat_encounter_follow_up_9;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_followup
--

-- Wrapper for the follow-up materialization.
-- Always performs a full rebuild: _create (idempotent CREATE TABLE)
-- followed by _insert (TRUNCATE + 10-way LEFT JOIN INSERT).
-- The table is dropped by sp_data_processing_derived_follow_up
-- before this wrapper is called, so the wrapper is responsible only
-- for the create-then-populate sequence.
DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_followup;

~
CREATE PROCEDURE sp_fact_hmis_followup()
BEGIN
    CALL sp_fact_hmis_followup_create();
    CALL sp_fact_hmis_followup_insert();
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_followup_create
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_followup_create;

~
CREATE PROCEDURE sp_fact_hmis_followup_create()
BEGIN
    CREATE TABLE IF NOT EXISTS mamba_fact_followup (
        encounter_id                                       INT          NOT NULL PRIMARY KEY,
        client_id                                          INT          NOT NULL,
        follow_up_status                                   VARCHAR(255)     NULL,
        follow_up_date_followup_                           DATETIME         NULL,
        art_antiretroviral_start_date                      DATETIME         NULL,
        treatment_end_date                                 DATETIME         NULL,
        next_visit_date                                    DATETIME         NULL,
        regimen                                            VARCHAR(255)     NULL,
        currently_breastfeeding_child                      VARCHAR(255)     NULL,
        pregnancy_status                                   VARCHAR(255)     NULL,
        transferred_in_check_this_for_all_t                VARCHAR(255)     NULL,
        antiretroviral_art_dispensed_dose_i                VARCHAR(255)     NULL,
        adherence                                          VARCHAR(255)     NULL,
        cd4_count                                          DOUBLE           NULL,
        weight_text_                                       VARCHAR(255)     NULL,
        date_viral_load_results_received                   DATETIME         NULL,
        hiv_viral_load                                     DOUBLE           NULL,
        viral_load_test_status                             VARCHAR(255)     NULL,
        viral_load_test_indication                         VARCHAR(255)     NULL,
        viral_load_received_                               VARCHAR(255)     NULL,
        date_of_reported_hiv_viral_load                    DATETIME         NULL,
        dsd_category                                       VARCHAR(255)     NULL,
        assessment_date                                    DATETIME         NULL,
        date_started_on_tuberculosis_prophy                DATETIME         NULL,
        date_completed_tuberculosis_prophyl                DATETIME         NULL,
        tb_prophylaxis_type                                VARCHAR(255)     NULL,
        was_the_patient_screened_for_tuberc                VARCHAR(255)     NULL,
        tb_screening_date                                  DATETIME         NULL,
        tb_treatment_status                                VARCHAR(255)     NULL,
        screening_test_result_tuberculosis                 VARCHAR(255)     NULL,
        lf_lam_result                                      VARCHAR(255)     NULL,
        cervical_cancer_screening_status                   VARCHAR(255)     NULL,
        cervical_cancer_screening_method_strategy          VARCHAR(255)     NULL,
        via_screening_result                               VARCHAR(255)     NULL,
        hpv_dna_screening_result                           VARCHAR(255)     NULL,
        date_hpv_test_was_done                             DATETIME         NULL,
        date_visual_inspection_of_the_cervi                DATETIME         NULL,
        treatment_of_precancerous_lesions_of_the_cervix    VARCHAR(255)     NULL,
        treatment_start_date                               DATETIME         NULL,
        hpv_dna_result_received_date                       DATETIME         NULL,
        is_the_client_screened_in_this_facility            VARCHAR(255)     NULL,
        nutritional_supplements_provided                  VARCHAR(255)     NULL,
        eats_nutritious_foods                              VARCHAR(255)     NULL,
        nutritional_screening_result                       VARCHAR(255)     NULL,
        nutritional_status_of_adult                        VARCHAR(255)     NULL,
        nutritional_status_of_older_child_a                VARCHAR(255)     NULL,
        weight_for_age_status                              VARCHAR(255)     NULL,
        method_of_family_planning                          VARCHAR(255)     NULL,
        on_family_planning                                 VARCHAR(255)     NULL,

        INDEX idx_encounter_id (encounter_id),
        INDEX idx_client_id   (client_id),
        INDEX idx_client_date (client_id, follow_up_date_followup_)
    ) ENGINE=InnoDB
      ROW_FORMAT=COMPRESSED
      KEY_BLOCK_SIZE=8;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_followup_insert
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_followup_insert;

~
CREATE PROCEDURE sp_fact_hmis_followup_insert()
BEGIN
    TRUNCATE TABLE mamba_fact_followup;

    INSERT INTO mamba_fact_followup (
        encounter_id, client_id, follow_up_status, follow_up_date_followup_,
        art_antiretroviral_start_date, treatment_end_date, next_visit_date, regimen,
        currently_breastfeeding_child, pregnancy_status,
        transferred_in_check_this_for_all_t, antiretroviral_art_dispensed_dose_i,
        adherence, cd4_count, weight_text_,
        date_viral_load_results_received, hiv_viral_load, viral_load_test_status,
        viral_load_test_indication, viral_load_received_,
        date_of_reported_hiv_viral_load, dsd_category, assessment_date,
        date_started_on_tuberculosis_prophy, date_completed_tuberculosis_prophyl,
        tb_prophylaxis_type, was_the_patient_screened_for_tuberc, tb_screening_date,
        tb_treatment_status, screening_test_result_tuberculosis, lf_lam_result,
        cervical_cancer_screening_status, cervical_cancer_screening_method_strategy,
        via_screening_result, hpv_dna_screening_result, date_hpv_test_was_done,
        date_visual_inspection_of_the_cervi, treatment_of_precancerous_lesions_of_the_cervix,
        treatment_start_date, hpv_dna_result_received_date,
        is_the_client_screened_in_this_facility, nutritional_supplements_provided,
        eats_nutritious_foods, nutritional_screening_result, nutritional_status_of_adult,
        nutritional_status_of_older_child_a, weight_for_age_status,
        method_of_family_planning, on_family_planning
    )
    SELECT
        follow_up.encounter_id,
        follow_up.client_id,
        follow_up_status,
        follow_up_date_followup_,
        art_antiretroviral_start_date,
        treatment_end_date,
        next_visit_date,
        regimen,
        currently_breastfeeding_child,
        pregnancy_status,
        transferred_in_check_this_for_all_t,
        antiretroviral_art_dispensed_dose_i,
        adherence,
        cd4_count,
        weight_text_,
        date_viral_load_results_received,
        hiv_viral_load,
        viral_load_test_status,
        viral_load_test_indication,
        viral_load_received_,
        date_of_reported_hiv_viral_load,
        dsd_category,
        assessment_date,
        date_started_on_tuberculosis_prophy,
        date_completed_tuberculosis_prophyl,
        tb_prophylaxis_type,
        was_the_patient_screened_for_tuberc,
        tb_screening_date,
        tb_treatment_status,
        screening_test_result_tuberculosis,
        lf_lam_result,
        cervical_cancer_screening_status,
        cervical_cancer_screening_method_strategy,
        via_screening_result,
        hpv_dna_screening_result,
        date_hpv_test_was_done,
        date_visual_inspection_of_the_cervi,
        treatment_of_precancerous_lesions_of_the_cervix,
        treatment_start_date,
        hpv_dna_result_received_date,
        is_the_client_screened_in_this_facility,
        nutritional_supplements_provided,
        eats_nutritious_foods,
        nutritional_screening_result,
        nutritional_status_of_adult,
        nutritional_status_of_older_child_a,
        weight_for_age_status,
        method_of_family_planning,
        on_family_planning
    FROM mamba_flat_encounter_follow_up follow_up
             LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                       ON follow_up.encounter_id = follow_up_1.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                       ON follow_up.encounter_id = follow_up_2.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                       ON follow_up.encounter_id = follow_up_3.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                       ON follow_up.encounter_id = follow_up_4.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                       ON follow_up.encounter_id = follow_up_5.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                       ON follow_up.encounter_id = follow_up_6.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                       ON follow_up.encounter_id = follow_up_7.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                       ON follow_up.encounter_id = follow_up_8.encounter_id
             LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                       ON follow_up.encounter_id = follow_up_9.encounter_id;

    ANALYZE TABLE mamba_fact_followup;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_create_follow_up_tmp
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_create_follow_up_tmp;

~
CREATE PROCEDURE sp_fact_hmis_create_follow_up_tmp()
BEGIN
    DROP TABLE IF EXISTS tmp_hmis_follow_up;
