      AND regimen = '2j -TDF+3TC+DTG'
      AND sex = 'Female'
      AND (pregnancy_status = 'No' or pregnancy_status is null)
-- 20.2.19 2k - AZT+3TC+DTG, Male
    UNION ALL
    SELECT 'HIV_TX_CURR_REG_20.2. 19' AS S_NO,
           '2k = AZT + 3TC + DTG, Male'   as Activity,
