      AND regimen not in ('2e - AZT+3TC+LPVr', '2f - AZT+3TC+ATVr', '2g - TDF+3TC+LPVr', '2h - TDF+3TC+ATVr',
                          '2i - ABC+3TC+LPVr', '2j -TDF+3TC+DTG', '2k - AZT+3TC+DTG')
      AND (regimen_line = '2' or regimen_line = '5')
      AND sex = 'Female'
