-- 20.3.13 3f - DRV/r+AZT+3TC+EFV, Male
    UNION ALL
    SELECT 'HIV_TX_CURR_REG_20.3. 13'     AS S_NO,
           '3f= DRV/r+AZT+3TC +EFV, Male' as Activity,
