      AND pregnancy_status = 'Yes'
-- 20.3.15 3f - DRV/r+AZT+3TC+EFV, Female - non-pregnant
    UNION ALL
    SELECT 'HIV_TX_CURR_REG_20.3. 15'                      AS S_NO,
           '3f= DRV/r+AZT+3TC +EFV, Female - non-pregnant' as Activity,
