    FROM art_start_date_before_12_months
    WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 25 AND 29
      AND sex = 'Female'
      AND pregnancy_status = 'Yes'
-- 21 25 - 29 years, Female - non-pregnant
    UNION ALL
    SELECT 'HIV_ART_RET_NET. 21'                   AS S_NO,
