FROM art_tpt
WHERE tb_prophylaxis_type = '3HP'
  and TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
  and sex = 'Male'
-- < 15 years, Female
UNION ALL
SELECT 'HIV_ART_TPT_3HP. 2' AS S_NO,
       '< 15 years, Female' as Activity,
       COUNT(*)             as Value
FROM art_tpt
WHERE tb_prophylaxis_type = '3HP'
