-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_art_intr_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_art_intr_query;

~
CREATE PROCEDURE sp_fact_hmis_art_intr_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             antiretroviral_art_dispensed_dose_i as dose_days,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               regimen,
                                               dose_days,
                                               adherence,
                                               next_visit_date,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         -- TX curr
         tmp_lost_follow_up AS (SELECT client_id,
                                       follow_up_date,
                                       encounter_id,
                                       follow_up_status,
                                       treatment_end_date,
                                       art_start_date,
                                       regimen,
                                       dose_days,
                                       adherence,
                                       next_visit_date,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                FROM FollowUp
                                WHERE follow_up_status IS NOT NULL
                                  AND art_start_date IS NOT NULL
                                  AND follow_up_date <= REPORT_END_DATE),
         lost_follow_up as (select *
                            from tmp_lost_follow_up
                            where row_num = 1),
         tx_curr_end AS (select *
                         from tmp_lost_follow_up
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),

         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select tmp_lost_follow_up.*
                        from tmp_lost_follow_up
                                 join first_follow_up on tmp_lost_follow_up.client_id = first_follow_up.client_id
                        where art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                          AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != 'Yes')
                          AND first_follow_up.follow_up_status in ('Alive', 'Restart medication')
                          AND tmp_lost_follow_up.row_num = 1),
         tx_new as (select *
                    from tx_new_tmp),

         on_art as (select *
                    from tx_new
                    union ALL
                    select *
                    from tx_curr_start),
         interrupted_art as (select on_art.*,
                                    client.sex,
                                    client.date_of_birth,
                                    TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE)        as Age,
                                    lost_follow_up.follow_up_status                                   as lost_follow_up_status,
                                    lost_follow_up.follow_up_date                                     as lost_follow_up_date
                             from on_art
                                      join mamba_dim_client client on on_art.client_id = client.client_id
                                      join lost_follow_up
                                           on on_art.client_id = lost_follow_up.client_id
                             where on_art.client_id not in (select client_id from tx_curr_end))
    SELECT 'HIV_ART_INTR'                                     AS S_NO,
           'Number of ART Clients that interrupted Treatment' as Activity,
           COUNT(*)                                           as Value
    FROM interrupted_art
-- Number of ART Clients Interrupted treatment by outcome
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT'                                       AS S_NO,
           'Number of ART Clients Interrupted treatment by outcome' as Activity,
           COUNT(*)                                                 as Value
    FROM interrupted_art
-- Lost after treatemnt < 3month
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.1'            AS S_NO,
           'Lost after treatemnt < 3month' as Activity,
           COUNT(*)                        as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.1. 1' AS S_NO,
           '< 15 years, Male'      as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.1. 2' AS S_NO,
           '< 15 years, Female'    as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.1. 3' AS S_NO,
           '>= 15 years, Male'     as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.1. 4' AS S_NO,
           '>= 15 years, Female'   as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female'
-- Lost after treatement > 3month
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.2'             AS S_NO,
           'Lost after treatement > 3month' as Activity,
           COUNT(*)                         as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.2. 1' AS S_NO,
           '< 15 years, Male'      as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.2. 2' AS S_NO,
           '< 15 years, Female'    as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.2. 3' AS S_NO,
           '>= 15 years, Male'     as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.2. 4' AS S_NO,
           '>= 15 years, Female'   as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3
      AND lost_follow_up_status not in ('Transferred out', 'Stop all', 'Dead')
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female'
-- Transferred out
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.3' AS S_NO,
           'Transferred out'    as Activity,
           COUNT(*)             as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Transferred out'
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.3. 1' AS S_NO,
           '< 15 years, Male'      as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Transferred out'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.3. 2' AS S_NO,
           '< 15 years, Female'    as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Transferred out'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.3. 3' AS S_NO,
           '>= 15 years, Male'     as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Transferred out'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.3. 4' AS S_NO,
           '>= 15 years, Female'   as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Transferred out'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female'
-- Refused (stopped) treatement
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.4'           AS S_NO,
           'Refused (stopped) treatement' as Activity,
           COUNT(*)                       as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Stop all'
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.4. 1' AS S_NO,
           '< 15 years, Male'      as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Stop all'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.4. 2' AS S_NO,
           '< 15 years, Female'    as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Stop all'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.4. 3' AS S_NO,
           '>= 15 years, Male'     as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Stop all'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.4. 4' AS S_NO,
           '>= 15 years, Female'   as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Stop all'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female'
-- Died
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.5' AS S_NO,
           'Died'               as Activity,
           COUNT(*)             as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Dead'
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.5. 1' AS S_NO,
           '< 15 years, Male'      as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Dead'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.5. 2' AS S_NO,
           '< 15 years, Female'    as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Dead'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.5. 3' AS S_NO,
           '>= 15 years, Male'     as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Dead'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_INTR_OUT.5. 4' AS S_NO,
           '>= 15 years, Female'   as Activity,
           COUNT(*)                as Value
    FROM interrupted_art
    WHERE lost_follow_up_status = 'Dead'
      AND TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female';
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_art_restart_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_art_restart_query;

~
CREATE PROCEDURE sp_fact_hmis_art_restart_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             antiretroviral_art_dispensed_dose_i,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             cd4_count,
                             weight_text_,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               cd4_count,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= REPORT_START_DATE),           -- Param 1 @start_date
         latest_follow_up_start as (select *
                                    from tmp_latest_follow_up_start
                                    where row_num = 1),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= REPORT_START_DATE),                    -- Param 2 @start_date
         interrupted_at_start AS (select latest_follow_up_start.*
                                  from latest_follow_up_start
                                           left join tx_curr_start
                                                     on latest_follow_up_start.client_id = tx_curr_start.client_id
                                  where tx_curr_start.client_id is null
                                    and latest_follow_up_start.follow_up_status != 'Transferred out'),

         -- TX curr
         tmp_latest_follow_up_end AS (SELECT client_id,
                                             follow_up_date,
                                             encounter_id,
                                             follow_up_status,
                                             treatment_end_date,
                                             art_start_date,
                                             cd4_count,
                                             regimen,
                                             weight_text_,
                                             antiretroviral_art_dispensed_dose_i,
                                             adherence,
                                             next_visit_date,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE follow_up_status IS NOT NULL
                                        AND art_start_date IS NOT NULL
                                        AND follow_up_date <= REPORT_END_DATE),             -- Param 3 @end_date
         -- TX curr
         tmp_restart_follow_up_end AS (SELECT client_id,
                                              follow_up_date                                                                     as restart_follow_up_date,
                                              encounter_id,
                                              follow_up_status                                                                   as restart_status,
                                              treatment_end_date,
                                              art_start_date,
                                              cd4_count                                                                          as restart_cd4_count,
                                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                       FROM FollowUp
                                       WHERE follow_up_status IS NOT NULL
                                         AND art_start_date IS NOT NULL
                                         AND follow_up_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE), -- Param 4 and 5 @start_date, @end_date
         tx_curr_end AS (select *
                         from tmp_latest_follow_up_end
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),                      -- Param 6 @end_date
         restart_follow_up_end as (select tmp_restart_follow_up_end.*
                                   from tmp_restart_follow_up_end
                                            join tx_curr_end on tmp_restart_follow_up_end.client_id = tx_curr_end.client_id
                                   where tmp_restart_follow_up_end.row_num = 1),

         tx_rtt as (select tx_curr_end.follow_up_date                          as latest_follow_up_date,
                           tx_curr_end.encounter_id,
                           tx_curr_end.follow_up_status                        as latest_follow_up_status,
                           tx_curr_end.treatment_end_date                      as latest_follow_up_treatment_end_date,
                           tx_curr_end.art_start_date                          as latest_follow_up_art_start_date,
                           tx_curr_end.cd4_count                               as latest_follow_up_cd4_count,
                           restart_follow_up_end.restart_cd4_count,
                           restart_follow_up_end.restart_status,
                           restart_follow_up_end.restart_follow_up_date,
                           sex,
                           date_of_birth,
                           mrn,
                           uan,
                           patient_name,
                           patient_uuid,
                           tx_curr_end.regimen,
                           tx_curr_end.weight_text_,
                           tx_curr_end.antiretroviral_art_dispensed_dose_i,
                           tx_curr_end.adherence,
                           tx_curr_end.next_visit_date,
                           interrupted_at_start.follow_up_date                 as interrupted_follow_up_follow_up_date,
                           interrupted_at_start.follow_up_status               as interrupted_follow_up_follow_up_status,
                           interrupted_at_start.treatment_end_date             as interrupted_follow_up_treatment_end_date,
                           CASE
                               WHEN interrupted_at_start.follow_up_status in ('Alive', 'Restart medication')
                                   and interrupted_at_start.treatment_end_date <= REPORT_START_DATE THEN -- Param 9 @start_date
                                   TIMESTAMPDIFF(MONTH, interrupted_at_start.treatment_end_date,
                                                 restart_follow_up_end.restart_follow_up_date)
                               ELSE TIMESTAMPDIFF(MONTH, interrupted_at_start.follow_up_date,
                                                  restart_follow_up_end.restart_follow_up_date)
                               END                                             AS 'interrupted_months'
                    from interrupted_at_start
                             join tx_curr_end
                                  on interrupted_at_start.client_id = tx_curr_end.client_id
                             join mamba_dim_client client on interrupted_at_start.client_id = client.client_id
                             join restart_follow_up_end on tx_curr_end.client_id = restart_follow_up_end.client_id)

-- Number of ART clients restarted ARV treatment in the reporting period
    SELECT 'HIV_ART_RE_ARV'                                                        AS S_NO,
           'Number of ART clients restarted ARV treatment in the reporting period' as Activity,
           COUNT(*)                                                                as Value
    FROM tx_rtt
-- < 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_RE_ARV. 1' AS S_NO,
           '< 15 years, Male'  as Activity,
           COUNT(*)            as Value
    FROM tx_rtt
    WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Male'
-- < 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_RE_ARV. 2'  AS S_NO,
           '< 15 years, Female' as Activity,
           COUNT(*)             as Value
    FROM tx_rtt
    WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) < 15
      AND sex = 'Female'
-- >= 15 years, Male
    UNION ALL
    SELECT 'HIV_ART_RE_ARV. 3' AS S_NO,
           '>= 15 years, Male' as Activity,
           COUNT(*)            as Value
    FROM tx_rtt
    WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Male'
-- >= 15 years, Female
    UNION ALL
    SELECT 'HIV_ART_RE_ARV. 4'   AS S_NO,
           '>= 15 years, Female' as Activity,
           COUNT(*)              as Value
    FROM tx_rtt
    WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) >= 15
      AND sex = 'Female';
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_fp_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_fp_query;

~
CREATE PROCEDURE sp_fact_hmis_hiv_fp_query(IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp as (select follow_up.encounter_id,
                         follow_up.client_id,
                         method_of_family_planning,
                         on_family_planning,
                         follow_up_date_followup_,
                         pregnancy_status,
                         follow_up_status,
                         treatment_end_date,
                         art_antiretroviral_start_date art_start_date
                  FROM mamba_flat_encounter_follow_up follow_up
                           LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                     ON follow_up.encounter_id = follow_up_1.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                     ON follow_up.encounter_id = follow_up_2.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                     ON follow_up.encounter_id = follow_up_3.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                     ON follow_up.encounter_id = follow_up_4.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                     ON follow_up.encounter_id = follow_up_5.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                     ON follow_up.encounter_id = follow_up_6.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                     ON follow_up.encounter_id = follow_up_7.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                     ON follow_up.encounter_id = follow_up_8.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                     ON follow_up.encounter_id = follow_up_9.encounter_id),
     -- TX curr
     tx_curr_all AS (SELECT client_id,
                            follow_up_date_followup_                                                                             AS FollowupDate,
                            encounter_id,
                            follow_up_status,
                            treatment_end_date,
                            method_of_family_planning,
                            on_family_planning,
                            pregnancy_status,
                            follow_up_date_followup_,
                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) AS row_num
                     FROM FollowUp
                     WHERE follow_up_status IS NOT NULL
                       AND art_start_date IS NOT NULL
                       AND follow_up_date_followup_ <= REPORT_END_DATE),

     tx_curr AS (select *
                 from tx_curr_all
                 where row_num = 1
                   AND follow_up_status in ('Alive', 'Restart medication')
                   AND treatment_end_date >= REPORT_END_DATE),
     tmp_fp as (select encounter_id,
                       client_id,
                       method_of_family_planning,
                       on_family_planning,
                       pregnancy_status,
                       ROW_NUMBER() over (PARTITION BY client_id order by follow_up_date_followup_ DESC ,encounter_id DESC) as row_num
                from tx_curr
                where method_of_family_planning != 'None'
                  and method_of_family_planning != 'Sexual abstinence'),
    fp as (select tmp_fp.*,
    client.sex,
    client.date_of_birth,
    patient_name,
    mrn
from tmp_fp
    join mamba_dim_client client on tmp_fp.client_id = client.client_id
    join tx_curr on tmp_fp.client_id = tx_curr.client_id
where tmp_fp.row_num = 1),
    family_planning_wo_age as (select *
from fp
where sex = 'Female'
  and (pregnancy_status = 'No' or pregnancy_status is null)),
    family_planning as (select *
from fp
where sex = 'Female'
  and TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 15 AND 49
  and (pregnancy_status = 'No' or pregnancy_status is null))
-- Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by age
SELECT 'HIV_ART_FP_AGE'                                                                                                                      AS S_NO,
       'Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by age' as Activity,
       COUNT(*)                                                                                                                          as Value
FROM family_planning
-- 10 - 14 years
UNION ALL
SELECT 'HIV_ART_FP_AGE. 1' AS S_NO,
       '10 - 14 years' as Activity,
       COUNT(*)        as Value
FROM family_planning_wo_age
WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 10 AND 14
-- 15 - 19 years
UNION ALL
SELECT 'HIV_ART_FP_AGE. 2' AS S_NO,
       '15 - 19 years' as Activity,
       COUNT(*)        as Value
FROM family_planning
WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 15 AND 19
-- 20 - 24 years
UNION ALL
SELECT 'HIV_ART_FP_AGE. 3' AS S_NO,
       '20 - 24 years' as Activity,
       COUNT(*)        as Value
FROM family_planning
WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 20 AND 24
-- 25 - 29 years
UNION ALL
SELECT 'HIV_ART_FP_AGE. 4' AS S_NO,
       '25 - 29 years' as Activity,
       COUNT(*)        as Value
FROM family_planning
WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 25 AND 29
-- 30 - 49 years
UNION ALL
SELECT 'HIV_ART_FP_AGE. 5' AS S_NO,
       '30 - 49 years' as Activity,
       COUNT(*)        as Value
FROM family_planning
WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 30 AND 49

-- Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by method
UNION ALL
SELECT 'HIV_ART_FP_MET'                                                                                                                     AS S_NO,
       'Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by method' as Activity,
       COUNT(*)                                                                                                                             as Value
FROM family_planning
-- Oral contraceptives
UNION ALL
SELECT 'HIV_ART_FP_MET. 1'   AS S_NO,
       'Oral contraceptives' as Activity,
       COUNT(*)              as Value
FROM family_planning
WHERE method_of_family_planning = 'Oral contraception'
-- Injectables
UNION ALL
SELECT 'HIV_ART_FP_MET. 2' AS S_NO,
       'Injectables'       as Activity,
       COUNT(*)            as Value
FROM family_planning
WHERE method_of_family_planning = 'Injectable contraceptives'
-- Implants
UNION ALL
SELECT 'HIV_ART_FP_MET. 3' AS S_NO,
       'Implants'          as Activity,
       COUNT(*)            as Value
FROM family_planning
WHERE method_of_family_planning = 'Implantable contraceptive (unspecified type)'
-- IUCD
UNION ALL
SELECT 'HIV_ART_FP_MET. 4' AS S_NO,
       'IUCD'              as Activity,
       COUNT(*)            as Value
FROM family_planning
WHERE method_of_family_planning = 'Intrauterine device'
-- Others
UNION ALL
SELECT 'HIV_ART_FP_MET. 5' AS S_NO,
       'Others'            as Activity,
       COUNT(*)            as Value
FROM family_planning
WHERE method_of_family_planning not in
    ('Oral contraception', 'Injectable contraceptives', 'Implantable contraceptive (unspecified type)','Intrauterine device');
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_linkage_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_linkage_query;

~
CREATE PROCEDURE sp_fact_hmis_hiv_linkage_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

WITH linkage as (select *
                 from mamba_flat_encounter_positive_tracking
                 where date_enrolled_in_care BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
     linkage_agg AS (
         SELECT COUNT(*) AS total,
                SUM(CASE WHEN (linked_to_hiv_care = 'Yes' AND reason_art_not_started_the_same_day IS NULL AND final_outcome IS NULL)
                           OR final_outcome = 'On antiretroviral therapy'
                           OR (on_antiretroviral_therapy = 'On antiretroviral therapy' AND final_outcome IS NULL)
                          THEN 1 ELSE 0 END)                                                                                     AS linked_to_care,
                SUM(CASE WHEN reason_art_not_started_the_same_day = 'Enrolled in HIV/ART care'
                           AND final_outcome IS NULL THEN 1 ELSE 0 END)                                                          AS known_on_art,
                SUM(CASE WHEN final_outcome = 'Loss to follow-up (LTFU)' THEN 1 ELSE 0 END)                                     AS ltfu,
                SUM(CASE WHEN final_outcome = 'Confirmed referral'
                           OR final_outcome = 'Started ART in other health facility'
                           OR (reason_art_not_started_the_same_day = 'Referred TX not initiated' AND final_outcome IS NULL)
                          THEN 1 ELSE 0 END)                                                                                     AS referred,
                SUM(CASE WHEN final_outcome = 'Died'
                           OR reason_art_not_started_the_same_day = 'Died' THEN 1 ELSE 0 END)                                   AS died,
                SUM(CASE WHEN final_outcome = 'Refusal of treatment by patient'
                           OR final_outcome = 'Other'
                           OR (reason_art_not_started_the_same_day = 'Refusal of treatment by patient' AND final_outcome IS NULL)
                           OR (reason_art_not_started_the_same_day = 'On adherence preparation' AND final_outcome IS NULL)
                           OR (reason_art_not_started_the_same_day = 'On OI management' AND final_outcome IS NULL)
                           OR (reason_art_not_started_the_same_day = 'Other' AND final_outcome IS NULL)
                           OR ((linked_to_hiv_care IS NULL OR linked_to_hiv_care = 'No')
                               AND (on_antiretroviral_therapy IS NULL OR on_antiretroviral_therapy = 'No')
                               AND final_outcome IS NULL)
                          THEN 1 ELSE 0 END)                                                                                     AS others
         FROM linkage
     )

SELECT 'HIV_Linkage_NEW_CT'                                                                   AS S_NO,
       'Linkage outcome of newly identified Hiv positive individuals in the reporting period' as Activity,
       total                                                                                  as Value
FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 1', 'Linked to care and treatment', linked_to_care FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 2', 'Known on ART',                 known_on_art   FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 3', 'Lost to follow up art',        ltfu           FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 4', 'Referred to other facility',   referred       FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 5', 'Died',                         died           FROM linkage_agg
UNION ALL SELECT 'HIV_Linkage_NEW_CT. 6', 'Others',                       others         FROM linkage_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_phliv_tsp_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_phliv_tsp_query;

~
CREATE PROCEDURE sp_fact_hmis_phliv_tsp_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp as (select follow_up.encounter_id,
                         follow_up.client_id,
                         nutritional_supplements_provided,
                         eats_nutritious_foods,
                         nutritional_screening_result,
                         follow_up_date_followup_,
                         art_antiretroviral_start_date   as art_start_date,
                         pregnancy_status,
                         follow_up_status,
                         treatment_end_date,
                         coalesce(nutritional_status_of_adult,
                                  nutritional_status_of_older_child_a,
                                  weight_for_age_status) as nutritional_screening_status
                  FROM mamba_flat_encounter_follow_up follow_up
                           LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                     ON follow_up.encounter_id = follow_up_1.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                     ON follow_up.encounter_id = follow_up_2.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                     ON follow_up.encounter_id = follow_up_3.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                     ON follow_up.encounter_id = follow_up_4.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                     ON follow_up.encounter_id = follow_up_5.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                     ON follow_up.encounter_id = follow_up_6.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                     ON follow_up.encounter_id = follow_up_7.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                     ON follow_up.encounter_id = follow_up_8.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                     ON follow_up.encounter_id = follow_up_9.encounter_id),
     tx_curr_all AS (SELECT client_id,
                            follow_up_date_followup_ AS FollowupDate,
                            encounter_id,
                            follow_up_status,
                            treatment_end_date,
                            ROW_NUMBER()                OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) AS row_num
                     FROM FollowUp
                     WHERE follow_up_status IS NOT NULL
                       AND art_start_date IS NOT NULL
                       AND follow_up_date_followup_ <= REPORT_END_DATE),

     tx_curr AS (select *
                 from tx_curr_all
                 where row_num = 1
                   AND follow_up_status in ('Alive', 'Restart medication')
                   AND treatment_end_date >= REPORT_END_DATE),
     tmp_screened_for_nutrition as (select encounter_id,
                                           client_id,
                                           nutritional_supplements_provided,
                                           eats_nutritious_foods,
                                           nutritional_screening_result,
                                           follow_up_date_followup_,
                                           pregnancy_status,
                                           nutritional_screening_status,
                                           ROW_NUMBER() over (PARTITION BY client_id order by follow_up_date_followup_ DESC ,encounter_id DESC ) as row_num
                                    from FollowUp
                                    where nutritional_screening_result is not null
                                      and follow_up_date_followup_ BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                                      and art_start_date is not null),
     screened_for_nutrition as (select tmp_screened_for_nutrition.*,
                                       client.date_of_birth,
                                       client.sex
                                from tmp_screened_for_nutrition
                                         join tx_curr on tmp_screened_for_nutrition.client_id = tx_curr.client_id
                                         join mamba_dim_client client
                                              on tmp_screened_for_nutrition.client_id = client.client_id
                                where tmp_screened_for_nutrition.row_num = 1),
     percentage_calc AS (SELECT 'HIV_PLHIV_TSP'                                                                                                         AS S_NO,
                                'Proportion of clinically undernourished People Living with HIV (PLHIV) who received therapeutic or supplementary food' AS Activity,
                                CASE
                                    WHEN (SELECT COUNT(*)
                                          FROM screened_for_nutrition
                                          WHERE nutritional_screening_result = 'Undernourished') = 0 THEN
                                        '0%'
                                    ELSE
                                        CONCAT(CAST(ROUND(
                                                (CAST((SELECT COUNT(*)
                                                       FROM screened_for_nutrition
                                                       WHERE nutritional_screening_result = 'Undernourished'
                                                         AND (eats_nutritious_foods = 'Yes' OR
                                                              nutritional_supplements_provided IS NOT NULL)) AS REAL) *
                                                 100.0) /
                                                (SELECT COUNT(*)
                                                 FROM screened_for_nutrition
                                                 WHERE nutritional_screening_result = 'Undernourished')
                                            , 2) AS CHAR), '%')
                                    END                                                                                                                 AS Value
FROM (SELECT 1) AS dummy -- Added a dummy table to ensure the CTE returns at least one row
    )
-- Number of individuals receiving Pre-Exposure Prophylaxis
SELECT S_NO,
       Activity,
       Value
FROM percentage_calc
-- Number of PLHIV who were assessed/screened for malnutrition
UNION ALL
SELECT 'HIV_PLHIV_TSP.1'                                             AS S_NO,
       'Number of PLHIV who were assessed/screened for malnutrition' as Activity,
       COUNT(*) as Value
FROM screened_for_nutrition
-- < 15 years, Male
UNION ALL
SELECT 'HIV_PLHIV_TSP.1. 1' AS S_NO,
       '< 15 years, Male'   as Activity,
       COUNT(*) as Value
FROM screened_for_nutrition
WHERE TIMESTAMPDIFF(YEAR
    , date_of_birth
    , REPORT_END_DATE)
    < 15
  AND sex = 'Male'
-- < 15 years, Female
UNION ALL
SELECT 'HIV_PLHIV_TSP.1. 2' AS S_NO,
       '< 15 years, Female' as Activity,
       COUNT(*) as Value
FROM screened_for_nutrition
WHERE TIMESTAMPDIFF(YEAR
    , date_of_birth
    , REPORT_END_DATE)
    < 15
  AND sex = 'Female'
-- >= 15 years, Male
UNION ALL
SELECT 'HIV_PLHIV_TSP.1. 3' AS S_NO,
       '>= 15 years, Male'  as Activity,
       COUNT(*) as Value
FROM screened_for_nutrition
WHERE TIMESTAMPDIFF(YEAR
    , date_of_birth
    , REPORT_END_DATE) >= 15
  AND sex = 'Male'
