    UNION ALL SELECT 'HIV_HTS_TST_INDEX_4.2. 20',  '40 - 44 years, Female', COALESCE(u44_female, 0) FROM known_positive_agg
    UNION ALL SELECT 'HIV_HTS_TST_INDEX_4.2. 21',  '45 - 49 years, Male',   COALESCE(u49_male, 0)   FROM known_positive_agg
    UNION ALL SELECT 'HIV_HTS_TST_INDEX_4.2. 22',  '45 - 49 years, Female', COALESCE(u49_female, 0) FROM known_positive_agg
    UNION ALL SELECT 'HIV_HTS_TST_INDEX_4.2. 23',  '>= 50 years, Male',     COALESCE(o50_male, 0)   FROM known_positive_agg
    UNION ALL SELECT 'HIV_HTS_TST_INDEX_4.2. 24',  '>= 50 years, Female',   COALESCE(o50_female, 0) FROM known_positive_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_mtct_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_mtct_query;

~
CREATE PROCEDURE sp_fact_hmis_mtct_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH Enrollment_tmp as (select client_id,
                                   antenatal_care_provider,
                                   ld_client,
                                   post_natal_care,
                                   art_clinic,
                                   location_of_birth,
                                   ROW_NUMBER() over (PARTITION BY client_id ORDER BY date_of_enrollment_or_booking DESC, encounter_id DESC) as row_num
                            from mamba_flat_encounter_pmtct_enrollment
                            where date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         Enrollment as (select * from Enrollment_tmp where row_num = 1),
         delivery_tmp as (select client_id,
                                   antenatal_care_provider,
                                   ld_client,
                                   post_natal_care,
                                   art_clinic,
                                   location_of_birth,
                                   ROW_NUMBER() over (PARTITION BY client_id ORDER BY date_of_delivery DESC, encounter_id DESC) as row_num
                            from mamba_flat_encounter_pmtct_enrollment
                            where date_of_delivery BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         Delivery as (select * from delivery_tmp where row_num = 1),
         tmp_hei_test as (select hiv_test.client_id,
                                 hiv_test_date,
                                 date_of_birth,
                                 hiv_test_result,
                                 TIMESTAMPDIFF(MONTH, date_of_birth, dna_pcr_sample_collection_date)                                                 as age_in_months,
                                 ROW_NUMBER() over (PARTITION BY hiv_test.client_id ORDER BY dna_pcr_sample_collection_date DESC, encounter_id DESC) as row_num
                          from mamba_flat_encounter_hei_hiv_test hiv_test
                                   join mamba_dim_client client on hiv_test.client_id = client.client_id
                          where test_type = 'HIV DNA polymerase chain reaction, dried blood spot (DBS)' and test_round = 'Initial test'
                            and dna_pcr_sample_collection_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         hei_test as (select * from tmp_hei_test where row_num = 1),
         tmp_hei_confirmatory as (select hiv_test.client_id,
                                         hiv_test_date,
                                         date_of_birth,
                                         hiv_test_result,
                                         TIMESTAMPDIFF(MONTH, date_of_birth, followup_date_followup_1)                                                 as age_in_months,
                                         ROW_NUMBER() over (PARTITION BY hiv_test.client_id ORDER BY followup_date_followup_1 DESC, encounter_id DESC) as row_num
                                  from mamba_flat_encounter_hei_hiv_test hiv_test
                                           join mamba_dim_client client on hiv_test.client_id = client.client_id
                                  where test_type = 'Rapid test for HIV'
                                    and followup_date_followup_1 BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         hei_confirmatory as (select * from tmp_hei_confirmatory where row_num = 1),
         tmp_hei_cpt as (select f.client_id,
                                f.followup_date_followup                                                             as cpt_date,
                                c.date_of_birth,
                                arv_prophylaxis,
                                DATEDIFF(f.followup_date_followup, c.date_of_birth)                                  as age_days_at_cpt,
                                ROW_NUMBER() over (PARTITION BY f.client_id ORDER BY f.followup_date_followup, f.encounter_id ) as row_num
                         from mamba_flat_encounter_hei_followup f
                             left join mamba_flat_encounter_hei_followup_1 f1 on f.encounter_id = f1.encounter_id
                                  join mamba_dim_client c on f.client_id = c.client_id
                         where
                              f1.cotrimoxazole_prophylaxis_dose is not null                 and
                             f.followup_date_followup BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         hei_cpt as (select * from tmp_hei_cpt where row_num = 1),
         tmp_hei_enrollment as (SELECT e.client_id,
                                       c.date_of_birth,
                                       e.art_antiretroviral_start_date,
                                       e.arv_prophylaxis,
                                       ROW_NUMBER() over (PARTITION BY e.client_id ORDER BY e.date_enrolled_in_care DESC) as row_num
                                FROM mamba_flat_encounter_hei_enrollment e
                                         JOIN mamba_dim_client c ON e.client_id = c.client_id
                                WHERE e.date_enrolled_in_care BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         hei_enrollment as (SELECT * FROM tmp_hei_enrollment WHERE row_num = 1),
         enrollment_agg AS (
             SELECT COUNT(*)                                                   AS total,
                    SUM(CASE WHEN antenatal_care_provider IS NOT NULL THEN 1 ELSE 0 END) AS anc_count,
                    SUM(CASE WHEN ld_client IS NOT NULL THEN 1 ELSE 0 END)               AS ld_count,
                    SUM(CASE WHEN post_natal_care IS NOT NULL THEN 1 ELSE 0 END)         AS pnc_count,
                    SUM(CASE WHEN art_clinic IS NOT NULL THEN 1 ELSE 0 END)              AS art_count
             FROM Enrollment
             WHERE row_num = 1
         ),
         hei_test_agg AS (
             SELECT SUM(CASE WHEN age_in_months BETWEEN 0 AND 2 THEN 1 ELSE 0 END)                                                  AS in_0_2,
                    SUM(CASE WHEN age_in_months > 2 AND age_in_months <= 12 THEN 1 ELSE 0 END)                                       AS in_2_12,
                    SUM(CASE WHEN hiv_test_result IS NOT NULL THEN 1 ELSE 0 END)                                                     AS total_with_result,
                    SUM(CASE WHEN hiv_test_result IS NOT NULL AND age_in_months BETWEEN 0 AND 2 THEN 1 ELSE 0 END)                   AS in_0_2_tested,
                    SUM(CASE WHEN hiv_test_result = 'Positive' AND age_in_months BETWEEN 0 AND 2 THEN 1 ELSE 0 END)                 AS in_0_2_positive,
                    SUM(CASE WHEN hiv_test_result = 'Negative' AND age_in_months BETWEEN 0 AND 2 THEN 1 ELSE 0 END)                 AS in_0_2_negative,
                    SUM(CASE WHEN hiv_test_result IS NOT NULL AND age_in_months > 2 AND age_in_months <= 12 THEN 1 ELSE 0 END)       AS in_2_12_tested,
                    SUM(CASE WHEN hiv_test_result = 'Positive' AND age_in_months > 2 AND age_in_months <= 12 THEN 1 ELSE 0 END)     AS in_2_12_positive,
                    SUM(CASE WHEN hiv_test_result = 'Negative' AND age_in_months > 2 AND age_in_months <= 12 THEN 1 ELSE 0 END)     AS in_2_12_negative
             FROM hei_test
         ),
         hei_confirmatory_agg AS (
             SELECT COUNT(*)                                                                    AS total,
                    SUM(CASE WHEN hiv_test_result = 'Positive' THEN 1 ELSE 0 END)              AS positive,
                    SUM(CASE WHEN hiv_test_result = 'Negative' THEN 1 ELSE 0 END)              AS negative
             FROM hei_confirmatory
         )

    SELECT 'MTCT_ART'                                                                                                                                           AS S_NO,
           'Percentage of HIV-positive pregnant women who received ART to reduce the risk of mother-to child-transmission (MTCT) during pregnancy, L&D and PNC' as Activity,
           total                                                                                                                                                 as Value
    FROM enrollment_agg
    UNION ALL SELECT 'MTCT_ART.1.', 'Number of HIV positive women who received ART to reduce the risk of mother to child transmission during ANC for the first time',        COALESCE(anc_count,0) FROM enrollment_agg
    UNION ALL SELECT 'MTCT_ART.2.', 'Number of HIV positive Pregnant women who received ART to reduce the risk of mother to child transmission during L&D for the first time', COALESCE(ld_count,0)  FROM enrollment_agg
    UNION ALL SELECT 'MTCT_ART.3.', 'Number of HIV positive lactating women who received ART to reduce the risk of mother to child transmission during PNC for the first time', COALESCE(pnc_count,0) FROM enrollment_agg
    UNION ALL SELECT 'MTCT_ART.4.', 'Number of HIV-positive women who get pregnant while on ART and linked to ANC',                                                             COALESCE(art_count,0) FROM enrollment_agg
    UNION ALL SELECT 'MTCT_HEI_EID.',   'Percentage of  HIV exposed infants who received a virologic HIV test (sample collected) within 12 month',              COALESCE(in_0_2,0)        FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1',  'Number of HIV exposed infants who received a virologic HIV test (sample collected) 0- 2 months of birth',             COALESCE(in_0_2,0)        FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.2',  'Number of HIV exposed infants who received a virologic HIV test (sample collected) 2-12 months of birth',             COALESCE(in_2_12,0)       FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.3',  'Total Number of infants within 12 month received virological test result',                                             COALESCE(total_with_result,0) FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.1',   'Number of HIV exposed infants who received an HIV test 0- 2 months of birth',                                      COALESCE(in_0_2_tested,0)    FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.1. 1', 'Positive',                                                                                                        COALESCE(in_0_2_positive,0)  FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.1. 2', 'Negative',                                                                                                        COALESCE(in_0_2_negative,0)  FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.2',   'Number of HIV exposed infants who received an HIV test 2-12 months of birth',                                      COALESCE(in_2_12_tested,0)   FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.2. 1', 'Positive',                                                                                                        COALESCE(in_2_12_positive,0) FROM hei_test_agg
    UNION ALL SELECT 'MTCT_HEI_EID.1.2. 2', 'Negative',                                                                                                        COALESCE(in_2_12_negative,0) FROM hei_test_agg
    UNION ALL
    SELECT 'MTCT_HEI_COTR'                                                                                                                      AS S_NO,
           'Percentage of exposed Infants born to HIV positive women who were started on co-trimoxazole prophylaxis within two months of birth' as Activity,
           COUNT(*)                                                                                                                             as Value
    FROM hei_cpt
    where age_days_at_cpt <= 60
    UNION ALL
    SELECT 'MTCT_HEI_COTR.1.'                                                                                              AS S_NO,
           'Number of infants born to HIV positive women started on co-trimoxazole prophylaxis within two months of birth' as Activity,
           COUNT(*)                                                                                                        as Value
    FROM hei_cpt
    where age_days_at_cpt <= 60
    UNION ALL
    SELECT 'RMH_PMTCT_IARV'                                                                                                                                    AS S_NO,
           'Percentage of Infants born to HIV-infected women receiving antiretroviral (ARV) prophylaxis for prevention of Women-to-child transmission (PMTCT)' as Activity,
           COUNT(*)                                                                                                                                            as Value
    FROM hei_enrollment
    where arv_prophylaxis is not null
    UNION ALL
    SELECT 'MTCT_HEI_ARV.1.'                                                         AS S_NO,
           'Number of HIV exposed infants who received ARV prophylaxis For 12 weeks' as Activity,
           COUNT(*)                                                                  as Value
    FROM hei_enrollment
    where arv_prophylaxis is not null
    UNION ALL
    SELECT 'MTCT_HEI_ARV.2.'                                                   AS S_NO,
           'Number of HIV positive women who gave birth at health institution' as Activity,
           COUNT(*)                                                            as Value
    FROM Delivery
    where location_of_birth != 'Home Delivery'
    UNION ALL SELECT 'MTCT_HEI_ABTST',    'Percentage of HIV exposed infants receiving HIV confirmatory (antibody test) test by 18 months', COALESCE(total,0)    FROM hei_confirmatory_agg
    UNION ALL SELECT 'MTCT_HEI_ABTST.1',  'Number of HIV exposed infants receiving HIV confirmatory (antibody test) by 18 months',          COALESCE(total,0)    FROM hei_confirmatory_agg
    UNION ALL SELECT 'MTCT_HEI_ABTST.1. 1', 'Positive',                                                                                    COALESCE(positive,0) FROM hei_confirmatory_agg
    UNION ALL SELECT 'MTCT_HEI_ABTST.1. 2', 'Negative',                                                                                    COALESCE(negative,0) FROM hei_confirmatory_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_tb_lb_lf_lam_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_tb_lb_lf_lam_query;

~
CREATE PROCEDURE sp_fact_hmis_tb_lb_lf_lam_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
WITH FollowUp AS (select follow_up.encounter_id,
                         follow_up.client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc as tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t as transferred_in,
                         date_started_on_tuberculosis_prophy,
                         screening_test_result_tuberculosis     screening_result,
                         lf_lam_result
                  FROM mamba_flat_encounter_follow_up follow_up
                           LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                     ON follow_up.encounter_id = follow_up_1.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                     ON follow_up.encounter_id = follow_up_2.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                     ON follow_up.encounter_id = follow_up_3.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                     ON follow_up.encounter_id = follow_up_4.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                     ON follow_up.encounter_id = follow_up_5.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                     ON follow_up.encounter_id = follow_up_6.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                     ON follow_up.encounter_id = follow_up_7.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                     ON follow_up.encounter_id = follow_up_8.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                     ON follow_up.encounter_id = follow_up_9.encounter_id),
     tmp_latest_follow_up as (SELECT client_id,
                                     follow_up_date                                                                             AS FollowupDate,
                                     encounter_id,
                                     follow_up_status,
                                     tb_screening_date,
                                     art_start_date,
                                     tb_screened,
                                     screening_result,
                                     lf_lam_result,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND tb_screened = 'Yes'
                                AND follow_up_date <= REPORT_END_DATE),
     latest_tb_screened_follow_up as (SELECT follow_up.client_id,
                                             sex,
                                             date_of_birth,
                                             encounter_id,
                                             follow_up_status,
                                             tb_screening_date,
                                             art_start_date,
                                             tb_screened,
                                             screening_result,
                                             lf_lam_result
                                      from tmp_latest_follow_up follow_up
                                               inner join mamba_dim_client client on follow_up.client_id = client.client_id
                                      where row_num = 1),
     lf_lam as (select *
                from latest_tb_screened_follow_up
                where tb_screening_date between REPORT_START_DATE AND REPORT_END_DATE
                  and follow_up_status in ('Alive', 'Restart medication') and art_start_date is not null
                  and lf_lam_result is not null
     )


SELECT 'TB_LB_LF-LAM'                                                                              AS S_NO,
       'Total Number of tests performed using Lateral Flow Urine Lipoarabinomannan (LF-LAM) assay' as Activity,
       COUNT(*)                                                                                    as Value
FROM lf_lam
WHERE lf_lam_result is not null

UNION ALL
SELECT 'TB_LB_LF-LAM. 1' AS S_NO,
       'Positive'        as Activity,
       COUNT(*)          as Value
FROM lf_lam
WHERE lf_lam_result = 'Positive'

UNION ALL
SELECT 'TB_LB_LF-LAM. 2' AS S_NO,
       'Negative'        as Activity,
       COUNT(*)          as Value
FROM lf_lam
WHERE lf_lam_result = 'Negative result';
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_tx_curr_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_tx_curr_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_tx_curr_query_v2(
    IN REPORT_END_DATE DATE
)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id                     AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_      AS follow_up_date,
                             art_antiretroviral_start_date AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child    breast_feeding_status,
                             pregnancy_status
                      FROM tmp_hmis_follow_up),
         -- TX curr
         tx_curr_all AS (SELECT PatientId,
                                follow_up_date                                                                             AS FollowupDate,
                                encounter_id,
                                follow_up_status,
                                treatment_end_date,
                                pregnancy_status,
                                regimen,
                                left(regimen, 1)                                                   as regimen_line,
                                ROW_NUMBER() OVER (PARTITION BY PatientId ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                         FROM FollowUp
                         WHERE follow_up_status IS NOT NULL
                           AND art_start_date IS NOT NULL
                           AND follow_up_date <= REPORT_END_DATE),

         tx_curr AS (select *
                     from tx_curr_all
                     where row_num = 1
                       AND follow_up_status in ('Alive', 'Restart medication')
                       AND treatment_end_date >= REPORT_END_DATE),
         tx_curr_with_client as (select tx_curr.*,
                                        client.sex,
                                        client.date_of_birth,
                                        TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE)         as age
                                 from tx_curr
                                          left join mamba_dim_client client on tx_curr.PatientId = client.client_id),
         tx_curr_agg AS (
             SELECT
                 COUNT(*) AS Value,
                 SUM(CASE WHEN age < 15  THEN 1 ELSE 0 END) AS u15,
                 SUM(CASE WHEN age >= 15  THEN 1 ELSE 0 END) AS greater_than_15,
                 SUM(CASE WHEN age < 1  THEN 1 ELSE 0 END) AS u1,
                  SUM(CASE WHEN age < 19  THEN 1 ELSE 0 END) AS under_19,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '1' or regimen_line = '4') THEN 1 ELSE 0 END) AS u1_first_line,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '1' or regimen_line = '4') AND sex='Male' THEN 1 ELSE 0 END) AS u1_first_line_male,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '1' or regimen_line = '4') AND sex='Female' THEN 1 ELSE 0 END) AS u1_first_line_female,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '2' or regimen_line = '5') THEN 1 ELSE 0 END) AS u1_second_line,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '2' or regimen_line = '5') AND sex='Male' THEN 1 ELSE 0 END) AS u1_second_line_male,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '2' or regimen_line = '5') AND sex='Female' THEN 1 ELSE 0 END) AS u1_second_line_female,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '3' or regimen_line = '6') THEN 1 ELSE 0 END) AS u1_third_line,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '3' or regimen_line = '6') AND sex='Male' THEN 1 ELSE 0 END) AS u1_third_line_male,
                 SUM(CASE WHEN age < 1  AND (regimen_line = '3' or regimen_line = '6') AND sex='Female' THEN 1 ELSE 0 END) AS u1_third_line_female,

                 SUM(CASE WHEN age BETWEEN 1 AND 4  THEN 1 ELSE 0 END) AS u4,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '1' or regimen_line = '4') THEN 1 ELSE 0 END) AS u4_first_line,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '1' or regimen_line = '4') AND sex='Male' THEN 1 ELSE 0 END) AS u4_first_line_male,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '1' or regimen_line = '4') AND sex='Female' THEN 1 ELSE 0 END) AS u4_first_line_female,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '2' or regimen_line = '5') THEN 1 ELSE 0 END) AS u4_second_line,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '2' or regimen_line = '5') AND sex='Male' THEN 1 ELSE 0 END) AS u4_second_line_male,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '2' or regimen_line = '5') AND sex='Female' THEN 1 ELSE 0 END) AS u4_second_line_female,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '3' or regimen_line = '6') THEN 1 ELSE 0 END) AS u4_third_line,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '3' or regimen_line = '6') AND sex='Male' THEN 1 ELSE 0 END) AS u4_third_line_male,
                 SUM(CASE WHEN age BETWEEN 1 AND 4  AND (regimen_line = '3' or regimen_line = '6') AND sex='Female' THEN 1 ELSE 0 END) AS u4_third_line_female,

                 SUM(CASE WHEN age BETWEEN 5 AND 9  THEN 1 ELSE 0 END) AS u9,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '1' or regimen_line = '4') THEN 1 ELSE 0 END) AS u9_first_line,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '1' or regimen_line = '4') AND sex='Male' THEN 1 ELSE 0 END) AS u9_first_line_male,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '1' or regimen_line = '4') AND sex='Female' THEN 1 ELSE 0 END) AS u9_first_line_female,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '2' or regimen_line = '5') THEN 1 ELSE 0 END) AS u9_second_line,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '2' or regimen_line = '5') AND sex='Male' THEN 1 ELSE 0 END) AS u9_second_line_male,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '2' or regimen_line = '5') AND sex='Female' THEN 1 ELSE 0 END) AS u9_second_line_female,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '3' or regimen_line = '6') THEN 1 ELSE 0 END) AS u9_third_line,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '3' or regimen_line = '6') AND sex='Male' THEN 1 ELSE 0 END) AS u9_third_line_male,
                 SUM(CASE WHEN age BETWEEN 5 AND 9  AND (regimen_line = '3' or regimen_line = '6') AND sex='Female' THEN 1 ELSE 0 END) AS u9_third_line_female,

                 SUM(CASE WHEN age BETWEEN 10 AND 14  THEN 1 ELSE 0 END) AS u14,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '1' or regimen_line = '4') THEN 1 ELSE 0 END) AS u14_first_line,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '1' or regimen_line = '4') AND sex='Male' THEN 1 ELSE 0 END) AS u14_first_line_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '1' or regimen_line = '4') AND sex='Female' THEN 1 ELSE 0 END) AS u14_first_line_female,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '2' or regimen_line = '5') THEN 1 ELSE 0 END) AS u14_second_line,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '2' or regimen_line = '5') AND sex='Male' THEN 1 ELSE 0 END) AS u14_second_line_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '2' or regimen_line = '5') AND sex='Female' THEN 1 ELSE 0 END) AS u14_second_line_female,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '3' or regimen_line = '6') THEN 1 ELSE 0 END) AS u14_third_line,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '3' or regimen_line = '6') AND sex='Male' THEN 1 ELSE 0 END) AS u14_third_line_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14  AND (regimen_line = '3' or regimen_line = '6') AND sex='Female' THEN 1 ELSE 0 END) AS u14_third_line_female,

                 SUM(CASE WHEN age BETWEEN 15 AND 19  THEN 1 ELSE 0 END) AS u19,
                 SUM(CASE WHEN age BETWEEN 15 AND 19  AND (regimen_line = '1' or regimen_line = '4') THEN 1 ELSE 0 END) AS u19_first_line,
