    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 2','2e= AZT+3TC+LPV/r, Female - pregnant',greater_than_20_second_line_2e_female_pregnant FROM tx_curr_agg
-- 20.2.3 2e - AZT+3TC+LPVr, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 3','2e= AZT+3TC+LPV/r, Female - non-pregnant',greater_than_20_second_line_2e_female_non_pregnant FROM tx_curr_agg
-- 20.2.4 2f - AZT+3TC+ATVr, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 4','2f=AZT+3TC+ATV/r, Male',greater_than_20_second_line_2f_male FROM tx_curr_agg
-- 20.2.5 2f - AZT+3TC+ATVr, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 5','2f=AZT+3TC+ATV/r, Female - pregnant',greater_than_20_second_line_2f_female_pregnant FROM tx_curr_agg
-- 20.2.6 2f - AZT+3TC+ATVr, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 6','2f=AZT+3TC+ATV/r, Female - non-pregnant',greater_than_20_second_line_2f_female_non_pregnant FROM tx_curr_agg
-- 20.2.7 2g - TDF+3TC+LPVr, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 7','2g= TDF-3TC-LPV/r, Male',greater_than_20_second_line_2g_male FROM tx_curr_agg
-- 20.2.8 2g - TDF+3TC+LPVr, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 8','2g= TDF-3TC-LPV/r, Female - pregnant',greater_than_20_second_line_2g_female_pregnant FROM tx_curr_agg
-- 20.2.9 2g - TDF+3TC+LPVr, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 9','2g= TDF-3TC-LPV/r, Female - non-pregnant',greater_than_20_second_line_2g_female_non_pregnant FROM tx_curr_agg
-- 20.2.10 2h - TDF+3TC+ATVr, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 10','2h =TDF-3TC-ATV/r, Male',greater_than_20_second_line_2h_male FROM tx_curr_agg
-- 20.2.11 2h - TDF+3TC+ATVr, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 11','2h =TDF-3TC-ATV/r, Female - pregnant',greater_than_20_second_line_2h_female_pregnant FROM tx_curr_agg
-- 20.2.12 2h - TDF+3TC+ATVr, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 12','2h =TDF-3TC-ATV/r, Female - non-pregnant',greater_than_20_second_line_2h_female_non_pregnant FROM tx_curr_agg
-- 20.2.13 2i - ABC+3TC+LPVr, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 13','2i = ABC + 3TC + LPV/r, Male',greater_than_20_second_line_2i_male FROM tx_curr_agg
-- 20.2.14 2i - ABC+3TC+LPVr, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 14','2i = ABC + 3TC + LPV/r, Female - pregnant',greater_than_20_second_line_2i_female_pregnant FROM tx_curr_agg
-- 20.2.15 2i - ABC+3TC+LPVr, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 15','2i = ABC + 3TC + LPV/r, Female - non-pregnant',greater_than_20_second_line_2i_female_non_pregnant FROM tx_curr_agg
-- 20.2.16 2j -TDF+3TC+DTG, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 16','2j = TDF + 3TC + DTG, Male',greater_than_20_second_line_2j_male FROM tx_curr_agg
-- 20.2.17 2j -TDF+3TC+DTG, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 17','2j = TDF + 3TC + DTG, Female - pregnant',greater_than_20_second_line_2j_female_pregnant FROM tx_curr_agg
-- 20.2.18 2j -TDF+3TC+DTG, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 18','2j = TDF + 3TC + DTG, Female - non-pregnant',greater_than_20_second_line_2j_female_non_pregnant FROM tx_curr_agg
-- 20.2.19 2k - AZT+3TC+DTG, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 19','2k = AZT + 3TC + DTG, Male',greater_than_20_second_line_2k_male FROM tx_curr_agg
-- 20.2.20 2k - AZT+3TC+DTG, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 20','2k = AZT + 3TC + DTG, Female - pregnant',greater_than_20_second_line_2k_female_pregnant FROM tx_curr_agg
-- 20.2.21 2k - AZT+3TC+DTG, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 21','2k = AZT + 3TC + DTG, Female - non-pregnant',greater_than_20_second_line_2k_female_non_pregnant FROM tx_curr_agg
-- 20.2.22 2L - Other Adult 2nd line regimen, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 22','2l=other secondline, Male',greater_than_20_second_line_other_male FROM tx_curr_agg
-- 20.2.23 2L - Other Adult 2nd line regimen, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 23','2l=other secondline, Female - pregnant',greater_than_20_second_line_other_female_pregnant FROM tx_curr_agg
-- 20.2.24 2L - Other Adult 2nd line regimen, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.2. 24','2l=other secondline, Female - non-pregnant',greater_than_20_second_line_other_female_non_pregnant FROM tx_curr_agg
-- 20.3 Adults >=20 years currently on Third Line regimen by regimen type
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3','Adults >=20 years currently on Third Line regimen by regimen type',greater_than_20_third_line FROM tx_curr_agg
-- 20.3.1 3a -  DRV/r+DTG+AZT+3TC, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 1','3a=DRV/r+DTG+AZT/3TC, Male',greater_than_20_third_line_3a_male FROM tx_curr_agg
-- 20.3.2 3a -  DRV/r+DTG+AZT+3TC, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 2','3a=DRV/r+DTG+AZT/3TC, Female - pregnant',greater_than_20_third_line_3a_female_pregnant FROM tx_curr_agg
-- 20.3.3 3a -  DRV/r+DTG+AZT+3TC, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 3','3a=DRV/r+DTG+AZT/3TC, Female - non-pregnant',greater_than_20_third_line_3a_female_non_pregnant FROM tx_curr_agg
-- 20.3.4 3b - DRV/r+DTG+TDF+3TC, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 4','3b=DRV/r+DTG+TDF/3TC, Male',greater_than_20_third_line_3b_male FROM tx_curr_agg
-- 20.3.5 3b - DRV/r+DTG+TDF+3TC, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 5','3b=DRV/r+DTG+TDF/3TC, Female - pregnant',greater_than_20_third_line_3b_female_pregnant FROM tx_curr_agg
-- 20.3.6 3b - DRV/r+DTG+TDF+3TC, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 6','3b=DRV/r+DTG+TDF/3TC, Female - non-pregnant',greater_than_20_third_line_3b_female_non_pregnant FROM tx_curr_agg
-- 20.3.7 3c - DRV/r+ABC+3TC+DTG, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 7','3c=DRV/r+ABC+3TC+DTG, Male',greater_than_20_third_line_3c_male FROM tx_curr_agg
-- 20.3.8 3c - DRV/r+ABC+3TC+DTG, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 8','3c=DRV/r+ABC+3TC+DTG, Female - pregnant',greater_than_20_third_line_3c_female_pregnant FROM tx_curr_agg
-- 20.3.9 3c - DRV/r+ABC+3TC+DTG, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 9','3c=DRV/r+ABC+3TC+DTG, Female - non-pregnant',greater_than_20_third_line_3c_female_non_pregnant FROM tx_curr_agg
-- 20.3.10 3e - DRV/r+TDF+3TC+EFV, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 10','3e= DRV/r+TDF+3TC+EFV, Male',greater_than_20_third_line_3e_male FROM tx_curr_agg
-- 20.3.11 3e - DRV/r+TDF+3TC+EFV, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 11','3e= DRV/r+TDF+3TC+EFV, Female - pregnant',greater_than_20_third_line_3e_female_pregnant FROM tx_curr_agg
-- 20.3.12 3e - DRV/r+TDF+3TC+EFV, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 12','3e= DRV/r+TDF+3TC+EFV, Female - non-pregnant',greater_than_20_third_line_3e_female_non_pregnant FROM tx_curr_agg
-- 20.3.13 3f - DRV/r+AZT+3TC+EFV, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 13','3f= DRV/r+AZT+3TC +EFV, Male',greater_than_20_third_line_3f_male FROM tx_curr_agg
-- 20.3.14 3f - DRV/r+AZT+3TC+EFV, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 14','3f= DRV/r+AZT+3TC +EFV, Female - pregnant',greater_than_20_third_line_3f_female_pregnant FROM tx_curr_agg
-- 20.3.15 3f - DRV/r+AZT+3TC+EFV, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 15','3f= DRV/r+AZT+3TC +EFV, Female - non-pregnant',greater_than_20_third_line_3f_female_non_pregnant FROM tx_curr_agg
-- 20.3.16 3d - Other Adult 3rd line regimen, Male
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 16','3d=Other thirdline, Male',greater_than_20_third_line_other_male FROM tx_curr_agg
-- 20.3.17 3d - Other Adult 3rd line regimen, Female - pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 17','3d=Other thirdline, Female - pregnant',greater_than_20_third_line_other_female_pregnant FROM tx_curr_agg
-- 20.3.18 3d - Other Adult 3rd line regimen, Female - non-pregnant
    UNION ALL SELECT 'HIV_TX_CURR_REG_20.3. 18','3d=Other thirdline, Female - non-pregnant',greater_than_20_third_line_other_female_non_pregnant FROM tx_curr_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_tx_new_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_tx_new_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_tx_new_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in
                      FROM tmp_hmis_follow_up),
         tmp_latest_follow_up as (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         art_start_date,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= REPORT_END_DATE),
         latest_follow_up as (SELECT *
                              from tmp_latest_follow_up
                              where row_num = 1),
         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date                                                                     AS FollowupDate,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select latest_follow_up.client_id,
                               latest_follow_up.art_start_date,
                               latest_follow_up.FollowupDate,
                               transferred_in,
                               pregnancy_status
                        from latest_follow_up
                                 join first_follow_up on latest_follow_up.client_id = first_follow_up.client_id
                        where art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                          AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != 'Yes')
                          AND first_follow_up.follow_up_status in ('Alive', 'Restart medication')),
         tx_new as (select tx_new_tmp.client_id, sex, pregnancy_status, date_of_birth
                    from tx_new_tmp
                             join mamba_dim_client client on tx_new_tmp.client_id = client.client_id),
         tx_new_agg AS (
             SELECT
                 COUNT(*)                                                                                                                                          AS total,
                 SUM(CASE WHEN age < 1    AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS u1_male,
                 SUM(CASE WHEN age < 1    AND sex = 'Female'                                                                      THEN 1 ELSE 0 END) AS u1_female_np,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u4_male,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u4_female_np,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u9_male,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u9_female_np,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u14_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u14_female_np,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u19_male,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u19_female_p,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u19_female_np,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u24_male,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u24_female_p,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u24_female_np,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u29_male,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u29_female_p,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u29_female_np,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u34_male,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u34_female_p,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u34_female_np,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u39_male,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u39_female_p,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u39_female_np,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u44_male,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u44_female_p,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u44_female_np,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u49_male,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u49_female_p,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u49_female_np,
                 SUM(CASE WHEN age >= 50 AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS o50_male,
                 SUM(CASE WHEN age >= 50 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL)            THEN 1 ELSE 0 END) AS o50_female_np
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM tx_new) t
         )

    SELECT 'HIV_TX_NEW' AS S_NO, 'Number of adults and children with HIV infection newly started on ART' AS Activity, total AS Value FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 1',  '< 1 year, Male',                       COALESCE(u1_male,0)        FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 3',  '< 1 year, Female - non-pregnant',       COALESCE(u1_female_np,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 4',  '1 - 4 years, Male',                     COALESCE(u4_male,0)        FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 6',  '1 - 4 years, Female - non-pregnant',    COALESCE(u4_female_np,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 7',  '5 - 9 years, Male',                     COALESCE(u9_male,0)        FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 9',  '5 - 9 years, Female - non-pregnant',    COALESCE(u9_female_np,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 10', '10 - 14 years, Male',                   COALESCE(u14_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 12', '10 - 14 years, Female - non-pregnant',  COALESCE(u14_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 13', '15 - 19 years, Male',                   COALESCE(u19_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 14', '15 - 19 years, Female - pregnant',      COALESCE(u19_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 15', '15 - 19 years, Female - non-pregnant',  COALESCE(u19_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 16', '20 - 24 years, Male',                   COALESCE(u24_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 17', '20 - 24 years, Female - pregnant',      COALESCE(u24_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 18', '20 - 24 years, Female - non-pregnant',  COALESCE(u24_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 19', '25 - 29 years, Male',                   COALESCE(u29_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 20', '25 - 29 years, Female - pregnant',      COALESCE(u29_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 21', '25 - 29 years, Female - non-pregnant',  COALESCE(u29_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 22', '30 - 34 years, Male',                   COALESCE(u34_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 23', '30 - 34 years, Female - pregnant',      COALESCE(u34_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 24', '30 - 34 years, Female - non-pregnant',  COALESCE(u34_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 25', '35 - 39 years, Male',                   COALESCE(u39_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 26', '35 - 39 years, Female - pregnant',      COALESCE(u39_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 27', '35 - 39 years, Female - non-pregnant',  COALESCE(u39_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 28', '40 - 44 years, Male',                   COALESCE(u44_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 29', '40 - 44 years, Female - pregnant',      COALESCE(u44_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 30', '40 - 44 years, Female - non-pregnant',  COALESCE(u44_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 31', '45 - 49 years, Male',                   COALESCE(u49_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 32', '45 - 49 years, Female - pregnant',      COALESCE(u49_female_p,0)   FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 33', '45 - 49 years, Female - non-pregnant',  COALESCE(u49_female_np,0)  FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 34', '>= 50 years, Male',                     COALESCE(o50_male,0)       FROM tx_new_agg
    UNION ALL SELECT 'HIV_TX_NEW. 36', '>= 50 years, Female - non-pregnant',    COALESCE(o50_female_np,0)  FROM tx_new_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_art_ret_net_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_art_ret_net_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_art_ret_net_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in
                      FROM tmp_hmis_follow_up),
         tmp_latest_follow_up as (select client_id,
                                         follow_up_status,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  from FollowUp
                                  where follow_up_date <= REPORT_END_DATE),
         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
         tmp_art_start_date_before_12_months as (SELECT encounter_id,
                                                        client_id,
                                                        follow_up_date                                                                             AS FollowupDate,
                                                        follow_up_status,
                                                        art_start_date,
                                                        treatment_end_date,
                                                        TIMESTAMPDIFF(MONTH, art_start_date, follow_up_date)                                       as months_on_art,
                                                        pregnancy_status,
                                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                                 FROM FollowUp
                                                 WHERE follow_up_status IS NOT NULL
                                                   AND art_start_date IS NOT NULL
                                                   AND art_start_date >=  fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -12 MONTH))
                                                   AND art_start_date <=  fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_END_DATE, 'Y-M-D'), INTERVAL -12 MONTH))
                                                   AND follow_up_date <= REPORT_END_DATE),
         art_start_date_before_12_months as (select curr.client_id,
                                                    curr.FollowupDate,
                                                    curr.follow_up_status,
                                                    curr.pregnancy_status,
                                                    client.date_of_birth,
                                                    client.sex
                                             from tmp_art_start_date_before_12_months as curr
                                                      join mamba_dim_client client on curr.client_id = client.client_id
                                                      join latest_follow_up latest_follow_up
                                                           on curr.client_id = latest_follow_up.client_id
                                             where curr.row_num = 1
                                               and latest_follow_up.follow_up_status != 'Transferred out'),
         net_agg AS (
             SELECT
                 COUNT(*)                                                                                                                                          AS total,
                 SUM(CASE WHEN age < 1    AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS u1_male,
                 SUM(CASE WHEN age < 1    AND sex = 'Female'                                                                      THEN 1 ELSE 0 END) AS u1_female_np,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u4_male,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u4_female_np,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u9_male,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u9_female_np,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u14_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u14_female_np,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u19_male,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u19_female_p,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u19_female_np,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u24_male,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u24_female_p,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u24_female_np,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u29_male,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u29_female_p,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u29_female_np,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u34_male,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u34_female_p,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u34_female_np,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u39_male,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u39_female_p,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u39_female_np,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u44_male,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u44_female_p,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u44_female_np,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u49_male,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u49_female_p,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u49_female_np,
                 SUM(CASE WHEN age >= 50 AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS o50_male,
                 SUM(CASE WHEN age >= 50 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL)            THEN 1 ELSE 0 END) AS o50_female_np
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM art_start_date_before_12_months) t
         )

    SELECT 'HIV_ART_RET_NET' AS S_NO, 'Number of persons on ART in the original cohort including those transferred in, minus those transferred out (net current cohort)' AS Activity, total AS Value FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 1',  '< 1 year, Male',                       COALESCE(u1_male,0)        FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 3',  '< 1 year, Female - non-pregnant',       COALESCE(u1_female_np,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 4',  '1 - 4 years, Male',                     COALESCE(u4_male,0)        FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 6',  '1 - 4 years, Female - non-pregnant',    COALESCE(u4_female_np,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 7',  '5 - 9 years, Male',                     COALESCE(u9_male,0)        FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 9',  '5 - 9 years, Female - non-pregnant',    COALESCE(u9_female_np,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 10', '10 - 14 years, Male',                   COALESCE(u14_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 12', '10 - 14 years, Female - non-pregnant',  COALESCE(u14_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 13', '15 - 19 years, Male',                   COALESCE(u19_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 14', '15 - 19 years, Female - pregnant',      COALESCE(u19_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 15', '15 - 19 years, Female - non-pregnant',  COALESCE(u19_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 16', '20 - 24 years, Male',                   COALESCE(u24_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 17', '20 - 24 years, Female - pregnant',      COALESCE(u24_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 18', '20 - 24 years, Female - non-pregnant',  COALESCE(u24_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 19', '25 - 29 years, Male',                   COALESCE(u29_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 20', '25 - 29 years, Female - pregnant',      COALESCE(u29_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 21', '25 - 29 years, Female - non-pregnant',  COALESCE(u29_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 22', '30 - 34 years, Male',                   COALESCE(u34_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 23', '30 - 34 years, Female - pregnant',      COALESCE(u34_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 24', '30 - 34 years, Female - non-pregnant',  COALESCE(u34_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 25', '35 - 39 years, Male',                   COALESCE(u39_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 26', '35 - 39 years, Female - pregnant',      COALESCE(u39_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 27', '35 - 39 years, Female - non-pregnant',  COALESCE(u39_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 28', '40 - 44 years, Male',                   COALESCE(u44_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 29', '40 - 44 years, Female - pregnant',      COALESCE(u44_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 30', '40 - 44 years, Female - non-pregnant',  COALESCE(u44_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 31', '45 - 49 years, Male',                   COALESCE(u49_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 32', '45 - 49 years, Female - pregnant',      COALESCE(u49_female_p,0)   FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 33', '45 - 49 years, Female - non-pregnant',  COALESCE(u49_female_np,0)  FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 34', '>= 50 years, Male',                     COALESCE(o50_male,0)       FROM net_agg
    UNION ALL SELECT 'HIV_ART_RET_NET. 36', '>= 50 years, Female - non-pregnant',    COALESCE(o50_female_np,0)  FROM net_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_art_ret_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_art_ret_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_art_ret_query_v2(  IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in
                      FROM tmp_hmis_follow_up),

         tmp_latest_follow_up AS (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         treatment_end_date,
                                         art_start_date,
                                         pregnancy_status,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                  --  AND follow_up_date <= REPORT_END_DATE

                                  ),
         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
         tmp_art_start_date_before_12_months as (SELECT encounter_id,
                                                        client_id,
                                                        follow_up_date                                                                             AS FollowupDate,
                                                        follow_up_status,
                                                        art_start_date,
                                                        treatment_end_date,
                                                        TIMESTAMPDIFF(MONTH, art_start_date, follow_up_date)                                       as months_on_art,
                                                        pregnancy_status,
                                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                                 FROM FollowUp
                                                 WHERE follow_up_status IS NOT NULL
                                                   AND art_start_date IS NOT NULL
                                                   AND art_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -12 MONTH))
                                                   AND art_start_date <= fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_END_DATE, 'Y-M-D'), INTERVAL -12 MONTH))
                                                 --  AND follow_up_date <= REPORT_END_DATE
                                                 ),
         art_start_date_before_12_months as (select curr.client_id,
                                                    curr.FollowupDate,
                                                    curr.follow_up_status,
                                                    curr.pregnancy_status,
                                                    client.date_of_birth,
                                                    client.sex
                                             from tmp_art_start_date_before_12_months as curr
                                                      join mamba_dim_client client on curr.client_id = client.client_id
                                                      join latest_follow_up latest_follow_up
                                                           on curr.client_id = latest_follow_up.client_id
                                             where curr.row_num = 1
                                               and latest_follow_up.follow_up_status != 'Transferred out'),
         tx_curr_ret AS (select latest_follow_up.*,
                                client.sex,
                                client.date_of_birth
                         from latest_follow_up
                                  join mamba_dim_client client on latest_follow_up.client_id = client.client_id
                                  join art_start_date_before_12_months 12_months on latest_follow_up.client_id = 12_months.client_id
                         where latest_follow_up.follow_up_status in ('Alive', 'Restart medication')
                           AND latest_follow_up.treatment_end_date >= REPORT_END_DATE
                        --   AND art_start_date >= DATE_ADD(REPORT_START_DATE, INTERVAL -1 YEAR)
                        --   AND art_start_date <= DATE_ADD(REPORT_END_DATE, INTERVAL -1 YEAR)
        ),
         ret_agg AS (
             SELECT
                 COUNT(*)                                                                                                                                          AS total,
                 SUM(CASE WHEN age < 1    AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS u1_male,
                 SUM(CASE WHEN age < 1    AND sex = 'Female'                                                                      THEN 1 ELSE 0 END) AS u1_female_np,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u4_male,
                 SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u4_female_np,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u9_male,
                 SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u9_female_np,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u14_male,
                 SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female'                                                          THEN 1 ELSE 0 END) AS u14_female_np,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u19_male,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u19_female_p,
                 SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u19_female_np,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u24_male,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u24_female_p,
                 SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u24_female_np,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u29_male,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u29_female_p,
                 SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u29_female_np,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u34_male,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u34_female_p,
                 SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u34_female_np,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u39_male,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u39_female_p,
                 SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u39_female_np,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u44_male,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u44_female_p,
                 SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u44_female_np,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'                                                            THEN 1 ELSE 0 END) AS u49_male,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END) AS u49_female_p,
                 SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END) AS u49_female_np,
                 SUM(CASE WHEN age >= 50 AND sex = 'Male'                                                                        THEN 1 ELSE 0 END) AS o50_male,
                 SUM(CASE WHEN age >= 50 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL)            THEN 1 ELSE 0 END) AS o50_female_np
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM tx_curr_ret) t
         )

    SELECT 'HIV_ART_RET' AS S_NO,
           'ART retention rate (Percentage of adult and children on ART treatment after 12 month of initation of ARV therapy )' AS Activity,
           CASE
               WHEN (SELECT COUNT(*) FROM art_start_date_before_12_months) = 0 THEN '0%'
               ELSE CONCAT(CAST(ROUND(
                       (CAST(total AS REAL) * 100.0) /
                       (SELECT COUNT(*) FROM art_start_date_before_12_months)
                   , 2) AS CHAR), '%')
               END AS Value
    FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1',      'Number of adults and children who are still on treatment at 12 months after initiating ART', total        FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 1',  '< 1 year, Male',                       u1_male        FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 3',  '< 1 year, Female - non-pregnant',       u1_female_np   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 4',  '1 - 4 years, Male',                     u4_male        FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 6',  '1 - 4 years, Female - non-pregnant',    u4_female_np   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 7',  '5 - 9 years, Male',                     u9_male        FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 9',  '5 - 9 years, Female - non-pregnant',    u9_female_np   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 10', '10 - 14 years, Male',                   u14_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 12', '10 - 14 years, Female - non-pregnant',  u14_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 13', '15 - 19 years, Male',                   u19_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 14', '15 - 19 years, Female - pregnant',      u19_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 15', '15 - 19 years, Female - non-pregnant',  u19_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 16', '20 - 24 years, Male',                   u24_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 17', '20 - 24 years, Female - pregnant',      u24_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 18', '20 - 24 years, Female - non-pregnant',  u24_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 19', '25 - 29 years, Male',                   u29_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 20', '25 - 29 years, Female - pregnant',      u29_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 21', '25 - 29 years, Female - non-pregnant',  u29_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 22', '30 - 34 years, Male',                   u34_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 23', '30 - 34 years, Female - pregnant',      u34_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 24', '30 - 34 years, Female - non-pregnant',  u34_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 25', '35 - 39 years, Male',                   u39_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 26', '35 - 39 years, Female - pregnant',      u39_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 27', '35 - 39 years, Female - non-pregnant',  u39_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 28', '40 - 44 years, Male',                   u44_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 29', '40 - 44 years, Female - pregnant',      u44_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 30', '40 - 44 years, Female - non-pregnant',  u44_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 31', '45 - 49 years, Male',                   u49_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 32', '45 - 49 years, Female - pregnant',      u49_female_p   FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 33', '45 - 49 years, Female - non-pregnant',  u49_female_np  FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 34', '>= 50 years, Male',                     o50_male       FROM ret_agg
    UNION ALL SELECT 'HIV_ART_RET.1. 36', '>= 50 years, Female - non-pregnant',    o50_female_np  FROM ret_agg;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_dsd_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_dsd_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_dsd_query_v2(IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id                     AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_      AS follow_up_date,
                             art_antiretroviral_start_date AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child    breast_feeding_status,
                             pregnancy_status,
                             dsd_category,
                             assessment_date
                      FROM tmp_hmis_follow_up),
         -- TX curr
         tx_curr_all AS (SELECT PatientId,
                                follow_up_date                                                                             AS FollowupDate,
                                encounter_id,
                                follow_up_status,
                                treatment_end_date,
                                ROW_NUMBER() OVER (PARTITION BY PatientId ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                         FROM FollowUp
                         WHERE follow_up_status IS NOT NULL
                           AND art_start_date IS NOT NULL
                           AND follow_up_date <= REPORT_END_DATE
         ),

         tx_curr AS (select *
                     from tx_curr_all
                     where row_num = 1
                       AND follow_up_status in ('Alive', 'Restart medication')
                       AND treatment_end_date >= REPORT_END_DATE),
         dsd as (select tx_curr.*,
                        client.sex,
                        client.date_of_birth,
                        pregnancy_status,
                        regimen,
                        dsd_category
                 from FollowUp
                          inner join tx_curr on FollowUp.encounter_id = tx_curr.encounter_id
                          left join mamba_dim_client client on tx_curr.PatientId = client.client_id
                 where dsd_category is not null
                   and assessment_date <= REPORT_END_DATE
                 and (
                     dsd_category = '3MMD'
                         or
                     (dsd_category = 'Appointment spacing model / 6MMD'
                     AND TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE) >= 15)
                     or
                     (dsd_category = 'Fast track antiretroviral refill'
                         AND TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE) >= 15)
                     or
                     (dsd_category = 'Health extension professional led community'
                         AND TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE) >= 15)
                     or
                     (dsd_category = 'Community based group model by peer'
                         AND TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE) >= 15)
                     or
                     (dsd_category = 'DSD for adolescent')
                    or
                     (dsd_category = 'DSD for key populations')
                         or
                    (dsd_category = 'DSD for maternal child health')
                    or
                     (dsd_category = 'Other')
                    or
                     (dsd_category = 'Advanced HIV disease model')
                     )
         ),
         dsd_percentage AS (SELECT 'HIV_TX_DSD'                                                                   AS S_NO,
                                   'Proportion of PLHIV currently on differentiated service Delivery model (DSD)' AS Activity,
                                   CASE
                                       WHEN (SELECT COUNT(*) FROM tx_curr) = 0 THEN
                                           '0%'
                                       ELSE
                                           CONCAT(CAST(ROUND(
                                                   (CAST((SELECT COUNT(*) FROM dsd) AS REAL) * 100.0) /
                                                   (SELECT COUNT(*) FROM tx_curr)
                                               , 2) AS CHAR), '%')
                                       END                                                                        AS Value
                            FROM (SELECT 1) AS dummy -- Added a dummy table to ensure the CTE returns at least one row
         ),
         dsd_agg AS (
             SELECT
                 SUM(CASE WHEN dsd_category = '3MMD'                                                                                                                    THEN 1 ELSE 0 END) AS _3mmd_total,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age < 1  AND sex = 'Male'                                                                                      THEN 1 ELSE 0 END) AS _3mmd_u1_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age < 1  AND sex = 'Female'                                                                                    THEN 1 ELSE 0 END) AS _3mmd_u1_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 1  AND 4  AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u4_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 1  AND 4  AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u4_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 5  AND 9  AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u9_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 5  AND 9  AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u9_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 10 AND 14 AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u14_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 10 AND 14 AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u14_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u19_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u19_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u24_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u24_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                                                         THEN 1 ELSE 0 END) AS _3mmd_u49_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                                                       THEN 1 ELSE 0 END) AS _3mmd_u49_f,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age >= 50 AND sex = 'Male'                                                                                     THEN 1 ELSE 0 END) AS _3mmd_o50_m,
                 SUM(CASE WHEN dsd_category = '3MMD' AND age >= 50 AND sex = 'Female'                                                                                   THEN 1 ELSE 0 END) AS _3mmd_o50_f,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age >= 15                                                                          THEN 1 ELSE 0 END) AS _asm_total,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _asm_u19_m,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _asm_u19_f,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _asm_u24_m,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _asm_u24_f,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _asm_u49_m,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _asm_u49_f,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age >= 50 AND sex = 'Male'                                                         THEN 1 ELSE 0 END) AS _asm_o50_m,
                 SUM(CASE WHEN dsd_category = 'Appointment spacing model / 6MMD' AND age >= 50 AND sex = 'Female'                                                       THEN 1 ELSE 0 END) AS _asm_o50_f,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age >= 15                                                                          THEN 1 ELSE 0 END) AS _ftar_total,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _ftar_u19_m,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _ftar_u19_f,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _ftar_u24_m,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _ftar_u24_f,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                             THEN 1 ELSE 0 END) AS _ftar_u49_m,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                           THEN 1 ELSE 0 END) AS _ftar_u49_f,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age >= 50 AND sex = 'Male'                                                         THEN 1 ELSE 0 END) AS _ftar_o50_m,
                 SUM(CASE WHEN dsd_category = 'Fast track antiretroviral refill' AND age >= 50 AND sex = 'Female'                                                       THEN 1 ELSE 0 END) AS _ftar_o50_f,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age >= 15                                                               THEN 1 ELSE 0 END) AS _cag_total,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                  THEN 1 ELSE 0 END) AS _cag_u19_m,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                THEN 1 ELSE 0 END) AS _cag_u19_f,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                  THEN 1 ELSE 0 END) AS _cag_u24_m,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                THEN 1 ELSE 0 END) AS _cag_u24_f,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                  THEN 1 ELSE 0 END) AS _cag_u49_m,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                THEN 1 ELSE 0 END) AS _cag_u49_f,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age >= 50 AND sex = 'Male'                                              THEN 1 ELSE 0 END) AS _cag_o50_m,
                 SUM(CASE WHEN dsd_category = 'Health extension professional led community' AND age >= 50 AND sex = 'Female'                                            THEN 1 ELSE 0 END) AS _cag_o50_f,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age >= 15                                                                       THEN 1 ELSE 0 END) AS _pcad_total,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                          THEN 1 ELSE 0 END) AS _pcad_u19_m,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                        THEN 1 ELSE 0 END) AS _pcad_u19_f,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                          THEN 1 ELSE 0 END) AS _pcad_u24_m,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                        THEN 1 ELSE 0 END) AS _pcad_u24_f,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                          THEN 1 ELSE 0 END) AS _pcad_u49_m,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                        THEN 1 ELSE 0 END) AS _pcad_u49_f,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age >= 50 AND sex = 'Male'                                                      THEN 1 ELSE 0 END) AS _pcad_o50_m,
                 SUM(CASE WHEN dsd_category = 'Community based group model by peer' AND age >= 50 AND sex = 'Female'                                                    THEN 1 ELSE 0 END) AS _pcad_o50_f,
                 SUM(CASE WHEN dsd_category = 'DSD for adolescent'                                                                                                      THEN 1 ELSE 0 END) AS adol_total,
                 SUM(CASE WHEN dsd_category = 'DSD for key populations'                                                                                                 THEN 1 ELSE 0 END) AS kp_total,
                 SUM(CASE WHEN dsd_category = 'DSD for maternal child health'                                                                                           THEN 1 ELSE 0 END) AS mch_total,
                 SUM(CASE WHEN dsd_category = 'Other'                                                                                                                   THEN 1 ELSE 0 END) AS other_total,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model'                                                                                              THEN 1 ELSE 0 END) AS _ahdcm_total,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age < 1  AND sex = 'Male'                                                                THEN 1 ELSE 0 END) AS _ahdcm_u1_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age < 1  AND sex = 'Female'                                                              THEN 1 ELSE 0 END) AS _ahdcm_u1_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 1  AND 4  AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u4_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 1  AND 4  AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u4_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 5  AND 9  AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u9_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 5  AND 9  AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u9_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 10 AND 14 AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u14_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 10 AND 14 AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u14_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 15 AND 19 AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u19_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 15 AND 19 AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u19_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 20 AND 24 AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u24_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 20 AND 24 AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u24_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 25 AND 49 AND sex = 'Male'                                                   THEN 1 ELSE 0 END) AS _ahdcm_u49_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age BETWEEN 25 AND 49 AND sex = 'Female'                                                 THEN 1 ELSE 0 END) AS _ahdcm_u49_f,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age >= 50 AND sex = 'Male'                                                               THEN 1 ELSE 0 END) AS _ahdcm_o50_m,
                 SUM(CASE WHEN dsd_category = 'Advanced HIV disease model' AND age >= 50 AND sex = 'Female'                                                             THEN 1 ELSE 0 END) AS _ahdcm_o50_f
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM dsd) t
         )
    SELECT S_NO, Activity, Value FROM dsd_percentage
    UNION ALL SELECT 'HIV_TX_3MMD',        'Total number of clients on 3MMD', COALESCE(_3mmd_total,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 1',  '< 1 year, Male',           COALESCE(_3mmd_u1_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 2',  '< 1 year, Female',          COALESCE(_3mmd_u1_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 3',  '1 - 4 years, Male',         COALESCE(_3mmd_u4_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 4',  '1 - 4 years, Female',       COALESCE(_3mmd_u4_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 5',  '5 - 9 years, Male',         COALESCE(_3mmd_u9_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 6',  '5 - 9 years, Female',       COALESCE(_3mmd_u9_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 7',  '10 - 14 years, Male',       COALESCE(_3mmd_u14_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 8',  '10 - 14 years, Female',     COALESCE(_3mmd_u14_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 9',  '15 - 19 years, Male',       COALESCE(_3mmd_u19_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 10', '15 - 19 years, Female',     COALESCE(_3mmd_u19_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 11', '20 - 24 years, Male',       COALESCE(_3mmd_u24_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 12', '20 - 24 years, Female',     COALESCE(_3mmd_u24_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 13', '25 - 49 years, Male',       COALESCE(_3mmd_u49_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 14', '25 - 49 years, Female',     COALESCE(_3mmd_u49_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 15', '>= 50 years, Male',         COALESCE(_3mmd_o50_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_3MMD. 16', '>= 50 years, Female',       COALESCE(_3mmd_o50_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM',      'Total number of clients on ASM(6MMD)', COALESCE(_asm_total,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 1',   '15 - 19 years, Male',       COALESCE(_asm_u19_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 2',   '15 - 19 years, Female',     COALESCE(_asm_u19_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 3',   '20 - 24 years, Male',       COALESCE(_asm_u24_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 4',   '20 - 24 years, Female',     COALESCE(_asm_u24_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 5',   '25 - 49 years, Male',       COALESCE(_asm_u49_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 6',   '25 - 49 years, Female',     COALESCE(_asm_u49_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 7',   '>= 50 years, Male',         COALESCE(_asm_o50_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ASM. 8',   '>= 50 years, Female',       COALESCE(_asm_o50_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR',     'Total number of clients on FTAR',       COALESCE(_ftar_total,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 1',  '15 - 19 years, Male',       COALESCE(_ftar_u19_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 2',  '15 - 19 years, Female',     COALESCE(_ftar_u19_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 3',  '20 - 24 years, Male',       COALESCE(_ftar_u24_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 4',  '20 - 24 years, Female',     COALESCE(_ftar_u24_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 5',  '25 - 49 years, Male',       COALESCE(_ftar_u49_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 6',  '25 - 49 years, Female',     COALESCE(_ftar_u49_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 7',  '>= 50 years, Male',         COALESCE(_ftar_o50_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_FTAR. 8',  '>= 50 years, Female',       COALESCE(_ftar_o50_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG',      'Total number of clients on CAG',        COALESCE(_cag_total,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 1',   '15 - 19 years, Male',       COALESCE(_cag_u19_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 2',   '15 - 19 years, Female',     COALESCE(_cag_u19_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 3',   '20 - 24 years, Male',       COALESCE(_cag_u24_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 4',   '20 - 24 years, Female',     COALESCE(_cag_u24_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 5',   '25 - 49 years, Male',       COALESCE(_cag_u49_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 6',   '25 - 49 years, Female',     COALESCE(_cag_u49_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 7',   '>= 50 years, Male',         COALESCE(_cag_o50_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_CAG. 8',   '>= 50 years, Female',       COALESCE(_cag_o50_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD',     'Total number of clients on PCAD',      COALESCE(_pcad_total,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 1',  '15 - 19 years, Male',       COALESCE(_pcad_u19_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 2',  '15 - 19 years, Female',     COALESCE(_pcad_u19_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 3',  '20 - 24 years, Male',       COALESCE(_pcad_u24_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 4',  '20 - 24 years, Female',     COALESCE(_pcad_u24_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 5',  '25 - 49 years, Male',       COALESCE(_pcad_u49_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 6',  '25 - 49 years, Female',     COALESCE(_pcad_u49_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 7',  '>= 50 years, Male',         COALESCE(_pcad_o50_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_PCAD. 8',  '>= 50 years, Female',       COALESCE(_pcad_o50_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_Adolescent DSD.', 'Total number of clients on Adolescent DSD', COALESCE(adol_total,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_KP DSD.',  'Total number of clients on KP DSD',     COALESCE(kp_total,0)    FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_MCH DSD.', 'Total number of clients on MCH DSD',    COALESCE(mch_total,0)   FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_ other types of DSD.', 'Total number of clients on other types of DSD', COALESCE(other_total,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM',    'Total number of clients on "Advanced HIV Disease Care Model"', COALESCE(_ahdcm_total,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 1',  '< 1 year, Male',           COALESCE(_ahdcm_u1_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 2',  '< 1 year, Female',         COALESCE(_ahdcm_u1_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 3',  '1 - 4 years, Male',        COALESCE(_ahdcm_u4_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 4',  '1 - 4 years, Female',      COALESCE(_ahdcm_u4_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 5',  '5 - 9 years, Male',        COALESCE(_ahdcm_u9_m,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 6',  '5 - 9 years, Female',      COALESCE(_ahdcm_u9_f,0)  FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 7',  '10 - 14 years, Male',      COALESCE(_ahdcm_u14_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 8',  '10 - 14 years, Female',    COALESCE(_ahdcm_u14_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 9',  '15 - 19 years, Male',      COALESCE(_ahdcm_u19_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 10', '15 - 19 years, Female',    COALESCE(_ahdcm_u19_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 11', '20 - 24 years, Male',      COALESCE(_ahdcm_u24_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 12', '20 - 24 years, Female',    COALESCE(_ahdcm_u24_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 13', '25 - 49 years, Male',      COALESCE(_ahdcm_u49_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 14', '25 - 49 years, Female',    COALESCE(_ahdcm_u49_f,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 15', '>= 50 years, Male',        COALESCE(_ahdcm_o50_m,0) FROM dsd_agg
    UNION ALL SELECT 'HIV_TX_AHDCM. 16', '>= 50 years, Female',      COALESCE(_ahdcm_o50_f,0) FROM dsd_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_tb_scrn_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_tb_scrn_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_tb_scrn_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             was_the_patient_screened_for_tuberc AS tb_screened,
                             tb_screening_date,
                             tb_treatment_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             date_started_on_tuberculosis_prophy,
                             screening_test_result_tuberculosis   AS screening_result,
                             lf_lam_result
                      FROM tmp_hmis_follow_up),
         tmp_latest_follow_up as (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         tb_screening_date,
                                         art_start_date,
                                         tb_screened,
                                         screening_result,
                                         lf_lam_result,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND tb_screening_date is not null
                                 --   AND tb_screened = 'Yes'
                                    and tb_screening_date between REPORT_START_DATE AND REPORT_END_DATE
         ),
         latest_tb_screened_follow_up as (SELECT follow_up.client_id,
                                                 sex,
                                                 date_of_birth,
                                                 encounter_id,
                                                 follow_up_status,
                                                 tb_screening_date,
                                                 art_start_date,
                                                 tb_screened,
                                                 screening_result,
                                                 lf_lam_result,
                                                 mrn,
                                                 uan
                                          from tmp_latest_follow_up follow_up
                                                   inner join mamba_dim_client client on follow_up.client_id = client.client_id
                                          where row_num = 1),
         tx_new_tb_screened as (select *
                                from latest_tb_screened_follow_up
                                where art_start_date between REPORT_START_DATE AND REPORT_END_DATE
         ),
         prev_on_art_tb_screened as (select *
                                      from latest_tb_screened_follow_up
                                      where art_start_date < REPORT_START_DATE
                                     --   and follow_up_status in ('Alive', 'Restart medication')
         ),
         tb_scrn_agg AS (
             SELECT
                 COUNT(*) AS Value,
                 SUM(CASE WHEN age < 15  AND sex = 'Male'                                THEN 1 ELSE 0 END) AS u15_male,
                 SUM(CASE WHEN age < 15  AND sex = 'Female'                              THEN 1 ELSE 0 END) AS u15_female,
                 SUM(CASE WHEN age >= 15 AND sex = 'Male'                                THEN 1 ELSE 0 END) AS o15_male,
                 SUM(CASE WHEN age >= 15 AND sex = 'Female'                              THEN 1 ELSE 0 END) AS o15_female,
                 SUM(CASE WHEN screening_result = 'Positive'                             THEN 1 ELSE 0 END) AS pos_total,
                 SUM(CASE WHEN screening_result = 'Positive' AND age < 15  AND sex = 'Male'   THEN 1 ELSE 0 END) AS pos_u15_male,
                 SUM(CASE WHEN screening_result = 'Positive' AND age < 15  AND sex = 'Female' THEN 1 ELSE 0 END) AS pos_u15_female,
                 SUM(CASE WHEN screening_result = 'Positive' AND age >= 15 AND sex = 'Male'   THEN 1 ELSE 0 END) AS pos_o15_male,
                 SUM(CASE WHEN screening_result = 'Positive' AND age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END) AS pos_o15_female
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM tx_new_tb_screened) t
         ),
         prev_agg AS (
             SELECT
                 COUNT(*) AS total,
                 SUM(CASE WHEN age < 15  AND sex = 'Male'                                THEN 1 ELSE 0 END) AS u15_male,
                 SUM(CASE WHEN age < 15  AND sex = 'Female'                              THEN 1 ELSE 0 END) AS u15_female,
                 SUM(CASE WHEN age >= 15 AND sex = 'Male'                                THEN 1 ELSE 0 END) AS o15_male,
                 SUM(CASE WHEN age >= 15 AND sex = 'Female'                              THEN 1 ELSE 0 END) AS o15_female,
                 SUM(CASE WHEN screening_result = 'Positive'                             THEN 1 ELSE 0 END) AS pos_total,
                 SUM(CASE WHEN screening_result = 'Positive' AND age < 15  AND sex = 'Male'   THEN 1 ELSE 0 END) AS pos_u15_male,
                 SUM(CASE WHEN screening_result = 'Positive' AND age < 15  AND sex = 'Female' THEN 1 ELSE 0 END) AS pos_u15_female,
                 SUM(CASE WHEN screening_result = 'Positive' AND age >= 15 AND sex = 'Male'   THEN 1 ELSE 0 END) AS pos_o15_male,
                 SUM(CASE WHEN screening_result = 'Positive' AND age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END) AS pos_o15_female
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM prev_on_art_tb_screened) t
         )

    SELECT 'HIV_TB_SCRN' AS S_NO, 'Proportion of patients enrolled in HIV care who were screened for TB (FD)' AS Activity, COUNT(*) AS Value
    FROM latest_tb_screened_follow_up
    UNION ALL SELECT 'HIV_TB_SCRN.1',       'Number of NEWLY Enrolled ART clients who were screened for TB during the reporting period', Value          FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN.1. 1',    '< 15 years, Male',         COALESCE(u15_male,0)        FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN.1. 2',    '< 15 years, Female',       COALESCE(u15_female,0)      FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN.1. 3',    '>= 15 years, Male',        COALESCE(o15_male,0)        FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN.1. 4',    '>= 15 years, Female',      COALESCE(o15_female,0)      FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_P',       'Screened Positive for TB', COALESCE(pos_total,0)       FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_P. 1',    '< 15 years, Male',         COALESCE(pos_u15_male,0)    FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_P. 2',    '< 15 years, Female',       COALESCE(pos_u15_female,0)  FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_P. 3',    '>= 15 years, Male',        COALESCE(pos_o15_male,0)    FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_P. 4',    '>= 15 years, Female',      COALESCE(pos_o15_female,0)  FROM tb_scrn_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART',     'Number of PLHIVs PREVIOUSLY on ART and screened for TB', total  FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART. 1',  '< 15 years, Male',         COALESCE(u15_male,0)        FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART. 2',  '< 15 years, Female',       COALESCE(u15_female,0)      FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART. 3',  '>= 15 years, Male',        COALESCE(o15_male,0)        FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART. 4',  '>= 15 years, Female',      COALESCE(o15_female,0)      FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART_P',   'Screened Positive for TB', COALESCE(pos_total,0)       FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART_P. 1','< 15 years, Male',         COALESCE(pos_u15_male,0)    FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART_P. 2','< 15 years, Female',       COALESCE(pos_u15_female,0)  FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART_P. 3','>= 15 years, Male',        COALESCE(pos_o15_male,0)    FROM prev_agg
    UNION ALL SELECT 'HIV_TB_SCRN_ART_P. 4','>= 15 years, Female',      COALESCE(pos_o15_female,0)  FROM prev_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_tpt_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_tpt_query_v2;

~
CREATE PROCEDURE  sp_fact_hmis_hiv_tpt_query_v2(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN
WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         date_started_on_tuberculosis_prophy AS tpt_start_date,
                         date_completed_tuberculosis_prophyl AS tpt_completed_date,
                         follow_up_date_followup_            AS follow_up_date,
                         tb_prophylaxis_type,
                         art_antiretroviral_start_date       AS art_start_date,
                         follow_up_status,
                         treatment_end_date
                  FROM tmp_hmis_follow_up),
     -- TX curr
     tx_curr_all AS (SELECT client_id,
                            follow_up_date                                                                             AS FollowupDate,
                            encounter_id,
                            follow_up_status,
                            treatment_end_date,
                            tpt_start_date,
                            tpt_completed_date,
                            tb_prophylaxis_type,
                            art_start_date,
                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                     FROM FollowUp
                     WHERE follow_up_status IS NOT NULL
                       AND art_start_date IS NOT NULL
                       AND follow_up_date <= REPORT_END_DATE),

     tx_curr AS (select *
                 from tx_curr_all
                 where row_num = 1
                   AND follow_up_status in ('Alive', 'Restart medication')
                   AND treatment_end_date >= REPORT_END_DATE),
     art_tpt as (select tx_curr.encounter_id,
                        tx_curr.client_id,
                        tx_curr.FollowupDate,
                        tx_curr.tpt_start_date,
                        tx_curr.tpt_completed_date,
                        client.sex,
                        tx_curr.tb_prophylaxis_type,
                        date_of_birth
                 from tx_curr
                          left join mamba_dim_client client on tx_curr.client_id = client.client_id
                 where row_num = 1
                   and art_start_date is not null
                   and tpt_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
     art_tpt_cr as (select tx_curr.encounter_id,
                           tx_curr.client_id,
                           tx_curr.FollowupDate,
                           tpt_start_date,
                           tpt_completed_date,
                           client.sex,
                           tb_prophylaxis_type,
                           date_of_birth,
                           mrn,
                           uan
                    from tx_curr
                             left join mamba_dim_client client on tx_curr.client_id = client.client_id
                    where row_num = 1
                      and art_start_date is not null
                      and  tpt_start_date BETWEEN fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -12 MONTH)) AND
                        fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(REPORT_END_DATE, 'Y-M-D'), INTERVAL -12 MONTH))
     ),
     tpt_agg AS (
         SELECT
             COUNT(*) AS total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'                                              THEN 1 ELSE 0 END) AS _6h_total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H' AND age < 15  AND sex = 'Male'               THEN 1 ELSE 0 END) AS _6h_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H' AND age < 15  AND sex = 'Female'             THEN 1 ELSE 0 END) AS _6h_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '6H' AND age >= 15 AND sex = 'Male'               THEN 1 ELSE 0 END) AS _6h_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H' AND age >= 15 AND sex = 'Female'             THEN 1 ELSE 0 END) AS _6h_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP'                                             THEN 1 ELSE 0 END) AS _3hp_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Male'              THEN 1 ELSE 0 END) AS _3hp_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Female'            THEN 1 ELSE 0 END) AS _3hp_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Male'              THEN 1 ELSE 0 END) AS _3hp_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Female'            THEN 1 ELSE 0 END) AS _3hp_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR'                                             THEN 1 ELSE 0 END) AS _3hr_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Male'              THEN 1 ELSE 0 END) AS _3hr_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Female'            THEN 1 ELSE 0 END) AS _3hr_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Male'              THEN 1 ELSE 0 END) AS _3hr_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Female'            THEN 1 ELSE 0 END) AS _3hr_o15_female
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM art_tpt) t
     ),
     tpt_cr_agg AS (
         SELECT
             -- CR.1: started (no completion filter)
             COUNT(*) AS cr_total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'                                                                       THEN 1 ELSE 0 END) AS cr_6h_total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age < 15  AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_6h_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age < 15  AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_6h_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age >= 15 AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_6h_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age >= 15 AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_6h_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP'                                                                      THEN 1 ELSE 0 END) AS cr_3hp_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_3hp_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_3hp_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_3hp_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_3hp_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR'                                                                      THEN 1 ELSE 0 END) AS cr_3hr_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_3hr_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_3hr_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Male'                                       THEN 1 ELSE 0 END) AS cr_3hr_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Female'                                     THEN 1 ELSE 0 END) AS cr_3hr_o15_female,
             -- CR.2: completed
             SUM(CASE WHEN tpt_completed_date IS NOT NULL                                                                   THEN 1 ELSE 0 END) AS cr2_total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND tpt_completed_date IS NOT NULL                                   THEN 1 ELSE 0 END) AS cr2_6h_total,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age < 15  AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_6h_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age < 15  AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_6h_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age >= 15 AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_6h_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '6H'  AND age >= 15 AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_6h_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND tpt_completed_date IS NOT NULL                                   THEN 1 ELSE 0 END) AS cr2_3hp_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hp_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age < 15  AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hp_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hp_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HP' AND age >= 15 AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hp_o15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND tpt_completed_date IS NOT NULL                                   THEN 1 ELSE 0 END) AS cr2_3hr_total,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hr_u15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age < 15  AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hr_u15_female,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Male'   AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hr_o15_male,
             SUM(CASE WHEN tb_prophylaxis_type = '3HR' AND age >= 15 AND sex = 'Female' AND tpt_completed_date IS NOT NULL  THEN 1 ELSE 0 END) AS cr2_3hr_o15_female
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM art_tpt_cr) t
     )

SELECT 'HIV_ART_TPT.1' AS S_NO, 'Number of ART patients who started on a standard course of TB Preventive Treatment (TPT) in the reporting period' AS Activity, total AS Value FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_6H',      'Patients on 6H',         _6h_total        FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_6H. 1',   '< 15 years, Male',       _6h_u15_male     FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_6H. 2',   '< 15 years, Female',     _6h_u15_female   FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_6H. 3',   '>= 15 years, Male',      _6h_o15_male     FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_6H. 4',   '>= 15 years, Female',    _6h_o15_female   FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HP',     'Patients on 3HP',        _3hp_total       FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HP. 1',  '< 15 years, Male',       _3hp_u15_male    FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HP. 2',  '< 15 years, Female',     _3hp_u15_female  FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HP. 3',  '>= 15 years, Male',      _3hp_o15_male    FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HP. 4',  '>= 15 years, Female',    _3hp_o15_female  FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HR',     'Patients on 3HR',        _3hr_total       FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HR. 1',  '< 15 years, Male',       _3hr_u15_male    FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HR. 2',  '< 15 years, Female',     _3hr_u15_female  FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HR. 3',  '>= 15 years, Male',      _3hr_o15_male    FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_3HR. 4',  '>= 15 years, Female',    _3hr_o15_female  FROM tpt_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1',    'Number of ART patients who were initiated on any course of TPT 12 months before the reporting period', cr_total          FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.1',  'Patients on 6H 12 months prior to the reporting period',  cr_6h_total      FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.1. 1', '< 15 years, Male',    cr_6h_u15_male   FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.1. 2', '< 15 years, Female',  cr_6h_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.1. 3', '>= 15 years, Male',   cr_6h_o15_male   FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.1. 4', '>= 15 years, Female', cr_6h_o15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.2',  'Patients on 3HP 12 months prior to the reporting period', cr_3hp_total     FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.2. 1', '< 15 years, Male',    cr_3hp_u15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.2. 2', '< 15 years, Female',  cr_3hp_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.2. 3', '>= 15 years, Male',   cr_3hp_o15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.2. 4', '>= 15 years, Female', cr_3hp_o15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.3',  'Patients on 3HR 12 months prior to the reporting period', cr_3hr_total     FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.3. 1', '< 15 years, Male',    cr_3hr_u15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.3. 2', '< 15 years, Female',  cr_3hr_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.3. 3', '>= 15 years, Male',   cr_3hr_o15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.1.3. 4', '>= 15 years, Female', cr_3hr_o15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2',    'Number of ART patients who started TPT 12 months prior to the reproting period that completed a full course of therapy', cr2_total FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.1',  'Patients who completed 6H',  cr2_6h_total      FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.1. 1', '< 15 years, Male',    cr2_6h_u15_male   FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.1. 2', '< 15 years, Female',  cr2_6h_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.1. 3', '>= 15 years, Male',   cr2_6h_o15_male   FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.1. 4', '>= 15 years, Female', cr2_6h_o15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.2',  'Patients who completed 3HP', cr2_3hp_total     FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.2. 1', '< 15 years, Male',    cr2_3hp_u15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.2. 2', '< 15 years, Female',  cr2_3hp_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.2. 3', '>= 15 years, Male',   cr2_3hp_o15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.2. 4', '>= 15 years, Female', cr2_3hp_o15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.3',  'Patients who completed 3HR', cr2_3hr_total     FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.3. 1', '< 15 years, Male',    cr2_3hr_u15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.3. 2', '< 15 years, Female',  cr2_3hr_u15_female FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.3. 3', '>= 15 years, Male',   cr2_3hr_o15_male  FROM tpt_cr_agg
UNION ALL SELECT 'HIV_ART_TPT_CR.2.3. 4', '>= 15 years, Female', cr2_3hr_o15_female FROM tpt_cr_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_tx_pvls_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_tx_pvls_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_tx_pvls_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         transferred_in_check_this_for_all_t AS transferred_in,
                         date_viral_load_results_received    AS viral_load_performed_date,
                         hiv_viral_load                      AS viral_load_count,
                         viral_load_test_status,
                         viral_load_test_indication,
                         viral_load_received_                AS viral_load_performed,
                         date_of_reported_hiv_viral_load     AS viral_load_sent_date
                  FROM tmp_hmis_follow_up),
     tmp_latest_follow_up AS (SELECT client_id,
                                     follow_up_date                                                                             AS FollowupDate,
                                     encounter_id,
                                     follow_up_status,
                                     treatment_end_date,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND follow_up_date <= REPORT_END_DATE),
     latest_follow_up AS (select *
                          from tmp_latest_follow_up
                          where row_num = 1

     ),
     tmp_pvls as (select encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date,
                         viral_load_performed_date,
                         pregnancy_status,
                         viral_load_count,
                         viral_load_test_status,
                         viral_load_sent_date,
                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_performed_date DESC, encounter_id DESC) AS row_num
                  from FollowUp
                  where viral_load_performed_date is not null
                    and viral_load_performed_date >= REPORT_START_DATE
                    AND viral_load_performed_date <= REPORT_END_DATE),
     tmp_pvls_2 as (select * from tmp_pvls where row_num = 1),
     pvls as (select client.client_id,
                     pregnancy_status,
                     sex,
                     date_of_birth,
                     viral_load_count,
                     viral_load_test_status,
                     follow_up_date
              from tmp_pvls_2
                       inner join mamba_dim_client client on tmp_pvls_2.client_id = client.client_id
                       inner join latest_follow_up on tmp_pvls_2.client_id = latest_follow_up.client_id)
        ,
     pvls_agg AS (
         SELECT
             COUNT(*)                                                                                                                                                                                                AS total,
             SUM(CASE WHEN ((viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed') OR (viral_load_count BETWEEN 50 AND 1000)                              THEN 1 ELSE 0 END) AS suppressed_or_lv,
             -- Total by age/sex (HIV_TX_PVLS.1)
             SUM(CASE WHEN age < 1    AND sex = 'Male'                                                                        THEN 1 ELSE 0 END)                                                AS t_u1_male,
             SUM(CASE WHEN age < 1    AND sex = 'Female'                                                                      THEN 1 ELSE 0 END)                                                AS t_u1_female_np,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u4_male,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female'                                                          THEN 1 ELSE 0 END)                                                AS t_u4_female_np,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u9_male,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female'                                                          THEN 1 ELSE 0 END)                                                AS t_u9_female_np,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u14_male,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female'                                                          THEN 1 ELSE 0 END)                                                AS t_u14_female_np,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u19_male,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u19_female_p,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u19_female_np,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u24_male,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u24_female_p,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u24_female_np,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u29_male,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u29_female_p,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u29_female_np,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u34_male,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u34_female_p,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u34_female_np,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u39_male,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u39_female_p,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u39_female_np,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u44_male,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u44_female_p,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u44_female_np,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'                                                            THEN 1 ELSE 0 END)                                                AS t_u49_male,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             THEN 1 ELSE 0 END)                                                AS t_u49_female_p,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                               AS t_u49_female_np,
             SUM(CASE WHEN age >= 50 AND sex = 'Male'                                                                        THEN 1 ELSE 0 END)                                                AS t_o50_male,
             SUM(CASE WHEN age >= 50 AND sex = 'Female'                                                                      THEN 1 ELSE 0 END)                                                AS t_o50_female_np,
             -- Suppressed (UN) by age/sex (HIV_TX_PVLS_UN)
             SUM(CASE WHEN (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                                                                        THEN 1 ELSE 0 END) AS un_total,
             SUM(CASE WHEN age < 1    AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                                     THEN 1 ELSE 0 END) AS un_u1_male,
             SUM(CASE WHEN age < 1    AND sex = 'Female' AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                                     THEN 1 ELSE 0 END) AS un_u1_female_np,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u4_male,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female' AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u4_female_np,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u9_male,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female' AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u9_female_np,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u14_male,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female' AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u14_female_np,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u19_male,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u19_female_p,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u19_female_np,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u24_male,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u24_female_p,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u24_female_np,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u29_male,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u29_female_p,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u29_female_np,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u34_male,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u34_female_p,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u34_female_np,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u39_male,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u39_female_p,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u39_female_np,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u44_male,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u44_female_p,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u44_female_np,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                         THEN 1 ELSE 0 END) AS un_u49_male,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u49_female_p,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed' THEN 1 ELSE 0 END) AS un_u49_female_np,
             SUM(CASE WHEN age >= 50 AND sex = 'Male'   AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                                     THEN 1 ELSE 0 END) AS un_o50_male,
             SUM(CASE WHEN age >= 50 AND sex = 'Female' AND (viral_load_count < 50 OR viral_load_count IS NULL) AND viral_load_test_status = 'Suppressed'                                     THEN 1 ELSE 0 END) AS un_o50_female_np,
             -- Low viremia (LV) by age/sex (HIV_TX_PVLS_LV)
             SUM(CASE WHEN viral_load_count BETWEEN 50 AND 1000                                                                                                                                THEN 1 ELSE 0 END) AS lv_total,
             SUM(CASE WHEN age < 1    AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                             THEN 1 ELSE 0 END) AS lv_u1_male,
             SUM(CASE WHEN age < 1    AND sex = 'Female' AND viral_load_count BETWEEN 50 AND 1000                                                                                             THEN 1 ELSE 0 END) AS lv_u1_female_np,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u4_male,
             SUM(CASE WHEN age BETWEEN 1  AND 4  AND sex = 'Female' AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u4_female_np,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u9_male,
             SUM(CASE WHEN age BETWEEN 5  AND 9  AND sex = 'Female' AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u9_female_np,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u14_male,
             SUM(CASE WHEN age BETWEEN 10 AND 14 AND sex = 'Female' AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u14_female_np,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u19_male,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u19_female_p,
             SUM(CASE WHEN age BETWEEN 15 AND 19 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u19_female_np,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u24_male,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u24_female_p,
             SUM(CASE WHEN age BETWEEN 20 AND 24 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u24_female_np,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u29_male,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u29_female_p,
             SUM(CASE WHEN age BETWEEN 25 AND 29 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u29_female_np,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u34_male,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u34_female_p,
             SUM(CASE WHEN age BETWEEN 30 AND 34 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u34_female_np,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u39_male,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u39_female_p,
             SUM(CASE WHEN age BETWEEN 35 AND 39 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u39_female_np,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u44_male,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u44_female_p,
             SUM(CASE WHEN age BETWEEN 40 AND 44 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u44_female_np,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                  THEN 1 ELSE 0 END) AS lv_u49_male,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND pregnancy_status = 'Yes'                             AND viral_load_count BETWEEN 50 AND 1000                        THEN 1 ELSE 0 END) AS lv_u49_female_p,
             SUM(CASE WHEN age BETWEEN 45 AND 49 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) AND viral_load_count BETWEEN 50 AND 1000                       THEN 1 ELSE 0 END) AS lv_u49_female_np,
             SUM(CASE WHEN age >= 50 AND sex = 'Male'   AND viral_load_count BETWEEN 50 AND 1000                                                                                              THEN 1 ELSE 0 END) AS lv_o50_male,
             SUM(CASE WHEN age >= 50 AND sex = 'Female' AND viral_load_count BETWEEN 50 AND 1000                                                                                              THEN 1 ELSE 0 END) AS lv_o50_female_np
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, follow_up_date) AS age FROM pvls) t
     )

SELECT 'HIV_TX_PVLS' AS S_NO,
       'Viral load Suppression (Percentage of ART clients with a suppressed viral load among those with a viral load test at 12 month in the reporting period)' AS Activity,
       CASE WHEN COALESCE(total, 0) = 0 THEN '0%'
            ELSE CONCAT(CAST(ROUND((CAST(COALESCE(suppressed_or_lv, 0) AS REAL) * 100.0) / COALESCE(total, 0), 2) AS CHAR), '%')
            END AS Value
FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1',      'Number of adult and pediatric ART patients for whom viral load test result received in the reporting period (with in the past 12 months)', COALESCE(total, 0)          FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 1',  '< 1 year, Male',                       COALESCE(t_u1_male, 0)        FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 3',  '< 1 year, Female - non-pregnant',       COALESCE(t_u1_female_np, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 4',  '1 - 4 years, Male',                     COALESCE(t_u4_male, 0)        FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 6',  '1 - 4 years, Female - non-pregnant',    COALESCE(t_u4_female_np, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 7',  '5 - 9 years, Male',                     COALESCE(t_u9_male, 0)        FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 9',  '5 - 9 years, Female - non-pregnant',    COALESCE(t_u9_female_np, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 10', '10 - 14 years, Male',                   COALESCE(t_u14_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 12', '10 - 14 years, Female - non-pregnant',  COALESCE(t_u14_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 13', '15 - 19 years, Male',                   COALESCE(t_u19_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 14', '15 - 19 years, Female - pregnant',      COALESCE(t_u19_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 15', '15 - 19 years, Female - non-pregnant',  COALESCE(t_u19_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 16', '20 - 24 years, Male',                   COALESCE(t_u24_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 17', '20 - 24 years, Female - pregnant',      COALESCE(t_u24_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 18', '20 - 24 years, Female - non-pregnant',  COALESCE(t_u24_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 19', '25 - 29 years, Male',                   COALESCE(t_u29_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 20', '25 - 29 years, Female - pregnant',      COALESCE(t_u29_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 21', '25 - 29 years, Female - non-pregnant',  COALESCE(t_u29_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 22', '30 - 34 years, Male',                   COALESCE(t_u34_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 23', '30 - 34 years, Female - pregnant',      COALESCE(t_u34_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 24', '30 - 34 years, Female - non-pregnant',  COALESCE(t_u34_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 25', '35 - 39 years, Male',                   COALESCE(t_u39_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 26', '35 - 39 years, Female - pregnant',      COALESCE(t_u39_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 27', '35 - 39 years, Female - non-pregnant',  COALESCE(t_u39_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 28', '40 - 44 years, Male',                   COALESCE(t_u44_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 29', '40 - 44 years, Female - pregnant',      COALESCE(t_u44_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 30', '40 - 44 years, Female - non-pregnant',  COALESCE(t_u44_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 31', '45 - 49 years, Male',                   COALESCE(t_u49_male, 0)       FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 32', '45 - 49 years, Female - pregnant',      COALESCE(t_u49_female_p, 0)   FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 33', '45 - 49 years, Female - non-pregnant',  COALESCE(t_u49_female_np, 0)  FROM pvls_agg
UNION ALL SELECT 'HIV_TX_PVLS.1. 34', '>= 50 years, Male',                     COALESCE(t_o50_male, 0)       FROM pvls_agg
