-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_art_intr_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_art_intr_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_art_intr_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             antiretroviral_art_dispensed_dose_i AS dose_days,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             adherence
                      FROM tmp_hmis_follow_up),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               regimen,
                                               dose_days,
                                               adherence,
                                               next_visit_date,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         -- TX curr
         tmp_lost_follow_up AS (SELECT client_id,
                                       follow_up_date,
                                       encounter_id,
                                       follow_up_status,
                                       treatment_end_date,
                                       art_start_date,
                                       regimen,
                                       dose_days,
                                       adherence,
                                       next_visit_date,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                FROM FollowUp
                                WHERE follow_up_status IS NOT NULL
                                  AND art_start_date IS NOT NULL
                                  AND follow_up_date <= REPORT_END_DATE),
         lost_follow_up as (select *
                            from tmp_lost_follow_up
                            where row_num = 1),
         tx_curr_end AS (select *
                         from tmp_lost_follow_up
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),

         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select tmp_lost_follow_up.*
                        from tmp_lost_follow_up
                                 join first_follow_up on tmp_lost_follow_up.client_id = first_follow_up.client_id
                        where art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                          AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != 'Yes')
                          AND first_follow_up.follow_up_status in ('Alive', 'Restart medication')
                          AND tmp_lost_follow_up.row_num = 1),
         tx_new as (select *
                    from tx_new_tmp),

         on_art as (select *
                    from tx_new
                    union ALL
                    select *
                    from tx_curr_start),
         interrupted_art as (select on_art.*,
                                    client.sex,
                                    client.date_of_birth,
                                    TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE)        as Age,
                                    lost_follow_up.follow_up_status                                   as lost_follow_up_status,
                                    lost_follow_up.follow_up_date                                     as lost_follow_up_date
                             from on_art
                                      join mamba_dim_client client on on_art.client_id = client.client_id
                                      join lost_follow_up
                                           on on_art.client_id = lost_follow_up.client_id
                             where on_art.client_id not in (select client_id from tx_curr_end)),
         intr_agg AS (
             SELECT
                 COUNT(*) AS total,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3  AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead')                   THEN 1 ELSE 0 END) AS out1_total,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3  AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age < 15  AND sex = 'Male'   THEN 1 ELSE 0 END) AS out1_u15_male,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3  AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age < 15  AND sex = 'Female' THEN 1 ELSE 0 END) AS out1_u15_female,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3  AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age >= 15 AND sex = 'Male'   THEN 1 ELSE 0 END) AS out1_o15_male,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) < 3  AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END) AS out1_o15_female,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3 AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead')                   THEN 1 ELSE 0 END) AS out2_total,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3 AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age < 15  AND sex = 'Male'   THEN 1 ELSE 0 END) AS out2_u15_male,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3 AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age < 15  AND sex = 'Female' THEN 1 ELSE 0 END) AS out2_u15_female,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3 AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age >= 15 AND sex = 'Male'   THEN 1 ELSE 0 END) AS out2_o15_male,
                 SUM(CASE WHEN TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) >= 3 AND lost_follow_up_status NOT IN ('Transferred out', 'Stop all', 'Dead') AND Age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END) AS out2_o15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Transferred out'                                                                                                              THEN 1 ELSE 0 END) AS out3_total,
                 SUM(CASE WHEN lost_follow_up_status = 'Transferred out' AND Age < 15  AND sex = 'Male'                                                                              THEN 1 ELSE 0 END) AS out3_u15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Transferred out' AND Age < 15  AND sex = 'Female'                                                                            THEN 1 ELSE 0 END) AS out3_u15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Transferred out' AND Age >= 15 AND sex = 'Male'                                                                              THEN 1 ELSE 0 END) AS out3_o15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Transferred out' AND Age >= 15 AND sex = 'Female'                                                                            THEN 1 ELSE 0 END) AS out3_o15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Stop all'                                                                                                                    THEN 1 ELSE 0 END) AS out4_total,
                 SUM(CASE WHEN lost_follow_up_status = 'Stop all' AND Age < 15  AND sex = 'Male'                                                                                     THEN 1 ELSE 0 END) AS out4_u15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Stop all' AND Age < 15  AND sex = 'Female'                                                                                   THEN 1 ELSE 0 END) AS out4_u15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Stop all' AND Age >= 15 AND sex = 'Male'                                                                                     THEN 1 ELSE 0 END) AS out4_o15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Stop all' AND Age >= 15 AND sex = 'Female'                                                                                   THEN 1 ELSE 0 END) AS out4_o15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Dead'                                                                                                                        THEN 1 ELSE 0 END) AS out5_total,
                 SUM(CASE WHEN lost_follow_up_status = 'Dead' AND Age < 15  AND sex = 'Male'                                                                                         THEN 1 ELSE 0 END) AS out5_u15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Dead' AND Age < 15  AND sex = 'Female'                                                                                       THEN 1 ELSE 0 END) AS out5_u15_female,
                 SUM(CASE WHEN lost_follow_up_status = 'Dead' AND Age >= 15 AND sex = 'Male'                                                                                         THEN 1 ELSE 0 END) AS out5_o15_male,
                 SUM(CASE WHEN lost_follow_up_status = 'Dead' AND Age >= 15 AND sex = 'Female'                                                                                       THEN 1 ELSE 0 END) AS out5_o15_female
             FROM interrupted_art
         )

    SELECT 'HIV_ART_INTR' AS S_NO, 'Number of ART Clients that interrupted Treatment' AS Activity, total AS Value FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT',    'Number of ART Clients Interrupted treatment by outcome', total          FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.1',   'Lost after treatemnt < 3month',    COALESCE(out1_total,0)      FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.1. 1','< 15 years, Male',                 COALESCE(out1_u15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.1. 2','< 15 years, Female',               COALESCE(out1_u15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.1. 3','>= 15 years, Male',                COALESCE(out1_o15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.1. 4','>= 15 years, Female',              COALESCE(out1_o15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.2',   'Lost after treatement > 3month',   COALESCE(out2_total,0)      FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.2. 1','< 15 years, Male',                 COALESCE(out2_u15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.2. 2','< 15 years, Female',               COALESCE(out2_u15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.2. 3','>= 15 years, Male',                COALESCE(out2_o15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.2. 4','>= 15 years, Female',              COALESCE(out2_o15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.3',   'Transferred out',                  COALESCE(out3_total,0)      FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.3. 1','< 15 years, Male',                 COALESCE(out3_u15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.3. 2','< 15 years, Female',               COALESCE(out3_u15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.3. 3','>= 15 years, Male',                COALESCE(out3_o15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.3. 4','>= 15 years, Female',              COALESCE(out3_o15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.4',   'Refused (stopped) treatement',     COALESCE(out4_total,0)      FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.4. 1','< 15 years, Male',                 COALESCE(out4_u15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.4. 2','< 15 years, Female',               COALESCE(out4_u15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.4. 3','>= 15 years, Male',                COALESCE(out4_o15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.4. 4','>= 15 years, Female',              COALESCE(out4_o15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.5',   'Died',                             COALESCE(out5_total,0)      FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.5. 1','< 15 years, Male',                 COALESCE(out5_u15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.5. 2','< 15 years, Female',               COALESCE(out5_u15_female,0) FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.5. 3','>= 15 years, Male',                COALESCE(out5_o15_male,0)   FROM intr_agg
    UNION ALL SELECT 'HIV_ART_INTR_OUT.5. 4','>= 15 years, Female',              COALESCE(out5_o15_female,0) FROM intr_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_art_restart_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_art_restart_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_art_restart_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (SELECT encounter_id,
                             client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             antiretroviral_art_dispensed_dose_i,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             cd4_count,
                             weight_text_,
                             adherence
                      FROM tmp_hmis_follow_up),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               cd4_count,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= REPORT_START_DATE),           -- Param 1 @start_date
         latest_follow_up_start as (select *
                                    from tmp_latest_follow_up_start
                                    where row_num = 1),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= REPORT_START_DATE),                    -- Param 2 @start_date
         interrupted_at_start AS (select latest_follow_up_start.*
                                  from latest_follow_up_start
                                           left join tx_curr_start
                                                     on latest_follow_up_start.client_id = tx_curr_start.client_id
                                  where tx_curr_start.client_id is null
                                    and latest_follow_up_start.follow_up_status != 'Transferred out'),

         -- TX curr
         tmp_latest_follow_up_end AS (SELECT client_id,
                                             follow_up_date,
                                             encounter_id,
                                             follow_up_status,
                                             treatment_end_date,
                                             art_start_date,
                                             cd4_count,
                                             regimen,
                                             weight_text_,
                                             antiretroviral_art_dispensed_dose_i,
                                             adherence,
                                             next_visit_date,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE follow_up_status IS NOT NULL
                                        AND art_start_date IS NOT NULL
                                        AND follow_up_date <= REPORT_END_DATE),             -- Param 3 @end_date
         -- TX curr
         tmp_restart_follow_up_end AS (SELECT client_id,
                                              follow_up_date                                                                     as restart_follow_up_date,
                                              encounter_id,
                                              follow_up_status                                                                   as restart_status,
                                              treatment_end_date,
                                              art_start_date,
                                              cd4_count                                                                          as restart_cd4_count,
                                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                       FROM FollowUp
                                       WHERE follow_up_status IS NOT NULL
                                         AND art_start_date IS NOT NULL
                                         AND follow_up_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE), -- Param 4 and 5 @start_date, @end_date
         tx_curr_end AS (select *
                         from tmp_latest_follow_up_end
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),                      -- Param 6 @end_date
         restart_follow_up_end as (select tmp_restart_follow_up_end.*
                                   from tmp_restart_follow_up_end
                                            join tx_curr_end on tmp_restart_follow_up_end.client_id = tx_curr_end.client_id
                                   where tmp_restart_follow_up_end.row_num = 1),

         tx_rtt as (select tx_curr_end.follow_up_date                          as latest_follow_up_date,
                           tx_curr_end.encounter_id,
                           tx_curr_end.follow_up_status                        as latest_follow_up_status,
                           tx_curr_end.treatment_end_date                      as latest_follow_up_treatment_end_date,
                           tx_curr_end.art_start_date                          as latest_follow_up_art_start_date,
                           tx_curr_end.cd4_count                               as latest_follow_up_cd4_count,
                           restart_follow_up_end.restart_cd4_count,
                           restart_follow_up_end.restart_status,
                           restart_follow_up_end.restart_follow_up_date,
                           sex,
                           date_of_birth,
                           mrn,
                           uan,
                           patient_name,
                           patient_uuid,
                           tx_curr_end.regimen,
                           tx_curr_end.weight_text_,
                           tx_curr_end.antiretroviral_art_dispensed_dose_i,
                           tx_curr_end.adherence,
                           tx_curr_end.next_visit_date,
                           interrupted_at_start.follow_up_date                 as interrupted_follow_up_follow_up_date,
                           interrupted_at_start.follow_up_status               as interrupted_follow_up_follow_up_status,
                           interrupted_at_start.treatment_end_date             as interrupted_follow_up_treatment_end_date,
                           CASE
                               WHEN interrupted_at_start.follow_up_status in ('Alive', 'Restart medication')
                                   and interrupted_at_start.treatment_end_date <= REPORT_START_DATE THEN -- Param 9 @start_date
                                   TIMESTAMPDIFF(MONTH, interrupted_at_start.treatment_end_date,
                                                 restart_follow_up_end.restart_follow_up_date)
                               ELSE TIMESTAMPDIFF(MONTH, interrupted_at_start.follow_up_date,
                                                  restart_follow_up_end.restart_follow_up_date)
                               END                                             AS 'interrupted_months'
                    from interrupted_at_start
                             join tx_curr_end
                                  on interrupted_at_start.client_id = tx_curr_end.client_id
                             join mamba_dim_client client on interrupted_at_start.client_id = client.client_id
                             join restart_follow_up_end on tx_curr_end.client_id = restart_follow_up_end.client_id),
         rtt_agg AS (
             SELECT
                 COUNT(*) AS total,
                 SUM(CASE WHEN age < 15  AND sex = 'Male'   THEN 1 ELSE 0 END) AS u15_male,
                 SUM(CASE WHEN age < 15  AND sex = 'Female' THEN 1 ELSE 0 END) AS u15_female,
                 SUM(CASE WHEN age >= 15 AND sex = 'Male'   THEN 1 ELSE 0 END) AS o15_male,
                 SUM(CASE WHEN age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END) AS o15_female
             FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM tx_rtt) t
         )

    SELECT 'HIV_ART_RE_ARV' AS S_NO, 'Number of ART clients restarted ARV treatment in the reporting period' AS Activity, total AS Value FROM rtt_agg
    UNION ALL SELECT 'HIV_ART_RE_ARV. 1', '< 15 years, Male',    COALESCE(u15_male,0)   FROM rtt_agg
    UNION ALL SELECT 'HIV_ART_RE_ARV. 2', '< 15 years, Female',  COALESCE(u15_female,0) FROM rtt_agg
    UNION ALL SELECT 'HIV_ART_RE_ARV. 3', '>= 15 years, Male',   COALESCE(o15_male,0)   FROM rtt_agg
    UNION ALL SELECT 'HIV_ART_RE_ARV. 4', '>= 15 years, Female', COALESCE(o15_female,0) FROM rtt_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_hiv_fp_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_hiv_fp_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_hiv_fp_query_v2(IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         method_of_family_planning,
                         on_family_planning,
                         follow_up_date_followup_,
                         pregnancy_status,
                         follow_up_status,
                         treatment_end_date,
                         art_antiretroviral_start_date AS art_start_date
                  FROM tmp_hmis_follow_up),
     -- TX curr
     tx_curr_all AS (SELECT client_id,
                            follow_up_date_followup_                                                                             AS FollowupDate,
                            encounter_id,
                            follow_up_status,
                            treatment_end_date,
                            method_of_family_planning,
                            on_family_planning,
                            pregnancy_status,
                            follow_up_date_followup_,
                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) AS row_num
                     FROM FollowUp
                     WHERE follow_up_status IS NOT NULL
                       AND art_start_date IS NOT NULL
                       AND follow_up_date_followup_ <= REPORT_END_DATE),

     tx_curr AS (select *
                 from tx_curr_all
                 where row_num = 1
                   AND follow_up_status in ('Alive', 'Restart medication')
                   AND treatment_end_date >= REPORT_END_DATE),
     tmp_fp as (select encounter_id,
                       client_id,
                       method_of_family_planning,
                       on_family_planning,
                       pregnancy_status,
                       ROW_NUMBER() over (PARTITION BY client_id order by follow_up_date_followup_ DESC ,encounter_id DESC) as row_num
                from tx_curr
                where method_of_family_planning != 'None'
                  and method_of_family_planning != 'Sexual abstinence'),
    fp as (select tmp_fp.*,
    client.sex,
    client.date_of_birth,
    patient_name,
    mrn
from tmp_fp
    join mamba_dim_client client on tmp_fp.client_id = client.client_id
    join tx_curr on tmp_fp.client_id = tx_curr.client_id
where tmp_fp.row_num = 1),
    family_planning_wo_age as (select *
from fp
where sex = 'Female'
  and (pregnancy_status = 'No' or pregnancy_status is null)),
    family_planning as (select *
from fp
where sex = 'Female'
  and TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 15 AND 49
  and (pregnancy_status = 'No' or pregnancy_status is null)),
    fp_agg AS (
        SELECT
            COUNT(*) AS total,
            SUM(CASE WHEN age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS u19,
            SUM(CASE WHEN age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS u24,
            SUM(CASE WHEN age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS u29,
            SUM(CASE WHEN age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS u49,
            SUM(CASE WHEN method_of_family_planning = 'Oral contraception'                                                                                        THEN 1 ELSE 0 END) AS oral,
            SUM(CASE WHEN method_of_family_planning = 'Injectable contraceptives'                                                                                 THEN 1 ELSE 0 END) AS injectable,
            SUM(CASE WHEN method_of_family_planning = 'Implantable contraceptive (unspecified type)'                                                              THEN 1 ELSE 0 END) AS implant,
            SUM(CASE WHEN method_of_family_planning = 'Intrauterine device'                                                                                       THEN 1 ELSE 0 END) AS iucd,
            SUM(CASE WHEN method_of_family_planning NOT IN ('Oral contraception','Injectable contraceptives','Implantable contraceptive (unspecified type)','Intrauterine device') THEN 1 ELSE 0 END) AS other
        FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM family_planning) t
    )
SELECT 'HIV_ART_FP_AGE' AS S_NO, 'Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by age' AS Activity, total AS Value FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_AGE. 1', '10 - 14 years', COUNT(*) FROM family_planning_wo_age WHERE TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 10 AND 14
UNION ALL SELECT 'HIV_ART_FP_AGE. 2', '15 - 19 years', COALESCE(u19,0)   FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_AGE. 3', '20 - 24 years', COALESCE(u24,0)   FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_AGE. 4', '25 - 29 years', COALESCE(u29,0)   FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_AGE. 5', '30 - 49 years', COALESCE(u49,0)   FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET',    'Number of non-pregnant women living with HIV on ART aged 15-49 reporting the use of any method of modern family planning by method', total FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET. 1', 'Oral contraceptives', COALESCE(oral,0)       FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET. 2', 'Injectables',         COALESCE(injectable,0)  FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET. 3', 'Implants',            COALESCE(implant,0)     FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET. 4', 'IUCD',                COALESCE(iucd,0)        FROM fp_agg
UNION ALL SELECT 'HIV_ART_FP_MET. 5', 'Others',              COALESCE(other,0)       FROM fp_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_cxca_scrn_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_cxca_scrn_query_v2;

~
CREATE PROCEDURE  sp_fact_hmis_cxca_scrn_query_v2(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN
WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         cervical_cancer_screening_status          AS cx_ca_screening_status,
                         cervical_cancer_screening_method_strategy AS screening_type,
                         via_screening_result,
                         hpv_dna_screening_result,
                         follow_up_date_followup_                  AS follow_up_date,
                         date_hpv_test_was_done                    AS hpv_date,
                         date_visual_inspection_of_the_cervi       AS via_date,
                         hpv_dna_result_received_date              AS hpv_received_date,
                         is_the_client_screened_in_this_facility
                  FROM tmp_hmis_follow_up),
     tmp_cx_screened as (select *,
                                ROW_NUMBER() over (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) as row_num
                         from FollowUp
                         where cx_ca_screening_status = 'Cervical cancer screening performed'),
     cx_screened as (select tmp_cx_screened.*,
                            client.date_of_birth,
                            client.sex
                     from tmp_cx_screened
                              left join mamba_dim_client client on tmp_cx_screened.client_id=client.client_id
                     where row_num = 1
                       and (hpv_received_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE or
                            (via_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                               --  AND screening_type != 'Human Papillomavirus test'
                                )
                         )
                     and is_the_client_screened_in_this_facility = 'Yes'
                     ),
     scrn_agg AS (
         SELECT
             COUNT(*) AS Value,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)'  THEN 1 ELSE 0 END) AS via_total,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test'                               THEN 1 ELSE 0 END) AS hpv_total,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                                                               THEN 1 ELSE 0 END) AS via_normal_total,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                              AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS via_normal_u19,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                              AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS via_normal_u24,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                              AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS via_normal_u29,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                              AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS via_normal_u49,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'VIA negative'                                                              AND age >= 50              THEN 1 ELSE 0 END) AS via_normal_o50,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula')                  THEN 1 ELSE 0 END) AS via_precancer_total,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula') AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS via_precancer_u19,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula') AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS via_precancer_u24,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula') AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS via_precancer_u29,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula') AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS via_precancer_u49,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result IN ('VIA positive: non-eligible for cryo/thermo-coagula','VIA positive: eligible for cryo/thermo-coagula') AND age >= 50              THEN 1 ELSE 0 END) AS via_precancer_o50,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                                                               THEN 1 ELSE 0 END) AS via_cancer_total,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                 AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS via_cancer_u19,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                 AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS via_cancer_u24,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                 AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS via_cancer_u29,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                 AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS via_cancer_u49,
             SUM(CASE WHEN screening_type = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' AND via_screening_result = 'suspected cervical cancer'                                                 AND age >= 50              THEN 1 ELSE 0 END) AS via_cancer_o50,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive'                             THEN 1 ELSE 0 END) AS hpv_pos_total,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive' AND age BETWEEN 15 AND 19  THEN 1 ELSE 0 END) AS hpv_pos_u19,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive' AND age BETWEEN 20 AND 24  THEN 1 ELSE 0 END) AS hpv_pos_u24,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive' AND age BETWEEN 25 AND 29  THEN 1 ELSE 0 END) AS hpv_pos_u29,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive' AND age BETWEEN 30 AND 49  THEN 1 ELSE 0 END) AS hpv_pos_u49,
             SUM(CASE WHEN screening_type = 'Human Papillomavirus test' AND hpv_dna_screening_result = 'Positive' AND age >= 50               THEN 1 ELSE 0 END) AS hpv_pos_o50
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM cx_screened) t
     )
SELECT 'HIV_CXCA_SCRN.1'    AS S_NO, 'Cervical Cancer screening by type of test'   AS Activity, Value              FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.1. 1',   'Screened by VIA',                                     COALESCE(via_total,0)          FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.1. 2',   'Screened by HPV DNA',                                 COALESCE(hpv_total,0)          FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2',      'VIA Screening Result',                                 COALESCE(via_total,0)          FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1',    'Normal cervix:',                                       COALESCE(via_normal_total,0)   FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1. 1', '15 - 19 years',                                       COALESCE(via_normal_u19,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1. 2', '20 - 24 years',                                       COALESCE(via_normal_u24,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1. 3', '25 - 29 years',                                       COALESCE(via_normal_u29,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1. 4', '30 - 49 years',                                       COALESCE(via_normal_u49,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.1. 5', '>= 50 years',                                         COALESCE(via_normal_o50,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3',    'Precancerous Lesion:',                                 COALESCE(via_precancer_total,0) FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3. 1', '15 - 19 years',                                       COALESCE(via_precancer_u19,0)  FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3. 2', '20 - 24 years',                                       COALESCE(via_precancer_u24,0)  FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3. 3', '25 - 29 years',                                       COALESCE(via_precancer_u29,0)  FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3. 4', '30 - 49 years',                                       COALESCE(via_precancer_u49,0)  FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.3. 5', '>= 50 years',                                         COALESCE(via_precancer_o50,0)  FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4',    'Suspecious cancerous Lesion:',                         COALESCE(via_cancer_total,0)   FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4. 1', '15 - 19 years',                                       COALESCE(via_cancer_u19,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4. 2', '20 - 24 years',                                       COALESCE(via_cancer_u24,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4. 3', '25 - 29 years',                                       COALESCE(via_cancer_u29,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4. 4', '30 - 49 years',                                       COALESCE(via_cancer_u49,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.4. 5', '>= 50 years',                                         COALESCE(via_cancer_o50,0)     FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5',    'HPV DNA test positive:',                               COALESCE(hpv_pos_total,0)      FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5. 1', '15 - 19 years',                                       COALESCE(hpv_pos_u19,0)        FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5. 2', '20 - 24 years',                                       COALESCE(hpv_pos_u24,0)        FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5. 3', '25 - 29 years',                                       COALESCE(hpv_pos_u29,0)        FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5. 4', '30 - 49 years',                                       COALESCE(hpv_pos_u49,0)        FROM scrn_agg
UNION ALL SELECT 'HIV_CXCA_SCRN.2.5. 5', '>= 50 years',                                         COALESCE(hpv_pos_o50,0)        FROM scrn_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_cxca_rx_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_cxca_rx_query_v2;

~
CREATE PROCEDURE  sp_fact_hmis_cxca_rx_query_v2(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN
WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         cervical_cancer_screening_status               AS cx_ca_screening_status,
                         cervical_cancer_screening_method_strategy      AS screening_type,
                         via_screening_result,
                         hpv_dna_screening_result,
                         follow_up_date_followup_                       AS follow_up_date,
                         date_hpv_test_was_done                         AS hpv_date,
                         date_visual_inspection_of_the_cervi            AS via_date,
                         treatment_of_precancerous_lesions_of_the_cervix AS treatment_of_precancerous_lesions,
                         treatment_start_date
                  FROM tmp_hmis_follow_up),
     tmp_cx_rx as (select *,
                          ROW_NUMBER() over (PARTITION BY client_id ORDER BY treatment_start_date DESC, encounter_id DESC) as row_num
                   from FollowUp
                   where treatment_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),

     cx_rx as (select tmp_cx_rx.*,
                      client.date_of_birth,
                      client.sex
               from tmp_cx_rx
                        left join mamba_dim_client client on tmp_cx_rx.client_id = client.client_id
               where row_num = 1),
     rx_agg AS (
         SELECT
             COUNT(*) AS Value,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'                            THEN 1 ELSE 0 END) AS cryo_total,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'          AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS cryo_u19,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'          AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS cryo_u24,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'          AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS cryo_u29,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'          AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS cryo_u49,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Cryosurgery of lesion of cervix'          AND age >= 50              THEN 1 ELSE 0 END) AS cryo_o50,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix'                 THEN 1 ELSE 0 END) AS leep_total,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix' AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS leep_u19,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix' AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS leep_u24,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix' AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS leep_u29,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix' AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS leep_u49,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Loop electrosurgical excision procedure of cervix' AND age >= 50              THEN 1 ELSE 0 END) AS leep_o50,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'                                     THEN 1 ELSE 0 END) AS thermo_total,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'            AND age BETWEEN 15 AND 19 THEN 1 ELSE 0 END) AS thermo_u19,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'            AND age BETWEEN 20 AND 24 THEN 1 ELSE 0 END) AS thermo_u24,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'            AND age BETWEEN 25 AND 29 THEN 1 ELSE 0 END) AS thermo_u29,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'            AND age BETWEEN 30 AND 49 THEN 1 ELSE 0 END) AS thermo_u49,
             SUM(CASE WHEN treatment_of_precancerous_lesions = 'Thermocauterization of cervix'            AND age >= 50              THEN 1 ELSE 0 END) AS thermo_o50
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM cx_rx) t
     )
SELECT 'HIV_CXCA_RX'  AS S_NO, 'Treatment of precancerous cervical lesion'        AS Activity, Value        FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1',   'Treatment with Cryotherapy',                  COALESCE(cryo_total,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1. 1','15 - 19 years',                               COALESCE(cryo_u19,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1. 2','20 - 24 years',                               COALESCE(cryo_u24,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1. 3','25 - 29 years',                               COALESCE(cryo_u29,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1. 4','30 - 49 years',                               COALESCE(cryo_u49,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.1. 5','>= 50 years',                                 COALESCE(cryo_o50,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2',   'Treatment with LEEP',                          COALESCE(leep_total,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2. 1','15 - 19 years',                               COALESCE(leep_u19,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2. 2','20 - 24 years',                               COALESCE(leep_u24,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2. 3','25 - 29 years',                               COALESCE(leep_u29,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2. 4','30 - 49 years',                               COALESCE(leep_u49,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.2. 5','>= 50 years',                                 COALESCE(leep_o50,0)     FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3',   'Treatment with Thermal Ablation/Thermocoagulation', COALESCE(thermo_total,0) FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3. 1','15 - 19 years',                               COALESCE(thermo_u19,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3. 2','20 - 24 years',                               COALESCE(thermo_u24,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3. 3','25 - 29 years',                               COALESCE(thermo_u29,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3. 4','30 - 49 years',                               COALESCE(thermo_u49,0)   FROM rx_agg
UNION ALL SELECT 'HIV_CXCA_RX.3. 5','>= 50 years',                                 COALESCE(thermo_o50,0)   FROM rx_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_phliv_tsp_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_phliv_tsp_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_phliv_tsp_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         nutritional_supplements_provided,
                         eats_nutritious_foods,
                         nutritional_screening_result,
                         follow_up_date_followup_,
                         art_antiretroviral_start_date                  AS art_start_date,
                         pregnancy_status,
                         follow_up_status,
                         treatment_end_date,
                         COALESCE(nutritional_status_of_adult,
                                  nutritional_status_of_older_child_a,
                                  weight_for_age_status)                AS nutritional_screening_status
                  FROM tmp_hmis_follow_up),
     tx_curr_all AS (SELECT client_id,
                            follow_up_date_followup_ AS FollowupDate,
                            encounter_id,
                            follow_up_status,
                            treatment_end_date,
                            ROW_NUMBER()                OVER (PARTITION BY client_id ORDER BY follow_up_date_followup_ DESC, encounter_id DESC) AS row_num
                     FROM FollowUp
                     WHERE follow_up_status IS NOT NULL
                       AND art_start_date IS NOT NULL
                       AND follow_up_date_followup_ <= REPORT_END_DATE),
     tx_curr AS (select *
                 from tx_curr_all
                 where row_num = 1
                   AND follow_up_status in ('Alive', 'Restart medication')
                   AND treatment_end_date >= REPORT_END_DATE),
     tmp_screened_for_nutrition as (select encounter_id,
                                           client_id,
                                           nutritional_supplements_provided,
                                           eats_nutritious_foods,
                                           nutritional_screening_result,
                                           follow_up_date_followup_,
                                           pregnancy_status,
                                           nutritional_screening_status,
                                           ROW_NUMBER() over (PARTITION BY client_id order by follow_up_date_followup_ DESC ,encounter_id DESC ) as row_num
                                    from FollowUp
                                    where nutritional_screening_result is not null
                                      and follow_up_date_followup_ BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                                      and art_start_date is not null),
     screened_for_nutrition as (select tmp_screened_for_nutrition.*,
                                       client.date_of_birth,
                                       client.sex
                                from tmp_screened_for_nutrition
                                         join tx_curr on tmp_screened_for_nutrition.client_id = tx_curr.client_id
                                         join mamba_dim_client client
                                              on tmp_screened_for_nutrition.client_id = client.client_id
                                where tmp_screened_for_nutrition.row_num = 1),
     screened_agg AS (
         SELECT COUNT(*)                                                                                                                                                                             AS total,
                SUM(CASE WHEN age < 15 AND sex = 'Male'   THEN 1 ELSE 0 END)                                                                                                                        AS u15_male,
                SUM(CASE WHEN age < 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                        AS u15_female,
                SUM(CASE WHEN age >= 15 AND sex = 'Male'  THEN 1 ELSE 0 END)                                                                                                                        AS o15_male,
                SUM(CASE WHEN age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                       AS o15_female,
                -- undernourished totals
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished' THEN 1 ELSE 0 END)                                                                                                     AS und_total,
                -- MAM
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                          THEN 1 ELSE 0 END)                                                                                                                                                         AS mam_total,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age < 15 AND sex = 'Male'   THEN 1 ELSE 0 END)                                                                                                                       AS mam_u15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                       AS mam_u15_female,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age >= 15 AND sex = 'Male'  THEN 1 ELSE 0 END)                                                                                                                       AS mam_o15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                      AS mam_o15_female,
                -- SAM
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                          THEN 1 ELSE 0 END)                                                                                                                                                         AS sam_total,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age < 15 AND sex = 'Male'   THEN 1 ELSE 0 END)                                                                                                                       AS sam_u15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                       AS sam_u15_female,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age >= 15 AND sex = 'Male'  THEN 1 ELSE 0 END)                                                                                                                       AS sam_o15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' THEN 1 ELSE 0 END)                                                                                                                      AS sam_o15_female,
                -- supplementary food total
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                          THEN 1 ELSE 0 END)                                                                                                                                                         AS sup_total,
                -- MAM + food
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                          THEN 1 ELSE 0 END)                                                                                                                                                         AS sup_mam_total,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age < 15 AND sex = 'Male'   THEN 1 ELSE 0 END)                                                                                                                       AS sup_mam_u15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' AND pregnancy_status = 'Yes' THEN 1 ELSE 0 END)                                                                                          AS sup_mam_u15_female_p,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                                             AS sup_mam_u15_female_np,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age >= 15 AND sex = 'Male'  THEN 1 ELSE 0 END)                                                                                                                       AS sup_mam_o15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' AND pregnancy_status = 'Yes' THEN 1 ELSE 0 END)                                                                                         AS sup_mam_o15_female_p,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)',
                                                                'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                                            AS sup_mam_o15_female_np,
                -- SAM + food
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                          THEN 1 ELSE 0 END)                                                                                                                                                         AS sup_sam_total,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age < 15 AND sex = 'Male'   THEN 1 ELSE 0 END)                                                                                                                       AS sup_sam_u15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' AND pregnancy_status = 'Yes' THEN 1 ELSE 0 END)                                                                                          AS sup_sam_u15_female_p,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age < 15 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                                             AS sup_sam_u15_female_np,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age >= 15 AND sex = 'Male'  THEN 1 ELSE 0 END)                                                                                                                       AS sup_sam_o15_male,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' AND pregnancy_status = 'Yes' THEN 1 ELSE 0 END)                                                                                         AS sup_sam_o15_female_p,
                SUM(CASE WHEN nutritional_screening_result = 'Undernourished'
                           AND (eats_nutritious_foods = 'Yes' OR nutritional_supplements_provided IS NOT NULL)
                           AND nutritional_screening_status IN ('Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)')
                           AND age >= 15 AND sex = 'Female' AND (pregnancy_status = 'No' OR pregnancy_status IS NULL) THEN 1 ELSE 0 END)                                                            AS sup_sam_o15_female_np
         FROM (SELECT *, TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) AS age FROM screened_for_nutrition) t
     ),
     percentage_calc AS (SELECT 'HIV_PLHIV_TSP'                                                                                                         AS S_NO,
                                'Proportion of clinically undernourished People Living with HIV (PLHIV) who received therapeutic or supplementary food' AS Activity,
                                CASE
                                    WHEN (SELECT und_total FROM screened_agg) = 0 THEN
                                        '0%'
                                    ELSE
                                        CONCAT(CAST(ROUND(
                                                (CAST((SELECT sup_total FROM screened_agg) AS REAL) * 100.0) /
                                                (SELECT und_total FROM screened_agg)
                                            , 2) AS CHAR), '%')
                                    END                                                                                                                 AS Value
FROM (SELECT 1) AS dummy
    )

SELECT S_NO, Activity, Value FROM percentage_calc
UNION ALL SELECT 'HIV_PLHIV_TSP.1',      'Number of PLHIV who were assessed/screened for malnutrition',                                                                       COALESCE(total,0)              FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_TSP.1. 1',   '< 15 years, Male',                                                                                                                  COALESCE(u15_male,0)           FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_TSP.1. 2',   '< 15 years, Female',                                                                                                                COALESCE(u15_female,0)         FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_TSP.1. 3',   '>= 15 years, Male',                                                                                                                 COALESCE(o15_male,0)           FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_TSP.1. 4',   '>= 15 years, Female',                                                                                                               COALESCE(o15_female,0)         FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT',         'Number of PLHIV that were nutritionally assessed and found to be clinically undernourished (disaggregated by Age, Sex and Pregnancy)', COALESCE(und_total,0)       FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_MAM',    'Total MAM',                                                                                                                          COALESCE(mam_total,0)          FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_MAM. 1', '< 15 years, Male',                                                                                                                  COALESCE(mam_u15_male,0)       FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_MAM. 2', '< 15 years, Female',                                                                                                                COALESCE(mam_u15_female,0)     FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_MAM. 3', '>= 15 years, Male',                                                                                                                 COALESCE(mam_o15_male,0)       FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_MAM. 4', '>= 15 years, Female',                                                                                                               COALESCE(mam_o15_female,0)     FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_SAM',    'Total SAM',                                                                                                                          COALESCE(sam_total,0)          FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_SAM. 1', '< 15 years, Male',                                                                                                                  COALESCE(sam_u15_male,0)       FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_SAM. 2', '< 15 years, Female',                                                                                                                COALESCE(sam_u15_female,0)     FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_SAM. 3', '>= 15 years, Male',                                                                                                                 COALESCE(sam_o15_male,0)       FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_NUT_SAM. 4', '>= 15 years, Female',                                                                                                               COALESCE(sam_o15_female,0)     FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP',         'Clinically undernourished PLHIV who received therapeutic or supplementary food (disaggregated by age, sex and pregnancy status)',   COALESCE(sup_total,0)          FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1',       'Total MAM who received therapeutic or supplementary food',                                                                          COALESCE(sup_mam_total,0)      FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 1',   '< 15 years, Male',                                                                                                                  COALESCE(sup_mam_u15_male,0)   FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 2',   '< 15 years, Female - pregnant',                                                                                                     COALESCE(sup_mam_u15_female_p,0)  FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 3',   '< 15 years, Female - non-pregnant',                                                                                                 COALESCE(sup_mam_u15_female_np,0) FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 4',   '>= 15 years, Male',                                                                                                                 COALESCE(sup_mam_o15_male,0)   FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 5',   '>= 15 years, Female - pregnant',                                                                                                    COALESCE(sup_mam_o15_female_p,0)  FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.1. 6',   '>= 15 years, Female - non-pregnant',                                                                                                COALESCE(sup_mam_o15_female_np,0) FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2',       'Total SAM who received therapeutic or supplementary food',                                                                          COALESCE(sup_sam_total,0)      FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 1',   '< 15 years, Male',                                                                                                                  COALESCE(sup_sam_u15_male,0)   FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 2',   '< 15 years, Female - pregnant',                                                                                                     COALESCE(sup_sam_u15_female_p,0)  FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 3',   '< 15 years, Female - non-pregnant',                                                                                                 COALESCE(sup_sam_u15_female_np,0) FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 4',   '>= 15 years, Male',                                                                                                                 COALESCE(sup_sam_o15_male,0)   FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 5',   '>= 15 years, Female - pregnant',                                                                                                    COALESCE(sup_sam_o15_female_p,0)  FROM screened_agg
UNION ALL SELECT 'HIV_PLHIV_SUP.2. 6',   '>= 15 years, Female - non-pregnant',                                                                                                COALESCE(sup_sam_o15_female_np,0) FROM screened_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_hmis_tb_lb_lf_lam_query_v2
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_hmis_tb_lb_lf_lam_query_v2;

~
CREATE PROCEDURE sp_fact_hmis_tb_lb_lf_lam_query_v2(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
WITH FollowUp AS (SELECT encounter_id,
                         client_id,
                         follow_up_status,
                         follow_up_date_followup_            AS follow_up_date,
                         art_antiretroviral_start_date       AS art_start_date,
                         treatment_end_date,
                         next_visit_date,
                         regimen,
                         currently_breastfeeding_child          breast_feeding_status,
                         pregnancy_status,
                         was_the_patient_screened_for_tuberc AS tb_screened,
                         tb_screening_date,
                         tb_treatment_status,
                         transferred_in_check_this_for_all_t AS transferred_in,
                         date_started_on_tuberculosis_prophy,
                         screening_test_result_tuberculosis   AS screening_result,
                         lf_lam_result
                  FROM tmp_hmis_follow_up),
     tmp_latest_follow_up as (SELECT client_id,
                                     follow_up_date                                                                             AS FollowupDate,
                                     encounter_id,
                                     follow_up_status,
                                     tb_screening_date,
                                     art_start_date,
                                     tb_screened,
                                     screening_result,
                                     lf_lam_result,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND tb_screened = 'Yes'
                                AND follow_up_date <= REPORT_END_DATE),
     latest_tb_screened_follow_up as (SELECT follow_up.client_id,
                                             sex,
                                             date_of_birth,
                                             encounter_id,
                                             follow_up_status,
                                             tb_screening_date,
                                             art_start_date,
                                             tb_screened,
                                             screening_result,
                                             lf_lam_result
                                      from tmp_latest_follow_up follow_up
                                               inner join mamba_dim_client client on follow_up.client_id = client.client_id
                                      where row_num = 1),
     lf_lam as (select *
                from latest_tb_screened_follow_up
                where tb_screening_date between REPORT_START_DATE AND REPORT_END_DATE
                  and follow_up_status in ('Alive', 'Restart medication') and art_start_date is not null
                  and lf_lam_result is not null),
     lf_lam_agg AS (
         SELECT COUNT(*)                                                                    AS total,
                SUM(CASE WHEN lf_lam_result = 'Positive'       THEN 1 ELSE 0 END)          AS positive,
                SUM(CASE WHEN lf_lam_result = 'Negative result' THEN 1 ELSE 0 END)         AS negative
         FROM lf_lam
     )

SELECT 'TB_LB_LF-LAM'                                                                              AS S_NO,
       'Total Number of tests performed using Lateral Flow Urine Lipoarabinomannan (LF-LAM) assay' as Activity,
       total                                                                                        as Value
FROM lf_lam_agg
UNION ALL SELECT 'TB_LB_LF-LAM. 1', 'Positive', COALESCE(positive,0) FROM lf_lam_agg
UNION ALL SELECT 'TB_LB_LF-LAM. 2', 'Negative', COALESCE(negative,0) FROM lf_lam_agg;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_child_cohort_analysis_summary_query
--

DELIMITER //
DROP PROCEDURE IF EXISTS sp_fact_line_list_child_cohort_analysis_summary_query;

~
CREATE PROCEDURE sp_fact_line_list_child_cohort_analysis_summary_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE
    DATE)
BEGIN

    WITH IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 13
                          UNION ALL
                          SELECT 19
                          UNION ALL
                          SELECT 25
                          UNION ALL
                          SELECT 31),

         HIEInCohort AS (SELECT hei_enrollment.encounter_id                                                                                  as hei_encounter_id,
                                maternal_enrollment.encounter_id                                                                             as mother_encounter_id,
                                linked_mother.identifier                                                                                     as mother_mrn,
                                hei_enrollment.client_id                                                                                     as hei_client_id,
                                maternal_enrollment.client_id                                                                                as mother_client_id,

                                CASE
                                    WHEN maternal_enrollment.date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                                        THEN maternal_enrollment.date_of_enrollment_or_booking
                                    ELSE hei_enrollment.date_enrolled_in_care
                                    END                                                                                                      AS effective_enrollment_date,

                                hei_enrollment.date_enrolled_in_care                                                                         as hei_enrollment_date,


                                ROW_NUMBER() OVER (PARTITION BY hei_enrollment.client_id ORDER BY hei_enrollment.date_enrolled_in_care DESC) AS row_num

                         FROM mamba_flat_encounter_hei_enrollment as hei_enrollment
                                  LEFT JOIN mamba_dim_patient_identifier as linked_mother
                                            on hei_enrollment.contact_mrn = linked_mother.identifier
                                                and linked_mother.identifier_type = 5
                                  LEFT JOIN mamba_flat_encounter_pmtct_enrollment as maternal_enrollment
                                            on maternal_enrollment.client_id = linked_mother.patient_id
                                  LEFT JOIN mamba_flat_encounter_hei_final_outcome as final_outcome
                                            on hei_enrollment.client_id = final_outcome.client_id
                         WHERE (maternal_enrollment.date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE)
                            OR (hei_enrollment.date_enrolled_in_care BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                             AND (maternal_enrollment.date_of_enrollment_or_booking IS NULL
                                 OR
                                  maternal_enrollment.date_of_enrollment_or_booking NOT BETWEEN REPORT_START_DATE AND REPORT_END_DATE))),

         HIEInCohortFiltered AS (SELECT * FROM HIEInCohort WHERE row_num = 1),

         HeiIntervals AS (SELECT h.hei_client_id,
                                 h.mother_client_id,
                                 h.effective_enrollment_date,
                                 h.hei_enrollment_date,
                                 i.interval_month,
                                 CASE
                                     WHEN i.interval_month = 0 THEN h.hei_enrollment_date
                                     ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                             fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                             INTERVAL i.interval_month MONTH))
                                     END AS interval_end_date,
                                 CASE
                                     WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                     ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                             fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                             INTERVAL i.interval_month MONTH)))
                                                       OVER (PARTITION BY h.hei_client_id ORDER BY i.interval_month),
                                                   REPORT_START_DATE)
                                     END AS interval_start_date
                          FROM HIEInCohortFiltered h
                                   CROSS JOIN IntervalsDef i),

         CohortHeaderDates AS (SELECT interval_month,
                                      CASE
                                          WHEN interval_month = 0 THEN REPORT_START_DATE
                                          ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                  fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                  INTERVAL interval_month MONTH))
                                          END AS header_gregorian_date
                               FROM IntervalsDef),
         CohortHeaderCalc AS (SELECT interval_month,
                                     CASE CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(
                                                                       fn_gregorian_to_ethiopian_calendar(header_gregorian_date, 'Y-M-D'),
                                                                       '-', 2), '-', -1) AS UNSIGNED)
                                         WHEN 1 THEN 'Meskerem'
                                         WHEN 2 THEN 'Tikimt'
                                         WHEN 3 THEN 'Hidar'
                                         WHEN 4 THEN 'Tahsas'
                                         WHEN 5 THEN 'Tir'
                                         WHEN 6 THEN 'Yekatit'
                                         WHEN 7 THEN 'Megabit'
                                         WHEN 8 THEN 'Miyazia'
                                         WHEN 9 THEN 'Ginbot'
                                         WHEN 10 THEN 'Sene'
                                         WHEN 11 THEN 'Hamle'
                                         WHEN 12 THEN 'Nehase'
                                         WHEN 13 THEN 'Pagume'
                                         END             AS et_month,
                                     CAST(SUBSTRING_INDEX(
                                             fn_gregorian_to_ethiopian_calendar(header_gregorian_date, 'Y-M-D'), '-',
                                             1) AS CHAR) as et_year
                              FROM CohortHeaderDates),

         HeiCohortEnriched AS (SELECT hi.hei_client_id,
                                      hi.interval_month,

                                      fn_get_ti_status(hi.mother_client_id, hi.effective_enrollment_date,
                                                       hi.interval_end_date)    as ti_status,

                                      CASE
                                          WHEN EXISTS (SELECT 1
                                                       FROM mamba_flat_encounter_follow_up_4 f4
                                                                JOIN mamba_flat_encounter_follow_up_6 f6 ON f4.encounter_id = f6.encounter_id
                                                       WHERE f4.client_id = hi.mother_client_id
                                                         AND f4.follow_up_status IN
                                                             ('Dead', 'Transferred out', 'Stop all',
                                                              'Loss to follow-up (LTFU)', 'Ran away')
                                                         AND f6.follow_up_date_followup_ BETWEEN hi.hei_enrollment_date AND hi.interval_end_date) OR
                                               EXISTS (SELECT 1
                                                       FROM mamba_flat_encounter_hei_followup hf
                                                       WHERE hf.client_id = hi.hei_client_id
                                                         AND hf.decision IN ('Lost to Follow-up', 'TO', 'Dead', 'Died')
                                                         AND hf.followup_date_followup BETWEEN hi.hei_enrollment_date AND hi.interval_end_date)
                                              THEN 1
                                          ELSE 0
                                          END                                   AS is_ltfu,

                                      (SELECT MIN(TIMESTAMPDIFF(MONTH, c.date_of_birth,
                                                                COALESCE(hf.dna_pcr_sample_collection_date,
                                                                         hf.date_dbs_result_received,
                                                                         hf.hiv_test_date)))
                                       FROM mamba_flat_encounter_hei_hiv_test hf
                                                JOIN mamba_dim_client c ON c.client_id = hi.hei_client_id
                                       WHERE hf.client_id = hi.hei_client_id
                                         AND hf.hiv_test_performed IS NOT NULL) as age_at_pcr_test,

                                      (SELECT ho.hei_pmtct_final_outcome
                                       FROM mamba_flat_encounter_hei_final_outcome ho
                                       WHERE ho.client_id = hi.hei_client_id
                                         AND ho.date_when_final_outcome_was_known <= hi.interval_end_date
                                       ORDER BY ho.date_when_final_outcome_was_known DESC
                                       LIMIT 1)                                 as final_outcome_val

                               FROM HeiIntervals hi),

         MonthlyStats AS (SELECT interval_month,

                                 SUM(CASE WHEN ti_status != 'TI' OR ti_status IS NULL THEN 1 ELSE 0 END)    as count_base,

                                 SUM(CASE WHEN ti_status = 'TI' THEN 1 ELSE 0 END)                          as count_ti,

                                 SUM(is_ltfu)                                                               as count_ltfu,

                                 SUM(CASE WHEN age_at_pcr_test < 2 THEN 1 ELSE 0 END)                       as count_pcr_lt_2,

                                 SUM(CASE WHEN age_at_pcr_test BETWEEN 2 AND 12 THEN 1 ELSE 0 END)          as count_pcr_2_12,

                                 SUM(CASE WHEN final_outcome_val = 'Discharged Negative' THEN 1 ELSE 0 END) as count_out_neg,
                                 SUM(CASE WHEN final_outcome_val = 'Positive' THEN 1 ELSE 0 END)            as count_out_pos,
                                 SUM(CASE WHEN final_outcome_val = 'Lost to Follow-up' THEN 1 ELSE 0 END)   as count_out_ltfu,
                                 SUM(CASE WHEN final_outcome_val = 'Still on BF/Exposed' THEN 1 ELSE 0 END) as count_out_bf,
                                 SUM(CASE WHEN final_outcome_val IN ('Died', 'Dead') THEN 1 ELSE 0 END)     as count_out_died,
                                 SUM(CASE WHEN final_outcome_val = 'TO' THEN 1 ELSE 0 END)                  as count_out_to

                          FROM HeiCohortEnriched
                          GROUP BY interval_month)

    SELECT 'Maternal Cohort Intervals (Ethiopian Calendar)'                                   AS Name,
           MAX(CASE WHEN interval_month = 13 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 12',
           MAX(CASE WHEN interval_month = 19 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 18',
           MAX(CASE WHEN interval_month = 25 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 24',
           MAX(CASE WHEN interval_month = 31 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 30'
    FROM CohortHeaderCalc

    UNION ALL

    SELECT 'A. Number of HEI born to HIV+mothers who enrolled in PMTCT',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_base END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'B. Total number of HEI Transfer in (TI) since Month 0',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_ti END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'C. Number of HEI in the current cohort (A+B)',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_base + count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_base + count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_base + count_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_base + count_ti END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'D. HEI Lost to F/U (not seen > 1 month after scheduled appointment)',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_ltfu END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_ltfu END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_ltfu END), 0) AS SIGNED),
           0
    FROM MonthlyStats

    UNION ALL

    SELECT 'E. HEI with DNA PCR collected by 2 months of age',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_pcr_lt_2 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_pcr_lt_2 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_pcr_lt_2 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_pcr_lt_2 END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL
    SELECT 'E. HEI with DNA PCR collected by 2 months of age Percentage' AS Category,
           CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_pcr_lt_2 END), 0) AS SIGNED),
                  ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 13 THEN (count_pcr_lt_2 /(count_base + count_ti)) * 100 END), 0), 1), '%)') AS '12_Months',
            CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_pcr_lt_2 END), 0) AS SIGNED),
                ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 19 THEN (count_pcr_lt_2 / (count_base + count_ti)) * 100 END), 0), 1), '%)') AS '18_Months',
            CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_pcr_lt_2 END), 0) AS SIGNED),
                ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 25 THEN (count_pcr_lt_2 / (count_base + count_ti)) * 100 END), 0), 1), '%)') AS '24_Months',
            CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_pcr_lt_2 END), 0) AS SIGNED),
                ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 31 THEN (count_pcr_lt_2 / (count_base + count_ti)) * 100 END), 0), 1), '%)') AS '30_Months'
    FROM MonthlyStats

    UNION ALL

    SELECT 'F. HEI with DNA PCR collected between 2 and 12 months of age',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_pcr_2_12 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_pcr_2_12 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_pcr_2_12 END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_pcr_2_12 END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL
    SELECT 'F. HEI with DNA PCR collected between 2 and 12 months of age Percentage',
           -- 12 Months
           CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_pcr_2_12 END), 0) AS SIGNED),
                  ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 13 THEN (count_pcr_2_12 / (count_base + count_ti)) * 100 END), 0), 1), '%)'),
           -- 18 Months
           CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 19 THEN count_pcr_2_12 END), 0) AS SIGNED),
                  ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 19 THEN (count_pcr_2_12 / (count_base + count_ti)) * 100 END), 0), 1), '%)'),
           -- 24 Months
           CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_pcr_2_12 END), 0) AS SIGNED),
                  ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 25 THEN (count_pcr_2_12 / (count_base + count_ti)) * 100 END), 0), 1), '%)'),
           -- 30 Months
           CONCAT(CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_pcr_2_12 END), 0) AS SIGNED),
                  ' (', ROUND(IFNULL(MAX(CASE WHEN interval_month = 31 THEN (count_pcr_2_12 / (count_base + count_ti)) * 100 END), 0), 1), '%)')
    FROM MonthlyStats

    UNION ALL

    SELECT 'G. HEI discharged negative (DN)',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_neg END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'H. HEI diagnosed positive (p)',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_pos END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'I. Final HEI Lost to F/U',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_ltfu END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'J. HEI still exposed /breastfeeding (CPT)',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_bf END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'K. HEI known dead',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_died END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'L. HEI transferred out (TO to another facility)',
           0,
           0,
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 31 THEN count_out_to END), 0) AS SIGNED)
    FROM MonthlyStats;

END //
DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_child_cohort_analysis_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_child_cohort_analysis_query;

~
CREATE PROCEDURE sp_fact_line_list_child_cohort_analysis_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH HeiEnrolled AS (SELECT hei_enrollment.encounter_id                       as hei_encounter_id,
                                maternal_enrollment.encounter_id                  as mother_encounter_id,
                                linked_mother.identifier                          as mother_mrn,
                                hei_enrollment.client_id                          as hei_client_id,
                                maternal_enrollment.client_id                     as mother_client_id,
                                maternal_enrollment.date_of_enrollment_or_booking as date_of_erollement,
                                hei_enrollment.date_enrolled_in_care              as hei_enrollment_date,
                                hei_enrollment.infant_referred                    as infant_referred,
                                final_outcome.hei_pmtct_final_outcome             as final_out_come,
                                CASE
                                    WHEN maternal_enrollment.date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                                        THEN maternal_enrollment.date_of_enrollment_or_booking
                                    ELSE hei_enrollment.date_enrolled_in_care
                                    END                                           AS effective_enrollment_date,
                                followup_date_followup
                         FROM mamba_flat_encounter_hei_enrollment as hei_enrollment
                                  LEFT JOIN mamba_dim_patient_identifier as linked_mother
                                            on hei_enrollment.contact_mrn = linked_mother.identifier
                                                and linked_mother.identifier_type = 5
                                  LEFT JOIN mamba_flat_encounter_pmtct_enrollment as maternal_enrollment
                                            on maternal_enrollment.client_id = linked_mother.patient_id
                                  LEFT JOIN mamba_flat_encounter_hei_final_outcome as final_outcome
                                            on hei_enrollment.client_id = final_outcome.client_id
                         WHERE (maternal_enrollment.date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE)

                            OR (hei_enrollment.date_enrolled_in_care BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                             AND (maternal_enrollment.date_of_enrollment_or_booking IS NULL
                                 OR
                                  maternal_enrollment.date_of_enrollment_or_booking NOT BETWEEN REPORT_START_DATE AND REPORT_END_DATE)
                             )
        -- hei_enrollment.date_enrolled_in_care between REPORT_START_DATE and DATE_ADD(REPORT_START_DATE, INTERVAL 12 MONTH)
    ),

         HIEInCohortFiltered AS (SELECT *
                                 FROM (SELECT a.*,
                                              ROW_NUMBER() OVER (PARTITION BY a.hei_client_id ORDER BY a.hei_enrollment_date DESC) AS row_num
                                       FROM HeiEnrolled a
                                       WHERE hei_enrollment_date is not null) t
                                 WHERE row_num = 1),

         IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 13
                          UNION ALL
                          SELECT 19
                          UNION ALL
                          SELECT 25
                          UNION ALL
                          SELECT 31),

         PatientIntervals AS (SELECT h.hei_client_id,
                                     h.hei_enrollment_date,
                                     i.interval_month,
                                     CASE
                                         WHEN i.interval_month = 0 THEN h.hei_enrollment_date
                                         ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH))
                                         END AS interval_end_date,
                                     CASE
                                         WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                         ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH)))
                                                           OVER (PARTITION BY h.hei_client_id ORDER BY i.interval_month),
                                                       REPORT_START_DATE)
                                         END AS interval_start_date
                              FROM HIEInCohortFiltered h
                                       CROSS JOIN IntervalsDef i),

         AllEvents AS (SELECT h.hei_client_id,
                              f6.follow_up_date_followup_ as event_date,
                              CASE
                                  WHEN f7.follow_up_status IN ('Dead', 'Died') THEN 'Dead'
                                  WHEN f7.follow_up_status IN ('Transferred out', 'TO') THEN 'Transferred out'
                                  WHEN f7.follow_up_status IN ('Stop all', 'Loss to follow-up (LTFU)', 'Ran away')
                                      THEN 'Lost to follow-up'
                                  ELSE 'Active'
                                  END                    as status,
                              1                          as priority
                       FROM HIEInCohortFiltered h
                                JOIN mamba_flat_encounter_follow_up_6 f6 ON h.mother_client_id = f6.client_id
                                LEFT JOIN mamba_flat_encounter_follow_up_4 f7 ON h.mother_client_id = f6.client_id
                       WHERE f6.follow_up_date_followup_ IS NOT NULL

                       UNION ALL

                       SELECT h.hei_client_id,
                              hf.followup_date_followup as event_date,
                              CASE
                                  WHEN hf.decision IN ('Dead', 'Died') THEN 'Dead'
                                  WHEN hf.decision IN ('TO', 'Transferred out') THEN 'Transferred out'
                                  WHEN hf.decision IN ('Lost to Follow-up') THEN 'Lost to follow-up'
                                  ELSE 'Active'
                                  END                   as status,
                              2                         as priority
                       FROM HIEInCohortFiltered h
                                JOIN mamba_flat_encounter_hei_followup hf ON h.hei_client_id = hf.client_id
                       WHERE hf.followup_date_followup IS NOT NULL

                       UNION ALL

                       SELECT h.hei_client_id,
                              ho.date_when_final_outcome_was_known as event_date,
                              ho.hei_pmtct_final_outcome           as status,
                              3                                    as priority
                       FROM HIEInCohortFiltered h
                                JOIN mamba_flat_encounter_hei_final_outcome ho ON h.hei_client_id = ho.client_id
                       WHERE ho.date_when_final_outcome_was_known IS NOT NULL),

         LatestStatus AS (SELECT pi.hei_client_id,
                                 pi.interval_month,
                                 ae.status,
                                 ae.event_date,
                                 ROW_NUMBER() OVER (PARTITION BY pi.hei_client_id, pi.interval_month ORDER BY ae.event_date DESC, ae.priority DESC) as rn
                          FROM PatientIntervals pi
                                   LEFT JOIN AllEvents ae ON pi.hei_client_id = ae.hei_client_id
                              AND ae.event_date <= pi.interval_end_date),

         CohortSnapshot AS (SELECT hei_client_id,
                                   interval_month,
                                   COALESCE(status, 'Lost to follow-up') as status,
                                   event_date
                            FROM LatestStatus
                            WHERE rn = 1),

         PCRInfo AS (SELECT h.hei_client_id,
                            -- PCR < 2 Months
                            MAX(CASE
                                    WHEN TIMESTAMPDIFF(MONTH, c.date_of_birth,
                                                       COALESCE(hf.dna_pcr_sample_collection_date,
                                                                hf.date_dbs_result_received, hf.hiv_test_date)) < 2
                                        THEN hf.hiv_test_date END)   as pcr_date_lt_2m,
                            MAX(CASE
                                    WHEN TIMESTAMPDIFF(MONTH, c.date_of_birth,
                                                       COALESCE(hf.dna_pcr_sample_collection_date,
                                                                hf.date_dbs_result_received, hf.hiv_test_date)) < 2
                                        THEN hf.hiv_test_result END) as pcr_result_lt_2m,
                            -- PCR 2-12 Months
                            MAX(CASE
                                    WHEN TIMESTAMPDIFF(MONTH, c.date_of_birth,
                                                       COALESCE(hf.dna_pcr_sample_collection_date,
                                                                hf.date_dbs_result_received,
                                                                hf.hiv_test_date)) BETWEEN 2 AND 12
                                        THEN hf.hiv_test_date END)   as pcr_date_2_12m,
                            MAX(CASE
                                    WHEN TIMESTAMPDIFF(MONTH, c.date_of_birth,
                                                       COALESCE(hf.dna_pcr_sample_collection_date,
                                                                hf.date_dbs_result_received,
                                                                hf.hiv_test_date)) BETWEEN 2 AND 12
                                        THEN hf.hiv_test_result END) as pcr_result_2_12m
                     FROM HIEInCohortFiltered h
                              JOIN mamba_dim_client c ON h.hei_client_id = c.client_id
                              JOIN mamba_flat_encounter_hei_hiv_test hf ON h.hei_client_id = hf.client_id
                     WHERE hf.hiv_test_performed IS NOT NULL
                     GROUP BY h.hei_client_id)

    SELECT c.patient_name                                                         AS 'Patient Name',
           c.patient_uuid                                                         AS 'UUID',
           CAST(c.mrn AS CHAR(20))                                                AS 'MRN',
           h.mother_mrn                                                           AS 'Mother MRN',
           c.Sex                                                                  AS 'Sex',
           c.date_of_birth                                                        AS 'Date of Birth',
           c.date_of_birth                                                        AS 'Date of Birth EC.',
           h.hei_enrollment_date                                                  AS 'Enrollment Date',
           h.hei_enrollment_date                                                  AS 'Enrollment Date EC.',

           -- PCR Details
           pcr.pcr_date_lt_2m                                                     AS 'PCR Date (< 2 Months)',
           pcr.pcr_date_lt_2m                                                     AS 'PCR Date (< 2 Months) EC.',
           pcr.pcr_result_lt_2m                                                   AS 'PCR Result (< 2 Months)',
           pcr.pcr_date_2_12m                                                     AS 'PCR Date (2-12 Months)',
           pcr.pcr_date_2_12m                                                     AS 'PCR Date (2-12 Months) EC.',
           pcr.pcr_result_2_12m                                                   AS 'PCR Result (2-12 Months)',

           -- 12 Months
           MAX(CASE WHEN cs.interval_month = 13 THEN cs.status ELSE NULL END)     AS 'Status at 12 Months',
           MAX(CASE WHEN cs.interval_month = 13 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 12 Months',
           MAX(CASE WHEN cs.interval_month = 13 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 12 Months EC.',

           -- 18 Months
           MAX(CASE WHEN cs.interval_month = 19 THEN cs.status ELSE NULL END)     AS 'Status at 18 Months',
           MAX(CASE WHEN cs.interval_month = 19 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 18 Months',
           MAX(CASE WHEN cs.interval_month = 19 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 18 Months EC.',

           -- 24 Months
           MAX(CASE WHEN cs.interval_month = 25 THEN cs.status ELSE NULL END)     AS 'Status at 24 Months',
           MAX(CASE WHEN cs.interval_month = 25 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 24 Months',
           MAX(CASE WHEN cs.interval_month = 25 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 24 Months EC.',

           -- 30 Months
           MAX(CASE WHEN cs.interval_month = 31 THEN cs.status ELSE NULL END)     AS 'Status at 30 Months',
           MAX(CASE WHEN cs.interval_month = 31 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 30 Months',
           MAX(CASE WHEN cs.interval_month = 31 THEN cs.event_date ELSE NULL END) AS 'Latest Event Date at 30 Months EC.'

    FROM HIEInCohortFiltered h
             JOIN mamba_dim_client c ON h.hei_client_id = c.client_id
             LEFT JOIN CohortSnapshot cs ON h.hei_client_id = cs.hei_client_id
             LEFT JOIN PCRInfo pcr ON h.hei_client_id = pcr.hei_client_id
    GROUP BY h.hei_client_id, c.patient_name, c.patient_uuid, c.mrn, h.mother_mrn, c.Sex, c.date_of_birth,
             h.hei_enrollment_date
    ORDER BY h.hei_enrollment_date DESC;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_mother_cohort_analysis_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_mother_cohort_analysis_query;

~
CREATE PROCEDURE sp_fact_line_list_mother_cohort_analysis_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUpEncounters AS (SELECT follow_up.encounter_id,
                                       follow_up.client_id                 AS PatientId,
                                       follow_up_status,
                                       follow_up_date_followup_            AS follow_up_date,
                                       art_antiretroviral_start_date       AS art_start_date,
                                       treatment_end_date,
                                       regimen,
                                       currently_breastfeeding_child,
                                       pregnancy_status,
                                       antiretroviral_art_dispensed_dose_i AS ARTDoseDays,
                                       anitiretroviral_adherence_level     AS AdherenceLevel,
                                       next_visit_date,
                                       date_of_reported_hiv_viral_load     AS viral_load_sent_date,
                                       date_viral_load_results_received    AS viral_load_received_date,
                                       viral_load_test_status              AS viral_load_result,
                                       hiv_viral_load                      AS viral_load_count,
                                       cd4_count,
                                       cd4_                                AS cd4_percent,
                                       current_functional_status,
                                       visitect_cd4_result,
                                       visitect_cd4_test_date
                                FROM mamba_flat_encounter_follow_up follow_up
                                         LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                                   ON follow_up.encounter_id = follow_up_1.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                                   ON follow_up.encounter_id = follow_up_2.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                                   ON follow_up.encounter_id = follow_up_3.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                                   ON follow_up.encounter_id = follow_up_4.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                                   ON follow_up.encounter_id = follow_up_5.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                                   ON follow_up.encounter_id = follow_up_6.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                                   ON follow_up.encounter_id = follow_up_7.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                                   ON follow_up.encounter_id = follow_up_8.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                                   ON follow_up.encounter_id = follow_up_9.encounter_id
                                WHERE follow_up.client_id IS NOT NULL
                                  AND follow_up_date_followup_ IS NOT NULL
                                  AND follow_up_status IS NOT NULL),

         PMTCT_ENROLLMENT AS (SELECT enrollment.client_id                          AS PatientId,
                                     MIN(enrollment.date_of_enrollment_or_booking) AS date_of_enrollment_or_booking
                              FROM mamba_flat_encounter_pmtct_enrollment enrollment
                              WHERE date_of_enrollment_or_booking IS NOT NULL
                                AND date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                              GROUP BY enrollment.client_id),

         IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 4
                          UNION ALL
                          SELECT 7
                          UNION ALL
                          SELECT 13
                          UNION ALL
                          SELECT 25),

         PatientIntervals AS (SELECT a.PatientId,
                                     a.date_of_enrollment_or_booking,
                                     i.interval_month,
                                     CASE
                                         WHEN i.interval_month = 0 THEN a.date_of_enrollment_or_booking
                                         ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH))
                                         END AS interval_end_date,
                                     CASE
                                         WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                         ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH)))
                                                           OVER (PARTITION BY a.PatientId ORDER BY i.interval_month),
                                                       REPORT_START_DATE)
                                         END AS interval_start_date
                              FROM PMTCT_ENROLLMENT a
                                       CROSS JOIN IntervalsDef i),

         StrictIntervalData AS (SELECT pi.PatientId,
                                       pi.interval_month,
                                       pi.interval_start_date,
                                       pi.interval_end_date,

                                       f.follow_up_status              AS strict_status,
                                       f.treatment_end_date            AS strict_tx_end_date,
                                       f.regimen                       AS strict_regimen,
                                       f.pregnancy_status              AS strict_pregnancy,
                                       f.currently_breastfeeding_child AS strict_breastfeeding,

                                       f.follow_up_date,
                                       f.ARTDoseDays,
                                       f.AdherenceLevel,
                                       f.next_visit_date,
                                       f.current_functional_status

                                FROM PatientIntervals pi
                                         LEFT JOIN FollowUpEncounters f ON pi.PatientId = f.PatientId
                                    AND f.follow_up_date BETWEEN pi.interval_start_date AND pi.interval_end_date
                                    AND f.follow_up_date = (SELECT MAX(sub_f.follow_up_date)
                                                            FROM FollowUpEncounters sub_f
                                                            WHERE sub_f.PatientId = pi.PatientId
                                                              AND sub_f.follow_up_date BETWEEN pi.interval_start_date AND pi.interval_end_date)),

         StateCalculation AS (SELECT sid.*,
                                     COUNT(strict_status)
                                           OVER (PARTITION BY PatientId ORDER BY interval_month)                                                as status_partition,
                                     MAX(strict_tx_end_date)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as max_tx_end_date_so_far
                              FROM StrictIntervalData sid),

         FilledState AS (SELECT sc.*,
                                FIRST_VALUE(strict_status)
                                            OVER (PARTITION BY PatientId, status_partition ORDER BY interval_month) as last_known_status,
                                FIRST_VALUE(strict_regimen)
                                            OVER (PARTITION BY PatientId, status_partition ORDER BY interval_month) as last_known_regimen,
                                FIRST_VALUE(strict_pregnancy)
                                            OVER (PARTITION BY PatientId, status_partition ORDER BY interval_month) as last_known_pregnancy,
                                FIRST_VALUE(strict_breastfeeding)
                                            OVER (PARTITION BY PatientId, status_partition ORDER BY interval_month) as last_known_breastfeeding
                         FROM StateCalculation sc),

         CohortDetails AS (SELECT fs.PatientId,
                                  client.patient_name,
                                  client.patient_uuid,
                                  client.mrn,
                                  client.UAN,
                                  client.Sex,
                                  client.date_of_birth,
                                  fs.interval_month,
                                  fs.interval_start_date,
                                  fs.interval_end_date,

                                  CASE
                                      WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                          THEN strict_status
                                      WHEN last_known_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                          THEN last_known_status
                                      WHEN strict_status IS NOT NULL THEN strict_status
                                      WHEN strict_status IS NULL AND max_tx_end_date_so_far >= interval_end_date
                                          THEN 'Active'
                                      ELSE 'Loss to follow-up (LTFU)'
                                      END                               AS final_outcome,

                                  -- B. Final Regimen (Carried Forward)
                                  CASE
                                      WHEN strict_regimen IS NOT NULL THEN strict_regimen
                                      WHEN max_tx_end_date_so_far >= interval_end_date THEN last_known_regimen
                                      ELSE NULL
                                      END                               AS final_regimen,

                                  -- C. Strict Visit Data (Keep NULL if they didn't come)
                                  fs.follow_up_date                     AS strict_visit_date,
                                  fs.ARTDoseDays,
                                  fs.AdherenceLevel,
                                  fs.strict_tx_end_date                 AS treatment_end_date_visit,
                                  fs.next_visit_date,
                                  fs.strict_status                      AS follow_up_status_visit,
                                  fs.current_functional_status,

                                  CASE
                                      WHEN strict_pregnancy IS NOT NULL THEN strict_pregnancy
                                      ELSE last_known_pregnancy END     AS final_pregnancy,
                                  CASE
                                      WHEN strict_breastfeeding IS NOT NULL THEN strict_breastfeeding
                                      ELSE last_known_breastfeeding END AS final_breastfeeding

                           FROM FilledState fs
                                    JOIN mamba_dim_client client ON fs.PatientId = client.client_id)

    SELECT co.patient_name                                                                      AS 'Patient Name',
           co.patient_uuid                                                                      AS 'UUID',
           co.mrn                                                                               AS 'MRN',
           co.UAN,
           co.Sex,
           co.date_of_birth                                                                     AS 'Date of Birth',
           co.date_of_birth                                                                     AS 'Date of Birth EC.',
           ai.date_of_enrollment_or_booking                                                     AS 'Date of Enrollment or Booking',
           ai.date_of_enrollment_or_booking                                                     AS 'Date of Enrollment or Booking EC.',

           -- === 0 MONTHS ===
           MAX(CASE
                   WHEN co.interval_month = 0 THEN TIMESTAMPDIFF(YEAR, co.date_of_birth, co.interval_end_date)
                   ELSE NULL END)                                                               AS 'Age at 0 Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN
                       CASE
                           WHEN TIMESTAMPDIFF(YEAR, co.date_of_birth, co.interval_end_date) < 15 AND
                                co.final_regimen LIKE '4%' THEN 'On Original 1st Line'
                           WHEN TIMESTAMPDIFF(YEAR, co.date_of_birth, co.interval_end_date) < 15 AND
                                co.final_regimen LIKE '1%' THEN 'On Alternate 1st Line'
                           WHEN TIMESTAMPDIFF(YEAR, co.date_of_birth, co.interval_end_date) >= 15 AND
                                co.final_regimen LIKE '1%' THEN 'On Original 1st Line'
                           WHEN TIMESTAMPDIFF(YEAR, co.date_of_birth, co.interval_end_date) >= 15 AND
                                co.final_regimen LIKE '4%' THEN 'On Alternate 1st Line'
                           ELSE 'Other'
                           END
                   ELSE NULL END)                                                               AS 'Regimen Line at Zero Months',

           MAX(CASE WHEN co.interval_month = 0 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at Zero Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at Zero Months EC.',
           MAX(CASE WHEN co.interval_month = 0 THEN co.final_regimen ELSE NULL END)             AS 'Latest Regimen at Zero Months',
           COALESCE(MAX(CASE WHEN co.interval_month = 0 THEN co.ARTDoseDays ELSE NULL END),
                    0)                                                                          AS 'Latest Regimen Dose Days at Zero Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.follow_up_status_visit
                   ELSE NULL END)                                                               AS 'Latest Follow-up Status at Zero Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.final_pregnancy ELSE NULL END)           AS 'Pregnancy Status at Month Zero',
           MAX(CASE WHEN co.interval_month = 0 THEN co.final_breastfeeding ELSE NULL END)       AS 'Breast Feeding Status at Month Zero',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at Zero Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at Zero Months EC.',

           -- === 3 MONTHS (Interval 4) ===
           MAX(CASE WHEN co.interval_month = 4 THEN co.interval_start_date ELSE NULL END)       AS 'Interval start date at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.interval_start_date ELSE NULL END)       AS 'Interval start date at 3 Months EC.',
           MAX(CASE WHEN co.interval_month = 4 THEN co.interval_end_date ELSE NULL END)         AS 'Interval end date at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.interval_end_date ELSE NULL END)         AS 'Interval end date at 3 Months EC.',
           MAX(CASE WHEN co.interval_month = 4 THEN co.final_outcome ELSE NULL END)             AS 'Outcome at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at 3 Months EC.',
           MAX(CASE WHEN co.interval_month = 4 THEN co.final_regimen ELSE NULL END)             AS 'Latest Regimen at 3 Months',
           MAX(CASE
                   WHEN co.interval_month = 4 THEN co.follow_up_status_visit
                   ELSE NULL END)                                                               AS 'Latest Follow-up Status at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.final_pregnancy ELSE NULL END)           AS 'Pregnant at 3 Months',
           MAX(CASE WHEN co.interval_month = 4 THEN co.final_breastfeeding ELSE NULL END)       AS 'Breast Feeding Status at 3 Months',
           MAX(CASE
                   WHEN co.interval_month = 4 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 3 Months',
           MAX(CASE
                   WHEN co.interval_month = 4 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 3 Months EC.',

           -- === 6 MONTHS (Interval 7) ===
           MAX(CASE WHEN co.interval_month = 7 THEN co.interval_start_date ELSE NULL END)       AS 'Interval start date at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.interval_start_date ELSE NULL END)       AS 'Interval start date at 6 Months EC.',
           MAX(CASE WHEN co.interval_month = 7 THEN co.interval_end_date ELSE NULL END)         AS 'Interval end date at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.interval_end_date ELSE NULL END)         AS 'Interval end date at 6 Months EC.',
           MAX(CASE WHEN co.interval_month = 7 THEN co.final_outcome ELSE NULL END)             AS 'Outcome at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.strict_visit_date ELSE NULL END)         AS 'Latest Follow-Up Date at 6 Months EC.',
           MAX(CASE WHEN co.interval_month = 7 THEN co.final_regimen ELSE NULL END)             AS 'Latest Regimen at 6 Months',
           MAX(CASE
                   WHEN co.interval_month = 7 THEN co.follow_up_status_visit
                   ELSE NULL END)                                                               AS 'Latest Follow-up Status at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.final_pregnancy ELSE NULL END)           AS 'Pregnant at 6 Months',
           MAX(CASE WHEN co.interval_month = 7 THEN co.final_breastfeeding ELSE NULL END)       AS 'Breast Feeding Status at 6 Months',
           MAX(CASE
                   WHEN co.interval_month = 7 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 6 Months',
           MAX(CASE
                   WHEN co.interval_month = 7 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 6 Months EC.',

           -- === 12 MONTHS (Interval 13) ===
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.interval_start_date
                   ELSE NULL END)                                                               AS 'Interval start date at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.interval_start_date
                   ELSE NULL END)                                                               AS 'Interval start date at 12 Months EC.',
           MAX(CASE WHEN co.interval_month = 13 THEN co.interval_end_date ELSE NULL END)        AS 'Interval end date at 12 Months',
           MAX(CASE WHEN co.interval_month = 13 THEN co.interval_end_date ELSE NULL END)        AS 'Interval end date at 12 Months EC.',
           MAX(CASE WHEN co.interval_month = 13 THEN co.final_outcome ELSE NULL END)            AS 'Outcome at 12 Months',
           MAX(CASE WHEN co.interval_month = 13 THEN co.strict_visit_date ELSE NULL END)        AS 'Latest Follow-Up Date at 12 Months',
           MAX(CASE WHEN co.interval_month = 13 THEN co.strict_visit_date ELSE NULL END)        AS 'Latest Follow-Up Date at 12 Months EC.',
           MAX(CASE WHEN co.interval_month = 13 THEN co.final_regimen ELSE NULL END)            AS 'Latest Regimen at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.follow_up_status_visit
                   ELSE NULL END)                                                               AS 'Latest Follow-up Status at 12 Months',
           MAX(CASE WHEN co.interval_month = 13 THEN co.final_pregnancy ELSE NULL END)          AS 'Pregnant at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.final_breastfeeding
                   ELSE NULL END)                                                               AS 'Breast Feeding Status at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 13 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 12 Months EC.',

           -- === 24 MONTHS (Interval 25) ===
           MAX(CASE
                   WHEN co.interval_month = 25 THEN co.interval_start_date
                   ELSE NULL END)                                                               AS 'Interval start date at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 25 THEN co.interval_start_date
                   ELSE NULL END)                                                               AS 'Interval start date at 24 Months EC.',
           MAX(CASE WHEN co.interval_month = 25 THEN co.interval_end_date ELSE NULL END)        AS 'Interval end date at 24 Months',
           MAX(CASE WHEN co.interval_month = 25 THEN co.interval_end_date ELSE NULL END)        AS 'Interval end date at 24 Months EC.',
           MAX(CASE WHEN co.interval_month = 25 THEN co.final_outcome ELSE NULL END)            AS 'Outcome at 24 Months',
           MAX(CASE WHEN co.interval_month = 25 THEN co.strict_visit_date ELSE NULL END)        AS 'Latest Follow-Up Date at 24 Months',
           MAX(CASE WHEN co.interval_month = 25 THEN co.strict_visit_date ELSE NULL END)        AS 'Latest Follow-Up Date at 24 Months EC.',
           MAX(CASE WHEN co.interval_month = 25 THEN co.final_regimen ELSE NULL END)            AS 'Latest Regimen at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 25 THEN co.follow_up_status_visit
                   ELSE NULL END)                                                               AS 'Latest Follow-up Status at 24 Months',
           MAX(CASE WHEN co.interval_month = 25 THEN co.final_pregnancy ELSE NULL END)          AS 'Pregnant at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 25 THEN co.final_breastfeeding
                   ELSE NULL END)                                                               AS 'Breast Feeding Status at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 25 THEN co.treatment_end_date_visit
                   ELSE NULL END)                                                               AS 'Last TX_Curr Date at 24 Months',
        MAX(CASE
                       WHEN co.interval_month = 25 THEN co.treatment_end_date_visit
                       ELSE NULL END)                                                               AS 'Last TX_Curr Date at 24 Months EC.'

    FROM PMTCT_ENROLLMENT ai
             JOIN CohortDetails co ON ai.PatientId = co.PatientId
    GROUP BY ai.PatientId, ai.date_of_enrollment_or_booking
    ORDER BY ai.date_of_enrollment_or_booking;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_mother_cohort_analysis_summary_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_mother_cohort_analysis_summary_query;

~
CREATE PROCEDURE sp_fact_line_list_mother_cohort_analysis_summary_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUpEncounters AS (SELECT follow_up.encounter_id,
                                       follow_up.client_id                                                     AS PatientId,
                                       follow_up_status,
                                       follow_up_date_followup_                                                AS follow_up_date,
                                       treatment_end_date,
                                       regimen,
                                       transferred_in_check_this_for_all_t,
                                       CASE WHEN transferred_in_check_this_for_all_t = 'Yes' THEN 1 ELSE 0 END as is_ti_visit,
                                       follow_up.encounter_id                                                  AS enc_id
                                FROM mamba_flat_encounter_follow_up follow_up
                                         LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                                   ON follow_up.encounter_id = follow_up_1.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                                   ON follow_up.encounter_id = follow_up_2.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                                   ON follow_up.encounter_id = follow_up_3.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                                   ON follow_up.encounter_id = follow_up_4.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                                   ON follow_up.encounter_id = follow_up_5.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                                   ON follow_up.encounter_id = follow_up_6.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                                   ON follow_up.encounter_id = follow_up_7.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                                   ON follow_up.encounter_id = follow_up_8.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                                   ON follow_up.encounter_id = follow_up_9.encounter_id
                                WHERE follow_up_date_followup_ IS NOT NULL
                                  AND follow_up_status IS NOT NULL),

         PMTCT_ENROLLMENT AS (SELECT enrollment.client_id                          AS PatientId,
                                     MIN(enrollment.date_of_enrollment_or_booking) AS date_of_enrollment_or_booking
                              FROM mamba_flat_encounter_pmtct_enrollment enrollment
                              WHERE date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                              GROUP BY enrollment.client_id),

         IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 4
                          UNION ALL
                          SELECT 7
                          UNION ALL
                          SELECT 13
                          UNION ALL
                          SELECT 25),

         PatientIntervals AS (SELECT a.PatientId,
                                     a.date_of_enrollment_or_booking,
                                     i.interval_month,
                                     CASE
                                         WHEN i.interval_month = 0 THEN a.date_of_enrollment_or_booking
                                         ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH))
                                         END AS interval_end_date,
                                     CASE
                                         WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                         ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH)))
                                                           OVER (PARTITION BY a.PatientId ORDER BY i.interval_month),
                                                       REPORT_START_DATE)
                                         END AS interval_start_date
                              FROM PMTCT_ENROLLMENT a
                                       CROSS JOIN IntervalsDef i),

         RankedIntervalData AS (SELECT pi.PatientId,
                                       pi.interval_month,
                                       pi.interval_end_date,
                                       pi.interval_start_date,
                                       f.follow_up_status                            AS strict_status,
                                       f.treatment_end_date                          AS strict_tx_end_date,
                                       CASE WHEN f.is_ti_visit = 1 THEN 1 ELSE 0 END AS ti_in_this_interval,
                                       ROW_NUMBER() OVER (
                                           PARTITION BY pi.PatientId, pi.interval_month
                                           ORDER BY f.follow_up_date DESC
                                           )                                         AS rn
                                FROM PatientIntervals pi
                                         LEFT JOIN FollowUpEncounters f
                                                   ON pi.PatientId = f.PatientId
                                                       AND
                                                      f.follow_up_date BETWEEN pi.interval_start_date AND pi.interval_end_date),

         StrictIntervalData AS (SELECT PatientId,
                                       interval_month,
                                       interval_end_date,
                                       interval_start_date,
                                       strict_status,
                                       strict_tx_end_date,
                                       ti_in_this_interval
                                FROM RankedIntervalData
                                WHERE rn = 1),

         StateCalculation AS (SELECT sid.*,
                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as is_cumulative_ti,

                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId)                                                                          as ever_ti,

                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away',
                                                                    'Loss to follow-up', 'LTFU',
                                                                    'Loss to follow-up (LTFU)')
                                                 THEN 1
                                             ELSE 0 END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as has_terminal_event,

                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away',
                                                                    'Loss to follow-up', 'LTFU',
                                                                    'Loss to follow-up (LTFU)')
                                                 THEN strict_status
                                             ELSE NULL END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as specific_terminal_event,

                                     MAX(strict_tx_end_date)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as max_tx_end_date_so_far
                              FROM StrictIntervalData sid),

         CohortDetails AS (SELECT sc.*,
                                  CASE
                                      WHEN has_terminal_event = 1 THEN specific_terminal_event
                                      WHEN max_tx_end_date_so_far >= interval_end_date THEN
                                          CASE
                                              WHEN strict_status IS NOT NULL THEN 'Active'
                                              ELSE 'Active - Carry Forward Rx' END
                                      ELSE 'Loss to follow-up (LTFU)'
                                      END AS final_cohort_outcome
                           FROM StateCalculation sc),

         CohortHeaderDates AS (SELECT interval_month,
                                      CASE
                                          WHEN interval_month = 0 THEN REPORT_START_DATE
                                          ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                  fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                  INTERVAL interval_month MONTH))
                                          END AS header_gregorian_date
                               FROM IntervalsDef),

         CohortHeaderCalc AS (SELECT interval_month,
                                     CASE CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(
                                                                       fn_gregorian_to_ethiopian_calendar(header_gregorian_date, 'Y-M-D'),
                                                                       '-', 2), '-', -1) AS UNSIGNED)
                                         WHEN 1 THEN 'Meskerem'
                                         WHEN 2 THEN 'Tikimt'
                                         WHEN 3 THEN 'Hidar'
                                         WHEN 4 THEN 'Tahsas'
                                         WHEN 5 THEN 'Tir'
                                         WHEN 6 THEN 'Yekatit'
                                         WHEN 7 THEN 'Megabit'
                                         WHEN 8 THEN 'Miyazia'
                                         WHEN 9 THEN 'Ginbot'
                                         WHEN 10 THEN 'Sene'
                                         WHEN 11 THEN 'Hamle'
                                         WHEN 12 THEN 'Nehase'
                                         WHEN 13 THEN 'Pagume'
                                         END             AS ethiopian_month_name,
                                     CAST(SUBSTRING_INDEX(
                                             fn_gregorian_to_ethiopian_calendar(header_gregorian_date, 'Y-M-D'), '-',
                                             1) AS CHAR) as ethiopian_year
                              FROM CohortHeaderDates),

         SummaryCounts AS (SELECT interval_month,
                                  COUNT(DISTINCT PatientId)                                                 AS Total_Base,

                                  SUM(CASE WHEN is_cumulative_ti = 1 THEN 1 ELSE 0 END)                     AS Cumulative_TI,
                                  SUM(CASE WHEN final_cohort_outcome = 'Transferred out' THEN 1 ELSE 0 END) AS Cumulative_TO,
                                  SUM(CASE WHEN final_cohort_outcome = 'Dead' THEN 1 ELSE 0 END)            AS Cumulative_Dead,
                                  SUM(CASE WHEN final_cohort_outcome = 'Stop all' THEN 1 ELSE 0 END)        AS Cumulative_Stop,

                                  SUM(CASE WHEN ti_in_this_interval = 1 THEN 1 ELSE 0 END)                  AS Interval_TI,
                                  SUM(CASE WHEN strict_status = 'Transferred out' THEN 1 ELSE 0 END)        AS Interval_TO,
                                  SUM(CASE WHEN strict_status = 'Dead' THEN 1 ELSE 0 END)                   AS Interval_Dead,
                                  SUM(CASE WHEN strict_status = 'Stop all' THEN 1 ELSE 0 END)               AS Interval_Stop,

                                  SUM(CASE
                                          WHEN final_cohort_outcome IN ('Active', 'Active - Carry Forward Rx') THEN 1
                                          ELSE 0 END)                                                       AS Total_Active,
                                  SUM(CASE
                                          WHEN final_cohort_outcome IN
                                               ('Loss to follow-up (LTFU)', 'Ran away', 'Loss to follow-up') THEN 1
                                          ELSE 0 END)                                                       AS Total_LTFU

                           FROM CohortDetails
                           GROUP BY interval_month)

    SELECT ''                    AS Name,
           MAX(CASE
                   WHEN interval_month = 0 THEN CONCAT(ethiopian_month_name, ' ', ethiopian_year)
                   ELSE '-' END) AS 'Maternal Cohort Month 0',
           MAX(CASE
                   WHEN interval_month = 4 THEN CONCAT(ethiopian_month_name, ' ', ethiopian_year)
                   ELSE '-' END) AS 'Maternal Cohort Month 3',
           MAX(CASE
                   WHEN interval_month = 7 THEN CONCAT(ethiopian_month_name, ' ', ethiopian_year)
                   ELSE '-' END) AS 'Maternal Cohort Month 6',
           MAX(CASE
                   WHEN interval_month = 13 THEN CONCAT(ethiopian_month_name, ' ', ethiopian_year)
                   ELSE '-' END) AS 'Maternal Cohort Month 12',
           MAX(CASE
                   WHEN interval_month = 25 THEN CONCAT(ethiopian_month_name, ' ', ethiopian_year)
                   ELSE '-' END) AS 'Maternal Cohort Month 24'
    FROM CohortHeaderCalc

    UNION ALL

    SELECT 'A. Enrolled in PMTCT in this facility (Month 0)'                  AS Name,
           0                                                                  AS 'Month 0',
           COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) AS 'Month 3',
           COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) AS 'Month 6',
           COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) AS 'Month 12',
           COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) AS 'Month 24'
    FROM SummaryCounts

    UNION ALL

    SELECT 'B. Total number of Transfer in (TI) Cumulative',
           0,
           COALESCE(MAX(CASE WHEN interval_month = 4 THEN Cumulative_TI END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 7 THEN Cumulative_TI END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 13 THEN Cumulative_TI END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 25 THEN Cumulative_TI END), 0)
    FROM SummaryCounts

    UNION ALL

    SELECT 'C. Total Number of Transfer out (TO) Cumulative',
           0,
           COALESCE(MAX(CASE WHEN interval_month = 4 THEN Cumulative_TO END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 7 THEN Cumulative_TO END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 13 THEN Cumulative_TO END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 25 THEN Cumulative_TO END), 0)
    FROM SummaryCounts

    UNION ALL

    SELECT 'D. Net Current Cohort (A + B - C)' AS Name,
           0                                   AS 'Month 0',
           (COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
            COALESCE(MAX(CASE WHEN interval_month = 4 THEN Interval_TI END), 0) -
            COALESCE(MAX(CASE WHEN interval_month = 4 THEN Interval_TO END), 0)),

           (COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
            COALESCE(MAX(CASE WHEN interval_month = 7 THEN Interval_TI END), 0) -
            COALESCE(MAX(CASE WHEN interval_month = 7 THEN Interval_TO END), 0)),

           (COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
            COALESCE(MAX(CASE WHEN interval_month = 13 THEN Interval_TI END), 0) -
            COALESCE(MAX(CASE WHEN interval_month = 13 THEN Interval_TO END), 0)),

           (COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
            COALESCE(MAX(CASE WHEN interval_month = 25 THEN Interval_TI END), 0) -
            COALESCE(MAX(CASE WHEN interval_month = 25 THEN Interval_TO END), 0))
    FROM SummaryCounts

    UNION ALL

    SELECT 'E. Mothers Alive and on ART',
           0,
           COALESCE(MAX(CASE WHEN interval_month = 4 THEN Total_Active END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 7 THEN Total_Active END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 13 THEN Total_Active END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 25 THEN Total_Active END), 0)
    FROM SummaryCounts

    UNION ALL

    SELECT 'F. Lost to F/U',
           0,
           COALESCE(MAX(CASE WHEN interval_month = 4 THEN Total_LTFU END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 7 THEN Total_LTFU END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 13 THEN Total_LTFU END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 25 THEN Total_LTFU END), 0)
    FROM SummaryCounts

    UNION ALL

    SELECT 'G. Known Dead',
           0,
           COALESCE(MAX(CASE WHEN interval_month = 4 THEN Cumulative_Dead END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 7 THEN Cumulative_Dead END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 13 THEN Cumulative_Dead END), 0),
           COALESCE(MAX(CASE WHEN interval_month = 25 THEN Cumulative_Dead END), 0)
    FROM SummaryCounts

    UNION ALL

    SELECT 'H. % Alive and on ART (E/D)',
           0,
           COALESCE(CONCAT(ROUND((MAX(CASE WHEN interval_month = 4 THEN Total_Active END) /
                                  NULLIF((COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
                                          COALESCE(MAX(CASE WHEN interval_month = 4 THEN Interval_TI END), 0) -
                                          COALESCE(MAX(CASE WHEN interval_month = 4 THEN Interval_TO END), 0)), 0)) * 100,
                                 1), '%'), '0%'),

           COALESCE(CONCAT(ROUND((MAX(CASE WHEN interval_month = 7 THEN Total_Active END) /
                                  NULLIF((COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
                                          COALESCE(MAX(CASE WHEN interval_month = 7 THEN Interval_TI END), 0) -
                                          COALESCE(MAX(CASE WHEN interval_month = 7 THEN Interval_TO END), 0)), 0)) * 100,
                                 1), '%'), '0%'),

           COALESCE(CONCAT(ROUND((MAX(CASE WHEN interval_month = 13 THEN Total_Active END) /
                                  NULLIF((COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
                                          COALESCE(MAX(CASE WHEN interval_month = 13 THEN Interval_TI END), 0) -
                                          COALESCE(MAX(CASE WHEN interval_month = 13 THEN Interval_TO END), 0)), 0)) * 100,
                                 1), '%'), '0%'),

           COALESCE(CONCAT(ROUND((MAX(CASE WHEN interval_month = 25 THEN Total_Active END) /
                                  NULLIF((COALESCE(MAX(CASE WHEN interval_month = 0 THEN Total_Base END), 0) +
                                          COALESCE(MAX(CASE WHEN interval_month = 25 THEN Interval_TI END), 0) -
                                          COALESCE(MAX(CASE WHEN interval_month = 25 THEN Interval_TO END), 0)), 0)) * 100,
                                 1), '%'), '0%')
    FROM SummaryCounts;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ti_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ti_query;

~
CREATE PROCEDURE sp_fact_line_list_ti_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,

                             cervical_cancer_screening_status    AS CCS_ScreenDoneYes,

                             treatment_end_date,
                             weight_text_                        AS Weight,
                             height,
                             date_of_event                       AS date_hiv_confirmed,
                             transferred_in_check_this_for_all_t,
                             antiretroviral_art_dispensed_dose_i AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level     as adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                      where follow_up_date_followup_ <= COALESCE(REPORT_END_DATE, CURDATE()
                                                        )),

         first_follow_up as (select client_id,
                                    transferred_in_check_this_for_all_t,
                                    follow_up_date     as ti_follow_up_date,
                                    ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date ,
                                        encounter_id ) AS r_n
                             from FollowUp),
         ti_follow_up as (select client_id, ti_follow_up_date as follow_up_date
                          from first_follow_up
                          where r_n = 1
                            and transferred_in_check_this_for_all_t = 'Yes'
                            and ti_follow_up_date >= COALESCE(REPORT_START_DATE, CURDATE())
                            and ti_follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE()))
            ,

         tmp_last_follow_up AS (SELECT *,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date desc ,
                                           encounter_id desc ) AS row_num
                                FROM FollowUp),

         in_range_ti_follow_up AS (select *
                                   from tmp_last_follow_up
                                   where row_num = 1
                                     and follow_up_date >= COALESCE(REPORT_START_DATE, CURDATE()))


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)                                       AS `#`,
           client.patient_uuid                                                             as UUID,
           client.patient_name                                                             as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                                                    as `MRN`,
           CONCAT('''', client.uan)                                                        AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as Age,
           client.sex                                                                      as Sex,
           f_case.art_start_date                                                           as `ART Start Date EC.`,
           f_case.art_start_date                                                           as `ART Start Date GC.`,
           ti.follow_up_date                                                               as `Follow Up Date (Date
of TI) EC.`,
           ti.follow_up_date                                                               as `Follow Up Date (Date of TI) GC.`,
           CASE f_case.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                                                         AS `Latest Follow Up Status`,
           f_case.regimen                                                                  as `Last ARV Regimen`,
           f_case.art_dose_days                                                            as `Last ART Dose Days`,
           f_case.adherence                                                                as `Adherence Level`,
           f_case.treatment_end_date                                                       as `Next Visit Date EC.`,
           f_case.treatment_end_date                                                       as `Next Visit Date GC.`
    FROM in_range_ti_follow_up AS f_case
             inner JOIN mamba_dim_client client on
        f_case.client_id = client.client_id
             inner join ti_follow_up as ti on ti.client_id = f_case.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_to_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_to_query;

~
CREATE PROCEDURE sp_fact_line_list_to_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,

                             cervical_cancer_screening_status    AS CCS_ScreenDoneYes,

                             treatment_end_date,
                             weight_text_                        AS Weight,
                             height,
                             date_of_event                       AS date_hiv_confirmed,

                             antiretroviral_art_dispensed_dose_i AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level     as adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                      where follow_up_date_followup_ <= COALESCE(REPORT_END_DATE, CURDATE()
                                                        )),


         tmp_first_follow_up AS (SELECT *,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC ,
                                            encounter_id DESC) AS row_num
                                 FROM FollowUp),

         first_follow_up AS (select *
                             from tmp_first_follow_up
                             where row_num = 1),

         temp_second_none_to_follow_up AS (select *,
                                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC,
                                                      encounter_id DESC) AS r_n
                                           from tmp_first_follow_up
                                           where follow_up_status <> 'Transferred out'),

         in_range_to_follow_up as (select *
                                   from first_follow_up
                                   where follow_up_status = 'Transferred out'
                                     and follow_up_date >= COALESCE
                                                           (REPORT_START_DATE, CURDATE())),

         second_none_to_follow_up AS (select *
                                      from temp_second_none_to_follow_up
                                      where r_n = 1)


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)                                       AS `#`,
           client.patient_uuid                                                             as UUID,
           client.patient_name                                                             as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                                                    as `MRN`,
           CONCAT('''', client.uan)                                                        AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as Age,
           client.sex                                                                      as Sex,
           second_none.art_start_date                                                      as `ART Start Date EC.`,
           second_none.art_start_date                                                      as `ART Start Date GC.`,
           f_case.follow_up_date                                                           as `Follow Up
Date (Date of TI) EC.`,
           f_case.follow_up_date                                                           as `Follow Up Date
(Date of TI) GC.`,
           CASE f_case.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                                                         AS `Latest Follow Up Status`,
           second_none.regimen                                                             as `Last ARV Regimen`,
           second_none.art_dose_days                                                       as `Last ART Dose Days`,
           second_none.adherence                                                           as `Adherence Level`,
           second_none.treatment_end_date                                                  as `Next Visit Date EC.`,
           second_none.treatment_end_date                                                  as `Next Visit Date GC.`
    FROM in_range_to_follow_up AS f_case
             inner JOIN mamba_dim_client client on f_case.client_id = client.client_id
             left JOIN second_none_to_follow_up second_none
                       ON f_case.client_id = second_none.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_post_exposure_query
--

DELIMITER //
DROP PROCEDURE IF EXISTS sp_fact_line_list_post_exposure_query;
~
CREATE PROCEDURE sp_fact_line_list_post_exposure_query(IN REPORT_START_DATE DATE,
                                                       IN REPORT_END_DATE DATE)
BEGIN
    WITH post_information AS (select encounter_id,
                                     ps.reporting_date,
                                     ps.client_id,
                                     occupation_retired,
                                     exposure_duration,
                                     exposure_type,
                                     exposure_code,
                                     exposed_person,
                                     source_of_exposure,
                                     source_person,
                                     eligible,
                                     ps.postexposure_prophylaxis_regimen,
                                     time_between_exposure_and_pep_in_hours,
                                     case_team
                              FROM mamba_flat_encounter_exposed_person_information as ps
                              WHERE ps.reporting_date >= COALESCE(REPORT_START_DATE, CURDATE())
                                AND ps.reporting_date <= COALESCE(REPORT_END_DATE, CURDATE()))
            ,
         latest_name AS (SELECT person_id,
                                prefix,
                                given_name,
                                middle_name,
                                family_name
                         FROM (SELECT *,
                                      ROW_NUMBER() OVER (PARTITION BY person_id ORDER BY person_name_id DESC) AS row_num
                               FROM mamba_dim_person_name
                               WHERE preferred = 1
                                 AND voided = 0) AS pn
                         WHERE row_num = 1),
         latest_address AS (SELECT person_id,
                                   state_province,
                                   county_district,
                                   city_village
                            FROM (SELECT *,
                                         ROW_NUMBER() OVER (PARTITION BY person_id ORDER BY person_address_id DESC) AS row_num
                                  FROM mamba_dim_person_address
                                  WHERE preferred = 1
                                    AND voided = 0) AS p_addr
                            WHERE row_num = 1),
         person_identifiers AS (SELECT patient_id,
                                       MAX(CASE WHEN identifier_type = 5 THEN identifier END) AS MRN,
                                       MAX(CASE WHEN identifier_type = 6 THEN identifier END) AS UAN
                                FROM mamba_dim_patient_identifier
                                GROUP BY patient_id),
         person_attributes AS (SELECT person_id,
                                      MAX(CASE WHEN person_attribute_type_id = 26 THEN value END) AS mobile_no,
                                      MAX(CASE WHEN person_attribute_type_id = 16 THEN value END) AS phone_no,
                                      MAX(CASE WHEN person_attribute_type_id = 25 THEN value END) AS key_population,
                                      MAX(CASE WHEN person_attribute_type_id = 5 THEN value END)  AS marital_status,
                                      MAX(CASE WHEN person_attribute_type_id = 24 THEN value END) AS education_level,
                                      MAX(CASE WHEN person_attribute_type_id = 11 THEN value END) AS house_number,
                                      MAX(CASE WHEN person_attribute_type_id = 12 THEN value END) AS kebele
                               FROM mamba_dim_person_attribute
                               GROUP BY person_id),
         client_list as (SELECT p.person_id,
                                p.person_name_long,
                                pn.prefix,
                                pn.given_name,
                                pn.middle_name,
                                pn.family_name,
                                pid.MRN,
                                pid.UAN,
                                p.uuid,
                                fn_mamba_age_calculator(p.birthdate, CURDATE()) AS current_age,
                                pa.mobile_no,
                                pa.phone_no,
                                p.birthdate,
                                CASE
                                    WHEN p.gender = 'F' THEN 'Female'
                                    WHEN p.gender = 'M' THEN 'Male'
                                    END                                         AS gender,
                                pa_addr.state_province,
                                pa_addr.county_district,
                                pa_addr.city_village,
                                pa.key_population,
                                pa.marital_status,
                                pa.education_level,
                                pa.house_number,
                                pa.kebele,
                                mag_normal.normal_agegroup                      AS coarse_age_group,
                                mag_datim.datim_agegroup                        AS fine_age_group
                         FROM mamba_dim_person p
                                  LEFT JOIN latest_name pn ON p.person_id = pn.person_id
                                  LEFT JOIN latest_address pa_addr ON p.person_id = pa_addr.person_id
                                  LEFT JOIN person_identifiers pid ON p.person_id = pid.patient_id
                                  LEFT JOIN person_attributes pa ON p.person_id = pa.person_id
                                  LEFT JOIN mamba_dim_agegroup mag_normal
                                            ON fn_mamba_age_calculator(p.birthdate, CURDATE()) = mag_normal.age
                                  LEFT JOIN mamba_dim_agegroup mag_datim
                                            ON fn_mamba_age_calculator(p.birthdate, CURDATE()) = mag_datim.age
                         WHERE pn.person_id IS NOT NULL),

         tmp_latest_reported AS (SELECT p.*,
                                        ROW_NUMBER() OVER (PARTITION BY p.client_id ORDER BY reporting_date DESC, encounter_id DESC) AS row_num
                                 FROM post_information as p
                                          join client_list client on p.client_id = client.person_id),
         latest_peported AS (select *
                             from tmp_latest_reported
                             where row_num = 1),
         2_weeks_follow_up as (select f.client_id,
                                      f.anitiretroviral_adherence_level,
                                      f.medication_side_effect,
                                      f.final_post_pep_hiv_status,
                                      f.visit_period
                               from mamba_flat_encounter_post_exposure_foll as f
                                        inner join latest_peported as p on p.client_id = f.client_id
                                   and f.reporting_date = p.reporting_date
                               where f.visit_period in ('2 weeks'))
            ,
         4_weeks_follow_up as (select f.client_id,
                                      f.anitiretroviral_adherence_level,
                                      f.medication_side_effect,
                                      f.final_post_pep_hiv_status,
                                      f.visit_period
                               from mamba_flat_encounter_post_exposure_foll as f
                                        inner join latest_peported as p on p.client_id = f.client_id
                                   and f.reporting_date = p.reporting_date
                               where f.visit_period in ('4 weeks')),
         6_weeks_follow_up as (select f.client_id,
                                      f.anitiretroviral_adherence_level,
                                      f.medication_side_effect,
                                      f.final_post_pep_hiv_status,
                                      f.visit_period
                               from mamba_flat_encounter_post_exposure_foll as f
                                        inner join latest_peported as p on p.client_id = f.client_id
                                   and f.reporting_date = p.reporting_date
                               where f.visit_period in ('6 weeks')),
         3_months_follow_up as (select f.client_id,
                                       f.anitiretroviral_adherence_level,
                                       f.medication_side_effect,
                                       f.final_post_pep_hiv_status,
                                       f.visit_period
                                from mamba_flat_encounter_post_exposure_foll as f
                                         inner join latest_peported as p on p.client_id = f.client_id
                                    and f.reporting_date = p.reporting_date
                                where f.visit_period in ('3 months')),
         6_months_follow_up as (select f.client_id,
                                       f.anitiretroviral_adherence_level,
                                       f.medication_side_effect,
                                       f.final_post_pep_hiv_status,
                                       f.visit_period
                                from mamba_flat_encounter_post_exposure_foll as f
                                         inner join latest_peported as p on p.client_id = f.client_id
                                    and f.reporting_date = p.reporting_date
                                where f.visit_period in ('6 months'))


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                            AS UAN,

           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.occupation_retired                           as `Occupation Retired`,
           f_case.case_team                                    as `Department/Case Team`,
           f_case.reporting_date                               as `Reporting Date EC.`,
           f_case.reporting_date                               as `Reporting Date GC.`,
           f_case.exposure_duration                            as `Exposure Duration (in hours)`,
           f_case.exposure_type                                as `Exposure Type`,
           f_case.exposure_code                                as `Exposure Code`,
           f_case.source_person                                as `Source Person HIV Status`,
           f_case.exposed_person                               as `Exposed Person HIV Status`,
           f_case.source_of_exposure                           as `Source of Exposure`,
           f_case.eligible                                     as `Eligible for PEP?`,
           f_case.postexposure_prophylaxis_regimen             as `ARV (PEP) Regimen`,
           f_case.time_between_exposure_and_pep_in_hours       as `Time Between Exposure and PEP (in hours)`,

           two_weeks.visit_period                              as `Follow-Up Visit Date (at 2WK) EC.`,
           two_weeks.visit_period                              as `Follow-Up Visit Date (at 2WK) GC.`,
           two_weeks.anitiretroviral_adherence_level           as `Adherence  (at 2WK)`,
           two_weeks.medication_side_effect                    as ` Side Effect (at 2WK)`,
           two_weeks.final_post_pep_hiv_status                 as `Exposed client HIV Status (at 2WK)`,

           four_weeks.visit_period                             as `Follow-Up Visit Date (at 4WK) EC.`,
           four_weeks.visit_period                             as `Follow-Up Visit Date (at 4WK) GC.`,
           four_weeks.anitiretroviral_adherence_level          as `Adherence  (at 4WK)`,
           four_weeks.medication_side_effect                   as ` Side Effect (at 4WK)`,
           four_weeks.final_post_pep_hiv_status                as `Exposed client HIV Status (at 4WK)`,

           six_weeks.visit_period                              as `Follow-Up Visit Date (at 6WK) EC.`,
           six_weeks.visit_period                              as `Follow-Up Visit Date (at 6WK) GC.`,
           six_weeks.anitiretroviral_adherence_level           as `Adherence  (at 6WK)`,
           six_weeks.medication_side_effect                    as ` Side Effect (at 6WK)`,
           six_weeks.final_post_pep_hiv_status                 as `Exposed client HIV Status (at 6WK)`,

           three_months.visit_period                           as `Follow-Up Visit Date (at 3M) EC.`,
           three_months.visit_period                           as `Follow-Up Visit Date (at 3M) GC.`,
           three_months.anitiretroviral_adherence_level        as `Adherence  (at 3M)`,
           three_months.medication_side_effect                 as ` Side Effect (at 3M)`,
           three_months.final_post_pep_hiv_status              as `Exposed client HIV Status (at 3M)`,

           six_months.visit_period                             as `Follow-Up Visit Date (at 6M) EC.`,
           six_months.visit_period                             as `Follow-Up Visit Date (at 6M) GC.`,
           six_months.anitiretroviral_adherence_level          as `Adherence  (at 6M)`,
           six_months.medication_side_effect                   as ` Side Effect (at 6M)`,
           six_months.final_post_pep_hiv_status                as `Exposed client HIV Status (at 6M)`

    FROM latest_peported AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
             Left JOIN 2_weeks_follow_up as two_weeks
                       ON f_case.client_id = two_weeks.client_id
             Left JOIN 4_weeks_follow_up as four_weeks
                       ON f_case.client_id = four_weeks.client_id
             Left JOIN 6_weeks_follow_up as six_weeks
                       ON f_case.client_id = six_weeks.client_id
             Left JOIN 3_months_follow_up as three_months
                       ON f_case.client_id = three_months.client_id
             Left JOIN 6_months_follow_up as six_months
                       ON f_case.client_id = six_months.client_id

    ORDER BY client.patient_name;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_pre_exposure_query
--

DELIMITER //
DROP PROCEDURE IF EXISTS sp_fact_line_list_pre_exposure_query;
~
CREATE PROCEDURE sp_fact_line_list_pre_exposure_query(IN REPORT_END_DATE DATE)
BEGIN
    WITH PreExposure AS (select screening.client_id,
                                screening.encounter_id,
                                screening.encounter_datetime,
                                screening.sex_worker,
                                screening.prep_started,
                                screening.type_of_client,
                                screening_1.treatment_start_date,
                                screening_1.do_you_have_an_hiv_positive_partner,
                                screening_1.antiretroviral_art_dispensed_dose_in_days                         as screened_dose,
                                follow_up.pregnancy_status                                                    as f_pregnancy_status,
                                follow_up_1.prep_dose_end_date,
                                screening.screening_date,
                                final_hiv_test_result,
                                prep_antiretrovirals_prescribed                                               as regimen_screened,
                                screening.prep_dose_end_date                                                  as screened_dose_end_date,
                                currently_breastfeeding_child,
                                preexposure_prophylaxis_prep_regimen                                          as regimen,
                                referred_from,
                                service_delivery_point_number,
                                followup_date_followup_1                                                      as follow_up_date,
                                screened_for_tuberculosis,
                                screening_1.screen_result_for_sti,
                                follow_up_1.chronic_kidney_disease_stage                                      AS EGFR,
                                contraindications_to_prep_medicines,
                                preexposure_prophylaxis_provision_site,
                                reason_for_stopping_adherence                                                 as reason_for_stopping,
                                follow_up_1.method_of_family_planning,
                                hiv_side_effects                                                              as side_effects,
                                next_visit_date,
                                number_of_missed_tablets_in_the_past_30_days,
                                CASE
                                    WHEN follow_up_status = 'Alive' THEN 'On PrEP'
                                    ELSE follow_up_status END                                                 as follow_up_status
                         FROM mamba_flat_encounter_pre_exposure_scree screening
                                  left join mamba_flat_encounter_pre_exposure_scree_1 screening_1
                                            on screening.encounter_id = screening_1.encounter_id
                                  LEFT JOIN mamba_flat_encounter_pre_exposure_follo follow_up
                                            on screening.client_id = follow_up.client_id
                                  LEFT JOIN mamba_flat_encounter_pre_exposure_follo_1 follow_up_1
                                            on follow_up.encounter_id = follow_up_1.encounter_id),
         tmp_latest_follow_up as (select prep_dose_end_date,
                                         prep_started,
                                         date_of_birth,
                                         sex,
                                         patient_uuid,
                                         mrn,
                                         uan,
                                         do_you_have_an_hiv_positive_partner,
                                         sex_worker,
                                         treatment_start_date,
                                         patient_name,
                                         screening_date,
                                         follow_up_status,
                                         final_hiv_test_result,
                                         type_of_client,
                                         currently_breastfeeding_child,
                                         client.client_id,
                                         screen_result_for_sti,
                                         next_visit_date,
                                         contraindications_to_prep_medicines,
                                         referred_from,
                                         side_effects,
                                         screened_dose_end_date,
                                         regimen,
                                         preexposure_prophylaxis_provision_site,
                                         f_pregnancy_status,
                                         method_of_family_planning,
                                         reason_for_stopping,
                                         service_delivery_point_number,
                                         number_of_missed_tablets_in_the_past_30_days,
                                         screened_for_tuberculosis,
                                         EGFR,
                                         regimen_screened,
                                         screened_dose,
                                         follow_up_date,
                                         ROW_NUMBER() OVER (
                                             PARTITION BY PreExposure.client_id
                                             ORDER BY
                                                 CASE
                                                     WHEN PreExposure.follow_up_date IS NULL THEN 1
                                                     ELSE 0
                                                     END,
                                                 PreExposure.follow_up_date DESC,
                                                 PreExposure.encounter_id DESC
                                             ) AS row_num
                                  from PreExposure
                                           join mamba_dim_client client on PreExposure.client_id = client.client_id
                                  where (follow_up_date <= REPORT_END_DATE
                                      or follow_up_date is null)),
         prep as (select * from tmp_latest_follow_up where row_num = 1)


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           patient_uuid                                        as `Patient GUID`,
           patient_name                                        as `Patient Name`,
           CAST(mrn AS CHAR(20))                               as MRN,
           uan                                                 AS UAN,

           TIMESTAMPDIFF(YEAR, date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           sex                                                 as Sex,
           prep.service_delivery_point_number                  as `UIC`,
           prep.screening_date                                 as `PrEP Screening Date in EC.`,
           prep.screening_date                                 as `PrEP Screening Date in GC.`,
           prep.prep_started                                   as `PrEP Started?`,
           prep.treatment_start_date                           as `PrEP Start Date in EC.`,
           prep.treatment_start_date                           as `PrEP Start Date in G.C`,
           prep.type_of_client                                 as `Type of Client`,
           prep.follow_up_date                                 as `PrEP Follow Up Date in EC.`,
           prep.follow_up_date                                 as `PrEP Follow Up Date in GC.`,
           prep.follow_up_status                               as `PrEP Follow Up Status`,
           case
               when prep.regimen is not null then prep.regimen
               else prep.regimen_screened end                  as `PrEP Regimen`,
           prep.number_of_missed_tablets_in_the_past_30_days   as `Missed Tablets`,
           prep.next_visit_date                                as `Next Visit Date in EC.`,
           prep.next_visit_date                                as `Next Visit Date in GC.`,
           case
               when prep.prep_dose_end_date is not null then prep.screened_dose_end_date
               else prep.screened_dose end                     as `Dose End Date in EC.`,
           case
               when prep.prep_dose_end_date is not null then prep.screened_dose_end_date
               else prep.screened_dose end                     as `Dose End Date in GC.`,
           prep.final_hiv_test_result                          as `HIV Test Final Result`,
           prep.f_pregnancy_status                             as `Pregnant?`,
           prep.currently_breastfeeding_child                  as `Breastfeeding?`,
           prep.method_of_family_planning                      as `Family Planning Method`,
           prep.screened_for_tuberculosis                      as `TB Screening Result`,
           prep.screen_result_for_sti                          as `STI Screening Result`,
           prep.EGFR                                           as `eGFR Estimate`,
           prep.side_effects                                   as `Side Effects`,
           prep.reason_for_stopping                            as `Reason to stop PrEP`,
           prep.contraindications_to_prep_medicines            as `Contraindications to PrEP Medicines`,
           prep.sex_worker                                     as `Self-Identifying WECSW`,
           prep.do_you_have_an_hiv_positive_partner            as `Have HIV+ Partner?`,
           prep.preexposure_prophylaxis_provision_site         as `PrEP Provision Site`,
           prep.referred_from                                  as `Referred From`

    FROM prep;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_positive_tracking_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_positive_tracking_query;

~
CREATE PROCEDURE sp_fact_line_list_positive_tracking_query(IN REPORT_START_DATE DATE,
                                                           IN REPORT_END_DATE DATE)
BEGIN

WITH FollowUp AS (select follow_up.encounter_id,
                         follow_up.client_id,
                         CASE follow_up_status
                             WHEN 'Alive' THEN 'Alive on ART'
                             WHEN 'Restart medication' THEN 'Restart'
                             WHEN 'Transferred out' THEN 'TO'
                             WHEN 'Stop all' THEN 'Stop'
                             WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                             WHEN 'Ran away' THEN 'Drop'
                             END                             as follow_up_status,
                         follow_up_date_followup_            as follow_up_date,
                         art_antiretroviral_start_date       as art_start_date,
                         height,
                         current_who_hiv_stage,
                         cd4_count,
                         follow_up_2.weight_text_            as weight,
                         antiretroviral_art_dispensed_dose_i AS art_dose_days,
                         regimen,
                         anitiretroviral_adherence_level     as adherence,
                         next_visit_date,
                         treatment_end_date
                  FROM mamba_flat_encounter_follow_up follow_up
                           LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                     ON follow_up.encounter_id = follow_up_1.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                     ON follow_up.encounter_id = follow_up_2.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                     ON follow_up.encounter_id = follow_up_3.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                     ON follow_up.encounter_id = follow_up_4.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                     ON follow_up.encounter_id = follow_up_5.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                     ON follow_up.encounter_id = follow_up_6.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                     ON follow_up.encounter_id = follow_up_7.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                     ON follow_up.encounter_id = follow_up_8.encounter_id
                           LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                     ON follow_up.encounter_id = follow_up_9.encounter_id
                           LEFT JOIN mamba_flat_encounter_registration reg
                                     ON reg.client_id = follow_up.client_id),

     tmp_positive_tracking as (select p_tracking.date_when_final_outcome_was_known   as date_final_outcome_known,
                                      p_tracking.client_id,
                                      p_tracking.date_of_hiv_diagnosis               as date_hiv_confirmed,
                                      p_tracking.entry_point                         as entry_point,
                                      p_tracking.linked_to_hiv_care                  as linked_to_treatment,
                                      p_tracking.date_linked_to_hiv_care             as linked_to_treatment_date,
                                      p_tracking.reason_art_not_started_the_same_day as reason_art_not_started,
                                      p_tracking.plan_for_next_step                  as plan_for_next_step,
                                      p_tracking.final_outcome_known,
                                      p_tracking.final_outcome,
                                      p_tracking.date_enrolled_in_care               as registration_date,
                                      ROW_NUMBER()                                      OVER (PARTITION BY p_tracking.client_id ORDER BY date_enrolled_in_care DESC,
                                              encounter_id DESC) AS row_num
                               FROM mamba_flat_encounter_positive_tracking p_tracking
                               WHERE p_tracking.date_enrolled_in_care >= COALESCE
                                                                         (REPORT_START_DATE, CURDATE())
                                 AND p_tracking.date_enrolled_in_care <= COALESCE
                                                                         (REPORT_END_DATE, CURDATE())),
     positive_tracking as (select * from tmp_positive_tracking where row_num = 1),


     tmp_latest_follow_up AS (SELECT f.*,
                                     ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                              FROM FollowUp as f
                              WHERE follow_up_date <= COALESCE
                                                      (REPORT_END_DATE, CURDATE())),


     latest_follow_up AS (select *
                          from tmp_latest_follow_up
                          where row_num = 1)


SELECT ROW_NUMBER()                                                                       OVER (ORDER BY patient_name)                                       as `#`, client.patient_uuid as `Patient GUID`,
       client.patient_name                                                             as `Patient Name`,
       CAST(client.mrn AS
           CHAR(20))                                                                   as MRN,
       CONCAT('''', client.uan)                                                        AS UAN,
       TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
       client.sex                                                                      as Sex,
       p_tracking.registration_date                                                    as `Registration Date in EC.`,
       p_tracking.registration_date                                                    as `Registration Date in G.C.`,
       p_tracking.date_hiv_confirmed                                                   as `Date Tested HIV +ve in EC.`,
       p_tracking.date_hiv_confirmed                                                   as `Date Tested HIV +ve in G.C.`,
       p_tracking.entry_point                                                          as `Entry Point`,
       p_tracking.date_hiv_confirmed                                                   as `HIV Confirmed Date in EC.`,
       p_tracking.date_hiv_confirmed                                                   as `HIV Confirmed Date in G.C.`,
       f_case.art_start_date                                                           as `ART Start Date EC.`,
       f_case.art_start_date                                                           as `ART Start Date G.C`,
       TIMESTAMPDIFF(YEAR, f_case.art_start_date,
                           COALESCE(date_hiv_confirmed, CURDATE()))                    as `Days Difference`,
       p_tracking.linked_to_treatment                                                  as `Linked to Care & Treatment?`,
       p_tracking.linked_to_treatment_date                                             as `Date Linked to Care & Treatment in EC.`,
       p_tracking.linked_to_treatment_date                                             as `Date Linked to Care & Treatment in G.C.`,
       p_tracking.reason_art_not_started                                               as `Reason for not Starting ART the same day`,
       p_tracking.plan_for_next_step                                                   as `Plan for Next Step`,
       p_tracking.final_outcome_known                                                  as `Final Outcome Known?`,
       p_tracking.date_final_outcome_known                                             as `Date Linked to Care & Treatment in EC.`,
       p_tracking.date_final_outcome_known                                             as `Date Linked to Care & Treatment in G.C.`,
       p_tracking.final_outcome                                                        as `Final Outcome`,
       client.mobile_no                                                                as `Mobile Phone Number`
FROM positive_tracking AS p_tracking
         LEFT JOIN latest_follow_up f_case ON p_tracking.client_id = f_case.client_id
         INNER JOIN mamba_dim_client client
                    on p_tracking.client_id = client.client_id
ORDER BY client.patient_name;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_schedule_visit_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_schedule_visit_query;

~
CREATE PROCEDURE sp_fact_line_list_schedule_visit_query(IN REPORT_START_DATE DATE,
                                                        IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Drop'
                                 END                             as follow_up_status,
                             follow_up_date_followup_            as follow_up_date,
                             art_antiretroviral_start_date       as art_start_date,
                             height,
                             mfeia.date_hiv_confirmed            as date_hiv_confirmed,
                             current_who_hiv_stage,
                             cd4_count,
                             follow_up_2.weight_text_            as weight,
                             antiretroviral_art_dispensed_dose_i AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level     as adherence,
                             next_visit_date,
                             treatment_end_date
                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id
                      WHERE follow_up_status in ('Alive', 'Restart medication')
                        AND follow_up_date_followup_ <= COALESCE
                                                        (REPORT_END_DATE, CURDATE()))
            ,


         tmp_latest_follow_up AS (SELECT f.*,
                                         ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp as f),


         dedup_follow_up AS (select *
                             from tmp_latest_follow_up
                             where row_num = 1),
         latest_follow_up As (SELECT *
                              FROM dedup_follow_up
                              WHERE next_visit_date >= COALESCE(REPORT_START_DATE, CURDATE())
                                AND next_visit_date <= COALESCE(REPORT_END_DATE, CURDATE()))


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                            AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.treatment_end_date                           as `Last TX_Curr Date`,
           f_case.treatment_end_date                           as `Last TX_Curr Date EC.`,
           f_case.next_visit_date                              as `Appointment Date EC.`,
           f_case.next_visit_date                              as `Appointment Date G.C.`,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           client.mobile_no                                    as `Mobile Phone Number.`,
           f_case.follow_up_date                               as `Latest Follow-Up Date EC.`,
           f_case.follow_up_date                               as `Latest Follow-Up Date G.C.`,
           f_case.follow_up_status                             AS `Latest Follow-Up Status`,
           f_case.regimen                                      as `Latest Regimen`,
           f_case.art_dose_days                                as `Latest ARV Dose Days`,
           f_case.adherence                                    as `Latest Adherence`,
           f_case.weight                                       as `Weight`,
           client.mobile_no                                    as `Mobile Phone Number`
    FROM latest_follow_up AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
    ORDER BY client.patient_name;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_art_retention_query
--

DELIMITER //
DROP PROCEDURE IF EXISTS sp_fact_line_list_art_retention_query;
~
CREATE PROCEDURE sp_fact_line_list_art_retention_query(IN REPORT_START_DATE DATE,
                                                       IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             height,
                             date_of_event            as date_hiv_confirmed,
                             follow_up_2.weight_text_            as weight,
                             next_visit_date                     as next_vist_date,
                             date_enrolled_in_care         as enrollement_date,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Drop'
                                 END                             as follow_up_status,
                             antiretroviral_art_dispensed_dose_i as dose_day,
                             anitiretroviral_adherence_level     as adherence

                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),

         tmp_latest_follow_up AS (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         treatment_end_date,
                                         art_start_date,
                                         pregnancy_status,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
             --  AND follow_up_date <= REPORT_END_DATE

         ),
         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
         tmp_art_start_date_before_12_months as (SELECT encounter_id,
                                                        client_id,
                                                        follow_up_date                                                                             AS FollowupDate,
                                                        follow_up_status,
                                                        art_start_date,
                                                        treatment_end_date,
                                                        adherence,
                                                        dose_day,
                                                        next_vist_date,
                                                        date_hiv_confirmed,
                                                        regimen,
                                                        TIMESTAMPDIFF(MONTH, art_start_date, follow_up_date)                                       as months_on_art,
                                                        pregnancy_status,
                                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                                 FROM FollowUp
                                                 WHERE follow_up_status IS NOT NULL
                                                   AND art_start_date IS NOT NULL
                                                   AND art_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(
                                                         fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                         INTERVAL -12 MONTH))
                                                   AND art_start_date <= fn_ethiopian_to_gregorian_calendar(date_add(
                                                         fn_gregorian_to_ethiopian_calendar(REPORT_END_DATE, 'Y-M-D'),
                                                         INTERVAL -12 MONTH))
             --  AND follow_up_date <= REPORT_END_DATE
         ),
         art_start_date_before_12_months as (select curr.client_id,
                                                    curr.FollowupDate,
                                                    curr.follow_up_status,
                                                    curr.pregnancy_status,
                                                    client.date_of_birth,
                                                    client.sex,
                                                    date_hiv_confirmed,
                                                    next_vist_date,
                                                    adherence,
                                                    curr.treatment_end_date,
                                                    dose_day,
                                                    regimen,
                                                    curr.art_start_date
                                             from tmp_art_start_date_before_12_months as curr
                                                      join mamba_dim_client client on curr.client_id = client.client_id
                                                      join latest_follow_up latest_follow_up
                                                           on curr.client_id = latest_follow_up.client_id
                                             where curr.row_num = 1
                                               and latest_follow_up.follow_up_status != 'Transferred out')

    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                                          AS UAN,

           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.date_hiv_confirmed                           as `HIV Confirmed Date EC.`,
           f_case.date_hiv_confirmed                           as `HIV Confirmed Date GC.`,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           case
               when fn_get_ti_status
                    (f_case.client_id, REPORT_START_DATE,
                     REPORT_END_DATE) = 'TI' then 'Yes'
               else '' end                                     as `TI?`,
           f_case.FollowupDate                               as `Last Follow Up Date EC.`,
           f_case.FollowupDate                               as `Last Follow Up Date G.C.`,
           f_case.follow_up_status                             as `Latest Follow Up Status`,
           f_case.regimen                                      as `Latest Regimen`,
           f_case.dose_day                                     as `Latest ARV Dose Days`,
           f_case.adherence                                    as `Latest Adherence`,
           f_case.pregnancy_status                             as `Pregnant`,
           f_case.next_vist_date                               as `Next Visit Date EC.`,
           f_case.next_vist_date                               as `Next Visit Date G.C.`,
           f_case.treatment_end_date                           as `Last TX_Curr Date EC.`,
           f_case.treatment_end_date                           as `Last TX_Curr Date G.C.`

    FROM art_start_date_before_12_months AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id

    ORDER BY client.patient_name;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_tbt_denominator_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_tbt_denominator_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_tbt_denominator_query(IN REPORT_START_DATE DATE,
                                                            IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child       AS breast_feeding_status,
                             pregnancy_status,
                             was_the_patient_screened_for_tuberc AS tb_screened,
                             tb_screening_date,
                             tb_treatment_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             date_started_on_tuberculosis_prophy AS tpt_start_date,
                             screening_test_result_tuberculosis  AS screening_result,
                             lf_lam_result,
                             patient_diagnosed_with_active_tuber,
                             diagnosis_date                      AS active_tb_diagnosed_date,
                             tuberculosis_drug_treatment_start_d AS tb_treatment_start_date,
                             eligibility_status,
                             tb_prophylaxis_type                 AS tpt_type,
                             adherence                           AS tpt_adherence,
                             tpt_dispensed_dose_in_days_inh_     AS tpt_dosday_type,
                             date_discontinued_tuberculosis_prop AS tpt_discontinue_date,
                             date_of_event                       AS date_hiv_confirmed,
                             date_completed_tuberculosis_prophyl AS tpt_completed_date,
                             weight_text_                        AS weight,
                             tpt_followup_6h_                    AS tpt_followup_status,
                             antiretroviral_art_dispensed_dose_i,
                             adherence                           AS arv_adherence -- FIXED: Aliased to prevent duplicate column error
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),

         tmp_tpt_start as (select client_id,
                                  tpt_start_date,
                                  art_start_date,
                                  tpt_type,
                                  tpt_followup_status, -- FIXED: Removed "follow_up_status as" overwrite
                                  tpt_dosday_type,
                                  tpt_adherence,
                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_start_date DESC, FollowUp.encounter_id DESC) AS row_num
                           from FollowUp
                           where tpt_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(
                                   fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -6 MONTH))
                             AND tpt_start_date < REPORT_START_DATE),

         tpt as (select *
                 from tmp_tpt_start
                 where row_num = 1),

         tmp_latest_follow_up AS (SELECT *,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS r_n
                                  FROM FollowUp
                                  where follow_up_date < REPORT_END_DATE),

         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where r_n = 1),

         tpt_events AS (SELECT client_id,
                               tpt_completed_date,
                               ROW_NUMBER() OVER (
                                   PARTITION BY client_id
                                   ORDER BY CASE WHEN tpt_completed_date IS NOT NULL THEN 0 ELSE 1 END, tpt_completed_date DESC )     AS rn_completed,
                               tpt_discontinue_date,
                               ROW_NUMBER() OVER (
                                   PARTITION BY client_id
                                   ORDER BY CASE WHEN tpt_discontinue_date IS NOT NULL THEN 0 ELSE 1 END, tpt_discontinue_date DESC ) AS rn_discontinued
                        FROM FollowUp
                        WHERE follow_up_date < REPORT_END_DATE
                          AND (tpt_completed_date IS NOT NULL OR tpt_discontinue_date IS NOT NULL)
         )

    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                                          AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.date_hiv_confirmed                           as `Hiv Confirmed Date in EC.`,
           f_case.date_hiv_confirmed                           as `Hiv Confirmed Date in G.C.`,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           tpt.tpt_start_date                                  as `TPT Start Date in EC.`,
           tpt.tpt_start_date                                  as `TPT Start Date in G.C.`,
           tpt_completed.tpt_completed_date                    as `TPT Completed Date in EC.`,
           tpt_completed.tpt_completed_date                    as `TPT Completed Date in G.C.`,
           tpt_discontinued.tpt_discontinue_date               as `TPT Discontinued Date in EC.`,
           tpt_discontinued.tpt_discontinue_date               as `TPT Discontinued Date in G.C.`,
           tpt.tpt_type                                        as `TpT Type`,
           tpt.tpt_followup_status                             as `TPT Follow-up status`,
           tpt.tpt_dosday_type                                 as `TPT Dispensed Dose`,
           tpt.tpt_adherence                                   as `TPT Adherence`,
           f_case.follow_up_date                               as `Latest Follow-up Date in EC.`,
           f_case.follow_up_date                               as `Latest Follow-up Date in G.C.`,
           CASE f_case.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                             as `Latest Follow-up Status`,
           f_case.regimen                                      as `Latest Regimen`,
           f_case.antiretroviral_art_dispensed_dose_i          as `Latest ARV Dose Days`,
           f_case.arv_adherence                                as `Latest Adherence`,
           f_case.next_visit_date                              as `Next Visit Date in EC.`,
           f_case.next_visit_date                              as `Next Visit Date in G.C.`,
           CASE
               WHEN fn_get_ti_status(f_case.client_id, REPORT_START_DATE, REPORT_END_DATE) = 'TI' THEN 'YES'
               ELSE 'NO' END                                  as `TI?`

    FROM latest_follow_up AS f_case
             INNER JOIN tpt on f_case.client_id = tpt.client_id
             LEFT JOIN tpt_events tpt_completed on tpt.client_id = tpt_completed.client_id and tpt_completed.rn_completed=1
             LEFT JOIN tpt_events tpt_discontinued on tpt.client_id = tpt_discontinued.client_id and tpt_discontinued.rn_discontinued=1
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_tbt_numerator_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_tbt_numerator_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_tbt_numerator_query(IN REPORT_START_DATE DATE,
                                                          IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             was_the_patient_screened_for_tuberc as tb_screened,
                             tb_screening_date,
                             tb_treatment_status,
                             transferred_in_check_this_for_all_t as transferred_in,
                             date_started_on_tuberculosis_prophy as tpt_start_date,
                             date_completed_tuberculosis_prophyl as tpt_completed_date,
                             screening_test_result_tuberculosis     screening_result,
                             lf_lam_result,
                             patient_diagnosed_with_active_tuber,
                             diagnosis_date                      as active_tb_diagnosed_date,
                             tuberculosis_drug_treatment_start_d as tb_treatment_start_date,
                             date_of_event                       as date_hiv_confirmed,
                             tb_prophylaxis_type                 as tpt_type,
                             tpt_followup_6h_                    as tpt_followup_status,
                             date_discontinued_tuberculosis_prop as tpt_discontinue_date,
                             tpt_dispensed_dose_in_days_inh_     as tpt_dosday_type,
                             adherence                           as tpt_adherence,
                             anitiretroviral_adherence_level,
                             antiretroviral_art_dispensed_dose_i
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         tmp_tpt_start as (select client_id,
                                  tpt_start_date,
                                  art_start_date,
                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_start_date DESC, FollowUp.encounter_id DESC) AS row_num
                           from FollowUp
                           where tpt_start_date >= fn_ethiopian_to_gregorian_calendar(date_add(
                                   fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -6 MONTH))
                             AND tpt_start_date < REPORT_START_DATE),
         tpt_started as (select tmp_tpt_start.*
                         from tmp_tpt_start
                         where row_num = 1),

         tmp_tpt_complete as (select client_id,
                                     tpt_completed_date,
                                     art_start_date,
                                     tpt_adherence,
                                     tpt_dosday_type,
                                     tpt_type,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_completed_date DESC, FollowUp.encounter_id DESC) AS row_num
                              from FollowUp
                              where tpt_completed_date >= fn_ethiopian_to_gregorian_calendar(date_add(
                                      fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'), INTERVAL -6
                                      MONTH))
                                AND tpt_completed_date < REPORT_END_DATE),
         tpt_completed as (select tmp_tpt_complete.*,
                                  tpt_started.tpt_start_date
                           from tmp_tpt_complete
                                    join tpt_started on tpt_started.client_id = tmp_tpt_complete.client_id
                           where tmp_tpt_complete.row_num = 1),

         tmp_latest_follow_up AS (SELECT *,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS r_n
                                  FROM FollowUp
                                  where follow_up_date < REPORT_END_DATE),

         tpt_events AS (SELECT client_id,
                               tpt_completed_date,
                               ROW_NUMBER() OVER (
                                   PARTITION BY client_id
                                   ORDER BY CASE WHEN tpt_completed_date IS NOT NULL THEN 0 ELSE 1 END, tpt_completed_date DESC )     AS rn_completed,
                               tpt_discontinue_date,
                               ROW_NUMBER() OVER (
                                   PARTITION BY client_id
                                   ORDER BY CASE WHEN tpt_discontinue_date IS NOT NULL THEN 0 ELSE 1 END, tpt_discontinue_date DESC ) AS rn_discontinued
                        FROM FollowUp
                        WHERE follow_up_date < REPORT_END_DATE
                          AND (tpt_completed_date IS NOT NULL OR tpt_discontinue_date IS NOT NULL)
         ),
         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where r_n = 1)

    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)                              as `#`,
           client.patient_uuid                                                    as `Patient GUID`,
           client.patient_name                                                    as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                                           as MRN,
           CONCAT('''', client.uan)                                                             AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE()))                    as `Age`,
           client.sex                                                             as Sex,
           date_hiv_confirmed                                                     as `Hiv Confirmed Date in EC.`,
           date_hiv_confirmed                                                     as `Hiv Confirmed Date in G.C.`,
           f_case.art_start_date                                                  as `ART Start Date EC.`,
           f_case.art_start_date                                                  as `ART Start Date G.C`,
           tpt_completed.tpt_start_date                                           as `TPT Start Date in EC.`,
           tpt_completed.tpt_start_date                                           as `TPT Start Date in G.C.`,
           tpt_completed.tpt_completed_date                                       as `TPT Completed Date in EC.`,
           tpt_completed.tpt_completed_date                                       as `TPT Completed Date in G.C.`,
           tpt_discontinued.tpt_discontinue_date                                            as `TPT Discontinued Date in EC.`,
           tpt_discontinued.tpt_discontinue_date                                            as `TPT Discontinued Date in G.C.`,
           tpt_completed.tpt_type                                                        as `TpT Type`,
           CASE f_case.tpt_followup_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                                                as `TPT Follow-up status`,
           tpt_completed.tpt_dosday_type                                          as `TPT Dispensed Dose`,
           tpt_completed.tpt_adherence                                            as `TPT Adherence`,
           f_case.follow_up_date                                                  as `Latest Follow-up Date in EC.`,
           f_case.follow_up_date                                                  as `Latest Follow-up Date in G.C.`,
           f_case.follow_up_status                                                as `Latest Follow-up Status`,
           f_case.regimen                                                         as `Latest Regimen`,
           f_case.antiretroviral_art_dispensed_dose_i                             as `Latest ARV Dose Days`,
           f_case.anitiretroviral_adherence_level                                 as `Latest Adherence`,
           f_case.next_visit_date                                                 as `Next Visit Date in EC.`,
           f_case.next_visit_date                                                 as `Next Visit Date in G.C.`,
           fn_get_ti_status(f_case.client_id, REPORT_START_DATE, REPORT_END_DATE) as `TI?`

    FROM latest_follow_up AS f_case
             INNER JOIN tpt_completed on f_case.client_id = tpt_completed.client_id
             LEFT JOIN tpt_events tpt_discontinued on f_case.client_id = tpt_discontinued.client_id AND tpt_discontinued.rn_discontinued=1
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id

    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_tb_art_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_tb_art_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_tb_art_query(IN REPORT_START_DATE DATE,
                                                   IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             was_the_patient_screened_for_tuberc as tb_screened,
                             tb_screening_date,
                             tb_treatment_status,
                             transferred_in_check_this_for_all_t as transferred_in,
                             date_started_on_tuberculosis_prophy,
                             screening_test_result_tuberculosis     screening_result,
                             lf_lam_result,
                             patient_diagnosed_with_active_tuber,
                             tb_diagnostic_test_result,
                             diagnostic_test                     as other_diagnostic_test,
                             gene_xpert_result,
                             diagnosis_date,
                             diagnosis_date                      as active_tb_diagnosed_date,
                             tuberculosis_drug_treatment_start_d as tb_treatment_start_date,
                             date_active_tbrx_completed,
                             date_active_tbrx_dc,
                             currently_taking_tuberculosis_proph,
                             specimen_sent_to_lab,
                             antiretroviral_art_dispensed_dose_i as art_dose_days,
                             date_active_tbrx_completed          as tb_treatment_completed_date,
                             date_active_tbrx_dc                 as tb_treatment_discontinued_date,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         tmp_latest_follow_up as (SELECT *,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= REPORT_END_DATE),
         tb_art as (select tmp_latest_follow_up.*,
                           sex,
                           date_of_birth,
                           mrn,
                           uan
                    from tmp_latest_follow_up
                             join mamba_dim_client client on client.client_id = tmp_latest_follow_up.client_id
                    where follow_up_status in ('Alive', 'Restart medication')
                      and row_num = 1
                      and art_start_date <= REPORT_END_DATE
                      and (active_tb_diagnosed_date <= REPORT_END_DATE OR tb_treatment_start_date <= REPORT_END_DATE)
                      and (
                        (date_active_tbrx_dc is null and date_active_tbrx_completed is null and
                         (DATE_ADD(tb_treatment_start_date, INTERVAL 1 YEAR) >= REPORT_END_DATE))
                            OR
                        (date_active_tbrx_completed > REPORT_END_DATE OR date_active_tbrx_dc > REPORT_END_DATE)
                        ))


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                                         AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           f_case.follow_up_date                               as `Follow-Up Date EC.`,
           f_case.follow_up_date                               as `Follow-Up Date G.C.`,
           f_case.follow_up_status                             AS `Follow-Up Status`,
           f_case.regimen                                      as `Regimen`,
           f_case.art_dose_days                                as `ARV Dose Days`,
           f_case.adherence                                    as ` Adherence`,
           f_case.pregnancy_status                                    as `Pregnant?`,
           breast_feeding_status                               as `Breastfeeding?`,
           ''
                                                               as `On PMTCT?`,
           tb_screening_date                                   as `TB Screening Date EC.`,
           tb_screening_date                                   as `TB Screening Date G.C.`,
           screening_result                                    as `TB Screening Result`,
           specimen_sent_to_lab                                as `Specimen Sent to Lab?`,
           lf_lam_result                                       as `LF LAM Result`,
           gene_xpert_result                                   as `Gene Xpert Result`,
           other_diagnostic_test                               AS `Other Diagnostic Test`,
           tb_diagnostic_test_result                           AS `Other TB Diagnostic Test Result`,
           diagnosis_date                                      as `Active TB Diagnosed Date EC.`,
           diagnosis_date                                      as `Active TB Diagnosed Date G.C.`,
           tb_treatment_start_date                             as `TB Treatment Start Date EC.`,
           tb_treatment_start_date                             as `TB Treatment Start Date G.C.`,
           tb_treatment_status                                 as `TB Treatment Status`,
           tb_treatment_completed_date                         as `TB Treatment Completed Date EC.`,
           tb_treatment_completed_date                         as `TB Treatment Completed Date G.C.`,
           tb_treatment_discontinued_date                      as `TB Treatment Discontinued Date EC.`,
           tb_treatment_discontinued_date                      as `TB Treatment Discontinued Date G.C.`

    FROM tb_art AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_tb_denominator_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_tb_denominator_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_tb_denominator_query(IN REPORT_START_DATE DATE,
                                                           IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Drop'
                                 END                                   as follow_up_status,
                             follow_up_date_followup_                  as follow_up_date,
                             art_antiretroviral_start_date             as art_start_date,
                             height,
                             follow_up_4.pregnancy_status,
                             follow_up_7.currently_breastfeeding_child,
                             specimen_sent_to_lab,
                             mfeia.date_hiv_confirmed                  as date_hiv_confirmed,
                             current_who_hiv_stage,
                             tb_screening_date,
                             follow_up_2.weight_text_                  as weight,
                             antiretroviral_art_dispensed_dose_i       AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level           as adherence,
                             next_visit_date,
                             treatment_end_date,
                             lf_lam_result,
                             gene_xpert_result,
                             diagnostic_test                           as other_diagnostic_test,
                             tb_diagnostic_test_result,
                             diagnosis_date,
                             tb_treatment_status,
                             screening_test_result_tuberculosis        as screening_result,
                             tuberculosis_drug_treatment_start_d       as tb_treatment_start_date,
                             date_active_tbrx_completed                as tb_treatment_completed_date,
                             date_active_tbrx_dc                       as tb_treatment_discontinued_date,
                             mfepe.date_of_enrollment_or_booking as booking_date
                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id
                               LEFT JOIN mamba_flat_encounter_pmtct_enrollment as mfepe
                                         ON mfepe.client_id = follow_up.client_id
                      WHERE tb_screening_date >= COALESCE(REPORT_START_DATE, CURDATE())
                        AND tb_screening_date <= COALESCE(REPORT_END_DATE, CURDATE())
                      --  AND follow_up_status in ('Alive', 'Restart medication')

                      ),


         tmp_latest_follow_up AS (SELECT f.*,
                                         ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp as f
                                           join mamba_dim_client client on f.client_id = client.client_id),


         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1)


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                                          AS UAN,
           client.date_of_birth                                as `Date of Birth`,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           f_case.follow_up_date                               as `Follow-Up Date EC.`,
           f_case.follow_up_date                               as `Follow-Up Date G.C.`,
           f_case.follow_up_status                             AS `Follow-Up Status`,
           f_case.regimen                                      as `Regimen`,
           f_case.art_dose_days                                as `ARV Dose Days`,
           f_case.adherence                                    as ` Adherence`,
           f_case.pregnancy_status                                    as `Pregnant?`,
           f_case.currently_breastfeeding_child                       as `Breastfeeding?`,
           case
               when client.sex = 'MALE'
                   then ''
               when booking_date is not null
                   then 'Yes'
               else 'No' end
                                                               as `On PMTCT?`,
           tb_screening_date                                   as `TB Screening Date EC.`,
           tb_screening_date                                   as `TB Screening Date G.C.`,
           screening_result                                    as `TB Screening Result`,
           specimen_sent_to_lab                                as `Specimen Sent to Lab?`,
           lf_lam_result                                       as `LF LAM Result`,
           gene_xpert_result                                   as `Gene Xpert Result`,
           other_diagnostic_test                               AS `Other Diagnostic Test`,
           tb_diagnostic_test_result                           AS `Other TB Diagnostic Test Result`,
           diagnosis_date                                      as `Active TB Diagnosed Date EC.`,
           diagnosis_date                                      as `Active TB Diagnosed Date G.C.`,
           tb_treatment_start_date                             as `TB Treatment Start Date EC.`,
           tb_treatment_start_date                             as `TB Treatment Start Date G.C.`,
           tb_treatment_status                                 as `TB Treatment Status`,
           tb_treatment_completed_date                         as `TB Treatment Completed Date EC.`,
           tb_treatment_completed_date                         as `TB Treatment Completed Date G.C.`,
           tb_treatment_discontinued_date                      as `TB Treatment Discontinued Date EC.`,
           tb_treatment_discontinued_date                      as `TB Treatment Discontinued Date G.C.`

    FROM latest_follow_up AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
