                             height,
                             mfeia.date_hiv_confirmed            as date_hiv_confirmed,
                             current_who_hiv_stage,
                             cd4_count,
                             follow_up_2.weight_text_            as weight,
                             antiretroviral_art_dispensed_dose_i AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level     as adherence,
                             next_visit_date,
                             treatment_end_date,
                             assessment_status,
                             assessment_date                     as assessment_date,
                             dsd_category                        as current_dsd_category
                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id
                      WHERE assessment_date >= COALESCE(REPORT_START_DATE, CURDATE())
                        AND assessment_date <= COALESCE(REPORT_END_DATE, CURDATE())),


         tmp_latest_follow_up AS (SELECT f.*,
                                         ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY assessment_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp as f
                                           join mamba_dim_client client on f.client_id = client.client_id),


         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1),


         initial_dsd_assesment as (select follow_up_3.encounter_id,
                                          follow_up_3.client_id,
                                          follow_up_3.assessment_date    as initial_dsd_assesment_date,
                                          follow_up_2.dsd_category       as dsd_category_at_enrollement,
                                          follow_up_8.dsd_category_changed_by_this_date,
                                          follow_up_7.reason_for_dsd_category_change,
                                          ROW_NUMBER() OVER (PARTITION BY follow_up_3.client_id ORDER BY follow_up_3.assessment_date ,
                                              follow_up_3.encounter_id ) AS row_num
                                   from mamba_flat_encounter_follow_up_3 as follow_up_3
                                            inner join
                                        latest_follow_up as l on
                                            follow_up_3
                                                .client_id = l.client_id
                                            inner join mamba_flat_encounter_follow_up_2 as follow_up_2 on
                                       follow_up_2.encounter_id = follow_up_3.encounter_id and follow_up_3
                                                                                                   .assessment_date <>
                                                                                               l.assessment_date
                                            inner join mamba_flat_encounter_follow_up_8 as follow_up_8 on
                                       follow_up_8.encounter_id = follow_up_3.encounter_id
                                            inner join mamba_flat_encounter_follow_up_7 as follow_up_7 on
                                       follow_up_7.encounter_id = follow_up_2.encounter_id),

         deduplicat_dsd_assesment AS (SELECT * FROM initial_dsd_assesment WHERE row_num = 1)


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           CONCAT('''', client.uan)                                          AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.date_hiv_confirmed                           as `Date Confirmed HIV+ EC.`,
           f_case.date_hiv_confirmed                           as `Date Confirmed HIV+ G.C.`,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           client.mobile_no                                    as `Mobile Phone Number.`,
           f_case.follow_up_date                               as `Latest Follow-Up Date EC.`,
           f_case.follow_up_date                               as `Latest Follow-Up Date G.C.`,
           f_case.follow_up_status                             AS `Latest Follow-Up Status`,
           f_case.regimen                                      as `Latest Regimen`,
           f_case.art_dose_days                                as `Latest ARV Dose Days`,
           f_case.adherence                                    as `Latest Adherence`,
           assessment_status                                   as `Assessment Status`,
           f_case.next_visit_date                              as `Next Visit Date EC.`,
           f_case.next_visit_date                              as `Next Visit Date G.C.`,
           f_case.treatment_end_date                           as `Last TX_CURR Date EC.`,
           f_case.treatment_end_date                           as `Last TX_CURR Date G.C.`,
           case
               when initial_dsd_assesment_date is null
                   then f_case.assessment_date
               else initial_dsd_assesment_date end
                                                               as `Initial DSD Assessment Date EC.`,
           case
               when initial_dsd_assesment_date is null
                   then f_case.assessment_date
               else initial_dsd_assesment_date end             as `Initial DSD Assessment Date G.C`,

           case
               when initial_dsd_assesment_date is null
                   then f_case.current_dsd_category
               else dsd_category_at_enrollement end            as `DSD Category at Enrollement`,
           f_case.assessment_date                              as `Current DSD Category Entry Date in EC.`,
           f_case.assessment_date                              as `Current DSD Category Entry Date in G.C.`,
           current_dsd_category                                as `Current DSD Category`,
           dsd_category_changed_by_this_date                   as `DSD Category Changed by this Date`,
           reason_for_dsd_category_change                      as `Reason for DSD Category Change`
    FROM latest_follow_up AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
             LEFT JOIN deduplicat_dsd_assesment as d on d.client_id = f_case.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_eid_dna_pcr_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_eid_dna_pcr_query;

~
CREATE PROCEDURE sp_fact_line_list_eid_dna_pcr_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN


    WITH Enrollment AS (SELECT e.client_id,
                               e.hei_code,
                               e.arv_prophylaxis as enrollment_arv_prophylaxis,
                               e.mother_status
                        FROM mamba_flat_encounter_hei_enrollment e
                        WHERE e.date_enrolled_in_care <= REPORT_END_DATE),

         LatestFollowUp AS (SELECT f.client_id,
                                   f.followup_date_followup                                                            as follow_up_date,
                                   COALESCE(f1.infant_feeding_practice_within_the_first_6_months_of_life,
                                            f1.infant_feeding_practice_older_than_6_months_of_life)                    as feeding_practice,
                                   ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY f.followup_date_followup DESC) as rn
                            FROM mamba_flat_encounter_hei_followup f
                                     left join mamba_flat_encounter_hei_followup_1 f1
                                               on f.encounter_id = f1.encounter_id
                            WHERE f.followup_date_followup <= REPORT_END_DATE),

         DNAPCRTests as (select hiv_test.client_id,
                                hiv_test.maternal_art_status,
                                hiv_test.initial_test,
                                hiv_test.specimen_type,
                                hiv_test.dna_pcr_sample_collection_date,
                                hiv_test.hiv_test_result                                                                                  as dna_pcr_result,
                                hiv_test.date_dbs_result_received,
                                DATEDIFF(hiv_test.date_dbs_result_received,
                                         hiv_test.dna_pcr_sample_collection_date)                                                         as tat,
                                hiv_test.specimen_received_date,
                                hiv_test.laboratory_name,
                                hiv_test.sample_quality,
                                hiv_test.reason_sample_rejected_or_test_not_done,
                                hiv_test.hiv_test_date                                                                                    as date_test_performed,
                                hiv_test.platform_used,
                                hiv_test.telephone_number_of_referringordering_clinician                                                  as mothers_phone_no,
                                ROW_NUMBER() OVER (PARTITION BY hiv_test.client_id ORDER BY hiv_test.dna_pcr_sample_collection_date DESC) as rn
                         from mamba_flat_encounter_hei_hiv_test hiv_test
                                  join mamba_dim_client client on hiv_test.client_id = client.client_id
                         where dna_pcr_sample_collection_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                         -- test_type = 'HIV DNA polymerase chain reaction, dried blood spot (DBS)'
                         ),
         hei_test as (select * from DNAPCRTests where rn = 1)


    SELECT c.patient_name                                         as `Full Name`,
           c.sex                                                  as `Sex`,
           c.date_of_birth                                        as `DOB`,
           c.date_of_birth                                        as `DOB EC.`,
           TIMESTAMPDIFF(MONTH, c.date_of_birth, REPORT_END_DATE) as `Age (in months)`,
           c.mrn                                                  as `MRN`,
           e.hei_code                                             as `HEI Code`,
           f.follow_up_date                                       as `Follow-up Date`,
           f.follow_up_date                                       as `Follow-up Date EC.`,
           f.feeding_practice                                     as `Infant on BF?`,
           e.enrollment_arv_prophylaxis                           as `ARV Prophylaxis`,
           t.maternal_art_status                                  as `Maternal ART Status`,
           t.initial_test                                         as `Test Indication`,
           t.specimen_type                                        as `Specimen Type`,
           t.dna_pcr_sample_collection_date                       as `Date of Sample Collection`,
           t.dna_pcr_sample_collection_date                       as `Date of Sample Collection EC.`,
           t.dna_pcr_result                                       as `DNA PCR Result`,
           t.date_dbs_result_received                             as `Date of Result Received by H.F`,
           t.date_dbs_result_received                             as `Date of Result Received by H.F EC.`,
           t.tat                                                  as `TAT (in days)`,
           t.specimen_received_date                               as `Date of DBS referral to regional lab`,
           t.specimen_received_date                               as `Date of DBS referral to regional lab EC.`,
           t.laboratory_name                                      as `Name of Testing Lab`,
           t.specimen_received_date                               as `Date of sample received by Lab`,
           t.specimen_received_date                               as `Date of sample received by Lab EC.`,
           t.sample_quality                                       as `Sample Quality`,
           t.reason_sample_rejected_or_test_not_done              as `Reason for Sample rejection/test not done`,
           t.date_test_performed                                  as `Date test performed by Lab`,
           t.date_test_performed                                  as `Date test performed by Lab EC.`,
           t.platform_used                                        as `Platform used`,
           t.mothers_phone_no                                     as `Mother's Phone No.`

    FROM hei_test t
             JOIN mamba_dim_client c ON t.client_id = c.client_id
             LEFT JOIN Enrollment e ON t.client_id = e.client_id
             LEFT JOIN LatestFollowUp f ON t.client_id = f.client_id AND f.rn = 1;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_eid_rapid_antibody_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_eid_rapid_antibody_query;

~
CREATE PROCEDURE sp_fact_line_list_eid_rapid_antibody_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN


    WITH Enrollment_tmp as (select client_id,
                                   hei_code,
                                   location_of_birth,
                                   ROW_NUMBER() over (PARTITION BY client_id ORDER BY date_enrolled_in_care DESC, encounter_id DESC) as row_num
                            from mamba_flat_encounter_hei_enrollment
                            where date_enrolled_in_care  <= REPORT_END_DATE),
         Enrollment as (select * from Enrollment_tmp where row_num = 1),

         tmp_hei_follow_up as (select f.client_id,
                                      f.followup_date_followup                                                                        as follow_up_date,
                                      arv_prophylaxis,
                                      ROW_NUMBER() over (PARTITION BY f.client_id ORDER BY f.followup_date_followup, f.encounter_id ) as row_num
                               from mamba_flat_encounter_hei_followup f
                                        left join mamba_flat_encounter_hei_followup_1 f1
                                                  on f.encounter_id = f1.encounter_id
                               where f.followup_date_followup <= REPORT_END_DATE),
         latest_hei_follow_up as (select * from tmp_hei_follow_up where row_num = 1),

         AntibodyTests AS (SELECT t.client_id,
                                  t.hiv_test_result                                                                     as rapid_antibody_test_result,
                                  ROW_NUMBER() OVER (PARTITION BY t.client_id ORDER BY t.followup_date_followup_1 DESC) as rn
                           FROM mamba_flat_encounter_hei_hiv_test t
                           WHERE t.followup_date_followup_1 BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                             AND (t.test_type = 'Rapid test for HIV' OR confirmatory_test_done = 'Yes'))

    SELECT c.patient_name                                         as `Full Name`,
           c.sex                                                  as `Sex`,
           c.date_of_birth                                        as `DOB`,
           TIMESTAMPDIFF(MONTH, c.date_of_birth, REPORT_END_DATE) as `Age (in months)`,
           c.mrn                                                  as `MRN`,
           e.hei_code                                             as `HEI Code`,
           f.follow_up_date                                       as `Follow-up Date`,
           t.rapid_antibody_test_result                           as `Rapid Antibody Test Result`

    FROM AntibodyTests t
             JOIN mamba_dim_client c ON t.client_id = c.client_id
             LEFT JOIN Enrollment e ON t.client_id = e.client_id
             LEFT JOIN latest_hei_follow_up f ON t.client_id = f.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_hei_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_hei_query;

~
CREATE PROCEDURE sp_fact_line_list_hei_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE
)
BEGIN


    WITH Enrollment AS (
        SELECT
            e.client_id,
            e.date_enrolled_in_care as enrollment_date,
            e.hei_code,
            e.mothers_name,
            infant_referred,
            mother_s_pmtct_interventions,
            e.mother_status,
            e.arv_prophylaxis as enrollment_arv_prophylaxis,
            e.weight_text as birth_weight,
            e.date_enrolled_in_care,
            e.referring_facility_name
        FROM mamba_flat_encounter_hei_enrollment e
        WHERE e.date_enrolled_in_care BETWEEN REPORT_START_DATE AND REPORT_END_DATE
    ),

    LatestFollowUp AS (
        SELECT
            f.client_id,
            f.growth_pattern,
            f.delayed_milestones,
            f.reason_for_growth_failure,
            COALESCE(mother_s_breast_condition,mothers_breast_condition) as mothers_breast_condition,
            f.reason_for_red_flag,
            f.followup_date_followup as follow_up_date,
            f.weight_text as current_weight,
             f1.infant_feeding_practice_within_the_first_6_months_of_life,
            f1.infant_feeding_practice_older_than_6_months_of_life,
             COALESCE(f1.infant_feeding_practice_within_the_first_6_months_of_life, f1.infant_feeding_practice_older_than_6_months_of_life) as feeding_practice,
             f1.cotrimoxazole_prophylaxis_dose,
             f1.cotrimoxazole_adherence_level,
             f1.developmental_milestone_for_children,
            f.next_visit_date,
            ROW_NUMBER() OVER (PARTITION BY f.client_id ORDER BY f.followup_date_followup DESC) as rn
        FROM mamba_flat_encounter_hei_followup f
        left join mamba_flat_encounter_hei_followup_1 f1 on f.encounter_id=f1.encounter_id
        WHERE f.followup_date_followup <= REPORT_END_DATE
    ),

    HIVTesting AS (
        SELECT
            t.client_id,
            -- PCR 1 (Initial)
            MAX(CASE WHEN t.test_round = 'Initial test' THEN t.hiv_test_date END) as pcr_1_date,
            MAX(CASE WHEN t.test_round = 'Initial test' THEN t.hiv_test_result END) as pcr_1_result,
            -- PCR 2 (Confirmatory or subsequent)
            MAX(CASE WHEN t.test_round != 'Initial test' AND t.specimen_type = 'DBS' THEN t.hiv_test_date END) as pcr_2_date,
            MAX(CASE WHEN t.test_round != 'Initial test' AND t.specimen_type = 'DBS' THEN t.hiv_test_result END) as pcr_2_result,
            -- Antibody Test (>= 18 months usually, or rapid)
            MAX(CASE WHEN t.specimen_type != 'DBS' THEN t.hiv_test_date END) as antibody_test_date,
            MAX(CASE WHEN t.specimen_type != 'DBS' THEN t.hiv_test_result END) as antibody_test_result
        FROM mamba_flat_encounter_hei_hiv_test t
        WHERE t.dna_pcr_sample_collection_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
        GROUP BY t.client_id
    ),

    FinalOutcome AS (
        SELECT
            fo.client_id,
            fo.hei_pmtct_final_outcome,
            fo.date_when_final_outcome_was_known,
            ROW_NUMBER() OVER (PARTITION BY fo.client_id ORDER BY fo.encounter_datetime DESC) as rn
        FROM mamba_flat_encounter_hei_final_outcome fo
        WHERE fo.encounter_datetime <= REPORT_END_DATE
    )

    SELECT
        c.patient_name as `Patient Name`,
        c.mrn as `MRN`,
        e.hei_code as `HEI Code`,
        e.infant_referred as `Infant Referred?`,
        e.referring_facility_name as `Referring Facility Name`,
        e.mother_s_pmtct_interventions as `Mother''s PMTCT Intervention`,
        TIMESTAMPDIFF(MONTH, c.date_of_birth, REPORT_END_DATE) as `Age (Months)`,
        c.date_of_birth as `Date of birth`,
        c.date_of_birth as `Date of birth EC.`,
        c.sex as `Sex`,
        
        -- Enrollment Info
        e.enrollment_date as `Enrollment Date`,
        e.enrollment_date as `Enrollment Date EC.`,
        e.mothers_name as `Mother's Name`,
        e.mother_status as `Mother's Status`,
        e.enrollment_arv_prophylaxis as `ARV Prophylaxis at Enrollment`,
        e.birth_weight as `Birth Weight (in gram)`,
        
        -- HIV Testing
        t.pcr_1_date as `DNA-PCR Sample Collection Date 1`,
        t.pcr_1_date as `DNA-PCR Sample Collection Date 1 EC.`,
        t.pcr_1_result as `DNA-PCR Result 1`,
        t.pcr_2_date as `DNA-PCR Sample Collection Date 2`,
        t.pcr_2_date as `DNA-PCR Sample Collection Date 2 EC.`,
        t.pcr_2_result as `DNA-PCR Result 2`,
        t.antibody_test_date as `Antibody Test Date`,
        t.antibody_test_date as `Antibody Test Date EC.`,
        t.antibody_test_result as `Antibody Test Result`,
        
        -- Follow Up
        f.follow_up_date as `Latest Follow-up Date`,
        f.follow_up_date as `Latest Follow-up Date EC.`,
        f.current_weight as `Current Weight`,
        f.growth_pattern as `Growth Pattern`,
        f.reason_for_growth_failure as `Reason for Growth Failure`,
         f.feeding_practice as `Infant Feeding Practice`,
         f.mothers_breast_condition as `Mothers Breast Condition`,
         f.cotrimoxazole_prophylaxis_dose as `CPT Dose`,
         f.developmental_milestone_for_children as `Development Milestone`,
         f.reason_for_red_flag as `Reason for Red Flag`,
        f.next_visit_date as `Next Visit Date`,
        f.next_visit_date as `Next Visit Date EC.`,
        
        -- Final Outcome
        fo.hei_pmtct_final_outcome as `Final Outcome`,
        fo.date_when_final_outcome_was_known as `Final Outcome Date`,
        fo.date_when_final_outcome_was_known as `Final Outcome Date EC.`

    FROM Enrollment e
    JOIN mamba_dim_client c ON e.client_id = c.client_id
    LEFT JOIN LatestFollowUp f ON e.client_id = f.client_id AND f.rn = 1
    LEFT JOIN HIVTesting t ON e.client_id = t.client_id
    LEFT JOIN FinalOutcome fo ON e.client_id = fo.client_id AND fo.rn = 1;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_missed_appointment_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_missed_appointment_query;

~
CREATE PROCEDURE sp_fact_line_list_missed_appointment_query(IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Drop'
                                 END                                         as follow_up_status,
                             follow_up_date_followup_                        as follow_up_date,
                             art_antiretroviral_start_date                   as art_start_date,
                             height,
                             mfeia.date_hiv_confirmed                        as date_hiv_confirmed,
                             current_who_hiv_stage,
                             follow_up_2.weight_text_                        as weight,
                             follow_up_6.method_of_family_planning           as family_planning_method,
                             follow_up_6.current_functional_status           as functional_status,
                             follow_up_4.pregnancy_status                    as pregnancy_status,
                             follow_up_7.currently_breastfeeding_child       as breastfeeding_status,
                             follow_up_9.tb_related_ois_opportunistic_illnes as tb_related_ois,
                             follow_up.cd4_                                  as cd4_percent,
                             follow_up_1.cd4_count                           as cd4_count,
                             follow_up_5.stages_of_disclosure                as disclosure_stage,
                             follow_up_8.date_viral_load_results_received    as vl_received_date,
                             follow_up_5.viral_load_test_status              as vl_test_status,
                             follow_up_7.nutritional_screening_result        as nutritional_screening_result,
                             nutritional_status_of_adult                     as nutritional_status,
                             screening_test_result_tuberculosis              as tb_screening_result,

                             CASE scheduled_visit
                                 WHEN scheduled_visit IS NOT NULL
                                     THEN 'Scheduled'
                                 ELSE 'Unscheduled'
                                 END                                         as scheduled_visit,
                             antiretroviral_art_dispensed_dose_i             AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level                 as adherence,
                             next_visit_date,
                             treatment_end_date,
                             CASE
                                 WHEN transferred_in_check_this_for_all_t = 'Yes'
                                     THEN follow_up_date_followup_
                                 end                                         as ti_date,
                             transferred_in_check_this_for_all_t             as transfer_in,
                             reg.registration_date                           as enrollement_date
                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id),


         tmp_latest_follow_up AS (SELECT FollowUp.*,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),

         missedAppiontement AS (select *, TIMESTAMPDIFF(DAY, next_visit_date, REPORT_END_DATE) AS missed_days

                                from tmp_latest_follow_up
                                where row_num = 1
                                  AND follow_up_status in ('Restart', 'Alive on ART')
                                  AND next_visit_date < COALESCE(REPORT_END_DATE, CURDATE()))


    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           client.uan                                          AS UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.art_start_date                               as `ART Start Date EC.`,
           f_case.art_start_date                               as `ART Start Date G.C`,
           f_case.follow_up_date                               as `Latest Follow-Up Date EC.`,
           f_case.follow_up_date                               as `Latest Follow-Up Date G.C.`,
           f_case.next_visit_date                              as `Last Appointment Date EC.`,
           f_case.next_visit_date                              as `Last Appointment Date G.C`,

           missed_days                                         as `No. of Missed Days`,
           CASE
               WHEN missed_days <= 30
                   THEN 'Missed Appointment'
               WHEN missed_days < 60
                   Then '1st Lost'
               WHEN missed_days < 90
                   THEN '2nd Lost'
               ELSE 'Dropped' END                              as `tracing-status`,
           f_case.follow_up_status                             AS `Latest Follow-Up Status`,
           f_case.regimen                                      as `Last Regimen`,
           f_case.art_dose_days                                as `Last ARV Dose Days`,
           f_case.adherence                                    as `Adherence`,
           f_case.treatment_end_date                           as `Last TX_CURR Date EC.`,
           f_case.treatment_end_date                           as `Last TX_CURR Date G.C.`,
           client.state_province                               as `Region`,
           client.county_district                              as `Zone`,
           client.city_village                                 as `Woreda`,
           client.kebele                                       as `Kebele`,
           client.house_number                                 as `House #`,
           client.mobile_no                                    as `Mobile Phone Number.`
    FROM missedAppiontement AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id

    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_monthly_visit_care_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_monthly_visit_care_query;

~
CREATE PROCEDURE sp_fact_line_list_monthly_visit_care_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE,
                                                            IN STATUS TEXT)
BEGIN
    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_2.weight_text_                 as weight,
                             follow_up_1.bmi_text_                    as bmi,
                             follow_up_7.nutritional_screening_result as nutritional_screening_result,
                             follow_up_4.pregnancy_status             as pregnancy,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Drop'
                                 END                                  as follow_up_status,
                             follow_up_date_followup_                 as follow_up_date,
                             art_antiretroviral_start_date            as art_start_date,
                             height,
                             tb_prophylaxis_type,
                             current_who_hiv_stage,
                             antiretroviral_art_dispensed_dose_i      as art_dose_days,
                             regimen,
                             date_of_reported_hiv_viral_load          as date_vl_requested,
                             date_viral_load_results_received         as date_vl_received,
                             anitiretroviral_adherence_level          as adherence,
                             next_visit_date                          as next_visit_date,
                             treatment_end_date                       as tx_curr_date,
                             viral_load_test_status                   as vl_test_status,
                             cd4_count ,
                             nutritional_status_of_adult              as nutritional_status,
                             tpt_followup_6h_                         as tpt_status,
                             screening_test_result_tuberculosis       as tb_screening_result,
                             dsd_category ,
                             assessment_date                          as dsd_assessment_date,
                             transferred_in_check_this_for_all_t      as transfer_in,
                             reg.registration_date                    as enrollement_date

                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id
                      WHERE follow_up_date_followup_ >= COALESCE(REPORT_START_DATE, CURDATE())
                        AND follow_up_date_followup_ <= COALESCE(REPORT_END_DATE, CURDATE())
                        and FIND_IN_SET(follow_up_status, STATUS)),

         tmp_latest_follow_up AS (SELECT FollowUp.*,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp
                                           join mamba_dim_client client on FollowUp.client_id = client.client_id),

         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1)

    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)           as `#`,
           client.patient_uuid                                 as `Patient GUID`,
           client.patient_name                                 as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                        as MRN,
           client.uan                                          as UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE())) as `Age`,
           client.sex                                          as Sex,
           f_case.art_start_date                               as `ART Start Date in EC.`,
           f_case.art_start_date                               as `ART Start Date in G.C.`,
           f_case.follow_up_date                               as `Follow-up Date in EC.`,
           f_case.follow_up_date                               as `Follow-up Date in G.C.`,
           f_case.follow_up_status                             as `Follow-up Status`,
           f_case.regimen                                      as `Regimen`,
           f_case.art_dose_days                                as `ARV Dose`,
           f_case.adherence                                    as `Adherence`,
           f_case.weight                                       as `Weight (kg)`,
           f_case.bmi                                          as `BMI`,
           nutritional_status                                  as `Nutritional Status`,
           pregnancy                                           as `Pregnancy Status`,
           f_case.cd4_count                                           as `CD4`,
           f_case.date_vl_requested                            as `VL Requested Date in EC.`,
           f_case.date_vl_requested                            as `VL Requested Date in G.C.`,
           f_case.date_vl_received                             as `VL Received Date in EC.`,
           f_case.date_vl_received                             as `VL Received Date in G.C.`,
           f_case.vl_test_status                               as `VL Status`,
           f_case.tpt_status                                   as `TPT Status`,
           f_case.tb_screening_result                          as `TB Screening Result`,
           f_case.dsd_category                                        as `DSD Category`,
           f_case.dsd_assessment_date                          as `Current DSD Assessment Date in EC.`,
           f_case.dsd_assessment_date                          as `Current DSD Assessment Date in G.C.`,
           f_case.next_visit_date                              as `Next Visit Date in EC.`,
           f_case.next_visit_date                              as `Next Visit Date in G.C.`,
           f_case.tx_curr_date                                 as `Last TX_CURR Date in EC.`,
           f_case.tx_curr_date                                 as `Last TX_CURR Date in GC.`,
           client.mobile_no                                    as `Mobile NO.`


    FROM latest_follow_up AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_chronic_care_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_chronic_care_query;

~
CREATE PROCEDURE sp_fact_line_list_chronic_care_query(IN REPORT_START_DATE DATE,
                                                      IN REPORT_END_DATE DATE,
                                                      IN STATUS TEXT)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             CASE follow_up_status
                                 WHEN 'Alive' THEN 'Alive on ART'
                                 WHEN 'Restart medication' THEN 'Restart'
                                 WHEN 'Transferred out' THEN 'TO'
                                 WHEN 'Stop all' THEN 'Stop'
                                 WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                 WHEN 'Ran away' THEN 'Dropped'
                                 ELSE follow_up_status
                                 END                                         as follow_up_status,
                             follow_up_date_followup_                        as follow_up_date,
                             art_antiretroviral_start_date                   as art_start_date,
                             height,
                             mfeia.date_hiv_confirmed                        as date_hiv_confirmed,
                             current_who_hiv_stage,
                             follow_up_2.weight_text_                        as weight,
                             follow_up_6.method_of_family_planning           as family_planning_method,
                             follow_up_6.current_functional_status           as functional_status,
                             follow_up_4.pregnancy_status                    as pregnancy_status,
                             follow_up_7.currently_breastfeeding_child       as breastfeeding_status,
                             follow_up_9.tb_related_ois_opportunistic_illnes as tb_related_ois,
                             follow_up_1.cd4_count                                  as cd4,
                             follow_up.cd4_                           as cd4_percent,
                             follow_up_5.stages_of_disclosure                as disclosure_stage,
                             follow_up_8.date_viral_load_results_received    as vl_received_date,
                             follow_up_5.viral_load_test_status              as vl_test_status,
                             follow_up_7.nutritional_screening_result        as nutritional_screening_result,
                             nutritional_status_of_adult                     as nutritional_status,
                             screening_test_result_tuberculosis              as tb_screening_result,

                             CASE scheduled_visit
                                 WHEN scheduled_visit <> NULL
                                     THEN 'Scheduled'
                                 ELSE 'Unscheduled'
                                 END                                         as scheduled_visit,
                             antiretroviral_art_dispensed_dose_i             AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level                 as adherence,
                             next_visit_date,
                             treatment_end_date,
                             CASE
                                 WHEN transferred_in_check_this_for_all_t = 'Yes'
                                     THEN follow_up_date_followup_
                                 end                                         as ti_date,
                             transferred_in_check_this_for_all_t             as transfer_in,
                             reg.registration_date                           as enrollement_date
                      FROM mamba_flat_encounter_intake_a mfeia
                               LEFT JOIN mamba_flat_encounter_follow_up follow_up
                                         on follow_up.client_id = mfeia.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_registration reg
                                         ON reg.client_id = follow_up.client_id
                      WHERE follow_up_date_followup_ >= COALESCE(REPORT_START_DATE, CURDATE())
                        AND follow_up_date_followup_ <= COALESCE(REPORT_END_DATE, CURDATE())
                        AND FIND_IN_SET(follow_up_status, STATUS)),


         tmp_latest_follow_up AS (SELECT FollowUp.*,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date DESC,
                                             encounter_id DESC) AS row_num
                                  FROM FollowUp
                                           join mamba_dim_client client on FollowUp.client_id = client.client_id),




         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1),

         previous_regiment as (select l.client_id,
                                      antiretroviral_side_effects,
                                      follow_up_7.reason_for_art_regimen_change                                           as reason_substitution,
                                      follow_up_5.regimen_switch_type                                                     as regimen_switch,
                                      CASE
                                          when follow_up_1.regimen is null then l.regimen
                                          else follow_up_1.regimen end                                                    as previous_regimen,
                                      ROW_NUMBER() OVER (PARTITION BY l.client_id ORDER BY follow_up_6.encounter_id DESC) as rn

                               from latest_follow_up as l
                                        left join mamba_flat_encounter_follow_up_1 as follow_up_1
                                                  on l.client_id = follow_up_1.client_id
                                        left join mamba_flat_encounter_follow_up_6 follow_up_6 on
                                   follow_up_1.encounter_id = follow_up_6.encounter_id
                                        left join mamba_flat_encounter_follow_up_5 follow_up_5 on
                                   follow_up_1.encounter_id = follow_up_5.encounter_id
                                        left join mamba_flat_encounter_follow_up_7 follow_up_7
                                                  on follow_up_7.encounter_id = follow_up_1.encounter_id
                               where follow_up_1.regimen <> l.regimen),

         deduped_previous_regiment AS (SELECT * FROM previous_regiment WHERE rn = 1)

    SELECT ROW_NUMBER() OVER (ORDER BY patient_name)                 as `#`,
           client.patient_uuid                                       as `Patient GUID`,
           client.patient_name                                       as `Patient Name`,
           CAST(client.mrn AS CHAR(20))                              as MRN,
           CONCAT('''', client.uan)                                                AS UAN,
           client.date_of_birth                                      as `Date of Birth`,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(enrollement_date, CURDATE()))      as `Age At Enrollment`,
           TIMESTAMPDIFF(YEAR, client.date_of_birth,
                         COALESCE(REPORT_END_DATE, CURDATE()))       as `Current Age`,
           client.sex                                                as Sex,
           f_case.enrollement_date                                   as `Enrollment Date EC.`,
           f_case.enrollement_date                                   as `Enrollment Date G.C.`,
           f_case.date_hiv_confirmed                                 as `Date Confirmed HIV+ EC.`,
           f_case.date_hiv_confirmed                                 as `Date Confirmed HIV+ G.C.`,
           f_case.art_start_date                                     as `ART Start Date EC.`,
           f_case.art_start_date                                     as `ART Start Date G.C`,
           TIMESTAMPDIFF(DAY, f_case.date_hiv_confirmed,
                         COALESCE(f_case.art_start_date, CURDATE())) as `Time to ART Initiation (in days)`,
           f_case.transfer_in                                        as `TI ?`,
           f_case.ti_date                                            as `TI Date`,
           f_case.follow_up_date                                     as `Latest Follow-Up Date EC.`,
           f_case.follow_up_date                                     as `Latest Follow-Up Date G.C.`,
           f_case.scheduled_visit                                    as `Scheduled Type`,
           f_case.follow_up_status                                   AS `Latest Follow-Up Status`,
           f_case.regimen                                            as `Current Regimen`,
           f_case.art_dose_days                                      as `Regimen Dose Days`,
           f_case.adherence                                          as `Adherence`,
           d.previous_regimen                                        as `Previous Regimen`,
           d.reason_substitution                                     as `Reason for Regimen Switch/Substitution`,
           d.regimen_switch                                          as `Regimen Switch/Substitution`,
           d.antiretroviral_side_effects                             as `Side Effects`,
           f_case.weight                                             as `Weight (kg)`,
           f_case.Current_who_hiv_stage                              as `WHO Stage`,
           f_case.functional_status                                  as `Functional Status`,
           f_case.pregnancy_status                                   as `Pregnancy Status`,
           f_case.breastfeeding_status                               as `Breastfeeding Status`,
           f_case.family_planning_method                             as `Family Planning`,
           f_case.tb_related_ois                                     as `OIs/HIV related cancers`,
           f_case.Cd4                                                as `CD4 `,
           f_case.cd4_percent                                        as `CD4 %`,
           f_case.disclosure_stage                                   as `Disclosure Stage(DSO-3) `,
           f_case.vl_received_date                                   as `Latest VL Received Date EC.`,
           f_case.vl_received_date                                   as `Latest VL Received Date G.C.`,
           f_case.vl_test_status                                     as `Latest VL Status`,
           f_case.nutritional_screening_result                       as `Nutritional Screening Result`,
           f_case.nutritional_status                                 as `Nutritional Status`,
           f_case.tb_screening_result                                as `TB Screening Result`,
           f_case.next_visit_date                                    as `Next Visit Date EC.`,
           f_case.next_visit_date                                    as `Next Visit Date G.C.`,
           f_case.treatment_end_date                                 as `Last TX_CURR Date EC.`,
           f_case.treatment_end_date                                 as `Last TX_CURR Date G.C.`,
           client.state_province                                     as `Region`,
           client.county_district                                    as `Zone`,
           client.city_village                                       as `Woreda`,
           client.kebele                                             as `Kebele`,
           client.house_number                                       as `House #`,
           client.mobile_no                                          as `Mobile Phone Number.`
    FROM latest_follow_up AS f_case
             INNER JOIN mamba_dim_client client on f_case.client_id = client.client_id
             LEFT JOIN deduped_previous_regiment as d on d.client_id = f_case.client_id
    ORDER BY client.patient_name;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ahd_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ahd_query;

~
CREATE PROCEDURE sp_fact_line_list_ahd_query(IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             date_started_on_tuberculosis_prophy AS tpt_start_date,
                             date_completed_tuberculosis_prophyl AS tpt_completed_date,
                             tb_prophylaxis_type                 AS tpt_type,
                             tpt_dispensed_dose_in_days_alternat AS TPT_DoseDaysNumberALT,
                             tpt_side_effects                    AS TPT_SideEffect,
                             diagnostic_test                     AS DiagnosticTest,
                             tb_diagnostic_test_result           AS DiagnosticTestResult,
                             lf_lam_result                       AS LF_LAM_result,
                             gene_xpert_result                   AS Gene_Xpert_result,
                             tuberculosis_drug_treatment_start_d AS activetbtreatmentStartDate,
                             tpt_dispensed_dose_in_days_inh_     AS TPT_DoseDaysNumberINH,
                             was_the_patient_screened_for_tuberc AS tb_screened,
                             screening_test_result_tuberculosis  AS tb_screening,
                             Adherence                           AS TPT_Adherance,
                             date_discontinued_tuberculosis_prop AS tpt_discontinued_date,
                             date_active_tbrx_completed          AS ActiveTBTreatmentCompletedDate,
                             date_active_tbrx_dc                 AS activetbtreatmentDisContinuedDate,
                             cervical_cancer_screening_status    AS CCS_ScreenDoneYes,
                             date_of_reported_hiv_viral_load     AS viral_load_sent_date,
                             date_viral_load_results_received    AS viral_load_perform_date,
                             viral_load_test_status,
                             hiv_viral_load                      AS viral_load_count,
                             hiv_viral_load_status,
                             viral_load_test_indication,
                             treatment_end_date,
                             weight_text_                        AS Weight,
                             height,
                             date_of_event                       AS date_hiv_confirmed,
                             current_who_hiv_stage,
                             cd4_count,
                             visitect_cd4_result,
                             visitect_cd4_test_date,
                             antiretroviral_art_dispensed_dose_i AS art_dose_days,
                             regimen,
                             anitiretroviral_adherence_level     as adherence,
                             pregnancy_status,
                             method_of_family_planning,
                             crag,
                             cotrimoxazole_prophylaxis_start_dat,
                             cotrimoxazole_prophylaxis_stop_date,
                             current_functional_status,
                             patient_diagnosed_with_active_tuber,
                             fluconazole_start_date              AS Fluconazole_Start_Date,
                             weight_for_age_status               AS NSLessthanFive,
                             nutritional_status_of_older_child_a AS NSAdolescent,
                             nutritional_status_of_adult         AS ns_adult,
                             are_there_any_ois_                  AS No_OI,
                             herpes_zoster                       AS Zoster,
                             bacterial_pneumonia                 AS Bacterial_Pneumonia,
                             extra_pulmonary_tuberculosis_tb     AS Extra_Pulmonary_TB,
                             candidiasis_of_the_esophagus        AS Oesophageal_Candidiasis,
                             candidiasis_vaginal                 AS Vaginal_Candidiasis,
                             mouth_ulcer                         AS Mouth_Ulcer,
                             diarrhea_chronic                    AS Chronic_Diarrhea,
                             acute_diarrhea                      AS Acute_Diarrhea,
                             toxoplasmosis                       AS CNS_Toxoplasmosis,
                             meningitis_cryptococcal             AS Cryptococcal_Meningitis,
                             kaposi_sarcoma_oral                 AS Kaposi_Sarcoma,
                             suspected_cervical_cancer           AS Cervical_Cancer,
                             pulmonary_tuberculosis_tb           AS Pulmonary_TB,
                             candidiasis_oral                    AS Oral_Candidiasis,
                             pneumocystis_carinii_pneumonia_pcp  AS Pneumocystis_Pneumonia,
                             malignant_lymphoma_nonhodgkins      AS NonHodgkins_Lymphoma,
                             female_genital_ulcer_disease        AS Genital_Ulcer,
                             other_opportunistic_illnesses       AS OI_Other,
                             fluconazole_stop_date               as Fluconazole_End_Date,
                             nutritional_screening_result,
                             dsd_category,
                             other_medications_med_1                Med1,
                             other_medications_med2                 Med2,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                   AS routine_viral_load_test_indication,
                             COALESCE(
                                     repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                     suspected_antiretroviral_failure
                             )                                   AS targeted_viral_load_test_indication
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id),
         tmp_latest_follow_up AS (SELECT client_id,
                                         follow_up_date,
                                         follow_up_status,
                                         encounter_id,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         latest_follow_up AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1
                                and follow_up_status not in ('Dead', 'Transferred out')),
         tmp_visitect as (select client_id,
                                 visitect_cd4_test_date,
                                 visitect_cd4_result,
                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY visitect_cd4_test_date DESC, encounter_id DESC) AS row_num
                          from FollowUp
                          where visitect_cd4_test_date is not null
                            and visitect_cd4_test_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         visitect as (select * from tmp_visitect where row_num = 1),
         tmp_vl_performed_date as (select encounter_id,
                                          client_id,
                                          viral_load_perform_date,
                                          viral_load_sent_date,
                                          follow_up_date,
                                          viral_load_test_status,
                                          viral_load_test_indication,
                                          routine_viral_load_test_indication,
                                          targeted_viral_load_test_indication,
                                          viral_load_count,
                                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_perform_date DESC , FollowUp.encounter_id DESC) AS row_num
                                   from FollowUp
                                   where hiv_viral_load_status = 'Completed'
                                     and viral_load_perform_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         vl_performed_date as (select *
                               from tmp_vl_performed_date
                               where row_num = 1
                                 and (
                                   (viral_load_test_indication = 'Routine viral load test indication'
                                       and routine_viral_load_test_indication in
                                           ('First viral load test at 6 months or longer post ART',
                                            'Second viral load test at 12 months post ART',
                                            'Annual viral load test',
                                            'First viral load test at 3 months or longer post ART',
                                            'At the first antenatal care visit',
                                            'At 34-36 weeks of gestation'
                                                'Three months after delivery',
                                            'Six months after the first viral load test at postnatal period',
                                            'Every six months until MTCT ends'))
                                       OR (viral_load_test_indication = 'Targeted viral load test indication'
                                       and targeted_viral_load_test_indication in
                                           ('Suspected Antiretroviral failure')
                                       and (viral_load_count > 50 or viral_load_test_status in ('Uncontrolled',
                                                                                                'HIV infection with high viral load',
                                                                                                'Low-level viremia'))
                                       )
                                   )),

         tmp_tpt_start AS (SELECT client_id,
                                  tpt_start_date,
                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_start_date DESC, encounter_id DESC) AS row_num
                           FROM FollowUp
                           WHERE tpt_start_date IS NOT NULL
                             AND tpt_start_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tpt_start as (select * from tmp_tpt_start where row_num = 1),

         tmp_tpt_completed AS (SELECT client_id,
                                      tpt_completed_date,
                                      ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY tpt_completed_date DESC, encounter_id DESC) AS row_num
                               FROM FollowUp
                               WHERE tpt_completed_date IS NOT NULL
                                 AND tpt_completed_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tpt_completed as (select *
                           from tmp_tpt_completed
                           where row_num = 1),

         tmp_tpt_type AS (SELECT client_id,
                                 tpt_type                                                                                   AS TB_ProphylaxisType,
                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                          FROM FollowUp
                          WHERE tpt_type IS NOT NULL),
         tpt_type as (select * from tmp_tpt_type where row_num = 1),

         tmp_tpt_dose_ALT AS (SELECT client_id,
                                     TPT_DoseDaysNumberALT                                                                      AS TPT_DoseDaysNumberALT,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE TPT_DoseDaysNumberALT IS NOT NULL),
         tpt_dose_ALT as (select * from tmp_tpt_dose_ALT where row_num = 1),

         tmp_tpt_dose_INH AS (SELECT client_id,
                                     TPT_DoseDaysNumberINH                                                                      AS TPT_DoseDaysNumberINH,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE TPT_DoseDaysNumberINH IS NOT NULL),
         tpt_dose_INH as (select * from tmp_tpt_dose_INH where row_num = 1),

         tmp_tpt_side_effect AS (SELECT client_id,
                                        TPT_SideEffect                                                                             AS TPT_SideEffect,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                 FROM FollowUp
                                 WHERE TPT_SideEffect IS NOT NULL),
         tpt_side_effect as (select * from tmp_tpt_side_effect where row_num = 1),

         tmp_tb_diagnostic_test AS (SELECT client_id,
                                           DiagnosticTest                                                                             AS TB_Diagnostic_Test,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                    FROM FollowUp
                                    WHERE DiagnosticTest IS NOT NULL
                                      AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tb_diagnostic_test as (select * from tmp_tb_diagnostic_test where row_num = 1),

         tmp_tb_diagnostic_result AS (SELECT client_id,
                                             DiagnosticTestResult                                                                       AS TB_Diagnostic_Result,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE DiagnosticTestResult IS NOT NULL
                                        AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tb_diagnostic_result as (select * from tmp_tb_diagnostic_result where row_num = 1),

         tmp_tb_LF_LAM_result AS (SELECT client_id,
                                         LF_LAM_result                                                                              AS LF_LAM_result,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE LF_LAM_result IS NOT NULL
                                    AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tb_LF_LAM_result as (select * from tmp_tb_LF_LAM_result where row_num = 1),
         tmp_tb_Gene_Xpert_result AS (SELECT client_id,
                                             Gene_Xpert_result                                                                          AS Gene_Xpert_result,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE Gene_Xpert_result IS NOT NULL
                                        AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tb_Gene_Xpert_result as (select * from tmp_tb_Gene_Xpert_result where row_num = 1),

         tmp_tpt_screened AS (SELECT client_id,
                                     tb_screened                                                                                AS TB_Screened,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE tb_screened = 'Yes'),
         tpt_screened as (select * from tmp_tpt_screened where row_num = 1),
         tmp_tpt_screening AS (SELECT client_id,
                                      encounter_id,
                                      tb_screening                                                                               AS TB_Screening_Result,
                                      ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                               FROM FollowUp
                               WHERE tb_screening IS NOT NULL
                                 AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tpt_screening as (select * from tmp_tpt_screening where row_num = 1),
         tmp_tpt_adherence AS (SELECT client_id,
                                      TPT_Adherance                                                                              AS TPT_Adherence,
                                      ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                               FROM FollowUp
                               WHERE TPT_Adherance IS NOT NULL),
         tpt_adherence as (select * from tmp_tpt_adherence where row_num = 1),
         tmp_ActiveTBTreatmentStarted AS (SELECT client_id,
                                                 activetbtreatmentStartDate                                                                             AS ActiveTBTreatmentStartDate,
                                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY activetbtreatmentStartDate DESC, encounter_id DESC) AS row_num
                                          FROM FollowUp
                                          WHERE activetbtreatmentStartDate IS NOT NULL
                                            AND activetbtreatmentStartDate <= COALESCE(REPORT_END_DATE, CURDATE())),
         ActiveTBTreatmentStarted as (select * from tmp_ActiveTBTreatmentStarted where row_num = 1),
         tmp_TBTreatmentCompleted AS (SELECT client_id,
                                             ActiveTBTreatmentCompletedDate                                                                             AS ActiveTBTreatmentCompletedDate,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY ActiveTBTreatmentCompletedDate DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE ActiveTBTreatmentCompletedDate IS NOT NULL
                                        AND ActiveTBTreatmentCompletedDate <= COALESCE(REPORT_END_DATE, CURDATE())),
         TBTreatmentCompleted as (select * from tmp_TBTreatmentCompleted where row_num = 1),
         tmp_TBTreatmentDiscontinued AS (SELECT client_id,
                                                activetbtreatmentDisContinuedDate                                                                             AS ActiveTBTreatmentDiscontinuedDate,
                                                ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY activetbtreatmentDisContinuedDate DESC, encounter_id DESC) AS row_num
                                         FROM FollowUp
                                         WHERE activetbtreatmentDisContinuedDate IS NOT NULL
                                           AND
                                             activetbtreatmentDisContinuedDate <= COALESCE(REPORT_END_DATE, CURDATE())),
         TBTreatmentDiscontinued as (select * from tmp_TBTreatmentDiscontinued where row_num = 1),
         tmp_cca_screened_tmp AS (SELECT DISTINCT client_id,
                                                  CCS_ScreenDoneYes                                                                          AS CCA_Screened,
                                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  where CCS_ScreenDoneYes IS NOT NULL),
         cca_screened AS (select * from tmp_cca_screened_tmp where row_num = 1)
    SELECT client.patient_name                                                             as `Patient Name`,
           client.patient_uuid                                                             as UUID,
           CAST(client.mrn AS CHAR(20))                                                    as mrn,
           CONCAT('''', client.uan) as uan,
           client.sex                                                                      as Sex,
           f_case.Weight                                                                   as Weight,
           TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as Age,
           f_case.height                                                                   as Height,
           f_case.date_hiv_confirmed                                                       as `HIV_Confirmed_Date GC.`,
           f_case.date_hiv_confirmed                                                       as `HIV_Confirmed_Date EC.`,
           f_case.art_start_date                                                           as `ARTStartDate GC.`,
           f_case.art_start_date                                                           as `ARTStartDate EC.`,
           PERIOD_DIFF(date_format(COALESCE(REPORT_END_DATE, CURDATE()), '%Y%m'),
                       date_format(f_case.art_start_date, '%Y%m'))                         as MonthsOnART,
           f_case.follow_up_date                                                           as `FollowUpDate GC.`,
           f_case.follow_up_date                                                           as `FollowUpDate EC.`,
           f_case.current_who_hiv_stage                                                    as WHOStage,
           f_case.cd4_count                                                                as CD4Count,
           visitect.visitect_cd4_result                                                    as `VISITECT CD4 Test Result`,
           visitect.visitect_cd4_test_date                                                 as `VISITECT CD4 Test Date GC.`,
           visitect.visitect_cd4_test_date                                                 as `VISITECT CD4 Test Date EC.`,
           f_case.art_dose_days                                                            as ARTDoseDays,
           f_case.regimen                                                                  as ARVRegimen,
           CASE f_case.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                                                         AS FollowupStatus,
           f_case.adherence                                                                as AdheranceLevel,
           f_case.pregnancy_status                                                         as IsPregnant,
           f_case.method_of_family_planning                                                as FpMethodUsed,
           f_case.crag                                                                     as CrAg,
           COALESCE(
                   f_case.ns_adult,
                   f_case.NSAdolescent,
                   f_case.NSLessthanFive
           )                                                                               as NutritionalStatus,
           f_case.current_functional_status                                                as FunctionalStatus,
           CONCAT_WS(
                   ', ',
                   NULLIF(f_case.No_OI, ''),
                   NULLIF(f_case.Zoster, ''),
                   NULLIF(f_case.Bacterial_Pneumonia, ''),
                   NULLIF(f_case.Extra_Pulmonary_TB, ''),
                   NULLIF(f_case.Oesophageal_Candidiasis, ''),
                   NULLIF(f_case.Vaginal_Candidiasis, ''),
                   NULLIF(f_case.Mouth_Ulcer, ''),
                   NULLIF(f_case.Chronic_Diarrhea, ''),
                   NULLIF(f_case.Acute_Diarrhea, ''),
                   NULLIF(f_case.CNS_Toxoplasmosis, ''),
                   NULLIF(f_case.Cryptococcal_Meningitis, ''),
                   NULLIF(f_case.Kaposi_Sarcoma, ''),
                   NULLIF(f_case.Cervical_Cancer, ''),
                   NULLIF(f_case.Pulmonary_TB, ''),
                   NULLIF(f_case.Oral_Candidiasis, ''),
                   NULLIF(f_case.Pneumocystis_Pneumonia, ''),
                   NULLIF(f_case.NonHodgkins_Lymphoma, ''),
                   NULLIF(f_case.Genital_Ulcer, ''),
                   NULLIF(f_case.OI_Other, '')
           )                                                                               AS OIs,
           f_case.Med1                                                                     as Med1,
           f_case.Med2                                                                     as Med2,
           f_case.cotrimoxazole_prophylaxis_start_dat                                      as `CotrimoxazoleStartDate GC.`,
           f_case.cotrimoxazole_prophylaxis_start_dat                                      as `CotrimoxazoleStartDate EC.`,
           f_case.cotrimoxazole_prophylaxis_stop_date                                      as `cortimoxazole_stop_date GC.`,
           f_case.cotrimoxazole_prophylaxis_stop_date                                      as `cortimoxazole_stop_date EC.`,
           f_case.Fluconazole_Start_Date                                                   as `Fluconazole_Start_Date GC.`,
           f_case.Fluconazole_Start_Date                                                   as `Fluconazole_Start_Date EC.`,
           f_case.Fluconazole_End_Date                                                     as `Fluconazole_End_Date GC.`,
           f_case.Fluconazole_End_Date                                                     as `Fluconazole_End_Date EC.`,
           tpt_type.TB_ProphylaxisType                                                     as TPT_Type,
           tpt_start.tpt_start_date                                                        as `inhprophylaxis_started_date GC.`,
           tpt_start.tpt_start_date                                                        as `inhprophylaxis_started_date EC.`,
           tpt_completed.tpt_completed_date                                                as `InhprophylaxisCompletedDate GC.`,
           tpt_completed.tpt_completed_date                                                as `InhprophylaxisCompletedDate EC.`,
           tpt_dose_ALT.TPT_DoseDaysNumberALT                                              as TPT_DoseDaysNumberALT,
           tpt_dose_INH.TPT_DoseDaysNumberINH                                              as TPT_DoseDaysNumberINH,
           COALESCE(tpt_dose_INH.TPT_DoseDaysNumberINH,
                    tpt_dose_ALT.TPT_DoseDaysNumberALT)                                    AS TPT_Dispensed_Dose,
           tpt_side_effect.TPT_SideEffect                                                  as TPT_SideEffect,
           tpt_adherence.TPT_Adherence                                                     as TPT_Adherence,
           tpt_screened.TB_Screened                                                        as tb_screened,
           tpt_screening.TB_Screening_Result                                               as tb_screening_result,
           tb_diagnostic_result.TB_Diagnostic_Result                                       as TB_Diagnostic_Result,
           tb_LF_LAM_result.LF_LAM_result                                                  as LF_LAM_result,
           tb_Gene_Xpert_result.Gene_Xpert_result                                          as Gene_Xpert_result,
           CASE
               WHEN tb_diagnostic_test.TB_Diagnostic_Test = 'Smear microscopy only' AND
                    tb_diagnostic_result.TB_Diagnostic_Result = 'Positive'
                   THEN 'Positive'
               WHEN tb_diagnostic_test.TB_Diagnostic_Test = 'Smear microscopy only' AND
                    tb_diagnostic_result.TB_Diagnostic_Result = 'Negative'
                   THEN 'Negative'
               ELSE '' END                                                                 AS Smear_Microscopy_Result,
           CASE
               WHEN tb_diagnostic_test.TB_Diagnostic_Test = 'Additional test other than Gene-Xpert' AND
                    tb_diagnostic_result.TB_Diagnostic_Result = 'Positive'
                   THEN 'Positive'
               WHEN tb_diagnostic_test.TB_Diagnostic_Test = 'Additional test other than Gene-Xpert' AND
                    tb_diagnostic_result.TB_Diagnostic_Result = 'Negative'
                   THEN 'Negative'
               ELSE '' END                                                                 AS Additional_TB_Diagnostic_Test_Result,
           f_case.patient_diagnosed_with_active_tuber                                      as Active_TB,
           ActiveTBTreatmentStarted.ActiveTBTreatmentStartDate                             as `ActiveTBTreatmentStartDate GC.`,
           ActiveTBTreatmentStarted.ActiveTBTreatmentStartDate                             as `ActiveTBTreatmentStartDate EC.`,
           TBTreatmentCompleted.ActiveTBTreatmentCompletedDate                             as `ActiveTBTreatmentCompletedDate GC.`,
           TBTreatmentCompleted.ActiveTBTreatmentCompletedDate                             as `ActiveTBTreatmentCompletedDate EC.`,
           TBTreatmentDiscontinued.ActiveTBTreatmentDiscontinuedDate                       as `ActiveTBTreatmentDiscontinuedDate GC.`,
           TBTreatmentDiscontinued.ActiveTBTreatmentDiscontinuedDate                       as `ActiveTBTreatmentDiscontinuedDate EC.`,
           vlperfdate.viral_load_perform_date                                              as `Viral_Load_Perform_Date GC.`,
           vlperfdate.viral_load_perform_date                                              as `Viral_Load_Perform_Date EC.`,
           vlperfdate.viral_load_test_status                                               as Viral_Load_Status,
           vlperfdate.viral_load_count                                                     as Viral_Load_count,
           vlperfdate.viral_load_sent_date                                                 as `VL_Sent_Date GC.`,
           vlperfdate.viral_load_sent_date                                                 as `VL_Sent_Date EC.`,
           vlperfdate.viral_load_perform_date                                              as `Viral_Load_Ref_Date GC.`,
           vlperfdate.viral_load_perform_date                                              as `Viral_Load_Ref_Date EC.`,
           cca_screened.CCA_Screened                                                       as CCA_Screened,
           f_case.dsd_category                                                             as DSD_Category,
           CASE
               WHEN TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) < 5 THEN 'Yes'
               WHEN TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) >= 5 AND
                    ((visitect.visitect_cd4_result is null and f_case.cd4_count IS NOT NULL AND
                      f_case.cd4_count < 200) or (visitect.visitect_cd4_result = 'VISITECT <200 copies/ml')) THEN 'Yes'
               WHEN TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) >= 5 AND
                    f_case.current_who_hiv_stage IS NOT NULL AND
                    (f_case.current_who_hiv_stage = 'WHO stage 3 adult' Or
                     f_case.current_who_hiv_stage = 'WHO stage 3 peds' Or
                     f_case.current_who_hiv_stage = 'WHO stage 4 peds') THEN 'Yes'
               WHEN (TIMESTAMPDIFF(YEAR, client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) >= 5 AND
                     f_case.current_who_hiv_stage IS NOT NULL AND
                     f_case.current_who_hiv_stage = 'WHO stage 4 adult') THEN 'Yes'
               ELSE 'No' END                                                               as AHD,
           f_case.follow_up_status                                                         as current_status
    FROM FollowUp AS f_case
             INNER JOIN latest_follow_up ON f_case.encounter_id = latest_follow_up.encounter_id
             LEFT JOIN mamba_dim_client client on latest_follow_up.client_id = client.client_id
             LEFT JOIN vl_performed_date AS vlperfdate ON vlperfdate.client_id = f_case.client_id
             LEFT JOIN visitect ON visitect.client_id = f_case.client_id
             LEFT JOIN tpt_start ON tpt_start.client_id = f_case.client_id
             LEFT JOIN tpt_completed ON tpt_completed.client_id = f_case.client_id
             LEFT JOIN tpt_type ON tpt_type.client_id = f_case.client_id
             LEFT JOIN tpt_dose_ALT ON tpt_dose_ALT.client_id = f_case.client_id
             LEFT JOIN tpt_dose_INH ON tpt_dose_INH.client_id = f_case.client_id
             LEFT JOIN tpt_side_effect ON tpt_side_effect.client_id = f_case.client_id
             LEFT JOIN
         tpt_screened ON tpt_screened.client_id = f_case.client_id
             LEFT JOIN tpt_screening ON tpt_screening.client_id = f_case.client_id
             LEFT JOIN tpt_adherence ON tpt_adherence.client_id = f_case.client_id
             LEFT JOIN tb_diagnostic_result ON tb_diagnostic_result.client_id = f_case.client_id
             LEFT JOIN tb_diagnostic_test ON tb_diagnostic_test.client_id = f_case.client_id
             LEFT JOIN tb_LF_LAM_result ON tb_LF_LAM_result.client_id = f_case.client_id
             LEFT JOIN tb_Gene_Xpert_result ON tb_Gene_Xpert_result.client_id = f_case.client_id
             LEFT JOIN ActiveTBTreatmentStarted ON ActiveTBTreatmentStarted.client_id = f_case.client_id
             LEFT JOIN TBTreatmentCompleted ON TBTreatmentCompleted.client_id = f_case.client_id
             LEFT JOIN TBTreatmentDiscontinued ON TBTreatmentDiscontinued.client_id = f_case.client_id
             LEFT JOIN cca_screened ON cca_screened.client_id = f_case.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_art_cohort_analysis_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_art_cohort_analysis_query;

~
CREATE PROCEDURE sp_fact_line_list_art_cohort_analysis_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUpEncounters AS (SELECT follow_up.encounter_id,
                                       follow_up.client_id                 AS PatientId,
                                       follow_up_status,
                                       follow_up_date_followup_            AS follow_up_date,
                                       art_antiretroviral_start_date       AS art_start_date,
                                       treatment_end_date,
                                       regimen,
                                       antiretroviral_art_dispensed_dose_i AS ARTDoseDays,
                                       anitiretroviral_adherence_level     AS AdherenceLevel,
                                       pregnancy_status,
                                       next_visit_date,
                                       date_of_reported_hiv_viral_load     AS viral_load_sent_date,
                                       date_viral_load_results_received    AS viral_load_received_date,
                                       viral_load_test_status              AS viral_load_result,
                                       hiv_viral_load                      AS viral_load_count,
                                       CASE transferred_in_check_this_for_all_t WHEN 'Yes' THEN 1 ELSE 0 END as is_ti_visit,
                                       cd4_count,
                                       cd4_                                AS cd4_percent,
                                       current_functional_status,
                                       visitect_cd4_result,
                                       visitect_cd4_test_date
                                FROM mamba_flat_encounter_follow_up follow_up
                                         LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                                   ON follow_up.encounter_id = follow_up_1.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                                   ON follow_up.encounter_id = follow_up_2.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                                   ON follow_up.encounter_id = follow_up_3.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                                   ON follow_up.encounter_id = follow_up_4.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                                   ON follow_up.encounter_id = follow_up_5.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                                   ON follow_up.encounter_id = follow_up_6.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                                   ON follow_up.encounter_id = follow_up_7.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                                   ON follow_up.encounter_id = follow_up_8.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                                   ON follow_up.encounter_id = follow_up_9.encounter_id
                                WHERE follow_up_date_followup_ IS NOT NULL
                                  AND follow_up_status IS NOT NULL),

         ART_Initiation AS (SELECT PatientId, MIN(art_start_date) AS art_start_date
                            FROM FollowUpEncounters
                            WHERE art_start_date IS NOT NULL
                              AND art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                            GROUP BY PatientId),

         IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 6
                          UNION ALL
                          SELECT 12
                          UNION ALL
                          SELECT 24
                          UNION ALL
                          SELECT 36),

         PatientIntervals AS (SELECT a.PatientId,
                                     a.art_start_date,
                                     i.interval_month,
                                     CASE
                                         WHEN i.interval_month = 0 THEN a.art_start_date
                                         ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH))
                                         END AS interval_end_date,
                                     CASE
                                         WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                         ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH)))
                                                           OVER (PARTITION BY a.PatientId ORDER BY i.interval_month),
                                                       REPORT_START_DATE)
                                         END AS interval_start_date
                              FROM ART_Initiation a
                                       CROSS JOIN IntervalsDef i),

         RankedIntervalData AS (SELECT pi.PatientId,
                                       pi.interval_month,
                                       pi.interval_end_date,
                                       f.ARTDoseDays,
                                       pi.interval_start_date,
                                       f.follow_up_status                            AS strict_status,
                                       f.treatment_end_date                          AS strict_tx_end_date,
                                       f.regimen                                     AS strict_regimen,
                                       f.current_functional_status,
                                       f.AdherenceLevel,
                                       f.cd4_count,
                                       f.cd4_percent,
                                       f.visitect_cd4_result,
                                       f.visitect_cd4_test_date,
                                       f.viral_load_received_date,
                                       f.viral_load_count,
                                       f.is_ti_visit,
                                       f.follow_up_date as latest_follow_up_date,
                                       CASE WHEN f.is_ti_visit = 1 THEN 1 ELSE 0 END AS ti_in_this_interval,
                                       ROW_NUMBER() OVER (
                                           PARTITION BY pi.PatientId, pi.interval_month
                                           ORDER BY f.follow_up_date DESC
                                           )                                         AS rn
                                FROM PatientIntervals pi
                                         LEFT JOIN FollowUpEncounters f
                                                   ON pi.PatientId = f.PatientId
                                                       AND
                                                      f.follow_up_date BETWEEN pi.interval_start_date AND pi.interval_end_date),
         StrictIntervalData AS (SELECT PatientId,
                                       interval_month,
                                       interval_end_date,
                                       interval_start_date,
                                       strict_status,
                                       latest_follow_up_date,
                                       strict_tx_end_date,
                                       strict_regimen,
                                       current_functional_status,
                                       ARTDoseDays,
                                       AdherenceLevel,
                                       cd4_count,
                                       cd4_percent,
                                       visitect_cd4_result,
                                       visitect_cd4_test_date,
                                       viral_load_received_date,
                                       viral_load_count,
                                       is_ti_visit,
                                       ti_in_this_interval
                                FROM RankedIntervalData
                                WHERE rn = 1),

         StateCalculation AS (SELECT sid.*,
                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as is_cumulative_ti,

                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId)                                                                          as ever_ti,

                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                                 THEN 1
                                             ELSE 0 END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as has_terminal_event,
                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                                 THEN strict_status
                                             ELSE NULL END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as specific_terminal_event,
                                     MAX(strict_tx_end_date)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as max_tx_end_date_so_far
                              FROM StrictIntervalData sid),

         CohortEnriched AS (SELECT sc.*,
                                   dc.date_of_birth,

                                   TIMESTAMPDIFF(YEAR, dc.date_of_birth, sc.interval_end_date) AS age_at_interval,

                                   CASE
                                       WHEN has_terminal_event = 1 THEN specific_terminal_event
                                       WHEN strict_status IS NOT NULL THEN strict_status
                                       WHEN strict_status IS NULL AND max_tx_end_date_so_far >= interval_end_date
                                           THEN 'Active - Carry Forward Rx'
                                       ELSE 'Loss to follow-up (LTFU)'
                                       END                                                     AS final_cohort_outcome,

                                   CASE
                                       WHEN strict_regimen IS NULL THEN NULL
                                       -- Adult (>= 15)
                                       WHEN TIMESTAMPDIFF(YEAR, dc.date_of_birth, sc.interval_end_date) >= 15 THEN
                                           CASE
                                               WHEN strict_regimen LIKE '1%' THEN 'On Original 1st Line'
                                               WHEN strict_regimen LIKE '4%' THEN 'On Alternate 1st Line'
                                               WHEN strict_regimen LIKE '2%' THEN 'On 2nd Line'
                                               ELSE 'Other'
                                               END
                                       -- Peds (< 15)
                                       ELSE
                                           CASE
                                               WHEN strict_regimen LIKE '4%' THEN 'On Original 1st Line'
                                               WHEN strict_regimen LIKE '1%' THEN 'On Alternate 1st Line'
                                               WHEN (interval_month < 36 AND strict_regimen LIKE '5%') OR
                                                    (interval_month = 36 AND strict_regimen LIKE '6%')
                                                   THEN 'On 2nd Line'
                                               ELSE 'Other'
                                               END
                                       END                                                     AS regimen_line_desc

                            FROM StateCalculation sc
                                     JOIN mamba_dim_client dc ON sc.PatientId = dc.client_id)

    SELECT dc.patient_name                                                                  AS 'Patient Name',
           dc.patient_uuid                                                                  AS 'UUID',
           CAST(dc.mrn AS CHAR(20))                                                         AS 'MRN',
           CONCAT('''', dc.uan) as UAN,
           dc.Sex,
           dc.date_of_birth                                                                 AS 'Date of Birth',
           dc.date_of_birth                                                                 AS 'Date of Birth EC.',
           ai.art_start_date                                                                AS 'ART Start Date',
           ai.art_start_date                                                                AS 'ART Start Date EC.',

           -- === 0 MONTHS ===
           MAX(CASE WHEN co.interval_month = 0 THEN co.age_at_interval ELSE NULL END)       AS 'Age at 0 Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.regimen_line_desc ELSE NULL END)     AS 'Regimen Line at Zero Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.final_cohort_outcome
                   ELSE NULL END)                                                           AS 'Outcome at Zero Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at Zero Months',
           MAX(CASE
                   WHEN co.interval_month = 0 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at Zero Months EC.',
           MAX(CASE WHEN co.interval_month = 0 THEN co.strict_regimen ELSE NULL END)        AS 'Latest Regimen at Zero Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.ARTDoseDays ELSE NULL END)           AS 'Latest Regimen Dose Days at Zero Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.AdherenceLevel ELSE NULL END)        AS 'Latest Adherence at Zero Months',
           MAX(CASE WHEN co.interval_month = 0 THEN co.viral_load_count ELSE NULL END)      AS 'Latest Viral Load Count at Zero Months',

           -- === 6 MONTHS ===
           MAX(CASE WHEN co.interval_month = 6 THEN co.age_at_interval ELSE NULL END)       AS 'Age at 6 Months',
           MAX(CASE WHEN co.interval_month = 6 THEN co.regimen_line_desc ELSE NULL END)     AS 'Regimen Line at 6 Months',
           MAX(CASE WHEN co.interval_month = 6 THEN co.final_cohort_outcome ELSE NULL END)  AS 'Outcome at 6 Months',
           MAX(CASE
                   WHEN co.interval_month = 6 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 6 Months',
           MAX(CASE
                   WHEN co.interval_month = 6 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 6 Months EC.',
           MAX(CASE WHEN co.interval_month = 6 THEN co.strict_regimen ELSE NULL END)        AS 'Latest Regimen at 6 Months',
           MAX(CASE WHEN co.interval_month = 6 THEN co.ARTDoseDays ELSE NULL END)           AS 'Latest Regimen Dose Days at 6 Months',
           MAX(CASE WHEN co.interval_month = 6 THEN co.AdherenceLevel ELSE NULL END)        AS 'Latest Adherence at 6 Months',
           MAX(CASE WHEN co.interval_month = 6 THEN co.viral_load_count ELSE NULL END)      AS 'Latest Viral Load Count at 6 Months',

           -- === 12 MONTHS ===
           MAX(CASE WHEN co.interval_month = 12 THEN co.age_at_interval ELSE NULL END)      AS 'Age at 12 Months',
           MAX(CASE WHEN co.interval_month = 12 THEN co.regimen_line_desc ELSE NULL END)    AS 'Regimen Line at 12 Months',
           MAX(CASE WHEN co.interval_month = 12 THEN co.final_cohort_outcome ELSE NULL END) AS 'Outcome at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 12 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 12 Months',
           MAX(CASE
                   WHEN co.interval_month = 12 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 12 Months EC.',
           MAX(CASE WHEN co.interval_month = 12 THEN co.strict_regimen ELSE NULL END)       AS 'Latest Regimen at 12 Months',
           MAX(CASE WHEN co.interval_month = 12 THEN co.ARTDoseDays ELSE NULL END)          AS 'Latest Regimen Dose Days at 12 Months',
           MAX(CASE WHEN co.interval_month = 12 THEN co.AdherenceLevel ELSE NULL END)       AS 'Latest Adherence at 12 Months',
           MAX(CASE WHEN co.interval_month = 12 THEN co.viral_load_count ELSE NULL END)     AS 'Latest Viral Load Count at 12 Months',

           -- === 24 MONTHS ===
           MAX(CASE WHEN co.interval_month = 24 THEN co.age_at_interval ELSE NULL END)      AS 'Age at 24 Months',
           MAX(CASE WHEN co.interval_month = 24 THEN co.regimen_line_desc ELSE NULL END)    AS 'Regimen Line at 24 Months',
           MAX(CASE WHEN co.interval_month = 24 THEN co.final_cohort_outcome ELSE NULL END) AS 'Outcome at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 24 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 24 Months',
           MAX(CASE
                   WHEN co.interval_month = 24 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 24 Months EC.',
           MAX(CASE WHEN co.interval_month = 24 THEN co.strict_regimen ELSE NULL END)       AS 'Latest Regimen at 24 Months',
           MAX(CASE WHEN co.interval_month = 24 THEN co.ARTDoseDays ELSE NULL END)          AS 'Latest Regimen Dose Days at 24 Months',
           MAX(CASE WHEN co.interval_month = 24 THEN co.AdherenceLevel ELSE NULL END)       AS 'Latest Adherence at 24 Months',
           MAX(CASE WHEN co.interval_month = 24 THEN co.viral_load_count ELSE NULL END)     AS 'Latest Viral Load Count at 24 Months',

           -- === 36 MONTHS ===
           MAX(CASE WHEN co.interval_month = 36 THEN co.age_at_interval ELSE NULL END)      AS 'Age at 36 Months',
           MAX(CASE WHEN co.interval_month = 36 THEN co.regimen_line_desc ELSE NULL END)    AS 'Regimen Line at 36 Months',
           MAX(CASE WHEN co.interval_month = 36 THEN co.final_cohort_outcome ELSE NULL END) AS 'Outcome at 36 Months',
           MAX(CASE
                   WHEN co.interval_month = 36 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 36 Months',
           MAX(CASE
                   WHEN co.interval_month = 36 THEN co.latest_follow_up_date
                   ELSE NULL END)                                                           AS 'Latest Follow-Up Date at 36 Months EC.',
           MAX(CASE WHEN co.interval_month = 36 THEN co.strict_regimen ELSE NULL END)       AS 'Latest Regimen at 36 Months',
           MAX(CASE WHEN co.interval_month = 36 THEN co.ARTDoseDays ELSE NULL END)          AS 'Latest Regimen Dose Days at 36 Months',
           MAX(CASE WHEN co.interval_month = 36 THEN co.AdherenceLevel ELSE NULL END)       AS 'Latest Adherence at 36 Months',
           MAX(CASE WHEN co.interval_month = 36 THEN co.viral_load_count ELSE NULL END)     AS 'Latest Viral Load Count at 36 Months'

    FROM ART_Initiation ai
             JOIN mamba_dim_client dc ON ai.PatientId = dc.client_id
             LEFT JOIN CohortEnriched co ON ai.PatientId = co.PatientId
    WHERE ai.art_start_date <= COALESCE(REPORT_END_DATE, CURDATE())
    GROUP BY ai.PatientId, dc.patient_name, dc.patient_uuid, dc.mrn, dc.UAN, dc.Sex, dc.date_of_birth, ai.art_start_date
    ORDER BY ai.art_start_date, dc.patient_name;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_art_cohort_analysis_summary_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_art_cohort_analysis_summary_query;

~
CREATE PROCEDURE sp_fact_line_list_art_cohort_analysis_summary_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUpEncounters AS (SELECT follow_up.encounter_id,
                                       follow_up.client_id                                                     AS PatientId,
                                       follow_up_status,
                                       follow_up_date_followup_                                                AS follow_up_date,
                                       art_antiretroviral_start_date                                           AS art_start_date,
                                       COALESCE(treatment_end_date, DATE_ADD(follow_up_date_followup_, INTERVAL
                                                                             CAST(antiretroviral_art_dispensed_dose_i AS UNSIGNED)
                                                                             DAY))                             as treatment_end_date,
                                       regimen,
                                       antiretroviral_art_dispensed_dose_i                                     AS ARTDoseDays,
                                       anitiretroviral_adherence_level                                         AS AdherenceLevel,
                                       pregnancy_status,
                                       next_visit_date,
                                       date_of_reported_hiv_viral_load                                         AS viral_load_sent_date,
                                       date_viral_load_results_received                                        AS viral_load_received_date,
                                       viral_load_test_status                                                  AS viral_load_result,
                                       hiv_viral_load                                                          AS viral_load_count,
                                       cd4_count,
                                       cd4_                                                                    AS cd4_percent,
                                       current_functional_status,
                                       visitect_cd4_result,
                                       visitect_cd4_test_date,
                                       transferred_in_check_this_for_all_t,
                                       CASE WHEN transferred_in_check_this_for_all_t = 'Yes' THEN 1 ELSE 0 END as is_ti_visit
                                FROM mamba_flat_encounter_follow_up follow_up
                                         LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                                   ON follow_up.encounter_id = follow_up_1.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                                   ON follow_up.encounter_id = follow_up_2.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                                   ON follow_up.encounter_id = follow_up_3.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                                   ON follow_up.encounter_id = follow_up_4.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                                   ON follow_up.encounter_id = follow_up_5.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                                   ON follow_up.encounter_id = follow_up_6.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                                   ON follow_up.encounter_id = follow_up_7.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                                   ON follow_up.encounter_id = follow_up_8.encounter_id
                                         LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                                   ON follow_up.encounter_id = follow_up_9.encounter_id
                                WHERE follow_up_date_followup_ IS NOT NULL
                                  AND follow_up_status IS NOT NULL),

         ART_Initiation AS (SELECT PatientId,
                                   MIN(art_start_date) AS art_start_date
                            FROM FollowUpEncounters
                            WHERE art_start_date IS NOT NULL
                              AND art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                            GROUP BY PatientId),

         IntervalsDef AS (SELECT 0 AS interval_month
                          UNION ALL
                          SELECT 7
                          UNION ALL
                          SELECT 13
                          UNION ALL
                          SELECT 25
                          UNION ALL
                          SELECT 37),

         PatientIntervals AS (SELECT a.PatientId,
                                     a.art_start_date,
                                     i.interval_month,
                                     CASE
                                         WHEN i.interval_month = 0 THEN a.art_start_date
                                         ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH))
                                         END AS interval_end_date,
                                     CASE
                                         WHEN i.interval_month = 0 THEN REPORT_START_DATE
                                         ELSE COALESCE(LAG(fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                 fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                 INTERVAL i.interval_month MONTH)))
                                                           OVER (PARTITION BY a.PatientId ORDER BY i.interval_month),
                                                       REPORT_START_DATE)
                                         END AS interval_start_date
                              FROM ART_Initiation a
                                       CROSS JOIN IntervalsDef i),

         RankedIntervalData AS (SELECT pi.PatientId,
                                       pi.interval_month,
                                       pi.interval_end_date,
                                       pi.interval_start_date,
                                       f.follow_up_status                            AS strict_status,
                                       f.treatment_end_date                          AS strict_tx_end_date,
                                       f.regimen                                     AS strict_regimen,
                                       f.current_functional_status,
                                       f.cd4_count,
                                       f.cd4_percent,
                                       f.visitect_cd4_result,
                                       f.visitect_cd4_test_date,
                                       f.viral_load_received_date,
                                       f.viral_load_count,
                                       f.is_ti_visit,
                                       CASE WHEN f.is_ti_visit = 1 THEN 1 ELSE 0 END AS ti_in_this_interval,
                                       ROW_NUMBER() OVER (
                                           PARTITION BY pi.PatientId, pi.interval_month
                                           ORDER BY f.follow_up_date DESC
                                           )                                         AS rn
                                FROM PatientIntervals pi
                                         LEFT JOIN FollowUpEncounters f
                                                   ON pi.PatientId = f.PatientId
                                                       AND
                                                      f.follow_up_date BETWEEN pi.interval_start_date AND pi.interval_end_date),
         StrictIntervalData AS (SELECT PatientId,
                                       interval_month,
                                       interval_end_date,
                                       interval_start_date,
                                       strict_status,
                                       strict_tx_end_date,
                                       strict_regimen,
                                       current_functional_status,

                                       cd4_count,
                                       cd4_percent,
                                       visitect_cd4_result,
                                       visitect_cd4_test_date,
                                       viral_load_received_date,
                                       viral_load_count,
                                       is_ti_visit,
                                       ti_in_this_interval
                                FROM RankedIntervalData
                                WHERE rn = 1),

         StateCalculation AS (SELECT sid.*,
                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as is_cumulative_ti,

                                     MAX(ti_in_this_interval)
                                         OVER (PARTITION BY PatientId)                                                                          as ever_ti,

                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away',
                                                                    'Loss to follow-up', 'LTFU',
                                                                    'Loss to follow-up (LTFU)')
                                                 THEN 1
                                             ELSE 0 END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as has_terminal_event,
                                     MAX(CASE
                                             WHEN strict_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away',
                                                                    'Loss to follow-up', 'LTFU',
                                                                    'Loss to follow-up (LTFU)')
                                                 THEN strict_status
                                             ELSE NULL END)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as specific_terminal_event,
                                     MAX(strict_tx_end_date)
                                         OVER (PARTITION BY PatientId ORDER BY interval_month ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) as max_tx_end_date_so_far
                              FROM StrictIntervalData sid),

         CohortDetails AS (SELECT sc.*,
                                  client.date_of_birth,
                                  CASE
                                      WHEN has_terminal_event = 1 THEN specific_terminal_event
                                      WHEN max_tx_end_date_so_far >= interval_end_date THEN
                                          CASE
                                              WHEN strict_status IS NOT NULL THEN 'Active'
                                              ELSE 'Active - Carry Forward Rx' END
                                      ELSE 'Loss to follow-up (LTFU)'
                                      END AS final_cohort_outcome
                           FROM StateCalculation sc
                                    JOIN mamba_dim_client client ON sc.PatientId = client.client_id),

         CohortHeaderDates AS (SELECT interval_month,
                                      CASE
                                          WHEN interval_month = 0 THEN REPORT_START_DATE
                                          ELSE fn_ethiopian_to_gregorian_calendar(DATE_ADD(
                                                  fn_gregorian_to_ethiopian_calendar(REPORT_START_DATE, 'Y-M-D'),
                                                  INTERVAL interval_month MONTH))
                                          END AS header_gregorian_date
                               FROM IntervalsDef),
         CohortHeaderCalc AS (SELECT interval_month,
                                     CASE CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(
                                                                       fn_gregorian_to_ethiopian_calendar(
                                                                               CASE
                                                                                   WHEN interval_month = 0
                                                                                       THEN REPORT_END_DATE
                                                                                   ELSE header_gregorian_date
                                                                                   END,
                                                                               'Y-M-D'
                                                                       ), '-', 2), '-', -1) AS UNSIGNED)
                                         WHEN 1 THEN 'Meskerem'
                                         WHEN 2 THEN 'Tikimt'
                                         WHEN 3 THEN 'Hidar'
                                         WHEN 4 THEN 'Tahsas'
                                         WHEN 5 THEN 'Tir'
                                         WHEN 6 THEN 'Yekatit'
                                         WHEN 7 THEN 'Megabit'
                                         WHEN 8 THEN 'Miyazia'
                                         WHEN 9 THEN 'Ginbot'
                                         WHEN 10 THEN 'Sene'
                                         WHEN 11 THEN 'Hamle'
                                         WHEN 12 THEN 'Nehase'
                                         WHEN 13 THEN 'Pagume'
                                         END                     AS et_month,
                                     CAST(SUBSTRING_INDEX(
                                             fn_gregorian_to_ethiopian_calendar(
                                                     CASE
                                                         WHEN interval_month = 0 THEN report_end_date
                                                         ELSE header_gregorian_date
                                                         END,
                                                     'Y-M-D'
                                             ), '-', 1) AS CHAR) AS et_year
                              FROM CohortHeaderDates),

         CohortEnriched AS (SELECT interval_month,
                                   is_cumulative_ti,
                                   ever_ti,
                                   strict_status,
                                   ti_in_this_interval,
                                   final_cohort_outcome,
                                   cd4_percent,

                                   CASE
                                       WHEN final_cohort_outcome IN ('Active', 'Active - Carry Forward Rx') THEN 1
                                       ELSE 0 END                                                   AS is_active,
                                   CASE
                                       WHEN TIMESTAMPDIFF(YEAR, date_of_birth, interval_end_date) < 15 THEN 'PEDS'
                                       ELSE 'ADULT' END                                             AS age_group,
                                   LEFT(strict_regimen, 1)                                          as reg_prefix,

                                   CASE WHEN viral_load_received_date IS NOT NULL THEN 1 ELSE 0 END AS has_vl_test,
                                   CASE WHEN viral_load_count < 50 THEN 1 ELSE 0 END                AS is_suppressed
                            FROM CohortDetails),

         MonthlyStats AS (SELECT interval_month,
                                 SUM(CASE WHEN ever_ti = 0 THEN 1 ELSE 0 END)                              AS count_base,
                                 SUM(CASE WHEN is_cumulative_ti = 1 THEN 1 ELSE 0 END)                     AS cumulative_ti,
                                 SUM(CASE WHEN ever_ti = 1 THEN 1 ELSE 0 END)                              AS ever_ti,
                                 SUM(CASE WHEN ti_in_this_interval = 1 THEN 1 ELSE 0 END)                  AS count_ti_this_interval,
                                 SUM(CASE WHEN final_cohort_outcome = 'Transferred out' THEN 1 ELSE 0 END) AS count_to,
                                 SUM(CASE WHEN strict_status = 'Transferred out' THEN 1 ELSE 0 END)        AS count_interval_to,

                                 SUM(CASE WHEN final_cohort_outcome = 'Stop all' THEN 1 ELSE 0 END)        AS count_stop,
                                 SUM(CASE WHEN final_cohort_outcome = 'Dead' THEN 1 ELSE 0 END)            AS count_dead,
                                 SUM(CASE
                                         WHEN final_cohort_outcome IN ('Ran away', 'Loss to follow-up (LTFU)') THEN 1
                                         ELSE 0 END)                                                       AS count_ltfu,

                                 SUM(CASE WHEN is_cumulative_ti = 0 AND is_active = 1 THEN 1 ELSE 0 END)   as count_orig_active,
                                 SUM(CASE
                                         WHEN is_cumulative_ti = 0 AND final_cohort_outcome = 'Transferred out' THEN 1
                                         ELSE 0 END)                                                       as count_orig_to,

                                 SUM(CASE
                                         WHEN is_active = 1 AND ((age_group = 'ADULT' AND reg_prefix = '1') OR
                                                                 (age_group = 'PEDS' AND reg_prefix = '4')) THEN 1
                                         ELSE 0 END)                                                       AS reg_orig,
                                 SUM(CASE
                                         WHEN is_active = 1 AND ((age_group = 'ADULT' AND reg_prefix = '4') OR
                                                                 (age_group = 'PEDS' AND reg_prefix = '1')) THEN 1
                                         ELSE 0 END)                                                       AS reg_alt,
                                 SUM(CASE
                                         WHEN is_active = 1 AND ((age_group = 'ADULT' AND reg_prefix = '2') OR
                                                                 (age_group = 'PEDS' AND reg_prefix = '5')) THEN 1
                                         ELSE 0 END)                                                       AS reg_2nd,
                                 SUM(CASE
                                         WHEN is_active = 1 AND ((age_group = 'ADULT' AND reg_prefix = '3') OR
                                                                 (age_group = 'PEDS' AND reg_prefix = '6')) THEN 1
                                         ELSE 0 END)                                                       AS reg_3rd,

                                 AVG(CASE WHEN age_group = 'PEDS' THEN cd4_percent ELSE NULL END)          as avg_peds_cd4_pct,
                                 SUM(CASE WHEN is_active = 1 AND has_vl_test = 1 THEN 1 ELSE 0 END)        as count_vl_tested,
                                 SUM(CASE WHEN is_active = 1 AND is_suppressed = 1 THEN 1 ELSE 0 END)      as count_vl_suppressed

                          FROM CohortEnriched
                          GROUP BY interval_month)

    SELECT 'For cohort starting ART by month/year: at baseline then results at 6 months on ART, 12 months on ART, 24 months on ART'                                            AS Name,
           MAX(CASE WHEN interval_month = 0 THEN CONCAT(et_month, ' ', et_year) ELSE '' END)  AS 'Month 0',
           MAX(CASE WHEN interval_month = 7 THEN CONCAT(et_month, ' ', et_year) ELSE '' END)  AS 'Month 6',
           MAX(CASE WHEN interval_month = 13 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 12',
           MAX(CASE WHEN interval_month = 25 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 24',
           MAX(CASE WHEN interval_month = 37 THEN CONCAT(et_month, ' ', et_year) ELSE '' END) AS 'Month 36'
    FROM CohortHeaderCalc

    UNION ALL

    SELECT 'A. Started on ART in this clinic: original cohort',
           CAST(IFNULL(MAX(CASE WHEN interval_month = 0 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 0 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 0 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 0 THEN count_base END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 0 THEN count_base END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'B. Transfer in Add+',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN cumulative_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN cumulative_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN cumulative_ti END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN cumulative_ti END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'C. Transfers Out Subtract -',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_to END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_to END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_to END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_to END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'D. Net current cohort (A + B - C)',
           0,
           CAST(GREATEST(0, IFNULL(
                   MAX(CASE WHEN interval_month = 7 THEN (count_base + count_ti_this_interval) - count_interval_to END),
                   0)) AS SIGNED),
           CAST(GREATEST(0, IFNULL(MAX(CASE
                                           WHEN interval_month = 13
                                               THEN (count_base + count_ti_this_interval) - count_interval_to END),
                                   0)) AS SIGNED),
           CAST(GREATEST(0, IFNULL(MAX(CASE
                                           WHEN interval_month = 25
                                               THEN (count_base + count_ti_this_interval) - count_interval_to END),
                                   0)) AS SIGNED),
           CAST(GREATEST(0, IFNULL(MAX(CASE
                                           WHEN interval_month = 37
                                               THEN (count_base + count_ti_this_interval) - count_interval_to END),
                                   0)) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'E. On Original 1st Line Regimen',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN reg_orig END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN reg_orig END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN reg_orig END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN reg_orig END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'F. On Alternate 1st Line Regimen (Substituted)',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN reg_alt END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN reg_alt END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN reg_alt END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN reg_alt END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'G. On 2nd Line Regimen (Switched)',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN reg_2nd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN reg_2nd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN reg_2nd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN reg_2nd END), 0) AS SIGNED)
    FROM MonthlyStats
    UNION ALL

    SELECT 'H. On 3rd Line Regimen (Switched) ',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN reg_3rd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN reg_3rd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN reg_3rd END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN reg_3rd END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'I. Stopped',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_stop END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_stop END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_stop END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_stop END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'J. Died',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_dead END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_dead END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_dead END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_dead END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'K. Lost to Follow-up (DROP)',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_ltfu END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_ltfu END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_ltfu END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_ltfu END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'Percent of Net Facility Cohort Alive and on ART',
           0,
           CONCAT(ROUND(IFNULL((MAX(CASE WHEN interval_month = 7 THEN count_orig_active END) * 100.0) / NULLIF(
                   MAX(CASE WHEN interval_month = 0 THEN count_base END) -
                   MAX(CASE WHEN interval_month = 7 THEN count_orig_to END), 0), 0), 0), '%'),
           CONCAT(ROUND(IFNULL((MAX(CASE WHEN interval_month = 13 THEN count_orig_active END) * 100.0) / NULLIF(
                   MAX(CASE WHEN interval_month = 0 THEN count_base END) -
                   MAX(CASE WHEN interval_month = 13 THEN count_orig_to END), 0), 0), 0), '%'),
           CONCAT(ROUND(IFNULL((MAX(CASE WHEN interval_month = 25 THEN count_orig_active END) * 100.0) / NULLIF(
                   MAX(CASE WHEN interval_month = 0 THEN count_base END) -
                   MAX(CASE WHEN interval_month = 25 THEN count_orig_to END), 0), 0), 0), '%'),
           CONCAT(ROUND(IFNULL((MAX(CASE WHEN interval_month = 37 THEN count_orig_active END) * 100.0) / NULLIF(
                   MAX(CASE WHEN interval_month = 0 THEN count_base END) -
                   MAX(CASE WHEN interval_month = 37 THEN count_orig_to END), 0), 0), 0), '%')
    FROM MonthlyStats

    UNION ALL

    SELECT 'L. Mean CD4 % (for children)',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN avg_peds_cd4_pct END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN avg_peds_cd4_pct END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN avg_peds_cd4_pct END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN avg_peds_cd4_pct END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'N. Viral Load tested',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_vl_tested END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_vl_tested END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_vl_tested END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_vl_tested END), 0) AS SIGNED)
    FROM MonthlyStats

    UNION ALL

    SELECT 'O. Viral load Suppressed ( < 50 copies/ml)',
           0,
           CAST(IFNULL(MAX(CASE WHEN interval_month = 7 THEN count_vl_suppressed END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 13 THEN count_vl_suppressed END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 25 THEN count_vl_suppressed END), 0) AS SIGNED),
           CAST(IFNULL(MAX(CASE WHEN interval_month = 37 THEN count_vl_suppressed END), 0) AS SIGNED)
    FROM MonthlyStats;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_cxca_eligibility_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_cxca_eligibility_query;

~
CREATE PROCEDURE sp_fact_line_list_cxca_eligibility_query(IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUP AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_date_followup_                        as follow_up_date,
                             follow_up_status,
                             treatment_end_date                              as art_end_date,
                             hpv_dna_result_received_date,
                             date_cytology_result_received                   as cytology_result_date,
                             next_follow_up_screening_date                   AS ccs_next_date,
                             cervical_cancer_screening_status                AS screening_status,
                             hpv_dna_screening_result                        AS ccs_hpv_result,
                             cytology_result                                 AS cytology_result,
                             via_screening_result                            AS ccs_via_result,
                             via_done_,
                             date_visual_inspection_of_the_cervi             AS via_date,
                             treatment_start_date                            AS ccs_treat_received_date,
                             colposcopy_of_cervix_findings                   AS colposcopy_exam_finding,
                             colposcopy_exam_date,
                             purpose_for_visit_cervical_screening            as screening_type,
                             cervical_cancer_screening_method_strategy       as screening_method,
                             hpv_subtype,
                             date_hpv_test_was_done,
                             cytology_sample_collection_date,
                             biopsy_sample_collected_date,
                             biopsy_result_received_date,
                             biopsy_result,
                             treatment_of_precancerous_lesions_of_the_cervix as CCS_Precancerous_Treat,
                             confirmed_cervical_cancer_cases_bas,
                             referral_or_linkage_status,
                             reason_for_referral_cacx,
                             date_client_served_in_the_referred_,
                             date_client_arrived_in_the_referred,
                             date_patient_referred_out,
                             prep_offered,
                             weight_text_,
                             art_antiretroviral_start_date                   as art_start_date,
                             next_visit_date,
                             regimen,
                             antiretroviral_art_dispensed_dose_i             as dose_days,
                             pre_test_counselling_for_cervical_c                CCaCounsellingGiven,
                             ready_for_cervical_cancer_screening                Accepted,
                             eligible_for_cxca_screening,
                             reason_for_not_being_eligible,
                             other_reason_for_not_being_eligible_for_cxca
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         tmp_latest_follow_up AS (select encounter_id,
                                         FollowUP.client_id,
                                         TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE)                                                 as Age,
                                         art_start_date                                                                                      as ArtStartDate,
                                         next_visit_date,
                                         regimen,
                                         dose_days,
                                         sex,
                                         mrn,
                                         uan,
                                         patient_name,
                                         patient_uuid,
                                         date_of_birth,
                                         CCaCounsellingGiven,
                                         follow_up_date,
                                         follow_up_status,
                                         eligible_for_cxca_screening,
                                         reason_for_not_being_eligible,
                                         other_reason_for_not_being_eligible_for_cxca,
                                         ccs_via_result,
                                         screening_status,
                                         via_date,
                                         ccs_treat_received_date,
                                         date_patient_referred_out,
                                         hpv_dna_result_received_date,
                                         cytology_result,
                                         cytology_sample_collection_date,
                                         cytology_result_date,
                                         ccs_hpv_result,
                                         screening_method,
                                         screening_type,
                                         ccs_next_date,
                                         colposcopy_exam_finding,
                                         hpv_subtype,
                                         date_hpv_test_was_done,
                                         colposcopy_exam_date,
                                         biopsy_sample_collected_date,
                                         biopsy_result_received_date,
                                         biopsy_result,
                                         CCS_Precancerous_Treat,
                                         confirmed_cervical_cancer_cases_bas,
                                         REFERRAL_OR_LINKAGE_STATUS,
                                         reason_for_referral_cacx,
                                         date_client_arrived_in_the_referred,
                                         date_client_served_in_the_referred_,
                                         Accepted,
                                         weight_text_                                                                                        as Weight,
                                         mobile_no,
                                         phone_no,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUP.client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  from FollowUP
                                           join mamba_dim_client client on FollowUP.client_id = client.client_id
                                  where follow_up_date <= REPORT_END_DATE),
         latest_follow_up as (select *
                              from tmp_latest_follow_up
                              where row_num = 1
                                and follow_up_status NOT IN ('Dead', 'Transferred out')
                                and sex = 'Female'
                                and TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) BETWEEN 25 AND 65),

         tmp_prev_screening as (select *,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS scrn_row_num
                                from tmp_latest_follow_up
                                where screening_status = 'Cervical cancer screening performed'),
         prev_screening as (select * from tmp_prev_screening where scrn_row_num = 1),
         cx_base_clients as (select latest_follow_up.*,
                                    prev_screening.follow_up_date as previous_screening_follow_up_date,
                                    CASE
                                        -- TC-02,TC-03,TC-04,TC-05 No previous screening and not eligible for cxca screening
                                        WHEN prev_screening.client_id IS NULL
                                            AND latest_follow_up.eligible_for_cxca_screening = 'No'
                                            THEN
                                            CONCAT('Not Eligible ',
                                                   COALESCE(latest_follow_up.reason_for_not_being_eligible,
                                                            latest_follow_up.other_reason_for_not_being_eligible_for_cxca))

                                        -- TC-06 User-Labeled as Eligible
                                        WHEN prev_screening.client_id IS NULL
                                            AND
                                             latest_follow_up.screening_status != 'Cervical cancer screening performed'
                                            AND latest_follow_up.eligible_for_cxca_screening = 'Yes'
                                            THEN 'Eligible Labeled by User'

                                        -- TC-07 Never screened/assessed
                                        WHEN prev_screening.client_id IS NULL
                                            AND latest_follow_up.eligible_for_cxca_screening IS NULL
                                            THEN 'Eligible Never Screened/Assessed'

                                        -- TC-08 Unknown VIA result
                                        WHEN prev_screening.ccs_via_result = 'Unknown'
                                            THEN 'Eligible Unknown VIA Screening Result'

                                        -- TC-09 VIA negative >2 years ago
                                        WHEN (TIMESTAMPDIFF(DAY, prev_screening.via_date, REPORT_END_DATE)) > 730
                                            AND prev_screening.ccs_via_result = 'VIA negative'
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-10 VIA Positive: Eligible for Cryo/Thermocoagulation & Treatment Given/Referred
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula'
#                                           or prev_screening.ccs_via_result =
#                                           'VIA positive: non-eligible for cryo/thermo-coagula' or
#                                           prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                 )
                                            AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                REPORT_END_DATE)) > 365 or
                                                 (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                REPORT_END_DATE)) > 365)
                                            AND prev_screening.biopsy_result is null
                                            THEN 'Eligible Post Treatment/Referral Follow-Up'

                                        -- TC-11 VIA Positive: Eligible for Cryo/Thermocoagulation No Treatment/Referral
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula'
#                                           or prev_screening.ccs_via_result =
#                                           'VIA positive: non-eligible for cryo/thermo-coagula' or
#                                           prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                 )
                                            AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                            and
                                             (prev_screening.date_patient_referred_out is null
                                                 or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            AND prev_screening.biopsy_result is null
                                            THEN 'Eligible Treatment Not Received or Not Referred'

                                        -- TC-12 VIA Positive & Not Eligible for Cryo/Thermocoagulation OR Suspicious for Cervical Cancer Treatment & NO BIOPSY
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: non-eligible for cryo/thermo-coagula'
                                            or
                                              prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                 )
                                            AND prev_screening.biopsy_result is null
                                            THEN 'Eligible Biopsy Test Not Done'

                                        -- TC-13 HPV negative >3 years ago
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Negative result'
                                                and TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                                  REPORT_END_DATE) > 1095
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-14 HPV positive, needs VIA triage
                                        WHEN
                                            prev_screening.ccs_via_result is null
                                                and prev_screening.ccs_hpv_result = 'Positive'
                                            THEN 'Eligible Needs VIA Triage'

                                        -- TC-15 Cytology Negative >3 years ago
                                        WHEN
                                            prev_screening.cytology_result = 'Negative result'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.cytology_result_date, REPORT_END_DATE) >
                                            1095
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-16 Cytology Positive  NO HPV Test Followed
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.hpv_dna_result_received_date is null
                                            THEN 'Eligible Needs HPV Triage'

                                        -- TC-17 Cytology Positive, HPV Test Done Next & Result Nagative (Reassess after Two Years)(Algorithm 7)
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.ccs_hpv_result = 'Negative result'
                                                AND prev_screening.hpv_dna_result_received_date >
                                                    prev_screening.cytology_result_date
                                                and TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                                  REPORT_END_DATE) > 730
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-18 Cytology Positive, HPV Test Done Next & Result Positive (Colposcopy Triage Needed)(Algorithm 7)
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.ccs_hpv_result = 'Positive'
                                                AND prev_screening.hpv_dna_result_received_date >
                                                    prev_screening.cytology_result_date
                                                and prev_screening.colposcopy_exam_finding is null
                                            THEN 'Eligible Needs Colposcopy Test'

                                        -- TC-19 Biopsy +ve (> CIN3) AND Treatment Give/Referred (See Algorithm 1, 2, 3 & 6)
                                        WHEN (prev_screening.biopsy_result = 'Carcinoma in situ'
                                            or prev_screening.biopsy_result = 'Invasive cervical cancer'
                                            or prev_screening.biopsy_result = 'Other')
                                            AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE
                                                or prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                            THEN 'Not Eligible Confirmed Cirvical Cancer'

                                        -- TC-20 Biopsy Result CIN-1, CIN-2 Rescreening Needed After One YEAR (See Algorithm 1, 2, 3 & 6)
                                        WHEN (prev_screening.biopsy_result = 'CIN (1-3)'
                                            or prev_screening.biopsy_result = 'CIN-2'
                                                 )
                                            and TIMESTAMPDIFF(DAY, prev_screening.biopsy_result_received_date,
                                                              REPORT_END_DATE) > 365
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-20A,TC-20B,TC-20C VIA result Positive & Biopsy Done (CIN1),CIN2,Negative
                                        WHEN
                                            (
                                                prev_screening.ccs_via_result =
                                                'VIA positive: non-eligible for cryo/thermo-coagula' or
                                                prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                )
                                                AND (prev_screening.biopsy_result = 'CIN (1-3)' or
                                                     prev_screening.biopsy_result = 'CIN-2' or
                                                     prev_screening.biopsy_result = 'Negative result')
                                                and TIMESTAMPDIFF(DAY, prev_screening.biopsy_result_received_date,
                                                                  REPORT_END_DATE) > 365
                                                AND
                                            prev_screening.biopsy_result_received_date >= prev_screening.via_date
                                            THEN 'Eligible Needs Re-Screening'

                                        -- TC-21 Colposcopy +ve but No Treatment/Referral
                                        WHEN (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                              prev_screening.colposcopy_exam_finding = 'High Grade')
                                            AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                            and
                                             (prev_screening.date_patient_referred_out is null
                                                 or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN 'Eligible Treatment Not Received or Not Referred'

                                        -- TC-22 Colposcopy +ve and treatment given
                                        WHEN (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                              prev_screening.colposcopy_exam_finding = 'High Grade')
                                            AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                REPORT_END_DATE)) > 365 or
                                                 (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                REPORT_END_DATE)) > 365)
                                            THEN 'Eligible Post Treatment/Referral Follow-Up'
                                        -- OLD
                                        WHEN
                                            prev_screening.ccs_hpv_result = 'Unknown'
                                            THEN 'Eligible Unknown HPV Screening Result'

                                        -- Cytology ASCUS, hpv positive, colposcopy normal
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.colposcopy_exam_date, REPORT_END_DATE) >
                                            1095
                                            THEN 'Eligible Needs Re-Screening'
                                        -- Cytology ASCUS, hpv positive, colposcopy low/high and 365 days since treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                #                                             AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE or
#                                                  prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                                AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                    REPORT_END_DATE)) > 365 or
                                                     (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                    REPORT_END_DATE)) > 365)
                                            THEN 'Eligible Post Treatment/Referral Follow-Up'
                                        -- Cytology ASCUS, hpv positive, colposcopy low/high and no referral or treatment
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                #                                             AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE or
#                                                  prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                                AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                                and
                                            (prev_screening.date_patient_referred_out is null
                                                or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN 'Eligible Treatment Not Received or Not Referred'

                                        -- Cytology ASCUS, hpv not done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result is null and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                            THEN 'Eligible (Needs HPV Triage)'


                                        -- Cytology > ASCUS, colposcopy normal
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.colposcopy_exam_date, REPORT_END_DATE) >
                                            1095
                                            THEN 'Eligible Needs Re-Screening'
                                        -- Cytology > ASCUS, colposcopy low/high and 365 days since treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                    REPORT_END_DATE)) > 365 or
                                                     (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                    REPORT_END_DATE)) > 365)
                                            THEN 'Eligible Post Treatment/Referral Follow-Up'
                                        -- Cytology > ASCUS, colposcopy low/high and no treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                                and
                                            (prev_screening.date_patient_referred_out is null
                                                or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN 'Eligible Treatment Not Received or Not Referred'

                                        -- Cytology > ASCUS, colposcopy not done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding is null
                                            THEN 'Eligible Needs Colposcopy Test'
                                        END
                                        AS EligibilityStatus,


                                    CASE
                                        WHEN prev_screening.client_id IS NULL
                                            AND latest_follow_up.eligible_for_cxca_screening = 'No'
                                            THEN
                                            'Not Eligible '

                                        -- TC-06 User-Labeled as Eligible
                                        WHEN prev_screening.client_id IS NULL
                                            AND latest_follow_up.screening_status !=
                                                'Cervical cancer screening performed'
                                            AND latest_follow_up.eligible_for_cxca_screening = 'Yes'
                                            THEN REPORT_END_DATE

                                        -- TC-07 Never screened/assessed
                                        WHEN prev_screening.client_id IS NULL
                                            AND latest_follow_up.eligible_for_cxca_screening IS NULL
                                            THEN REPORT_END_DATE

                                        -- TC-08 Unknown VIA result
                                        WHEN prev_screening.ccs_via_result = 'Unknown'
                                            THEN REPORT_END_DATE

                                        -- TC-09 VIA negative >2 years ago
                                        WHEN (TIMESTAMPDIFF(DAY, prev_screening.via_date, REPORT_END_DATE)) > 730
                                            AND prev_screening.ccs_via_result = 'VIA negative'
                                            THEN DATE_ADD(prev_screening.via_date, INTERVAL 730 DAY)

                                        -- TC-10 VIA Positive: Eligible for Cryo/Thermocoagulation & Treatment Given/Referred
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula')
                                            AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                REPORT_END_DATE)) > 365 or
                                                 (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                REPORT_END_DATE)) > 365)
                                            AND prev_screening.biopsy_result is null
                                            THEN COALESCE(
                                                DATE_ADD(prev_screening.ccs_treat_received_date, INTERVAL 365 DAY),
                                                DATE_ADD(prev_screening.date_patient_referred_out, INTERVAL 365 DAY))

                                        -- TC-11 VIA Positive: Eligible for Cryo/Thermocoagulation No Treatment/Referral
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula')
                                            AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                            and
                                             (prev_screening.date_patient_referred_out is null
                                                 or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            AND prev_screening.biopsy_result is null
                                            THEN REPORT_END_DATE

                                        -- TC-12 VIA Positive & Not Eligible for Cryo/Thermocoagulation OR Suspicious for Cervical Cancer Treatment & NO BIOPSY
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: non-eligible for cryo/thermo-coagula'
                                            or
                                              prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                 )
                                            AND prev_screening.biopsy_result is null
                                            THEN REPORT_END_DATE

                                        -- TC-13 HPV negative >3 years ago
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Negative result'
                                                and TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                                  REPORT_END_DATE) > 1095
                                            THEN DATE_ADD(prev_screening.hpv_dna_result_received_date, INTERVAL 1095
                                                          DAY)

                                        -- TC-14 HPV positive, needs VIA triage
                                        WHEN
                                            prev_screening.ccs_via_result is null
                                                and prev_screening.ccs_hpv_result = 'Positive'
                                            THEN REPORT_END_DATE

                                        -- TC-15 Cytology Negative >3 years ago
                                        WHEN
                                            prev_screening.cytology_result = 'Negative result'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.cytology_result_date,
                                                          REPORT_END_DATE) >
                                            1095
                                            THEN DATE_ADD(prev_screening.cytology_result_date, INTERVAL 1095 DAY)

                                        -- TC-16 Cytology Positive  NO HPV Test Followed
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.hpv_dna_result_received_date is null
                                            THEN REPORT_END_DATE

                                        -- TC-17 Cytology Positive, HPV Test Done Next & Result Nagative (Reassess after Two Years)(Algorithm 7)
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.ccs_hpv_result = 'Negative result'
                                                AND prev_screening.hpv_dna_result_received_date >
                                                    prev_screening.cytology_result_date
                                                and TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                                  REPORT_END_DATE) > 730
                                            THEN DATE_ADD(prev_screening.hpv_dna_result_received_date, INTERVAL 730
                                                          DAY)

                                        -- TC-18 Cytology Positive, HPV Test Done Next & Result Positive (Colposcopy Triage Needed)(Algorithm 7)
                                        WHEN
                                            (prev_screening.cytology_result =
                                             'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                or prev_screening.cytology_result = '> Ascus')
                                                AND prev_screening.ccs_hpv_result = 'Positive'
                                                AND prev_screening.hpv_dna_result_received_date >
                                                    prev_screening.cytology_result_date
                                                and prev_screening.colposcopy_exam_finding is null
                                            THEN REPORT_END_DATE

                                        -- TC-19 Biopsy +ve (> CIN3) AND Treatment Give/Referred (See Algorithm 1, 2, 3 & 6)
                                        WHEN (prev_screening.biopsy_result = 'Carcinoma in situ'
                                            or prev_screening.biopsy_result = 'Invasive cervical cancer'
                                            or prev_screening.biopsy_result = 'Other')
                                            AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE
                                                or prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                            THEN 'Not Applicable'

                                        -- TC-20 Biopsy Result CIN-1, CIN-2 Rescreening Needed After One YEAR (See Algorithm 1, 2, 3 & 6)
                                        WHEN (prev_screening.biopsy_result = 'CIN (1-3)'
                                            or prev_screening.biopsy_result = 'CIN-2'
                                                 )
                                            and TIMESTAMPDIFF(DAY, prev_screening.biopsy_result_received_date,
                                                              REPORT_END_DATE) > 365
                                            THEN DATE_ADD(prev_screening.biopsy_result, INTERVAL 365 DAY)

                                        -- TC-20A,TC-20B,TC-20C VIA result Positive & Biopsy Done (CIN1),CIN2,Negative
                                        WHEN
                                            (
                                                prev_screening.ccs_via_result =
                                                'VIA positive: non-eligible for cryo/thermo-coagula' or
                                                prev_screening.ccs_via_result = 'suspected cervical cancer'
                                                )
                                                AND (prev_screening.biopsy_result = 'CIN (1-3)' or
                                                     prev_screening.biopsy_result = 'CIN-2' or
                                                     prev_screening.biopsy_result = 'Negative result')
                                                and TIMESTAMPDIFF(DAY, prev_screening.biopsy_result_received_date,
                                                                  REPORT_END_DATE) > 365
                                                AND
                                            prev_screening.biopsy_result_received_date >= prev_screening.via_date
                                            THEN DATE_ADD(prev_screening.biopsy_result, INTERVAL 365 DAY)

                                        -- TC-21 Colposcopy +ve but No Treatment/Referral
                                        WHEN (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                              prev_screening.colposcopy_exam_finding = 'High Grade')
                                            AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                            and
                                             (prev_screening.date_patient_referred_out is null
                                                 or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN 'Not Applicable'

                                        -- TC-22 Colposcopy +ve and treatment given
                                        WHEN (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                              prev_screening.colposcopy_exam_finding = 'High Grade')
                                            AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                REPORT_END_DATE)) > 365 or
                                                 (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                REPORT_END_DATE)) > 365)
                                            THEN REPORT_END_DATE
                                        -- OLD
                                        -- No previous screening and eligible for cxca screening
                                        WHEN prev_screening.client_id IS NULL AND
                                             latest_follow_up.eligible_for_cxca_screening = 'Yes'
                                            THEN REPORT_END_DATE
                                        -- No previous screening and eligibility not documented
                                        WHEN prev_screening.client_id IS NULL AND
                                             latest_follow_up.eligible_for_cxca_screening IS NULL
                                            THEN REPORT_END_DATE

                                        -- VIA Negative and prev via date > 730 days
                                        WHEN
                                            (TIMESTAMPDIFF(DAY, prev_screening.via_date, REPORT_END_DATE)) > 730 AND
                                            prev_screening.ccs_via_result = 'VIA negative'
                                            THEN DATE_ADD(prev_screening.via_date, INTERVAL 730 DAY)

                                        -- VIA Positive or suspicious 365 days since treatment or referral
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula' or
                                              prev_screening.ccs_via_result =
                                              'VIA positive: non-eligible for cryo/thermo-coagula' or
                                              prev_screening.ccs_via_result = 'suspected cervical cancer')
                                            #                                         AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE or
#                                              prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                            AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                REPORT_END_DATE)) > 365 or
                                                 (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                REPORT_END_DATE)) > 365)
                                            THEN DATE_ADD(COALESCE(prev_screening.ccs_treat_received_date,
                                                                   prev_screening.date_patient_referred_out),
                                                          INTERVAL
                                                          730 DAY)

                                        -- VIA Positive or suspicious and no treatment and not referred
                                        WHEN (prev_screening.ccs_via_result =
                                              'VIA positive: eligible for cryo/thermo-coagula' or
                                              prev_screening.ccs_via_result =
                                              'VIA positive: non-eligible for cryo/thermo-coagula' or
                                              prev_screening.ccs_via_result = 'suspected cervical cancer')
                                            AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                            and
                                             (prev_screening.date_patient_referred_out is null
                                                 or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN REPORT_END_DATE

                                        -- VIA Unknown screening result
                                        WHEN prev_screening.ccs_via_result = 'Unknown'
                                            THEN REPORT_END_DATE

                                        -- HPV negative and previous hpv date > 1095
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Negative result' and
                                            TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                          REPORT_END_DATE) > 1095
                                            THEN DATE_ADD(prev_screening.hpv_dna_result_received_date, INTERVAL 1095
                                                          DAY)
                                        -- HPV Positive and no via done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive'
                                            THEN REPORT_END_DATE
                                        -- HPV date unknown
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Unknown'
                                            THEN REPORT_END_DATE
                                        -- Cytology negative result
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            -- prev_screening.ccs_hpv_result is null and
                                            prev_screening.cytology_result = 'Negative result' and
                                            TIMESTAMPDIFF(DAY, prev_screening.cytology_result_date,
                                                          REPORT_END_DATE) >
                                            1095
                                            THEN DATE_ADD(prev_screening.cytology_result_date, INTERVAL 1095 DAY)
                                        -- Cytology ASCUS, hpv positive, colposcopy normal
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.colposcopy_exam_date,
                                                          REPORT_END_DATE) >
                                            1095
                                            THEN DATE_ADD(prev_screening.colposcopy_exam_date, INTERVAL 1095 DAY)
                                        -- Cytology ASCUS, hpv positive, colposcopy low/high and 365 days since treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                #                                             AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE or
#                                                  prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                                AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                    REPORT_END_DATE)) > 365 or
                                                     (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                    REPORT_END_DATE)) > 365)
                                            THEN DATE_ADD(COALESCE(prev_screening.ccs_treat_received_date,
                                                                   prev_screening.date_patient_referred_out),
                                                          INTERVAL
                                                          365 DAY)
                                        -- Cytology ASCUS, hpv positive, colposcopy low/high and no referral or treatment
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                #                                             AND (prev_screening.ccs_treat_received_date <= REPORT_END_DATE or
#                                                  prev_screening.date_patient_referred_out <= REPORT_END_DATE)
                                                AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                                and
                                            (prev_screening.date_patient_referred_out is null
                                                or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN REPORT_END_DATE

                                        -- Cytology ASCUS, hpv positive, colposcopy not done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Positive' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and prev_screening.colposcopy_exam_finding is null
                                            THEN REPORT_END_DATE

                                        -- Cytology ASCUS, hpv Negative
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result = 'Negative result' and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                and TIMESTAMPDIFF(DAY, prev_screening.hpv_dna_result_received_date,
                                                                  REPORT_END_DATE) > 1095
                                            THEN DATE_ADD(prev_screening.hpv_dna_result_received_date, INTERVAL 1095
                                                          DAY)

                                        -- Cytology ASCUS, hpv not done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.ccs_hpv_result is null and
                                            prev_screening.cytology_result =
                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                            THEN REPORT_END_DATE


                                        -- Cytology > ASCUS, colposcopy normal
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and
                                            TIMESTAMPDIFF(DAY, prev_screening.colposcopy_exam_date,
                                                          REPORT_END_DATE) >
                                            1095
                                            THEN DATE_ADD(prev_screening.colposcopy_exam_date, INTERVAL 1095 DAY)
                                        -- Cytology > ASCUS, colposcopy low/high and 365 days since treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                AND ((TIMESTAMPDIFF(DAY, prev_screening.ccs_treat_received_date,
                                                                    REPORT_END_DATE)) > 365 or
                                                     (TIMESTAMPDIFF(DAY, prev_screening.date_patient_referred_out,
                                                                    REPORT_END_DATE)) > 365)
                                            THEN DATE_ADD(COALESCE(prev_screening.ccs_treat_received_date,
                                                                   prev_screening.date_patient_referred_out),
                                                          INTERVAL
                                                          365 DAY)
                                        -- Cytology > ASCUS, colposcopy low/high and no treatment or referral
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding = 'Normal'
                                                and (prev_screening.colposcopy_exam_finding = 'Low Grade' or
                                                     prev_screening.colposcopy_exam_finding = 'High Grade')
                                                AND (prev_screening.ccs_treat_received_date is null
                                                or prev_screening.ccs_treat_received_date > REPORT_END_DATE)
                                                and
                                            (prev_screening.date_patient_referred_out is null
                                                or prev_screening.date_patient_referred_out > REPORT_END_DATE)
                                            THEN REPORT_END_DATE

                                        -- Cytology > ASCUS, colposcopy not done
                                        WHEN
                                            -- prev_screening.ccs_via_result is null and
                                            prev_screening.cytology_result =
                                            '> Ascus'
                                                and prev_screening.colposcopy_exam_finding is null
                                            THEN REPORT_END_DATE
                                        END                       AS EligibilityDate
                             from latest_follow_up
                                      left join prev_screening on prev_screening.client_id = latest_follow_up.client_id),
        cx_eligibility as (  select patient_name                                                                 `Patient Name`,
                                    patient_uuid                                                                 `UUID`,
                                    CAST(mrn AS CHAR(20))                                                     as mrn,
                                    CONCAT('''', uan) as uan,
                                    mobile_no                                                                 as `Mobile No`,
                                    phone_no                                                                  as `Home Telephone No`,
                                    Weight,
                                    Age,
                                    CAST(EligibilityDate AS Date)                                                           as `Eligibility Date`,
                                    CAST(EligibilityDate AS Date)                                                           as `Eligibility Date EC.`,
                                    CASE WHEN EligibilityStatus IS NOT NULL THEN LEFT(EligibilityStatus, IF(LEFT(EligibilityStatus, 3) = 'Eli', 8, 12))
                                        ELSE 'Screened for CXCA' END
                                        as `Eligibility Status`,
                                    SUBSTR(EligibilityStatus, IF(LEFT(EligibilityStatus, 3) = 'Eli', 10, 14)) as `Eligibility Reason`,
                                    follow_up_date                                                            as `Follow Up Date`,
                                    follow_up_date                                                            as `Follow Up Date EC.`,
                                    ArtStartDate                                                              as `Art Start Date`,
                                    ArtStartDate                                                              as `Art Start Date EC.`,
                                    CASE follow_up_status
                                        WHEN 'Alive' THEN 'Alive on ART'
                                        WHEN 'Restart medication' THEN 'Restart'
                                        WHEN 'Transferred out' THEN 'TO'
                                        WHEN 'Stop all' THEN 'Stop'
                                        WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                                        WHEN 'Ran away' THEN 'Drop'
                                        END                                                                   AS `Follow Up Status`,
                                    next_visit_date                                                           as `Next Appointment Date`,
                                    next_visit_date                                                           as `Next Appointment Date EC.`,
                                    regimen                                                                   as `ARV Regimen`,
                                    dose_days                                                                 as `ART Dose Days`,
                                    CCaCounsellingGiven                                                       as Counselled,
                                    Accepted,
                                    screening_type                                                            as `Screening Type`,
                                    screening_method                                                             `Screening Method`,
                                    hpv_subtype                                                               as `HPV SubType`,
                                    date_hpv_test_was_done                                                    as `HPV Sample Collected Date`,
                                    date_hpv_test_was_done                                                    as `HPV Sample Collected Date EC.`,
                                    hpv_dna_result_received_date                                              as `HPV DNA Result Received Date`,
                                    hpv_dna_result_received_date                                              as `HPV DNA Result Received Date EC.`,
                                    ccs_hpv_result                                                            as `HPV Result`,
                                    via_date                                                                  as `VIA Screening Date`,
                                    via_date                                                                  as `VIA Screening Date EC.`,
                                    ccs_via_result                                                            as `VIA Screening Result`,
                                    cytology_sample_collection_date                                           as `Cytology Sample Collected Date`,
                                    cytology_sample_collection_date                                           as `Cytology Sample Collected Date EC.`,
                                    cytology_result_date                                                      as `Cytology Result Received Date`,
                                    cytology_result_date                                                      as `Cytology Result Received Date EC.`,
                                    cytology_result                                                           as `Cytology Result`,
                                    colposcopy_exam_date                                                      as `Colposcopy Exam Date`,
                                    colposcopy_exam_date                                                      as `Colposcopy Exam Date EC.`,
                                    colposcopy_exam_finding                                                   as `Colposcopy Exam Result`,
                                    biopsy_sample_collected_date                                              as `Biopsy Sample Collected Date`,
                                    biopsy_sample_collected_date                                              as `Biopsy Sample Collected Date EC.`,
                                    biopsy_result_received_date                                               as `Biopsy Result Received Date`,
                                    biopsy_result_received_date                                               as `Biopsy Result Received Date EC.`,
                                    biopsy_result                                                             as `Biopsy Result`,
                                    CCS_Precancerous_Treat                                                    as `Treatment Received For Precancerous Lesion`,
                                    ccs_treat_received_date                                                   as `Date Treatment Given`,
                                    ccs_treat_received_date                                                   as `Date Treatment Given EC.`,
                                    referral_or_linkage_status                                                as `Referral Status`,
                                    reason_for_referral_cacx                                                  as `Reason For Referral`,
                                    date_patient_referred_out                                                 as `Date Referred to Other HF`,
                                    date_patient_referred_out                                                 as `Date Referred to Other HF EC.`,
                                    date_client_arrived_in_the_referred                                       as `Date Client Arrived in Reffered HF`,
                                    date_client_arrived_in_the_referred                                       as `Date Client Arrived in Reffered HF EC.`,
                                    date_client_served_in_the_referred_                                       as `Date Client Served in Reffered HF`,
                                    date_client_served_in_the_referred_                                       as `Date Client Served in Reffered HF EC.`,
                                    ccs_next_date                                                             as `Next Appointment Date for CCS`,
                                    ccs_next_date                                                             as `Next Appointment Date for CCS EC.`
                             from cx_base_clients)
    select * from cx_eligibility;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_cxca_scrn_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_cxca_scrn_query;

~
CREATE PROCEDURE sp_fact_line_list_cxca_scrn_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp as (select follow_up.encounter_id,
                             follow_up.client_id,
                             cervical_cancer_screening_status          as cx_ca_screening_status,
                             cervical_cancer_screening_method_strategy as screening_method,
                             purpose_for_visit_cervical_screening      as type_of_screening,
                             via_screening_result,
                             hpv_dna_screening_result,
                             follow_up_date_followup_                  as follow_up_date,
                             date_hpv_test_was_done                    as hpv_date,
                             date_visual_inspection_of_the_cervi       as via_date,
                             cytology_sample_collection_date           as cytology_date,
                             follow_up_status,
                             treatment_end_date,
                             antiretroviral_art_dispensed_dose_i       as dose_days,
                             art_antiretroviral_start_date             as art_start_date,
                             cytology_result,
                             purpose_for_visit_cervical_screening      as visit_type,
                             hpv_dna_result_received_date              as hpv_received_date,
                             date_cytology_result_received             as cytology_received_date,
                             date_counseling_given,
                             ready_for_cervical_cancer_screening,
                             date_linked_to_cervical_cancer_scre,
                             colposcopy_of_cervix_findings,
                             colposcopy_exam_date,
                             biopsy_result,
                             biopsy_result_received_date,
                             biopsy_sample_collected_date,
                             treatment_of_precancerous_lesions_of_the_cervix,
                             next_visit_date,
                             next_follow_up_screening_date,
                             regimen,
                             adherence,
                             referral_or_linkage_status,
                             referred_to_higher_level_facility,
                             reason_for_referral_cacx,
                             date_client_arrived_in_the_referred,
                             date_client_served_in_the_referred_,
                             hpv_subtype,
                             treatment_start_date,
                             date_patient_referred_out
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         tmp_latest_follow_up AS (SELECT client_id,
                                         follow_up_date,
                                         encounter_id,
                                         follow_up_status,
                                         treatment_end_date,
                                         dose_days,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
             --  AND follow_up_date <= ?
         ),

         currently_on_art AS (select *
                              from tmp_latest_follow_up
                              where row_num = 1
                                -- AND follow_up_status in ('Alive', 'Restart medication')
                              ),
         tmp_cx_screened as (select FollowUp.*,
                                    ROW_NUMBER() over (PARTITION BY FollowUp.client_id ORDER BY via_date DESC,hpv_received_date DESC,cytology_received_date DESC , FollowUp.encounter_id DESC) as row_num
                             from FollowUp
                                      join currently_on_art on FollowUp.client_id = currently_on_art.client_id
                             where cx_ca_screening_status = 'Cervical cancer screening performed'
                               and ((via_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                                        -- AND screening_type != 'Human Papillomavirus test'
                                        ) OR
                                    (hpv_received_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE) OR
                                    (cytology_received_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE))),
         cx_screened as (select tmp_cx_screened.*,
                                CASE


                                    #  WHEN screening_type='Human Papillomavirus test' and hpv_dna_screening_result ='Unknown' then 'Cervical Cancer screen: Suspected Cancer'

                                    WHEN screening_method = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' and
                                         via_screening_result = 'VIA negative' then 'Cervical Cancer screen: Negative'
                                    WHEN screening_method = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' and
                                         (via_screening_result = 'VIA positive: eligible for cryo/thermo-coagulation' or
                                          via_screening_result = 'VIA positive: eligible for cryo/thermo-coagula' or
                                          via_screening_result =
                                          'VIA positive: non-eligible for cryo/thermo-coagulation')
                                        then 'Cervical Cancer screen: Positive'
                                    WHEN screening_method = 'Visual Inspection of the Cervix with Acetic Acid (VIA)' and
                                         via_screening_result = 'Suspicious for cervical cancer' or
                                         via_screening_result = 'suspected cervical cancer'
                                        then 'Cervical Cancer screen: Suspected Cancer'

                                    WHEN screening_method = 'Human Papillomavirus test' and
                                         hpv_dna_screening_result = 'Negative result'
                                        then 'Cervical Cancer screen: Negative'
                                    WHEN screening_method = 'Human Papillomavirus test' and
                                         hpv_dna_screening_result = 'Positive'
                                        and
                                         (via_screening_result = 'VIA positive: eligible for cryo/thermo-coagulation' or
                                          via_screening_result = 'VIA positive: eligible for cryo/thermo-coagula' or
                                          via_screening_result =
                                          'VIA positive: non-eligible for cryo/thermo-coagulation')
                                        then 'Cervical Cancer screen: Positive'
                                    WHEN screening_method = 'Human Papillomavirus test' and
                                         hpv_dna_screening_result = 'Positive'
                                        and via_screening_result = 'VIA negative'
                                        then 'Cervical Cancer screen: Negative'
                                    WHEN screening_method = 'Cytology' and
                                         (cytology_result = 'Negative' OR cytology_result = 'ASCUS')
                                        THEN 'Cervical Cancer screen: Negative'
                                    WHEN screening_method = 'Cytology' and cytology_result = '> Ascus'
                                        THEN 'Cervical Cancer screen: Positive'
                                    END AS screening_result,
                                client.uan,
                                CAST(client.mrn AS CHAR(20)) as mrn,
                                client.patient_uuid,
                                client.sex,
                                client.date_of_birth,
                                client.patient_name
                         from tmp_cx_screened
                                  join mamba_dim_client client
                                       on tmp_cx_screened.client_id = client.client_id
                         where row_num = 1
                           and TIMESTAMPDIFF(YEAR, date_of_birth, follow_up_date) >= 15
             -- and not (screening_type = 'Human Papillomavirus test' and hpv_dna_screening_result = 'Positive' and via_screening_result is null )
         )
    select patient_name                                        as `Patient Name`,
           patient_uuid                                        as `UUID`,
           MRN,
           CONCAT('''', uan) as UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) as `Current Age`,
           Sex,
           follow_up_date                                      as `Follow-Up Date`,
           follow_up_date                                      as `Follow-Up Date EC.`,
           art_start_date                                      as `Art Start Date`,
           art_start_date                                      as `Art Start Date EC.`,
           date_counseling_given                               as `Date Counseled For CCA`,
           date_counseling_given                               as `Date Counseled For CCA EC.`,
           ready_for_cervical_cancer_screening                 as `Date Accepted CxCa Screening`,
           ready_for_cervical_cancer_screening                 as `Date Accepted CxCa Screening EC.`,
           date_linked_to_cervical_cancer_scre                 as `Date Linked to CxCa Screening Unit`,
           date_linked_to_cervical_cancer_scre                 as `Date Linked to CxCa Screening Unit EC.`,
           type_of_screening                                   as `Type of Screening`,
           screening_method                                    as `Screening Strategy`,
           via_screening_result                                as `VIA Screening Result`,
           via_date                                            as `VIA Screening Date`,
           via_date                                            as `VIA Screening Date EC.`,
           hpv_dna_screening_result                            as `HPV DNA Screening Result`,
           hpv_date                                            as `HPV DNA Sample Collection Date`,
           hpv_date                                            as `HPV DNA Sample Collection Date EC.`,
           hpv_subtype                                            `HPV Subtype`,
           hpv_received_date                                   as `HPV DNA Result Received Date`,
           hpv_received_date                                   as `HPV DNA Result Received Date EC.`,
           cytology_result                                     as `Cytology Result`,
           cytology_date                                       as `Cytology Sample Collection Date`,
           cytology_date                                       as `Cytology Sample Collection Date EC.`,
           cytology_received_date                              as `Cytology Result Received Date`,
           cytology_received_date                              as `Cytology Result Received Date EC.`,
           colposcopy_of_cervix_findings                       as `Colposcopy Exam Finding`,
           colposcopy_exam_date                                as `Colposcopy Exam Date`,
           colposcopy_exam_date                                as `Colposcopy Exam Date EC.`,
           biopsy_result                                       as `Biopsy Result`,
           biopsy_sample_collected_date                        as `Biopsy Sample Collection Date`,
           biopsy_sample_collected_date                        as `Biopsy Sample Collection Date EC.`,
           biopsy_result_received_date                         as `Biopsy Result Received Date`,
           biopsy_result_received_date                         as `Biopsy Result Received Date EC.`,
           treatment_of_precancerous_lesions_of_the_cervix     as `Treatment for Precancerous Lesion`,
# Treatment for Confirmed CxCa
           treatment_start_date                                as `Date Treatment Received`,
           treatment_start_date                                as `Date Treatment Received EC.`,
           next_follow_up_screening_date                       as `Next Follow-up Screening Date`,
           next_follow_up_screening_date                       as `Next Follow-up Screening Date EC.`,
           referral_or_linkage_status                          as `Referral/ Linkage Status`,
           reason_for_referral_cacx                            as `Reason for Referral`,
           date_patient_referred_out                           as `Date of Referral to other HF`,
           date_patient_referred_out                           as `Date of Referral to other HF EC.`,
# Referral Confirmed Date EC.
# Feedback from the other HF
           date_client_served_in_the_referred_                 as `Date Client Served in the referred HF`,
           date_client_served_in_the_referred_                 as `Date Client Served in the referred HF EC.`,
           CASE follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                    as `Latest Follow-Up Status`,
           regimen                                             as `Latest Regimen`,
           dose_days                                           as `Latest ARV Dose Days`,
           adherence                                              `Latest Adherence`,
           next_visit_date                                     as `Next Visit Date`,
           next_visit_date                                     as `Next Visit Date EC.`,
           treatment_end_date                                  as `Last TX_Curr Date`,
           treatment_end_date                                  as `Last TX_Curr Date EC.`

    from cx_screened;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_hvl_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_hvl_query;

~
CREATE PROCEDURE sp_fact_line_list_hvl_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_date_followup_                          as follow_up_date,
                             follow_up_status,
                             art_antiretroviral_start_date                     as art_start_date,
                             regimen_change                                    as switch,
                             date_of_reported_hiv_viral_load                      viral_load_sent_date,
                             date_viral_load_results_received                     viral_load_performed_date,
                             viral_load_test_status,
                             hiv_viral_load                                    as viral_load_count,
                             viral_load_test_indication,
                             hiv_viral_load_status,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                                 AS routine_viral_load_test_indication,
                             COALESCE(
                                     repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                     suspected_antiretroviral_failure
                             )                                                 AS targeted_viral_load_test_indication,
                             date_third_enhanced_adherence_counseling_provided as eac_3,
                             date_second_enhanced_adherence_counseling_provided   eac_2,
                             date_first_enhanced_adherence_counseling_provided    eac_1,
                             weight_text_                                      as weight,
                             date_of_event                                     as hiv_confirmed_date,
                             pregnancy_status,
                             antiretroviral_art_dispensed_dose_i                  dispensed_dose,
                             regimen,
                             anitiretroviral_adherence_level                   as adherence,
                             next_visit_date,
                             treatment_end_date                                   art_dose_end_date
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id),


         tmp_vl_performed_date_1 AS (SELECT encounter_id,
                                            client_id,
                                            viral_load_performed_date,
                                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_performed_date DESC , FollowUp.encounter_id DESC ) AS row_num
                                     FROM FollowUp
                                     WHERE viral_load_performed_date BETWEEN COALESCE(REPORT_START_DATE,'1900-01-01') AND COALESCE(REPORT_END_DATE,CURDATE())
                                       -- AND routine_viral_load_test_indication IS NOT NULL
                                       AND routine_viral_load_test_indication NOT IN (
                                                                                      'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                                                      'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'
                                         )
                                       AND (
                                         targeted_viral_load_test_indication IS NULL
                                             OR targeted_viral_load_test_indication NOT IN
                                                ('Suspected ART failure', 'Suspected Antiretroviral failure')
                                         )),
         tmp_vl_performed_date_1_dedup AS (select * from tmp_vl_performed_date_1 where row_num = 1),

         tmp_vl_sent_date AS (SELECT FollowUp.client_id,
                                     viral_load_sent_date                                                                                                          AS VL_Sent_Date,
                                     ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.viral_load_sent_date DESC , FollowUp.encounter_id DESC ) AS row_num
                              FROM FollowUp
                                       Inner Join tmp_vl_performed_date_1_dedup
                                                  ON tmp_vl_performed_date_1_dedup.client_id = FollowUp.client_id
                                                      AND (tmp_vl_performed_date_1_dedup.viral_load_performed_date =
                                                           FollowUp.viral_load_performed_date)
                              WHERE FollowUp.follow_up_date <= COALESCE(REPORT_END_DATE,CURDATE())
                                and viral_load_sent_date is not null),
         vl_sent_date AS (select *
                          from tmp_vl_sent_date
                          where row_num = 1),

         vl_performed_date AS (SELECT FollowUp.encounter_id,
                                      FollowUp.client_id,
                                      FollowUp.viral_load_performed_date,
                                      FollowUp.viral_load_test_status,
                                      viral_load_count,
                                      CASE
                                          WHEN vl_sent_date.VL_Sent_Date IS NOT NULL
                                              THEN vl_sent_date.VL_Sent_Date
                                          WHEN FollowUp.viral_load_performed_date IS NOT NULL
                                              THEN FollowUp.viral_load_performed_date
                                          Else NULL END                   AS viral_load_ref_date,
                                      routine_viral_load_test_indication  AS routine_viral_load,
                                      targeted_viral_load_test_indication AS target,
                                      (SELECT f2.regimen
                                       FROM FollowUp f2
                                       WHERE f2.client_id = FollowUp.client_id
                                         AND f2.follow_up_date <=
                                             COALESCE(vl_sent_date.VL_Sent_Date, FollowUp.viral_load_performed_date)
                                       ORDER BY f2.follow_up_date DESC, f2.encounter_id DESC
                                       LIMIT 1)                           AS hvl_regimen
                               FROM FollowUp
                                        INNER JOIN tmp_vl_performed_date_1_dedup
                                                   ON FollowUp.encounter_id = tmp_vl_performed_date_1_dedup.encounter_id
                                        LEFT JOIN vl_sent_date ON FollowUp.client_id = vl_sent_date.client_id)
            ,
         tmp_vl_performed_date_cf AS (SELECT FollowUp.encounter_id,
                                             FollowUp.client_id,
                                             FollowUp.viral_load_performed_date                                                                                            AS viral_load_perform_date,
                                             ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.viral_load_performed_date , FollowUp.encounter_id DESC ) AS row_num
                                      FROM FollowUp
                                               join vl_performed_date on FollowUp.client_id = vl_performed_date.client_id
                                      where FollowUp.hiv_viral_load_status = 'Completed'
                                        and (
                                          (FollowUp.viral_load_test_indication = 'Routine viral load test indication'
                                              and FollowUp.routine_viral_load_test_indication in
                                                  ('Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                   'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'
                                                      ))
                                              OR
                                          (FollowUp.viral_load_test_indication = 'Targeted viral load test indication'
                                              and FollowUp.targeted_viral_load_test_indication in
                                               --  ('Repeat or confirmatory VL: initial viral load greater than 1000')
                                                  ('Suspected ART failure', 'Suspected Antiretroviral failure')
                                              )
                                          )
                                        and FollowUp.viral_load_performed_date >=
                                            vl_performed_date.viral_load_performed_date
                                        and FollowUp.viral_load_performed_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         tmp_vl_performed_date_cf_2 AS (select * from tmp_vl_performed_date_cf where row_num = 1),
         tmp_switch_sub_date AS (SELECT FollowUp.encounter_id,
                                        FollowUp.client_id,
                                        follow_up_date                                                                                     as switch_date,
                                        ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY follow_up_date, FollowUp.encounter_id) AS row_num
                                 FROM FollowUp
                                          JOIN tmp_vl_performed_date_cf_2 cf on FollowUp.client_id = cf.client_id
                                 WHERE FollowUp.follow_up_date BETWEEN cf.viral_load_perform_date AND COALESCE(REPORT_END_DATE,CURDATE())
                                   and switch is not null
                                   and switch = 'Regimen switch type'),
         switch_sub_date AS (select * from tmp_switch_sub_date where row_num = 1),

         tmp_vl_sent_date_cf AS (SELECT FollowUp.client_id,
                                        viral_load_sent_date                                                                                                     AS VL_Sent_Date,
                                        ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.viral_load_sent_date , FollowUp.encounter_id DESC ) AS row_num
                                 FROM FollowUp
                                          Inner Join tmp_vl_performed_date_cf_2
                                                     ON tmp_vl_performed_date_cf_2.client_id = FollowUp.client_id
                                                         AND (tmp_vl_performed_date_cf_2.viral_load_perform_date =
                                                              FollowUp.viral_load_performed_date)
                                 WHERE FollowUp.follow_up_date <= COALESCE(REPORT_END_DATE,CURDATE())
                                   and viral_load_sent_date is not null),
         vl_sent_date_cf AS (select *
                             from tmp_vl_sent_date_cf
                             where row_num = 1),


         tmp_vl_performed_date_cf_3 AS (SELECT FollowUp.encounter_id,
                                               FollowUp.client_id,
                                               FollowUp.viral_load_performed_date,
                                               FollowUp.viral_load_test_status,
                                               FollowUp.viral_load_count           AS viral_load_count,
                                               CASE
                                                   WHEN vl_sent_date_cf.VL_Sent_Date IS NOT NULL
                                                       THEN vl_sent_date_cf.VL_Sent_Date
                                                   WHEN FollowUp.viral_load_performed_date IS NOT NULL
                                                       THEN FollowUp.viral_load_performed_date
                                                   Else NULL END                   AS viral_load_ref_date,
                                               routine_viral_load_test_indication  AS routine_viral_load_cf,
                                               targeted_viral_load_test_indication AS targeted_viral_load_cf,

                                               targeted_viral_load_test_indication AS target_cf
                                        FROM FollowUp
                                                 INNER JOIN tmp_vl_performed_date_cf_2
                                                            ON FollowUp.encounter_id = tmp_vl_performed_date_cf_2.encounter_id
                                                 LEFT JOIN vl_sent_date_cf ON FollowUp.client_id = vl_sent_date_cf.client_id),
         tmp_vl_perf_date_eac_1 AS (SELECT FollowUp.client_id,
                                           eac_1                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_1 , FollowUp.encounter_id DESC ) AS row_num
                                    FROM FollowUp
                                             INNER JOIN vl_performed_date ON vl_performed_date.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_1 is not null
                                      AND vl_performed_date.viral_load_performed_date <= FollowUp.eac_1
                                      AND eac_1 <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_perf_date_eac_2 AS (SELECT FollowUp.client_id,
                                           eac_2                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_2 , FollowUp.encounter_id DESC ) AS row_num
                                    FROM FollowUp
                                             INNER JOIN vl_performed_date ON vl_performed_date.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_2 is not null
                                      AND vl_performed_date.viral_load_performed_date <= FollowUp.eac_2
                                      AND eac_2 <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_perf_date_eac_3 AS (SELECT FollowUp.client_id,
                                           eac_3                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_3 , FollowUp.encounter_id DESC ) as row_num
                                    FROM FollowUp
                                             INNER JOIN vl_performed_date ON vl_performed_date.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_3 is not null
                                      AND vl_performed_date.viral_load_performed_date <= FollowUp.eac_3
                                      AND eac_3 <= COALESCE(REPORT_END_DATE,CURDATE())),

         tmp_vl_perf_date_eac_1_cf AS (SELECT FollowUp.client_id,
                                           eac_1                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_1 , FollowUp.encounter_id DESC ) AS row_num
                                    FROM FollowUp
                                             INNER JOIN tmp_vl_performed_date_cf_2 ON tmp_vl_performed_date_cf_2.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_1 is not null
                                      AND tmp_vl_performed_date_cf_2.viral_load_perform_date <= FollowUp.eac_1
                                      AND eac_1 <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_perf_date_eac_2_cf AS (SELECT FollowUp.client_id,
                                           eac_2                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_2 , FollowUp.encounter_id DESC ) AS row_num
                                    FROM FollowUp
                                             INNER JOIN tmp_vl_performed_date_cf_2 ON tmp_vl_performed_date_cf_2.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_2 is not null
                                      AND tmp_vl_performed_date_cf_2.viral_load_perform_date <= FollowUp.eac_2
                                      AND eac_2 <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_perf_date_eac_3_cf AS (SELECT FollowUp.client_id,
                                           eac_3                                                                                                     AS Date_EAC_Provided,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.eac_3 , FollowUp.encounter_id DESC ) as row_num
                                    FROM FollowUp
                                             INNER JOIN tmp_vl_performed_date_cf_2 ON tmp_vl_performed_date_cf_2.client_id = FollowUp.client_id
                                    WHERE FollowUp.eac_3 is not null
                                      AND tmp_vl_performed_date_cf_2.viral_load_perform_date <= FollowUp.eac_3
                                      AND eac_3 <= COALESCE(REPORT_END_DATE,CURDATE())),

         vl_perf_date_eac_1 AS (select * from tmp_vl_perf_date_eac_1 where row_num = 1),
         vl_perf_date_eac_2 AS (select * from tmp_vl_perf_date_eac_2 where row_num = 1),
         vl_perf_date_eac_3 AS (select * from tmp_vl_perf_date_eac_3 where row_num = 1),
         vl_perf_date_eac_1_cf AS (select * from tmp_vl_perf_date_eac_1_cf where row_num = 1),
         vl_perf_date_eac_2_cf AS (select * from tmp_vl_perf_date_eac_2_cf where row_num = 1),
         vl_perf_date_eac_3_cf AS (select * from tmp_vl_perf_date_eac_3_cf where row_num = 1),

         tmp_latest_follow_up AS (SELECT FollowUp.client_id,
                                         FollowUp.encounter_id,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.follow_up_date DESC , FollowUp.encounter_id DESC ) as row_num
                                  FROM FollowUp
                                    --       left join tmp_vl_performed_date_cf_2 cf on FollowUp.client_id = cf.client_id
                                  where follow_up_status Is Not Null
                                    AND follow_up_date <= COALESCE(REPORT_END_DATE,CURDATE())
                              --      AND (cf.viral_load_perform_date IS NULL OR   follow_up_date >= cf.viral_load_perform_date)
                                  ),
         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
         hvl as (SELECT client.patient_uuid                                                                    as PatientGUID,
                        client.patient_name,
                        client.mrn,
                        client.uan,
                        TIMESTAMPDIFF(YEAR, client.date_of_birth,
                                      COALESCE(vlsentdate.VL_Sent_Date, vlperfdate.viral_load_performed_date)) AS age,
                        CASE Sex
                            WHEN 'FEMALE' THEN 'F'
                            WHEN 'MALE' THEN 'M'
                            end                                                                                as Sex,
                        f_case.encounter_id                                                                    as Id,
                        f_case.client_id                                                                       as PatientId,
                        f_case.weight,
                        f_case.hiv_confirmed_date                                                              as date_hiv_confirmed,
                        f_case.art_start_date,
                        f_case.follow_up_date                                                                  as FollowUpDate,
                        f_case.pregnancy_status                                                                as IsPregnant,
                        f_case.dispensed_dose                                                                  as ARVDispendsedDose,
                        f_case.regimen                                                                         as art_dose,
                        f_case.next_visit_date,
                        f_case.follow_up_status,
                        f_case.art_dose_end_date                                                               as art_dose_End,
                        vlperfdate.viral_load_performed_date                                                   as viral_load_perform_date,
                        vlperfdate.viral_load_test_status                                                      as viral_load_status,
                        vlperfdate.viral_load_count,
                        vlsentdate.VL_Sent_Date,
                        vlperfdate.viral_load_ref_date,
                        sub_switch_date.switch_date                                                            as SwitchDate,
                        date_eac1_cf.Date_EAC_Provided                                                            as date_eac_provided_1,
                        date_eac2_cf.Date_EAC_Provided                                                            as date_eac_provided_2,
                        date_eac3_cf.Date_EAC_Provided                                                            as date_eac_provided_3,
                        vlsentdate_cf.VL_Sent_Date                                                             as viral_load_sent_date_cf,
                        vlperfdate_cf.viral_load_performed_date                                                as viral_load_perform_date_cf,
                        vlperfdate_cf.viral_load_test_status                                                   as viral_load_status_cf,
                        vlperfdate_cf.viral_load_count                                                         as viral_load_count_cf,
                        vlperfdate.routine_viral_load,
                        vlperfdate.target,
                        vlperfdate_cf.routine_viral_load_cf,
                        vlperfdate_cf.targeted_viral_load_cf,
                        vlperfdate_cf.target_cf,
                        vlperfdate.hvl_regimen,
                        f_case.adherence
                 FROM FollowUp AS f_case
                          INNER JOIN latest_follow_up ON f_case.encounter_id = latest_follow_up.encounter_id
                          LEFT JOIN mamba_dim_client client on latest_follow_up.client_id = client.client_id
                          LEFT JOIN vl_performed_date as vlperfdate ON vlperfdate.client_id = f_case.client_id
                          LEFT JOIN tmp_vl_performed_date_cf_3 as vlperfdate_cf
                                    ON vlperfdate_cf.client_id = f_case.client_id
                          Left join vl_sent_date as vlsentdate ON vlsentdate.client_id = f_case.client_id
                          Left join vl_sent_date_cf as vlsentdate_cf ON vlsentdate_cf.client_id = f_case.client_id
                          Left join vl_perf_date_eac_1 as date_eac1 ON date_eac1.client_id = f_case.client_id
                          Left join vl_perf_date_eac_2 as date_eac2 ON date_eac2.client_id = f_case.client_id
                          Left join vl_perf_date_eac_3 as date_eac3 ON date_eac3.client_id = f_case.client_id
                          Left join vl_perf_date_eac_1_cf as date_eac1_cf ON date_eac1_cf.client_id = f_case.client_id
                          Left join vl_perf_date_eac_2_cf as date_eac2_cf ON date_eac2_cf.client_id = f_case.client_id
                          Left join vl_perf_date_eac_3_cf as date_eac3_cf ON date_eac3_cf.client_id = f_case.client_id
                          Left join switch_sub_date as sub_switch_date ON sub_switch_date.client_id = f_case.client_id)

    SELECT patient_name               as `Patient Name`,
           PatientGUID                as `UUID`,
           CAST(mrn AS CHAR(20))      as mrn,
           CONCAT('''', uan) as uan,
           age                        AS age,
           sex,
           weight,
           date_hiv_confirmed         as `HIV Confirmed Date`,
           date_hiv_confirmed         as `HIV Confirmed Date EC.`,
           art_start_date             as `ART Start Date`,
           art_start_date             as `ART Start Date EC.`,
           FollowUpDate               as `Follow Up Date`,
           FollowUpDate               as `Follow Up Date EC.`,
           IsPregnant                 as IsPregnant,
           ARVDispendsedDose          as `ART Regimen`,
           art_dose                   as art_dose,
           next_visit_date            as `Next Visit Date`,
           next_visit_date            as `Next Visit Date EC.`,
           CASE follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                    AS `Follow Up Status`,
           art_dose_End               as `ART Dose End Date`,
           art_dose_End               as `ART Dose End Date EC.`,
           vl_sent_date               as `First VL Sent Date`,
           vl_sent_date               as `First VL Sent Date EC.`,
           viral_load_perform_date    as `First VL Received Date`,
           viral_load_perform_date    as `First VL Received Date EC.`,
           CASE
               WHEN viral_load_count IS NOT NULL THEN
                   CASE
                       WHEN viral_load_count < 51 THEN 'Suppressed'
                       WHEN viral_load_count BETWEEN 51 AND 1000 THEN 'Low Level Viremia'
                       WHEN viral_load_count > 1000 THEN 'High VL'
                       END
               WHEN viral_load_status LIKE 'Su%'
                   OR viral_load_status LIKE 'Undet%' THEN 'Suppressed'
               WHEN viral_load_status LIKE 'Low Level Viremia%' THEN 'Low Level Viremia'
               WHEN viral_load_status LIKE 'Det%' OR viral_load_status LIKE 'Uns%' OR viral_load_status LIKE 'High VL%'
                   THEN 'High VL'
               ELSE NULL
               END                    as `First VL Status`,
           viral_load_count           as `First VL Count`,
           COALESCE(routine_viral_load,target)          as `First VL Indication`,
           SwitchDate                 as `Regimen Change Date`,
           SwitchDate                 as `Regimen Change Date EC.`,
           date_eac_provided_1        as `First VL EAC1`,
           date_eac_provided_1        as `First VL EAC1 EC.`,
           date_eac_provided_2        as `First VL EAC2`,
           date_eac_provided_2        as `First VL EAC2 EC.`,
           date_eac_provided_3        as `First VL EAC3`,
           date_eac_provided_3        as `First VL EAC3 EC.`,
           viral_load_sent_date_cf    as `Confirmatory VL Sent Date`,
           viral_load_sent_date_cf    as `Confirmatory VL Sent Date EC.`,
           viral_load_perform_date_cf as `Confirmatory VL Received Date`,
           viral_load_perform_date_cf as `Confirmatory VL Received Date EC.`,
           CASE
               WHEN viral_load_count_cf IS NOT NULL THEN
                   CASE
                       WHEN viral_load_count_cf < 51 THEN 'Suppressed'
                       WHEN viral_load_count_cf BETWEEN 51 AND 1000 THEN 'Low Level Viremia'
                       WHEN viral_load_count_cf > 1000 THEN 'High VL'
                       END
               WHEN viral_load_status_cf LIKE 'Su%'
                   OR viral_load_status_cf LIKE 'Undet%' THEN 'Suppressed'
               WHEN viral_load_status_cf LIKE 'Low Level Viremia%' THEN 'Low Level Viremia'
               WHEN viral_load_status_cf LIKE 'Det%' OR viral_load_status_cf LIKE 'Uns%' OR
                    viral_load_status_cf LIKE 'High VL%' THEN 'High VL'
               ELSE NULL
               END                    as `Confirmatory VL Status`,
           viral_load_count_cf        as `Confirmatory VL Count`,
           COALESCE(routine_viral_load_cf,targeted_viral_load_cf)       as `Confirmatory VL Indication`,
           date_eac_provided_1        as `Confirmatory EAC1  Date`,
           date_eac_provided_1        as `Confirmatory EAC1  Date EC.`,
           date_eac_provided_2        as `Confirmatory EAC2  Date`,
           date_eac_provided_2        as `Confirmatory EAC2  Date EC.`,
           date_eac_provided_3        as `Confirmatory EAC3  Date`,
           date_eac_provided_3        as `Confirmatory EAC3  Date EC.`
    FROM hvl
    where ((viral_load_count BETWEEN 51 AND 1000 OR viral_load_count > 1000)
        OR
           (viral_load_status LIKE 'Low Level Viremia%' OR viral_load_status LIKE 'Det%' OR
            viral_load_status LIKE 'Uns%' OR viral_load_status LIKE 'High VL%'))
      and TIMESTAMPDIFF(DAY, art_start_date, COALESCE(REPORT_END_DATE,CURDATE())) >= 0;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ict_contacts_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ict_contacts_query;

~
CREATE PROCEDURE sp_fact_line_list_ict_contacts_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH contact_list as (select g.client_id                                              as index_client_id,
                                 contact.client_id,
                                 contact.elicited_date,
                                 contact.hiv_test_date,
                                 contact.hiv_test_result,
                                 contact.trial_date_1st,
                                 contact.trial_date_2nd,
                                 contact.trial_date_3rd,
                                 contact.contact_category,
                                 contact.hivst_result,
                                 contact.hivst_report_date,
                                 contact.first_name                                       as contact_first_name,
                                 contact.middle_name                                      as contact_middle_name,
                                 contact.last_name                                        as contact_last_name,
                                 contact_1.hivst_kit_distributed_date,
                                 contact_1.is_ipv_intimate_partner_violence_risk_assessed,
                                 contact_1.prior_hiv_test_result,
                                 contact_1.prior_test_date_estimated,
                                 contact_1.ipv_intimate_partner_violence_risk_outcome,
                                 contact_1.hiv_status_disclosed_by_index_client,
                                 contact_1.trial_outcome_1st,
                                 contact_1.trial_outcome_2nd,
                                 contact_1.trial_outcome_3rd,
                                 contact_1.date_of_case_closure,
                                 contact_1.notification_plan,
                                 COALESCE(contact_1.ae_type_3rd_report, contact_1.ae_type_2nd_report,
                                          contact_1.ae_type_1st_report)                   as adverse_event_type,
                                 COALESCE(contact_1.ae_for_ipv_report_date_3rd, contact_1.ae_for_ipv_report_date_2nd,
                                          contact_1.ae_for_ipv_report_date_1st)           as adverse_event_reported,
                                 contact_1.date_linked_to_care,
                                 contact_1.reason_if_not_linked_to_ict,
                                 contact_1.date_linked_to_ict_service,
                                 contact_1.art_antiretroviral_start_date,
                                 g.ict_serial_number,
                                 g.hiv_selftest_performed,
                                 g.ict_indexclient_testing,
                                 g.link_date_ict,
                                 index_contact.state_province,
                                 index_contact.county_district,
                                 index_contact.city_village,
                                 index_contact.phone_no,
                                 index_contact.mobile_no,
                                 index_contact.mrn,
                                 index_contact.uan,

                                 index_client.patient_uuid,
                                 index_client.given_name,
                                 index_client.middle_name,
                                 index_client.family_name,
                                 index_client.mrn                                         as index_mrn,
                                 index_client.uan                                         as index_uan,
                                 coalesce(contact_birthdate, index_contact.date_of_birth) as birthdate,
                                 CASE
                                     WHEN COALESCE(index_contact.sex, contact_1.respondent_gender) IN
                                          ('F', 'Female gender') THEN 'Female'
                                     WHEN COALESCE(index_contact.sex, contact_1.respondent_gender) IN
                                          ('M', 'Male gender') THEN 'Male'
                                     ELSE COALESCE(index_contact.sex, contact_1.respondent_gender)
                                     END                                                  AS sex

                          from mamba_flat_encounter_index_contact_followup contact
                                   left join mamba_flat_encounter_index_contact_followup_1 contact_1
                                             on contact.encounter_id = contact_1.encounter_id
                                   left join mamba_flat_encounter_ict_general g on contact.client_id = g.client_id
                                   left join mamba_dim_client index_client on contact.client_id = index_client.client_id
                                   left join mamba_dim_encounter encounter
                                             on contact.encounter_id = encounter.encounter_id
                                   left join mamba_dim_person_attribute attribute on encounter.uuid = attribute.value
                                   left join mamba_dim_client index_contact
                                             on attribute.person_id = index_contact.client_id)
    select CONCAT_WS(' ', contact_first_name, contact_middle_name, contact_last_name) as `Contact’s Full Name`,
           elicited_date                                                              as `Elicited date GC.`,
           elicited_date                                                              as `Elicited date EC.`,

           contact_list.state_province                                                as Region,
           contact_list.county_district                                               as Zone,
           contact_list.city_village                                                  as Woreda,
           contact_list.phone_no                                                      as `Phone`,
           contact_list.mobile_no                                                     as `Mobile`,
           contact_category                                                           as `Contact Category (1-5)`,
           is_ipv_intimate_partner_violence_risk_assessed                             as `IPV Risk Assessed`,
           ipv_intimate_partner_violence_risk_outcome                                 as `IPV outcome [1-5]`,
           hiv_status_disclosed_by_index_client                                       as `HIV status disclosed by Index Client?`,
           notification_plan                                                          as `Notification plan`,
           trial_date_1st                                                             as `1st  Trial Date GC.`,
           trial_date_1st                                                             as `1st  Trial Date EC.`,
           trial_outcome_1st                                                          as `1stTrial Outcome`,
           trial_date_2nd                                                             as `2nd Trial Date GC.`,
           trial_date_2nd                                                             as `2nd Trial Date EC.`,
           trial_outcome_2nd                                                          as `2nd Trial Outcome`,
           trial_date_3rd                                                             as `3rd Trial Date GC.`,
           trial_date_3rd                                                             as `3rd Trial Date EC.`,
           trial_outcome_3rd                                                          as `3rd Trial Outcome`,
           prior_hiv_test_result                                                      as `Prior HIV Test Result`,
           hivst_kit_distributed_date                                                 as `Date Self-Test Kit distributed GC.`,
           hivst_kit_distributed_date                                                 as `Date Self-Test Kit distributed EC.`,
           hivst_report_date                                                          as `HIV Self-Test Report Date GC.`,
           hivst_report_date                                                          as `HIV Self-Test Report Date EC.`,
           hivst_result                                                               as `HIV Self-Test Result`,
           CASE WHEN hiv_test_date IS NOT NULL THEN 'YES' ELSE 'NO' END               AS `HIV Test Done by National Algorithm`,
           hiv_test_date                                                              as `Date HIV Test Done by National Algorithm GC.`,
           hiv_test_date                                                              as `Date HIV Test Done by National Algorithm EC.`,
           hiv_test_result                                                            as `HIV Test Result by National Algorithm`,
           date_linked_to_care                                                           `Date linked to care GC.`,
           date_linked_to_care                                                           `Date linked to care EC.`,
           art_antiretroviral_start_date                                                 `Date ART started GC.`,
           art_antiretroviral_start_date                                                 `Date ART started EC.`,
           CONCAT('''', contact_list.uan)                                             as `UAN of newly identified HIV +ve`,
           contact_list.mrn                                                           as `MRN of newly identified HIV +ve`,
           ict_indexclient_testing                                                       `Client Linked to ICT Service`,
           reason_if_not_linked_to_ict                                                   `Reason if not linked to ICT`,
           date_linked_to_ict_service                                                    `Date linked to ICT Service GC.`,
           date_linked_to_ict_service                                                    `Date linked to ICT Service EC.`,
           CASE WHEN adverse_event_reported is not null THEN 'Yes' ELSE 'No' END      as `Adverse Event Reported`,
           adverse_event_type                                                         as `Adverse Event Type`,
           patient_uuid                                                               as `GUID of Index Case`,
           index_mrn                                                                  as `MRN of Index Case`,
           CONCAT('''', index_uan)                                                    as `UAN of Index Case`,
           CONCAT_WS(' ', given_name, middle_name, family_name)                       as `Full Name of Index Case`,
           ict_serial_number                                                          as `ICT#`
    from contact_list
    WHERE elicited_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ict_screening_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ict_screening_query;

~
CREATE PROCEDURE sp_fact_line_list_ict_screening_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    With offer_list as (select client.client_id,
                               client.mrn,
                               client.uan,
                               client.sex,
                               client.patient_uuid,
                               client.patient_name,
                               offer.offered_date,
                               visit_date_ict_offer,
                               priority_criteria,
                               offered,
                               ict_serial_number,
                               offer.yes,
                               offer.no,
                               elicited,
                               high_risk_for_ipv,
                               accepted,
                               accepted_date,
                               linked_to_appropriate_care,
                               specify_other_adverse_event_type,
                               reason_ict_service_not_accepted,
                               adverse_event_type,
                               ROW_NUMBER() over (PARTITION BY client.client_id ORDER BY offered_date DESC ) as row_num
                        from mamba_flat_encounter_ict_general ict_general
                                 join mamba_flat_encounter_ict_offer offer on ict_general.client_id = offer.client_id
                                 join mamba_dim_client client on ict_general.client_id = client.client_id
                        where offered_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         offer as (select * from offer_list where row_num = 1),
         FollowUp as (SELECT follow_up.encounter_id,
                             follow_up.client_id                                                                                                      AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_                                                                                                 AS follow_up_date,
                             art_antiretroviral_start_date                                                                                            AS art_start_date,
                             treatment_end_date,
                             regimen,
                             antiretroviral_art_dispensed_dose_i                                                                                      AS ARTDoseDays,
                             anitiretroviral_adherence_level                                                                                          AS AdherenceLevel,
                             pregnancy_status,
                             next_visit_date,
                             date_of_reported_hiv_viral_load                                                                                          AS viral_load_sent_date,
                             date_viral_load_results_received                                                                                         AS viral_load_received_date,
                             viral_load_test_status                                                                                                   AS viral_load_result,
                             hiv_viral_load                                                                                                           as viral_load_count,
                             cd4_count,
                             cd4_                                                                                                                     as cd4_percent,
                             current_functional_status,
                             transferred_in_check_this_for_all_t,
                             visitect_cd4_result,
                             visitect_cd4_test_date,
                             date_of_event,
                             ROW_NUMBER() OVER (PARTITION BY follow_up.client_id ORDER BY follow_up_date_followup_ DESC, follow_up.encounter_id DESC) as rn
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                      WHERE follow_up_date_followup_ <= REPORT_END_DATE),
         LatestFollowUp AS (SELECT *
                            FROM FollowUp
                            where rn = 1)
    select patient_uuid                    as `GUID`,
           mrn                             as `MRN`,
           CONCAT('''', uan)                             as `UAN`,
           ict_serial_number               as `ICT#`,
           patient_name                    as `Full Name`,
           date_of_event                   as `Date Confirmed HIV+ve GC.`,
           date_of_event                   as `Date Confirmed HIV+ve EC.`,
           art_start_date                  as `ART Start Date GC.`,
           art_start_date                  as `ART Start Date EC.`,
           follow_up_date                  as `Last ART Follow-Up Date GC.`,
           follow_up_date                  as `Last ART Follow-Up Date EC.`,
           priority_criteria               as `Prioritization for ICT`,
           offered_date as `Offered Date GC.`,
           offered_date as `Offered Date EC.`,
           accepted                        as `Accepted (Yes)`,
           accepted_date as `Accepted Date GC.`,
           accepted_date as `Accepted Date EC.`,
           reason_ict_service_not_accepted as `Accepted (No): Reason`,
           elicited                        as `Elicited`
    from offer
             left join LatestFollowUp on offer.client_id = LatestFollowUp.PatientId;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_maternal_pmtct_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_maternal_pmtct_query;
~
CREATE PROCEDURE sp_fact_line_list_maternal_pmtct_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH Enrollment AS (SELECT client_id,
                               encounter_id,
                               antenatal_care_provider,
                               ld_client,
                               post_natal_care,
                               art_clinic,
                               location_of_birth,
                               date_of_enrollment_or_booking,
                               currently_breastfeeding_child,
                               pregnancy_status,
                               date_referred_to_pmtct,
                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY date_of_enrollment_or_booking , encounter_id ) as row_num
                        FROM mamba_flat_encounter_pmtct_enrollment
                        WHERE date_of_enrollment_or_booking BETWEEN REPORT_START_DATE AND REPORT_END_DATE),

         Discharge AS (SELECT *,
                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY discharge_date , encounter_id ) as row_num
                       FROM mamba_flat_encounter_pmtct_discharge
                       WHERE discharge_date > REPORT_START_DATE),

         Episode_Window AS (SELECT e.client_id,
                                   e.encounter_id                              as enrollment_id,
                                   e.antenatal_care_provider,
                                   e.ld_client,
                                   e.post_natal_care,
                                   e.art_clinic,
                                   e.date_of_enrollment_or_booking             as start_date,
                                   d.discharge_date,
                                   d.reason_for_discharge_from_pmtct,
                                   d.reason_for_discharge_from_pmtct           as discharge_outcome,
                                   e.currently_breastfeeding_child,
                                   e.pregnancy_status,
                                   e.date_referred_to_pmtct,
                                   COALESCE(d.discharge_date, REPORT_END_DATE) as effective_end_date
                            FROM Enrollment e
                                     LEFT JOIN Discharge d
                                               ON e.client_id = d.client_id
                                                   AND e.row_num = d.row_num
                                                   AND d.discharge_date > e.date_of_enrollment_or_booking),

         FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id                 AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             antiretroviral_art_dispensed_dose_i AS ARTDoseDays,
                             anitiretroviral_adherence_level     AS AdherenceLevel,
                             regimen,
                             currently_breastfeeding_child       as breast_feeding_status,
                             pregnancy_status,
                             nutritional_status_of_adult,
                             hiv_viral_load                      AS viral_load_count,
                             cd4_count,
                             date_of_reported_hiv_viral_load     as viral_load_sent_date,
                             date_viral_load_results_received    AS viral_load_perform_date,
                             date_referred_to_pmtct,
                             dsd_category,
                             next_visit_date,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                   AS routine_viral_load_test_indication,
                             COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                      suspected_antiretroviral_failure
                             )                                   AS targeted_viral_load_test_indication,
                             viral_load_test_status
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id),

         Events_Ranked AS (SELECT ew.enrollment_id,
                                  f.*,

                                  ROW_NUMBER() OVER (
                                      PARTITION BY ew.enrollment_id
                                      ORDER BY CASE
                                                   WHEN f.follow_up_date BETWEEN ew.start_date AND ew.effective_end_date
                                                       THEN f.follow_up_date
                                                   ELSE NULL
                                          END DESC,
                                          f.encounter_id DESC
                                      ) as rn_latest_visit,

                                  ROW_NUMBER() OVER (
                                      PARTITION BY ew.enrollment_id
                                      ORDER BY CASE
                                                   WHEN f.viral_load_sent_date BETWEEN ew.start_date AND ew.effective_end_date
                                                       THEN f.viral_load_sent_date
                                                   ELSE NULL
                                          END DESC
                                      ) as rn_latest_vl_sent,

                                  ROW_NUMBER() OVER (
                                      PARTITION BY ew.enrollment_id
                                      ORDER BY CASE
                                                   WHEN f.viral_load_perform_date BETWEEN ew.start_date AND ew.effective_end_date
                                                       THEN f.viral_load_perform_date
                                                   ELSE NULL
                                          END DESC
                                      ) as rn_latest_vl_res,
                                  ROW_NUMBER() OVER (
                                      PARTITION BY ew.enrollment_id
                                      ORDER BY CASE
                                                   WHEN f.dsd_category IS NOT NULL
                                                       AND
                                                        f.follow_up_date BETWEEN ew.start_date AND ew.effective_end_date
                                                       THEN f.follow_up_date
                                                   ELSE NULL
                                          END DESC,
                                          f.encounter_id DESC
                                      ) as rn_latest_dsd
                           FROM Episode_Window ew
                                    LEFT JOIN FollowUp f
                                              ON ew.client_id = f.PatientId)
    SELECT client.patient_name                                        as `Patient Name`,
           client.MRN,
           client.UAN,
           TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE) as `Age`,
           visit.art_start_date                                       as `Art Start Date`,
           visit.art_start_date                                       as `Art Start Date EC.`,
           dsd.dsd_category                                           as `DSD`,
           ew.start_date                                              as `PMTCT Booking Date`,
           ew.start_date                                              as `PMTCT Booking Date EC.`,
           CASE COALESCE(ew.art_clinic, ew.antenatal_care_provider, ew.ld_client,
                         ew.post_natal_care)
               WHEN ew.art_clinic is not null THEN 'Known +ve - on ART at Entry'
               WHEN ew.antenatal_care_provider is not null THEN 'New from ANC'
               WHEN ew.ld_client is not null THEN 'New from L&D'
               WHEN ew.post_natal_care is not null THEN 'New from PNC'
               ELSE COALESCE(ew.art_clinic, ew.antenatal_care_provider, ew.ld_client,
                             ew.post_natal_care) END                  as `Status at Enrollment`,
           ew.date_referred_to_pmtct                                     'Date Referred to PMTCT',
           ew.pregnancy_status                                           'Pregnant?',
           ew.currently_breastfeeding_child                              'Breastfeeding?',
           ew.discharge_date                                          as `Date of Discharge`,
           ew.reason_for_discharge_from_pmtct                         as `Reason for Discharge`,
           ew.discharge_outcome                                       as `Maternal PMTCT Final Outcome`,
           ew.effective_end_date                                      as `Date of Final Outcome`,
           ew.effective_end_date                                      as `Date of Final Outcome EC.`,
           visit.follow_up_date                                       as `Latest Follow-up Date`,
           visit.follow_up_date                                       as `Latest Follow-up Date EC.`,
           visit.follow_up_status                                     as `Latest Follow-up Status`,
           visit.regimen                                              as `Regimen Dose`,
           visit.AdherenceLevel                                       as `Adherence`,
           visit.nutritional_status_of_adult                          as `Nutritional Status`,
           visit.next_visit_date                                      as `Next Visit Date`,
           visit.next_visit_date                                      as `Next Visit Date EC.`,
           ew.pregnancy_status                                     as `Pregnant?`,
           ew.currently_breastfeeding_child                                as `Breastfeeding?`,
           visit.date_referred_to_pmtct                               as `Date Referred to PMTCT`,
           visit.date_referred_to_pmtct                               as `Date Referred to PMTCT EC.`,

           vl_s.viral_load_sent_date                                  as `Latest VL Sent Date`,
           vl_s.viral_load_sent_date                                  as `Latest VL Sent Date EC.`,
           vl_s.cd4_count                                             as `CD4 count`,
           COALESCE(vl_s.routine_viral_load_test_indication,
                    vl_s.targeted_viral_load_test_indication)         as `Latest VL Test Indication`,

           vl_r.viral_load_perform_date                               as `Latest VL Received Date`,
           vl_r.viral_load_perform_date                               as `Latest VL Received Date EC.`,
           vl_r.viral_load_test_status                                as `Latest VL Status`

    FROM Episode_Window ew
             LEFT JOIN mamba_dim_client client ON ew.client_id = client.client_id
             LEFT JOIN Events_Ranked visit
                       ON ew.enrollment_id = visit.enrollment_id AND visit.rn_latest_visit = 1
             LEFT JOIN Events_Ranked vl_s
                       ON ew.enrollment_id = vl_s.enrollment_id AND vl_s.rn_latest_vl_sent = 1
             LEFT JOIN Events_Ranked vl_r
                       ON ew.enrollment_id = vl_r.enrollment_id AND vl_r.rn_latest_vl_res = 1
             LEFT JOIN Events_Ranked dsd
                       ON ew.enrollment_id = dsd.enrollment_id AND dsd.rn_latest_dsd = 1;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ncd_screening_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ncd_screening_query;

~
CREATE PROCEDURE sp_fact_line_list_ncd_screening_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH art_history AS (SELECT client_id,
                                hiv_confirmed_date,
                                art_start_date,
                                art_followup_date,
                                art_followup_status,
                                art_regimen,
                                art_regimen_dose
                         FROM (SELECT mpf.client_id,
                                      mpf2.date_of_event                                                                                                AS hiv_confirmed_date,
                                      mpf7.art_antiretroviral_start_date                                                                                AS art_start_date,
                                      mpf6.follow_up_date_followup_                                                                                     AS art_followup_date,
                                      mpf4.follow_up_status                                                                                             AS art_followup_status,
                                      mpf1.regimen                                                                                                      AS art_regimen,
                                      mpf8.antiretroviral_art_dispensed_dose_i                                                                          AS art_regimen_dose,
                                      ROW_NUMBER() OVER (PARTITION BY mpf.client_id ORDER BY mpf6.follow_up_date_followup_ DESC, mpf.encounter_id DESC) AS rn
                               FROM mamba_flat_encounter_follow_up mpf
                                        LEFT JOIN mamba_flat_encounter_follow_up_1 mpf1
                                                  ON mpf.encounter_id = mpf1.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_2 mpf2
                                                  ON mpf.encounter_id = mpf2.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_4 mpf4
                                                  ON mpf.encounter_id = mpf4.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_6 mpf6
                                                  ON mpf.encounter_id = mpf6.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_7 mpf7
                                                  ON mpf.encounter_id = mpf7.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_8 mpf8
                                                  ON mpf.encounter_id = mpf8.encounter_id) sub
                         WHERE rn = 1),

         -- 2. Get NCD Screening Events in the date range
         ncd_screening AS (SELECT mpn.client_id,
                                  mpn.screening_date,
                                  risk_factors_present,
                                  past_complication,
                                  past_medication,
                                  weight_text_,
                                  bmi_text_,
                                  diastolic_blood_pressure,
                                  fasting_blood_glucose_measurement_m,
                                  baseline_diagnosis,
                                  diagnosed_previously,
                                  'Screening' AS visit_type
                           FROM mamba_flat_encounter_ncd_screening mpn
                           WHERE (REPORT_START_DATE IS NULL OR mpn.screening_date >= REPORT_START_DATE)
                             AND (REPORT_END_DATE IS NULL OR mpn.screening_date <= REPORT_END_DATE))

    -- 5. Final Select with Client and ART details
    SELECT mpc.patient_name                                  AS 'Full Name',
           CONCAT('''', mpc.uan)                                           AS 'UAN',
           mpc.mrn                                           AS 'MRN',
           TIMESTAMPDIFF(YEAR, mpc.date_of_birth, CURDATE()) AS 'Age',
           mpc.sex                                           AS 'Sex',
           art.hiv_confirmed_date                            AS 'HIV Confirmed Date EC.',
           art.hiv_confirmed_date                            AS 'HIV Confirmed Date (GC)',
           art.art_start_date                                AS 'ART Start Date EC.',
           art.art_start_date                                AS 'ART Start Date (GC)',

           art_followup_status                               as `Last Follow-Up Status`,
           e.screening_date                                  AS 'NCD Screening Date ',
           risk_factors_present                                 `Risk Factors`,
           diagnosed_previously                              as `Past Diagnosis`,
           past_complication                                 as `Past Complication`,
           past_medication                                   as `Past Medication`,
           weight_text_                                      as `Weight`,
           bmi_text_                                         as `BMI`,
           diastolic_blood_pressure                          as `Blood Pressure`,
           fasting_blood_glucose_measurement_m               as `FBS (mg/dl)`,
           baseline_diagnosis                                as `Baseline Diagnosis`,
# UNCD #


           art.art_followup_date                             AS 'Follow-Up Date (ART)',
           mpc.state_province                                AS 'Address: Region',
           mpc.county_district                               AS 'Address: Zone',
           mpc.city_village                                  AS 'Address: Woreda',
           mpc.mobile_no                                     AS 'Address: Phone Number (Mobile)',

           art.art_followup_status                           AS 'Follow-Up Status (ART)',

           art.art_regimen                                   AS 'ART Regimen',
           art.art_regimen_dose                              AS 'ART Regimen Dose',
           e.visit_type                                      AS 'Visit Type'
    FROM ncd_screening e
             INNER JOIN mamba_dim_client mpc ON e.client_id = mpc.client_id
             LEFT JOIN art_history art ON e.client_id = art.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_ncd_treatment_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_ncd_treatment_query;

~
CREATE PROCEDURE sp_fact_line_list_ncd_treatment_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    -- 1. Get the latest ART/HIV history for each client
    WITH art_history AS (SELECT client_id,
                                hiv_confirmed_date,
                                art_start_date,
                                art_followup_date,
                                art_followup_status,
                                art_regimen,
                                art_regimen_dose
                         FROM (SELECT mpf.client_id,
                                      mpf2.date_of_event                                                                                                AS hiv_confirmed_date,
                                      mpf7.art_antiretroviral_start_date                                                                                AS art_start_date,
                                      mpf6.follow_up_date_followup_                                                                                     AS art_followup_date,
                                      mpf4.follow_up_status                                                                                             AS art_followup_status,
                                      mpf1.regimen                                                                                                      AS art_regimen,
                                      mpf8.antiretroviral_art_dispensed_dose_i                                                                          AS art_regimen_dose,
                                      ROW_NUMBER() OVER (PARTITION BY mpf.client_id ORDER BY mpf6.follow_up_date_followup_ DESC, mpf.encounter_id DESC) AS rn
                               FROM mamba_flat_encounter_follow_up mpf
                                        LEFT JOIN mamba_flat_encounter_follow_up_1 mpf1
                                                  ON mpf.encounter_id = mpf1.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_2 mpf2
                                                  ON mpf.encounter_id = mpf2.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_4 mpf4
                                                  ON mpf.encounter_id = mpf4.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_6 mpf6
                                                  ON mpf.encounter_id = mpf6.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_7 mpf7
                                                  ON mpf.encounter_id = mpf7.encounter_id
                                        LEFT JOIN mamba_flat_encounter_follow_up_8 mpf8
                                                  ON mpf.encounter_id = mpf8.encounter_id) sub
                         WHERE rn = 1),

         -- 3. Get NCD Follow-up Events in the date range
         ncd_followup AS (SELECT mpnf.client_id,
                                 NULL                                                                              AS screening_date,
                                 mpnf.visit_type,
                                 COALESCE(mpnf1.diabetes_mellitus_diagnose_type,
                                          mpnf1.hypertension_diagnose_type)                                        AS diagnosis_type,
                                 mpnf1.baseline_diagnosis                                                          AS diagnosis,
                                 mpnf1.ncd_clinical_status                                                         AS outcome,
                                 mpnf1.return_visit_date                                                           AS next_appointment_date,
                                 mpnf.follow_up_date                                                               AS ncd_follow_up_date,
                                 CONCAT_WS(',',
                                           mpnf.use_of_tobacco,
                                           mpnf.excessive_alcohol,
                                           mpnf1.physical_inactivity,
                                           mpnf1.high_salt_consumption,
                                           mpnf1.high_sugar_consumption,
                                           mpnf1.high_fat_consumption,
                                           mpnf1.low_vegetable_fruit_consumption,
                                           mpnf1.family_history_of_dm_htn_cvd,
                                           mpnf.khat_consumption
                                 )                                                                                 AS risk_factors,
                                 CONCAT_WS(',',
                                           mpnf.polyuria,
                                           mpnf.nocturia,
                                           mpnf.polydipsia,
                                           mpnf.fatigue,
                                           mpnf.nausea,
                                           mpnf.vomiting,
                                           mpnf.deep_breathing,
                                           mpnf.fast_breathing,
                                           mpnf.weakness,
                                           mpnf.abdominal_pain,
                                           mpnf.hunger,
                                           mpnf.palpitations,
                                           mpnf.lightheadedness,
                                           mpnf.dizziness,
                                           mpnf.sweating,
                                           mpnf.extreme_fatigue,
                                           mpnf.confusion,
                                           mpnf.bad_dreams,
                                           mpnf.fever,
                                           mpnf.cough,
                                           mpnf.skin_lesions,
                                           mpnf.dysuria,
                                           mpnf1.frequent_urination,
                                           mpnf1.diabetic_foot_ulcer,
                                           mpnf.tingling,
                                           mpnf.numbness,
                                           mpnf.burning_sensation,
                                           mpnf1.postural_dizziness,
                                           mpnf1.sexual_dysfunction,
                                           mpnf.visual_blurring
                                 )                                                                                 AS dm_symptoms,
                                 CONCAT_WS(',',
                                           mpnf.dyspnea,
                                           mpnf.orthopnea,
                                           mpnf1.paroxysmal_nocturnal_dyspnea,
                                           mpnf.leg_swelling,
                                           mpnf.angina,
                                           mpnf1.intermittent_claudication,
                                           mpnf1.hemiparesis_hemiplegia,
                                           mpnf1.speech_abnormality,
                                           mpnf.seizure,
                                           mpnf.headache,
                                           mpnf.photophobia,
                                           mpnf.neck_pain
                                 )                                                                                 AS hypertension_symptoms,
                                 mpnf1.systolic_blood_pressure                                                     AS bp1,
                                 mpnf1.diastolic_blood_pressure                                                    AS bp2,
                                 mpnf.bmi_text_                                                                    AS bmi,
                                 mpnf1.fasting_blood_glucose_measurement_m                                         AS fbs,
                                 mpnf1.fundoscopic_exam_finding                                                    AS fundoscopy,
                                 CONCAT_WS(',',
                                           mpnf1.chronic_kidney_disease,
                                           mpnf1.transient_ischemic_attack,
                                           mpnf1.hypertensive_heart_disease,
                                           mpnf1.peripheral_arterial_disease,
                                           mpnf1.diabetic_retinopathy,
                                           mpnf1.diabetic_neuropathy,
                                           mpnf1.diabetic_nephropathy,
                                           mpnf1.coronary_artery_disease,
                                           mpnf1.diabetic_foot_ulcer,
                                           mpnf1.diabetes_ketoacidosis
                                 )                                                                                 AS dm_complications,
                                 CONCAT_WS(',',
                                           mpnf1.chronic_kidney_disease,
                                           mpnf1.transient_ischemic_attack,
                                           mpnf1.hypertensive_heart_disease,
                                           mpnf1.peripheral_arterial_disease,
                                           mpnf1.coronary_artery_disease
                                 )                                                                                 AS htn_complications,
                                 mpnf1.overall_treatment_adherence                                                 AS adherence,
                                 CONCAT_WS(',',
                                           mpnf1.cessation_of_smoking,
                                           mpnf1.exercise_150min_week,
                                           mpnf.weight_reduction,
                                           mpnf.healthy_diet,
                                           mpnf1.medication_adherence_side_effect,
                                           mpnf1.daily_foot_inspection,
                                           mpnf.family_screening,
                                           mpnf1.injection_techniques
                                 )                                                                                 AS lifestyle_changes
                          FROM mamba_flat_encounter_ncd_followup mpnf
                                   LEFT JOIN mamba_flat_encounter_ncd_followup_1 mpnf1
                                             ON mpnf.encounter_id = mpnf1.encounter_id
                          WHERE (REPORT_START_DATE IS NULL OR mpnf.follow_up_date >= REPORT_START_DATE)
                            AND (REPORT_END_DATE IS NULL OR mpnf.follow_up_date <= REPORT_END_DATE))

    -- 5. Final Select with Client and ART details
    SELECT

        mpc.patient_name                                  AS 'Full Name',
        CONCAT('''', mpc.uan)                                           AS 'UAN',
        mpc.mrn                                           AS 'MRN',
        TIMESTAMPDIFF(YEAR, mpc.date_of_birth, CURDATE()) AS 'Age',
        mpc.sex                                           AS 'Sex',
        art.hiv_confirmed_date                            AS 'HIV Confirmed Date EC.',
        art.hiv_confirmed_date                            AS 'HIV Confirmed Date (GC)',



           art.art_start_date                                AS 'ART Start Date EC.',
           art.art_start_date                                AS 'ART Start Date (GC)',
           e.screening_date                                  AS 'Screening Date',
           art.art_followup_date                             AS 'Follow-Up Date (ART)',
           mpc.state_province                                AS 'Address: Region',
           mpc.county_district                               AS 'Address: Zone',
           mpc.city_village                                  AS 'Address: Woreda',
           mpc.mobile_no                                     AS 'Address: Phone Number (Mobile)',
           e.diagnosis_type                                  AS 'Diagnosis Type',
           e.diagnosis                                       AS 'Diagnosis',
           e.outcome                                         AS 'Outcome',
           e.next_appointment_date                           AS 'Next Appointment Date (NCD) EC.',
           e.next_appointment_date                           AS 'Next Appointment Date (NCD) (GC)',
           e.ncd_follow_up_date                              AS 'Follow-Up Date NCD  EC.',
           e.ncd_follow_up_date                              AS 'Follow-Up Date NCD  (GC)',
           art.art_followup_status                           AS 'Follow-Up Status (ART)',

           art.art_regimen                                   AS 'ART Regimen',
           art.art_regimen_dose                              AS 'ART Regimen Dose',
           e.visit_type                                      AS 'Visit Type',
           e.risk_factors                                    AS 'Risk Factors',
           e.dm_symptoms                                     AS 'Diabetes Melitus (DM) Symptoms',
           e.hypertension_symptoms                           AS 'Hypertension (HTN) Symptoms',
           e.bp1                                             AS 'BP1',
           e.bp2                                             AS 'BP2',
           e.bmi                                             AS 'BMI',
           e.fbs                                             AS 'FBS',
           e.fundoscopy                                      AS 'Fundoscopy',
           e.dm_complications                                AS 'DM Complications',
           e.htn_complications                               AS 'HTN Complications',
           e.adherence                                       AS 'Adherence',
           e.lifestyle_changes                               AS 'Lifestyle Changes'
    FROM ncd_followup e
             INNER JOIN mamba_dim_client mpc ON e.client_id = mpc.client_id
             LEFT JOIN art_history art ON e.client_id = art.client_id;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_otz_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_otz_query;

~
CREATE PROCEDURE sp_fact_line_list_otz_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN


    WITH FollowUp as (select follow_up.client_id,
                             follow_up.encounter_id,
                             date_viral_load_results_received    AS viral_load_perform_date,
                             viral_load_received_,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date          art_start_date,
                             viral_load_test_status,
                             hiv_viral_load                      AS viral_load_count,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                   AS routine_viral_load_test_indication,
                             COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                      suspected_antiretroviral_failure
                             )                                   AS targeted_viral_load_test_indication,
                             viral_load_test_indication,
                             pregnancy_status,
                             currently_breastfeeding_child       AS breastfeeding_status,
                             antiretroviral_art_dispensed_dose_i    arv_dispensed_dose,
                             regimen,
                             next_visit_date,
                             treatment_end_date,
                             date_of_event                          date_hiv_confirmed,
                             weight_text_                        as weight,
                             date_of_reported_hiv_viral_load     as viral_load_sent_date,
                             regimen_change,
                             operation_triple_zero_enrollment_da as otz_date,
                             enrolled_to_otz_operation_triple_zo as otz_enrolled,
                             visit_type,
                             nutritional_status_of_adult,
                             nutritional_screening_result,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id
                      ),
         tmp_latest_follow_up as (SELECT encounter_id,
                                         client_id,
                                         follow_up_date,
                                         weight,
                                         date_hiv_confirmed,
                                         art_start_date,
                                         visit_type,
                                         nutritional_status_of_adult,
                                         nutritional_screening_result,
                                         adherence,
                                         next_visit_date,
                                         arv_dispensed_dose,
                                         regimen,
                                         follow_up_status,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         latest_follow_up as (select *
                              from tmp_latest_follow_up
                              where row_num = 1 -- temp3
         ),
         tmp_latest_vl_performed_date as (SELECT encounter_id,
                                                 client_id,
                                                 follow_up_date,
                                                 viral_load_perform_date,
                                                 viral_load_sent_date,
                                                 viral_load_count,
                                                 viral_load_test_status,
                                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_perform_date DESC, encounter_id DESC) AS row_num
                                          FROM FollowUp
                                          WHERE follow_up_status IS NOT NULL
                                            AND art_start_date IS NOT NULL
                                            AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         latest_vl_performed_date as (select *
                                      from tmp_latest_vl_performed_date
                                      where row_num = 1 -- temp6
         ),
         tmp_otz_date as (SELECT encounter_id,
                                 client_id,
                                 follow_up_date,
                                 viral_load_perform_date,
                                 viral_load_sent_date,
                                 otz_date,
                                 otz_enrolled,
                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY otz_date DESC, encounter_id DESC) AS row_num
                          FROM FollowUp
                          WHERE follow_up_status IS NOT NULL
                            AND art_start_date IS NOT NULL
                            AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         otz_date as (select *
                      from tmp_otz_date
                      where row_num = 1 -- temp9
         ),
-- Get baseline VL Performed date between 3 months earlier and 1 month later of enrollment date
         tmp_otz_vl_performed_date as (SELECT FollowUp.encounter_id,
                                              FollowUp.client_id,
                                              FollowUp.follow_up_date,
                                              FollowUp.viral_load_perform_date,
                                              FollowUp.viral_load_sent_date,
                                              FollowUp.otz_date,
                                              FollowUp.viral_load_count,
                                              FollowUp.viral_load_test_status,
                                              ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.viral_load_perform_date DESC, FollowUp.encounter_id DESC) AS row_num
                                       FROM FollowUp
                                                left join otz_date as otz on FollowUp.client_id = otz.client_id
                                       WHERE follow_up_status IS NOT NULL
                                         AND FollowUp.art_start_date IS NOT NULL
                                         AND FollowUp.follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())
                                         AND FollowUp.viral_load_perform_date BETWEEN fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(otz.otz_date, 'Y-M-D'), INTERVAL -3 MONTH))
                                             AND fn_ethiopian_to_gregorian_calendar(date_add(fn_gregorian_to_ethiopian_calendar(otz.otz_date, 'Y-M-D'), INTERVAL 1 MONTH))),
         otz_vl_performed_date as (select *
                                   from tmp_otz_vl_performed_date
                                   where row_num = 1 -- temp9
         ),

         tmp_oldest_follow_up as (SELECT encounter_id,
                                         client_id,
                                         follow_up_date,
                                         regimen,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         oldest_follow_up as (select *
                              from tmp_oldest_follow_up
                              where row_num = 1 -- temp13
         ),
         tmp_curr_regimen_start as (select FollowUp.follow_up_date                                                                                     as FirstRegimenDate,
                                           FollowUp.client_id,
                                           ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.follow_up_date, FollowUp.encounter_id) AS row_num
                                    from FollowUp
                                             left join latest_follow_up on FollowUp.client_id = latest_follow_up.client_id
                                    WHERE FollowUp.follow_up_status IS NOT NULL
                                      AND FollowUp.art_start_date IS NOT NULL
                                      AND FollowUp.follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())
                                      and FollowUp.regimen = latest_follow_up.regimen),
         curr_regimen_start as (select * from tmp_curr_regimen_start where row_num = 1)


    SELECT dim_client.patient_name                                                             AS `Patient Name`,
           patient_uuid                                                                        as `UUID`,
           otz.otz_date                                                                        AS EnrollementDate,
           otz.otz_date                                                                        AS `EnrollementDate EC.`,
           otz_enrolled                                                                        AS EnrollementStatus,
           TIMESTAMPDIFF(YEAR, dim_client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as Age,
           dim_client.sex                                                                      as Sex,
           latest_follow_up.weight                                                             AS Weight,
           dim_client.phone_no                                                                 AS PNumber,
           dim_client.mobile_no                                                                AS Mobile,
           CAST(dim_client.mrn AS CHAR(20))                                                    AS MRN,
           dim_client.uan                                                                      AS UART,
           latest_follow_up.date_hiv_confirmed                                                 AS confirmeddate,
           latest_follow_up.date_hiv_confirmed                                                 AS `confirmeddate EC.`,
           latest_follow_up.art_start_date                                                     AS startedDate,
           latest_follow_up.art_start_date                                                     AS `startedDate EC.`,
           latest_follow_up.follow_up_date                                                     AS FollowUpDate,
           latest_follow_up.follow_up_date                                                     AS `FollowUpDate EC.`,
           latest_follow_up.visit_type                                                         AS scheduletype,
           latest_follow_up.nutritional_screening_result                                       AS NutritionalStatus,
           latest_follow_up.adherence                                                          AS Adherance,
           latest_follow_up.next_visit_date                                                    AS nextvisitdate,
           latest_follow_up.next_visit_date                                                    AS `nextvisitdate EC.`,
           latest_follow_up.arv_dispensed_dose                                                 AS Dosedays,
           latest_follow_up.regimen                                                            AS Regimen,
           CASE latest_follow_up.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               END                                                                             AS FollowUpStatus,
           otz_vl_performed_date.viral_load_sent_date                                          AS BaselineVLsent,
           otz_vl_performed_date.viral_load_sent_date                                          AS `BaselineVLsent EC.`,
           otz_vl_performed_date.viral_load_perform_date                                       AS BaselineVLReceived,
           otz_vl_performed_date.viral_load_perform_date                                       AS `BaselineVLReceived EC.`,
           otz_vl_performed_date.viral_load_count                                              AS BaselineVLCount,
           otz_vl_performed_date.viral_load_test_status                                        AS BaselineVLStatus,
           latest_vl_performed_date.viral_load_sent_date                                       AS VLsent,
           latest_vl_performed_date.viral_load_sent_date                                       AS `VLsent EC.`,
           latest_vl_performed_date.viral_load_perform_date                                    AS VLReceived,
           latest_vl_performed_date.viral_load_perform_date                                    AS `VLReceived EC.`,
           latest_vl_performed_date.viral_load_count                                           AS VLCount,
           latest_vl_performed_date.viral_load_test_status                                     AS VLStatus,
           oldest_follow_up.regimen                                                            AS OriginalRegimen,
           curr_regimen_start.FirstRegimenDate                                                 AS currentRegimenStart,
           curr_regimen_start.FirstRegimenDate                                                 AS `currentRegimenStart EC.`
    FROM latest_follow_up
             LEFT JOIN mamba_dim_client dim_client
                       ON dim_client.client_id = latest_follow_up.client_id
             LEFT JOIN otz_vl_performed_date
                       ON otz_vl_performed_date.client_id = latest_follow_up.client_id
             LEFT JOIN latest_vl_performed_date
                       ON latest_vl_performed_date.client_id = latest_follow_up.client_id
             LEFT JOIN oldest_follow_up
                       ON oldest_follow_up.client_id = latest_follow_up.client_id
             LEFT JOIN curr_regimen_start
                       ON curr_regimen_start.client_id = latest_follow_up.client_id
             LEFT JOIN otz_date AS otz
                       ON otz.client_id = latest_follow_up.client_id
    WHERE (
        (latest_follow_up.follow_up_status not in ('Dead', 'Transferred Out'))
            OR
        (otz.otz_date is not null OR otz.otz_enrolled is not null)
        )
      AND dim_client.patient_name IS NOT NULL

      AND (
        (TIMESTAMPDIFF(YEAR, dim_client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) >= 10 AND
         TIMESTAMPDIFF(YEAR, dim_client.date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) <= 24)
            OR
        (otz.otz_date is not null OR otz.otz_enrolled is not null)
        )
      AND (
        (REPORT_START_DATE is not null and REPORT_END_DATE is not null and
         otz.otz_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE)
            OR
        (REPORT_START_DATE is null and REPORT_END_DATE is null and (otz.otz_date <= CURDATE() or otz.otz_date is null))
        );

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_patient_summary_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_patient_summary_query;

~
CREATE PROCEDURE sp_fact_line_list_patient_summary_query(IN in_patient_uuid VARCHAR(50))
BEGIN
   select * from mamba_fact_client where patient_uuid = in_patient_uuid;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_pediatric_age_out_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_pediatric_age_out_query;

~
CREATE PROCEDURE sp_fact_line_list_pediatric_age_out_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH Follow_up AS (SELECT follow_up_date_followup_                            AS follow_up_date,
                              follow_up.client_id                                 AS patient_id,
                              follow_up.encounter_id                              AS encounter_id,
                              follow_up_status,
                              TIMESTAMPDIFF(YEAR, date_of_birth, COALESCE(REPORT_END_DATE,CURDATE())) AS age,
                              mrn,
                              uan,
                              sex,
                              patient_uuid,
                              date_of_birth,
                              patient_name,
                              mobile_no                                           as mobilephonenumber,
                              regimen,
                              art_antiretroviral_start_date                       as art_sart_date,
                              date_of_event                                       as date_hiv_confirmed,
                              next_visit_date,
                              antiretroviral_art_dispensed_dose_i                 as art_dose,
                              intake_a.date_hiv_confirmed                      as registration_date
                       FROM mamba_flat_encounter_follow_up follow_up
                                LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                          ON follow_up.encounter_id = follow_up_1.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                          ON follow_up.encounter_id = follow_up_2.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                          ON follow_up.encounter_id = follow_up_3.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                          ON follow_up.encounter_id = follow_up_4.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                          ON follow_up.encounter_id = follow_up_5.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                          ON follow_up.encounter_id = follow_up_6.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                          ON follow_up.encounter_id = follow_up_7.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                          ON follow_up.encounter_id = follow_up_8.encounter_id
                                LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                          ON follow_up.encounter_id = follow_up_9.encounter_id
                                left JOIN mamba_dim_client dim_client
                                     ON follow_up.client_id = dim_client.client_id
                                left join mamba_flat_encounter_intake_a intake_a
                                          on intake_a.client_id = follow_up.client_id
                       where follow_up_date_followup_
                                 <= COALESCE(REPORT_END_DATE,CURDATE()))
       , firstArtRegimen as (select patient_id,
                                    follow_up_date                                                                              as followupdate,
                                    encounter_id,
                                    ROW_NUMBER() OVER (PARTITION BY patient_id ORDER BY follow_up_date DESC, encounter_id DESC) AS rn
                             FROM Follow_up
                             WHERE regimen IS NOT NULL
                             GROUP BY patient_id, encounter_id, follow_up_date)
       , firstArtRegimen2 as (SELECT regimen, Follow_up.patient_id
                              from Follow_up
                                       INNER JOIN firstArtRegimen
                                                  on Follow_up.encounter_id = firstArtRegimen.encounter_id
                              where Follow_up.regimen IS NOT NULL
                                and firstArtRegimen.rn = 1)
       , latest_follow_up_encounter as (SELECT patient_id,
                                               encounter_id,
                                               ROW_NUMBER() OVER (PARTITION BY patient_id ORDER BY follow_up_date DESC, encounter_id DESC) AS rn
                                        from Follow_up
                                        where follow_up_status IS NOT NULL
                                          and art_sart_date is not null)


    SELECT DISTINCT patient_name                              AS `Patient Name`,
                    patient_uuid                              AS `UUID`,
                    CAST(mrn AS CHAR(20)) as mrn,
                    CONCAT('''', uan) as uan,
                    sex,
                    date_of_birth                             AS `Date of birth`,
                    date_of_birth                             AS `Date of birth EC.`,
                    TIMESTAMPDIFF(YEAR, date_of_birth, date_hiv_confirmed)
                                                              AS age_at_enrollment,
                    age                                       AS current_age,
                    date_hiv_confirmed                         as `Enrollment Date`,
                    date_hiv_confirmed                         as `Enrollment Date EC.`,
                    date_hiv_confirmed                        as `HIV Confirmed Date`,
                    date_hiv_confirmed                        as `HIV Confirmed Date EC.`,
                    art_sart_date                             as `Art Start Date`,
                    art_sart_date                             as `Art Start Date EC.`,
                    follow_up_date                            AS `Follow Up Date`,
                    follow_up_date                            AS `Follow Up Date EC.`,
                    CASE follow_up_status
                        WHEN 'Alive' THEN 'Alive on ART'
                        WHEN 'Restart medication' THEN 'Restart'
                        WHEN 'Transferred out' THEN 'TO'
                        WHEN 'Stop all' THEN 'Stop'
                        WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                        WHEN 'Ran away' THEN 'Drop'
                        END AS follow_up_status,

                    firstArtRegimen2.regimen                  AS arv_regimen_when_started_art,
                    Follow_up.regimen                         AS `Regimen`,
                    art_dose                                  AS `Dose Days`,
                    next_visit_date                           AS `Next Visit Date`,
                    next_visit_date                           AS `Next Visit Date EC.`,
                    DATE_ADD(
                            date_of_birth, INTERVAL 15 YEAR
                    )                                         AS `Date of 15th Birth Day`,
                    DATE_ADD(date_of_birth, INTERVAL 15 YEAR) AS `Date of 15th Birth Day EC.`,
                    CASE
                        WHEN TIMESTAMPDIFF(YEAR, date_of_birth, COALESCE(REPORT_END_DATE,CURDATE())) >= 15 THEN 'YES'
                        ELSE 'NO'
                        END                                   AS age_out
    FROM latest_follow_up_encounter
             left join Follow_up on latest_follow_up_encounter.encounter_id = Follow_up.encounter_id
             LEFT OUTER JOIN firstArtRegimen2 on firstArtRegimen2.patient_id = Follow_up.patient_id
    where rn = 1

      and (TIMESTAMPDIFF(YEAR, date_of_birth, art_sart_date) <= 15)
      and (
        (REPORT_START_DATE is not null and REPORT_END_DATE is not null and DATE_ADD(
                date_of_birth, INTERVAL 15 YEAR
                                                                           ) BETWEEN REPORT_START_DATE AND REPORT_END_DATE)
          OR
        ((REPORT_START_DATE is null and REPORT_END_DATE is null and DATE_ADD(
                date_of_birth, INTERVAL 15 YEAR
                                                                            ) <= CURDATE()))
        )
    order by patient_name;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_phrh_service_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_phrh_service_query;

~
CREATE PROCEDURE sp_fact_line_list_phrh_service_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE,
                                                      IN TARGET_GROUP VARCHAR(255))
BEGIN
    WITH enrollment AS (SELECT mpe.client_id                                                                                         AS client_id,
                               ROW_NUMBER() OVER (PARTITION BY mpe.client_id ORDER BY mpf.followup_date DESC, mpf.encounter_id DESC) AS row_num,
                               client.mrn                                                                                            AS mrn,
                               client.patient_name                                                                                   AS full_name,
                               client.sex                                                                                            AS gender,
                               TIMESTAMPDIFF(YEAR, client.date_of_birth,
                                             COALESCE(REPORT_END_DATE, CURDATE()))                                                   AS age,
                               mpe.followup_date                                                                                     AS phrh_enrollment_date,
                               mpe.previously_tested_for_hiv                                                                         AS previously_tested_for_hiv,
                               mpf.followup_date                                                                                     AS phrh_followup_date_ec,
                               mpf.followup_date                                                                                     AS phrh_followup_date,
                               CONCAT_WS(',',
                                         mpf.history_of_sti,
                                         mpf.multiple_partners_exchange,
                                         mpf.inconsistent_condoms,
                                         mpf.consistent_condoms,
                                         mpf.drug_use,
                                         mpf.iv_drug_use,
                                         mpf.declined_to_disclose)                                                                   AS risk_behaviors,
                               CASE
                                   WHEN mpf.target_population = 'Female sex worker' THEN 'Women Engaged in Commercial Sex Work (WECSW)'
                                   WHEN mpf.target_population = 'People who inject drug' THEN 'PWID'
                                   WHEN mpf.target_population = 'Late adolescent/young adulthood period'
                                       THEN 'High Risk AGYW'
                                   WHEN mpf.target_population = 'Other' THEN 'Other KPP'
                                   ELSE 'General Population'
                                   END
                                                                                                                                     AS target_population,
                               mpf.modality_used_to_reach                                                                            AS modality,
                               art_start_date,
                               mpf.hiv_self_test_performed                                                                           AS hiv_self_test_kit,
                               mpf.hivst_result                                                                                      AS self_test_result,
                               mpf.final_hiv_test_result                                                                             AS conventional_result,
                               mpf.on_antiretroviral_therapy                                                                         AS art_started,
                               mpf.unique_art_number                                                                                 AS unique_art_number,
                               mpf.pmtct_linkage_date                                                                                AS date_linked_to_pmtct,
                               condoms_given_during_the_visit,
                               mpf1.prep_pre_exposure_prophylaxis_eligi                                                              AS eligible_for_prep,
                               mpf.discharge_date                                                                                    AS prep_discharge_date_ec,
                               mpf.discharge_date                                                                                    as prep_discharge_date,
                               mpf.prep_started                                                                                      AS prep_started,
                               mpf.next_visit_date                                                                                   AS next_visit_date_ec,
                               mpf.next_visit_date                                                                                   AS next_visit_date,
                               mpf.screen_result_for_sti                                                                             AS sti_diagnosis,
                               mpf.tb_diagnostic_test_result                                                                         AS tb_screening_result,
                               mpf.substance_use                                                                                     AS mhi_identified,
                               mpf.hepatitis_b_test_qualitative                                                                      AS hepatitis_b_result,
                               mpf.hepatitis_c_test_qualitative                                                                      AS hepatitis_c_result,
                               mpf.hepatitis_b_vaccination                                                                           AS hepatitis_b_vaccination,
                               mpf.family_planning_counseling                                                                        AS fp_counseling,
                               mpf1.ready_for_cervical_cancer_screening                                                              AS eligible_for_cxca_screen,
                               mpf1.linked_to_cervical_cancer_screening                                                              AS counseled_and_linked_cxca,
                               mpf.last_follow_up_outcome                                                                            AS last_follow_up_outcome,
                               mpf.decision                                                                                          AS final_decision
                        FROM mamba_flat_encounter_phrh_enrollment mpe
                                 LEFT JOIN mamba_flat_encounter_phrh_followup mpf
                                           ON mpe.client_id = mpf.client_id
                                 LEFT JOIN mamba_flat_encounter_phrh_followup_1 mpf1
                                            ON mpf.encounter_id = mpf1.encounter_id
                                 LEFT JOIN mamba_dim_client client
                                            ON mpe.client_id = client.client_id
                        WHERE REPORT_START_DATE is not null and REPORT_END_DATE is not null and
                              (mpf.followup_date BETWEEN REPORT_START_DATE and REPORT_END_DATE)
                           or (REPORT_START_DATE is not null and REPORT_END_DATE is null and
                               (mpf.followup_date >= REPORT_START_DATE))
                           or (REPORT_START_DATE is null and REPORT_END_DATE is not null and
                               (mpf.followup_date <= REPORT_END_DATE))
                           or (REPORT_START_DATE is null and REPORT_END_DATE is null)),

         phrhs AS (SELECT mpe.client_id  AS client_id,
                          mpi.identifier AS phrh
                   FROM mamba_flat_encounter_phrh_enrollment mpe
                            INNER JOIN mamba_dim_patient_identifier mpi
                                       ON mpe.client_id = mpi.patient_id
                            INNER JOIN mamba_dim_patient_identifier_type mpit
                                       ON mpi.identifier_type = mpit.patient_identifier_type_id
                   WHERE mpit.name = 'PHRH')

    SELECT en.mrn                       AS 'MRN',
           p.phrh                       AS 'PHRH Code',
           en.full_name                 AS 'Name',
           en.gender                    AS 'Sex',
           en.age                       AS 'Age',
           en.phrh_enrollment_date      AS 'PHRH Enrollment Date',
           en.phrh_enrollment_date      AS 'PHRH Enrollment Date EC.',
           en.previously_tested_for_hiv AS 'Previously Tested for HIV',
           en.phrh_followup_date_ec     AS 'FU Date (PHRH) EC.',
           en.phrh_followup_date        AS 'FU Date (PHRH) (GC)',
           en.risk_behaviors            AS 'Risk Behaviors',
           en.target_population         AS 'Target group',
           en.modality                  AS 'Modality',
           en.hiv_self_test_kit         AS 'Self-test kit',
           en.self_test_result          AS 'Self-testing result',
           en.conventional_result       AS 'Conventional Result',
           en.art_started               AS 'Start ART',
           en.unique_art_number         AS 'Unique ART #',
           en.date_linked_to_pmtct      AS 'Date Linked to PMTCT',
           en.date_linked_to_pmtct      AS 'Date Linked to PMTCT EC.',
           art_start_date as `Art Start Date`,
           art_start_date as `Art Start Date EC.`,
           en.eligible_for_prep         AS 'Eligible for PrEP',
           condoms_given_during_the_visit AS `# Condoms Provided?`,
           en.prep_started              AS 'PrEP Started',
           en.prep_discharge_date_ec    AS 'Date Discharged PrEP EC.',
           en.prep_discharge_date       AS 'Date Discharged PrEP(GC)',
           en.next_visit_date_ec        AS 'Next Appointment Date (PHRH) EC.',
           en.next_visit_date           AS 'Next Appointment Date (PHRH) (GC)',
           en.sti_diagnosis             AS 'STI Diagnosis',
           en.tb_screening_result       AS 'TB Screening Result',
           en.mhi_identified            AS 'Is MHI Identified?',
           en.hepatitis_b_result        AS 'Hepatitis B Result',
           en.hepatitis_c_result        AS 'Hepatitis C Result',
           en.hepatitis_b_vaccination   AS 'Hepatitis B vaccination (PWID)',
           en.fp_counseling             AS 'FP Counseling',
           en.eligible_for_cxca_screen  AS 'Eligible for CXCA Screen',
           en.counseled_and_linked_cxca AS 'Counseled & linked CXCA',
           en.last_follow_up_outcome    AS 'Last FU Outcome (PHRH)',
           en.final_decision            AS 'Final Decision'
    FROM enrollment en
             JOIN phrhs p on en.client_id = p.client_id
    WHERE en.row_num = 1
      and ((TARGET_GROUP != 'ALL' and en.target_population = TARGET_GROUP) or TARGET_GROUP = 'ALL');
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_phrh_sns_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_phrh_sns_query;

~
CREATE PROCEDURE sp_fact_line_list_phrh_sns_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE, IN PHRH_CODE VARCHAR(255))
BEGIN
	WITH provided_coupons AS (
        SELECT
            mps.client_id,
            mps.followup_date,
            mps.coupon_1  AS coupon_id,
            mpf.final_hiv_test_result AS conventional_result
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_flat_encounter_phrh_followup mpf
			ON mps.client_id = mpf.client_id
		WHERE mps.coupon_1 != ''

        UNION

        SELECT
            mps.client_id,
            mps.followup_date,
            mps.coupon_2  AS coupon_id,
            mpf.final_hiv_test_result AS conventional_result
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_flat_encounter_phrh_followup mpf
			ON mps.client_id = mpf.client_id
		WHERE mps.coupon_2 != ''

        UNION

        SELECT
            mps.client_id,
            mps.followup_date,
            mps.coupon_3  AS coupon_id,
            mpf.final_hiv_test_result AS conventional_result
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_flat_encounter_phrh_followup mpf
			ON mps.client_id = mpf.client_id
		WHERE mps.coupon_3 != ''

        UNION

        SELECT
            mps.client_id,
            mps.followup_date,
            mps.coupon_4  AS coupon_id,
            mpf.final_hiv_test_result AS conventional_result
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_flat_encounter_phrh_followup mpf
			ON mps.client_id = mpf.client_id
		WHERE mps.coupon_4 != ''

        UNION

        SELECT
            mps.client_id,
            mps.followup_date,
            mps.coupon_5  AS coupon_id,
            mpf.final_hiv_test_result AS conventional_result
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_flat_encounter_phrh_followup mpf
			ON mps.client_id = mpf.client_id
		WHERE mps.coupon_5 != ''
    ),
    provided_date AS (
		SELECT p.*
			FROM provided_coupons p
            WHERE REPORT_START_DATE is not null and REPORT_END_DATE is not null and (p.followup_date BETWEEN REPORT_START_DATE and REPORT_END_DATE) or
			(REPORT_START_DATE is not null and REPORT_END_DATE is null and (p.followup_date >= REPORT_START_DATE)) or
			(REPORT_START_DATE is null and REPORT_END_DATE is not null and (p.followup_date <= REPORT_END_DATE)) or
            (REPORT_START_DATE is null and REPORT_END_DATE is null)
    ),
    provided_and_retuned AS (
		SELECT
			pc.client_id,
            pc.coupon_id,
            pc.conventional_result,
            mpi.identifier AS phrh_code_returning_coupon,
            mpf.followup_date AS date_returned_ec,
            mpf.followup_date as date_returned,
            mpf.etb_paid_for_recruiter,
            mpf.final_hiv_test_result AS conventional_result_returning
		FROM provided_date pc
        LEFT JOIN mamba_flat_encounter_phrh_followup mpf
			ON mpf.coupon_id=pc.coupon_id
		LEFT JOIN mamba_dim_patient_identifier mpi
			ON mpf.client_id = mpi.patient_id and
            mpi.identifier_type = (SELECT patient_identifier_type_id FROM mamba_dim_patient_identifier_type WHERE name='PHRH')
    ),
    sns AS (
        SELECT
            mps.client_id AS client_id,
            mpi.identifier AS phrh,
            mps.followup_date AS date_provided_ec,
            mps.followup_date AS date_provided
        FROM mamba_flat_encounter_phrh_sns mps
        INNER JOIN mamba_dim_patient_identifier mpi
            ON mps.client_id = mpi.patient_id
        INNER JOIN mamba_dim_patient_identifier_type mpit
            ON mpi.identifier_type = mpit.patient_identifier_type_id  and mpit.name = 'PHRH'
		WHERE (PHRH_CODE is not null and mpi.identifier = PHRH_CODE) or PHRH_CODE is null
    )
    SELECT
		s.phrh AS 'PHRH Code Provided Coupon',
        p.coupon_id AS 'Coupon ID',
        s.date_provided_ec AS 'Date Provided EC.',
        s.date_provided AS 'Date Provided (GC)',
        p.conventional_result AS 'Contact Result Provided Coupon',
        p.phrh_code_returning_coupon AS 'PHRH Code Returning Coupon',
        p.date_returned_ec AS 'Date Returned EC.',
        p.date_returned AS 'Date Returned (GC)',
        p.etb_paid_for_recruiter AS 'ETB paid for Recruiter',
        p.conventional_result_returning AS 'Contact Test Result Returning Coupon'
    FROM provided_and_retuned p
    JOIN sns s ON p.client_id = s.client_id;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_providers_view_query
--

DELIMITER //
DROP PROCEDURE IF EXISTS sp_fact_line_list_providers_view_query;
~
CREATE PROCEDURE sp_fact_line_list_providers_view_query(IN TYPE_OF_CLIENT VARCHAR(50),
                                                        IN END_DATE DATE,
                                                        IN START_NV_DATE DATE, IN END_NV_DATE DATE,
                                                        IN PATIENT_GUID VARCHAR(50))
BEGIN

    -- Optimize by defining basic patient set first
    WITH tmp_address as (select patient_uuid,
                                client_id,
                                patient_name                                 AS PatientName,
                                timestampdiff(YEAR, date_of_birth, END_DATE) AS Age,
                                sex                                          as sex,
                                patient_name,
                                CASE
                                    WHEN
                                        (given_name <> '' and middle_name <> '' and family_name <> '' and
                                         (mobile_no <> '' or phone_no <> '')
                                            ) THEN 'Green'
                                    ELSE 'Yellow'
                                    END                                      AS Adrress,
                                CAST(mrn AS CHAR(20))                        as mrn,
                                uan
                         from mamba_dim_client
                         where mrn is not null
                           AND (PATIENT_GUID IS NULL OR patient_uuid = PATIENT_GUID)),

         FollowUp as (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_                        as follow_up_date,
                             art_antiretroviral_start_date                   as art_start_date,
                             date_started_on_tuberculosis_prophy             as inhprophylaxis_started_date,
                             date_completed_tuberculosis_prophyl             as inhprophylaxis_completed_date,
                             date_discontinued_tuberculosis_prop             as inhprophylaxis_discontinued_date,
                             date_active_tbrx_completed                      as date_active_tb_treatment_completed,
                             weight_text_                                    as weight,
                             eligible_for_tpt,
                             reason_not_eligible_for_tuberculosi,
                             date_of_reported_hiv_viral_load                 as viral_load_sent_date,
                             regimen_change,
                             date_viral_load_results_received                as viral_load_perform_date,
                             viral_load_test_status,
                             hiv_viral_load                                  as viral_load_count,
                             regimen,
                             cd4_count,
                             nutritional_status_of_adult                     as ns_adult,
                             nutritional_status_of_older_child_a             as ns_child,
                             nutritional_screening_result,
                             date_of_event                                   as hiv_confirmed_date,
                             pregnancy_status,
                             next_visit_date,
                             antiretroviral_art_dispensed_dose_i                arv_dose,
                             treatment_end_date                                 art_dose_end_date,
                             currently_breastfeeding_child                   as breastfeeding_status,
                             adherence,
                             date_of_last_menstrual_period_lmp_              as lmp_date,
                             pre_test_counselling_for_cervical_c             as councelling_given,
                             biopsy_result,
                             assessment_date,
                             next_follow_up_screening_date                   as ccs_next_date,
                             assessment_status,

                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                               AS routine_viral_load_test_indication,
                             dsd_category,
                             hpv_dna_result_received_date,
                             date_cytology_result_received                   as cytology_result_date,
                             cervical_cancer_screening_status                AS screening_status,
                             hpv_dna_screening_result                        AS ccs_hpv_result,
                             cytology_result                                 AS cytology_result,
                             via_screening_result                            AS ccs_via_result,
                             via_done_,
                             date_visual_inspection_of_the_cervi             AS via_date,
                             treatment_start_date                            AS ccs_treat_received_date,
                             colposcopy_of_cervix_findings                   AS colposcopy_exam_finding,
                             colposcopy_exam_date,
                             purpose_for_visit_cervical_screening            as screening_type,
                             cervical_cancer_screening_method_strategy       as screening_method,
                             hpv_subtype,
                             date_hpv_test_was_done,
                             cytology_sample_collection_date,
                             biopsy_sample_collected_date,
                             biopsy_result_received_date,
                             treatment_of_precancerous_lesions_of_the_cervix as CCS_Precancerous_Treat,
                             confirmed_cervical_cancer_cases_bas,
                             referral_or_linkage_status,
                             reason_for_referral_cacx,
                             date_client_served_in_the_referred_,
                             date_client_arrived_in_the_referred,
                             date_patient_referred_out,
                             prep_offered,
                             weight_text_,
                             antiretroviral_art_dispensed_dose_i             as dose_days,
                             pre_test_counselling_for_cervical_c                CCaCounsellingGiven,
                             ready_for_cervical_cancer_screening                Accepted,
                             eligible_for_cxca_screening,
                             reason_for_not_being_eligible,
                             other_reason_for_not_being_eligible_for_cxca
                      FROM mamba_flat_encounter_follow_up follow_up
                               INNER JOIN tmp_address ON follow_up.client_id = tmp_address.client_id
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id
                      WHERE follow_up_6.follow_up_date_followup_ <= COALESCE(END_DATE, CURDATE())),

         all_art_not_started as (select client_id,
                                            encounter_id,
                                            art_start_date,
                                            follow_up_status
                                     from (select client_id, encounter_id, art_start_date, follow_up_status,
                                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY art_start_date DESC, encounter_id DESC) AS row_num
                                           from FollowUp) t where row_num = 1),

         all_art_follow_ups as (select client_id,
                                           encounter_id,
                                           follow_up_date,
                                           follow_up_status
                                    from (select client_id, encounter_id, follow_up_date, follow_up_status,
                                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                          from FollowUp) t where row_num = 1),


         all_art_not_started_status as (select *, 'ART Not Started' as art_status
                                        from all_art_not_started
                                        where art_start_date is null),

         tpt_start as (select client_id, inhprophylaxis_started_date
                       from (select client_id, inhprophylaxis_started_date,
                                    ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY inhprophylaxis_started_date DESC, encounter_id DESC) AS row_num
                             from FollowUp
                             where inhprophylaxis_started_date is not null) t where row_num = 1),

         tpt_completed as (select client_id, inhprophylaxis_completed_date
                           from (select client_id, inhprophylaxis_completed_date,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY inhprophylaxis_completed_date DESC, encounter_id DESC) AS row_num
                                 from FollowUp
                                 where inhprophylaxis_completed_date is not null) t where row_num = 1),

         tpt_discontinued as (select client_id, inhprophylaxis_discontinued_date
                              from (select client_id, inhprophylaxis_discontinued_date,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY inhprophylaxis_discontinued_date DESC, encounter_id DESC) AS row_num
                                    from FollowUp
                                    where inhprophylaxis_discontinued_date is not null) t where row_num = 1),

         tb_treatment_completed as (select client_id, ActiveTBTreatmentCompletedDate
                                    from (SELECT client_id,
                                                 date_active_tb_treatment_completed                                                                             AS ActiveTBTreatmentCompletedDate,
                                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY date_active_tb_treatment_completed DESC, encounter_id DESC) AS row_num
                                          FROM FollowUp
                                          WHERE date_active_tb_treatment_completed IS NOT NULL
                                            and TIMESTAMPDIFF(DAY, date_active_tb_treatment_completed, END_DATE) < 1095) t where row_num = 1),

         tb_treatment_completed_2 as (select client_id, ActiveTBTreatmentCompletedDate
                                      from (SELECT client_id,
                                                   date_active_tb_treatment_completed                                                                             AS ActiveTBTreatmentCompletedDate,
                                                   ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY date_active_tb_treatment_completed DESC, encounter_id DESC) AS row_num
                                            FROM FollowUp
                                            where date_active_tb_treatment_completed is not null
                                              and TIMESTAMPDIFF(DAY, date_active_tb_treatment_completed, END_DATE) < 1095
                                              and inhprophylaxis_completed_date is null
                                              and inhprophylaxis_discontinued_date is null
                                              and inhprophylaxis_started_date) t where row_num = 1),


         tpt_eligible_yes as (select client_id, encounter_id
                              from (select client_id, encounter_id,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                    FROM FollowUp
                                    where eligible_for_tpt = 'Yes'
                                      and inhprophylaxis_completed_date is null
                                      and inhprophylaxis_discontinued_date is null
                                      and inhprophylaxis_started_date is null) t where row_num = 1),

         tpt_eligible_no as (select client_id, encounter_id
                             from (select client_id, encounter_id,
                                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                   FROM FollowUp
                                   where eligible_for_tpt = 'No'
                                     and inhprophylaxis_completed_date is null
                                     and inhprophylaxis_discontinued_date is null
                                     and inhprophylaxis_started_date is null) t where row_num = 1),


         tpt_not_eligible as (select client_id, encounter_id
                              from (select client_id, encounter_id,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                    FROM FollowUp
                                    where reason_not_eligible_for_tuberculosi = 'Contraindication'
                                      and inhprophylaxis_completed_date is null
                                      and inhprophylaxis_discontinued_date is null
                                      and inhprophylaxis_started_date is null
                                      and follow_up_date <= END_DATE) t where row_num = 1),

         contraindicated as (select client_id, 'Contraindicated' as tpt_status from tpt_not_eligible),

         tpt_bronze_5 as (select ActiveTBTreatmentCompletedDate,
                                 client_id,
                                 Case
                                     When timestampdiff(DAY, tb_treatment_completed.ActiveTBTreatmentCompletedDate,
                                                        END_DATE) < 1095
                                         THEN 'Treatment for TB'
                                     END as tpt_status
                          from tb_treatment_completed
                          where NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tb_treatment_completed.client_id)),

         tpt_gold as (select tpt_start.client_id,
                             Case
                                 When tpt_start.inhprophylaxis_started_date <=
                                      tpt_completed.inhprophylaxis_completed_date
                                     THEN 'Gold'
                                 When tpt_start.inhprophylaxis_started_date >
                                      tpt_completed.inhprophylaxis_completed_date
                                     THEN 'Gold'
                                 END as tpt_status
                      from tpt_start
                               inner join tpt_completed
                                          on tpt_start.client_id = tpt_completed.client_id
                      where NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_start.client_id)
                        AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_start.client_id)),

         tpt_silver_bronze_1 as (select client_id,
                                        Case
                                            When TIMESTAMPDIFF(DAY, tpt_start.inhprophylaxis_started_date, END_DATE) <=
                                                 270
                                                THEN 'Silver'
                                            When TIMESTAMPDIFF(
                                                         DAY, tpt_start.inhprophylaxis_started_date, END_DATE) > 270
                                                THEN 'Bronze1'
                                            END as tpt_status
                                 from tpt_start
                                 where NOT EXISTS (select 1 from tpt_completed where tpt_completed.client_id = tpt_start.client_id)
                                   and NOT EXISTS (select 1 from tpt_discontinued where tpt_discontinued.client_id = tpt_start.client_id)
                                   and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_start.client_id)
                                   AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_start.client_id)),

         tpt_bronze_3 as (select tpt_start.client_id,
                                 Case
                                     When tpt_start.inhprophylaxis_started_date <=
                                          tpt_discontinued.inhprophylaxis_discontinued_date
                                         THEN 'Bronze3'
                                     When tpt_start.inhprophylaxis_started_date >
                                          tpt_discontinued.inhprophylaxis_discontinued_date
                                         THEN 'Bronze3'
                                     END as tpt_status
                          from tpt_start
                                   inner join tpt_discontinued
                                              on tpt_start.client_id = tpt_discontinued.client_id
                          where NOT EXISTS (select 1 from tpt_gold where tpt_gold.client_id = tpt_start.client_id)
                            and NOT EXISTS (select 1 from tpt_silver_bronze_1 where tpt_silver_bronze_1.client_id = tpt_start.client_id)
                            and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_start.client_id)
                            AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_start.client_id)),

         tpt_bronze_5_changed as (select tb_treatment_completed_2.client_id,
                                         Case
                                             When
                                                 timestampdiff(DAY,
                                                               tb_treatment_completed_2.ActiveTBTreatmentCompletedDate,
                                                               END_DATE) >= 1095
                                                 THEN 'Bronze5'
                                             END as tpt_status
                                  from tb_treatment_completed_2
                                  where NOT EXISTS (select 1 from tpt_gold where tpt_gold.client_id = tb_treatment_completed_2.client_id)
                                    and NOT EXISTS (select 1 from tpt_silver_bronze_1 where tpt_silver_bronze_1.client_id = tb_treatment_completed_2.client_id)
                                    and NOT EXISTS (select 1 from tpt_bronze_3 where tpt_bronze_3.client_id = tb_treatment_completed_2.client_id)
                                    and NOT EXISTS (select 1 from tpt_bronze_5 where tpt_bronze_5.client_id = tb_treatment_completed_2.client_id)),

         tpt_bronze_4 as (select tpt_eligible_yes.client_id,
                                 'Bronze4' as tpt_status
                          from tpt_eligible_yes
                          where NOT EXISTS (select 1 from tpt_gold where tpt_gold.client_id = tpt_eligible_yes.client_id)
                            and NOT EXISTS (select 1 from tpt_silver_bronze_1 where tpt_silver_bronze_1.client_id = tpt_eligible_yes.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_3 where tpt_bronze_3.client_id = tpt_eligible_yes.client_id)
                            and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_eligible_yes.client_id)
                            AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_eligible_yes.client_id)
                            AND NOT EXISTS (select 1 from tpt_bronze_5_changed where tpt_bronze_5_changed.client_id = tpt_eligible_yes.client_id)),

         tpt_bronze_6 as (select tpt_completed.client_id,
                                 'Bronze6' as tpt_status
                          from tpt_completed
                          where NOT EXISTS (select 1 from tpt_gold where tpt_gold.client_id = tpt_completed.client_id)
                            and NOT EXISTS (select 1 from tpt_silver_bronze_1 where tpt_silver_bronze_1.client_id = tpt_completed.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_3 where tpt_bronze_3.client_id = tpt_completed.client_id)
                            and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_completed.client_id)
                            AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_completed.client_id)
                            AND NOT EXISTS (select 1 from tpt_bronze_5_changed where tpt_bronze_5_changed.client_id = tpt_completed.client_id)
                            AND NOT EXISTS (select 1 from tpt_bronze_4 where tpt_bronze_4.client_id = tpt_completed.client_id)
                            AND NOT EXISTS (select 1 from tpt_start where tpt_start.client_id = tpt_completed.client_id)
                          UNION ALL
                          select tpt_discontinued.client_id,
                                 'Bronze6' as tpt_status
                          from tpt_discontinued
                          where NOT EXISTS (select 1 from tpt_gold where tpt_gold.client_id = tpt_discontinued.client_id)
                            and NOT EXISTS (select 1 from tpt_silver_bronze_1 where tpt_silver_bronze_1.client_id = tpt_discontinued.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_3 where tpt_bronze_3.client_id = tpt_discontinued.client_id)
                            and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_discontinued.client_id)
                            AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_discontinued.client_id)
                            AND NOT EXISTS (select 1 from tpt_bronze_5_changed where tpt_bronze_5_changed.client_id = tpt_discontinued.client_id)
                            AND NOT EXISTS (select 1 from tpt_bronze_4 where tpt_bronze_4.client_id = tpt_discontinued.client_id)
                            AND NOT EXISTS (select 1 from tpt_start where tpt_start.client_id = tpt_discontinued.client_id)
                            AND NOT EXISTS (select 1 from tpt_completed where tpt_completed.client_id = tpt_discontinued.client_id)),

         tpt_bronze_2 as (select tpt_eligible_no.client_id,
                                          'Bronze2' as tpt_status
                          from tpt_eligible_no
                          where NOT EXISTS (select 1 from tpt_start where tpt_start.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_completed where tpt_completed.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tb_treatment_completed where tb_treatment_completed.client_id = tpt_eligible_no.client_id)
                            AND NOT EXISTS (select 1 from contraindicated where contraindicated.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_3 where tpt_bronze_3.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_4 where tpt_bronze_4.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_5 where tpt_bronze_5.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_5_changed where tpt_bronze_5_changed.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_bronze_6 where tpt_bronze_6.client_id = tpt_eligible_no.client_id)
                            and NOT EXISTS (select 1 from tpt_discontinued where tpt_discontinued.client_id = tpt_eligible_no.client_id)),

         vl_sent_date as (select client_id, VL_Sent_Date
                          from (SELECT client_id,
                                       viral_load_sent_date                                                                             AS VL_Sent_Date,
                                       ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_sent_date DESC, encounter_id DESC) AS row_num
                                FROM FollowUp
                                WHERE viral_load_sent_date <= COALESCE(END_DATE, CURDATE())) t where row_num = 1),

         switch_sub_date as (select client_id, FollowUpDate
                             from (SELECT client_id,
                                          follow_up_date                                                                             AS FollowUpDate,
                                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                   FROM FollowUp
                                   WHERE follow_up_date <= COALESCE(END_DATE, CURDATE())
                                     and regimen_change is not null) t where row_num = 1),

         tmp_vl_performed_date_2 as (select * from (SELECT encounter_id,
                                                            client_id,
                                                            viral_load_perform_date                                                                             AS viral_load_perform_date,
                                                            routine_viral_load_test_indication,
                                                            viral_load_test_status,
                                                            viral_load_count,
                                                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_perform_date DESC, encounter_id DESC) AS row_num
                                                     FROM FollowUp
                                                     WHERE art_start_date IS NOT NULL
                                                       AND (
                                                         (viral_load_perform_date IS NOT NULL AND
                                                          viral_load_perform_date <= COALESCE(END_DATE, CURDATE())
                                                             )
                                                             OR
                                                         viral_load_perform_date IS NULL
                                                         )) t where row_num = 1),

         tmp_vl_performed_date_3 as (SELECT tmp_vl_performed_date_2.encounter_id,
                                            tmp_vl_performed_date_2.client_id,
                                            vl_sent_date.VL_Sent_Date,
                                            viral_load_test_status,
                                            case
                                                when tmp_vl_performed_date_2.viral_load_perform_date <
                                                     vl_sent_date.VL_Sent_Date
                                                    then null
                                                else tmp_vl_performed_date_2.viral_load_perform_date end as viral_load_perform_date,
                                            case
                                                when tmp_vl_performed_date_2.viral_load_perform_date <
                                                     vl_sent_date.VL_Sent_Date
                                                    then null
                                                else tmp_vl_performed_date_2.viral_load_test_status end  as viral_load_status,
                                            CASE
                                                WHEN tmp_vl_performed_date_2.viral_load_count > 0 AND
                                                     tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date
                                                    THEN CAST(tmp_vl_performed_date_2.viral_load_count AS DECIMAL(12, 2))
                                                ELSE NULL END                                            AS viral_load_count,
                                            CASE
                                                WHEN
                                                    viral_load_test_status IS NULL AND
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date
                                                    THEN
                                                    NULL
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date AND
                                                     (viral_load_test_status LIKE 'Det%'
                                                         OR viral_load_test_status LIKE 'Uns%'
                                                         OR viral_load_test_status LIKE 'High VL%'
                                                         OR viral_load_test_status LIKE 'Low Level Viremia%')
                                                    THEN
                                                    'U'
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date AND
                                                     (viral_load_test_status LIKE 'Su%'
                                                         OR viral_load_test_status LIKE 'Undet%')
                                                    THEN
                                                    'S'
                                                WHEN
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date AND
                                                    (ISNULL(viral_load_count) > CAST(50 AS float)
                                                        )
                                                    THEN
                                                    'U'
                                                WHEN
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date AND
                                                    (ISNULL(viral_load_count) <= CAST(50 AS float)
                                                        )
                                                    THEN
                                                    'S'
                                                ELSE
                                                    NULL
                                                END                                                      AS viral_load_status_inferred,
                                            CASE
                                                WHEN vl_sent_date.VL_Sent_Date IS NOT NULL
                                                    THEN vl_sent_date.VL_Sent_Date
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date IS NOT NULL
                                                    THEN tmp_vl_performed_date_2.viral_load_perform_date
                                                ELSE NULL END                                            AS viral_load_ref_date,
                                            tmp_vl_performed_date_2.routine_viral_load_test_indication
                                     FROM tmp_vl_performed_date_2
                                              LEFT JOIN vl_sent_date
                                                        ON tmp_vl_performed_date_2.client_id = vl_sent_date.client_id),

         tmp_2 as (select client_id, encounter_id, follow_up_date
                   from (select client_id,
                                 encounter_id,
                                 follow_up_date,
                                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                          from FollowUp
                          where follow_up_status is not null
                            and follow_up_date <= END_DATE) t where row_num = 1),

         tmp_3 as (select f_case.client_id,
                          f_case.encounter_id,
                          f_case.weight,
                          f_case.hiv_confirmed_date,
                          f_case.art_start_date,
                          f_case.follow_up_date,
                          f_case.pregnancy_status,
                          regimen                                            as ARVDispendsedDoseCode,
                          f_case.arv_dose,
                          f_case.next_visit_date,
                          f_case.follow_up_status,
                          f_case.nutritional_screening_result,
                          f_case.ns_adult,
                          f_case.art_dose_end_date,
                          f_case.adherence,
                          f_case.breastfeeding_status,
                          f_case.cd4_count,
                          f_case.dsd_category,
                          vlperfdate.viral_load_perform_date,
                          vlperfdate.viral_load_test_status,
                          vlperfdate.viral_load_count,
                          vlsentdate.VL_Sent_Date,
                          vlperfdate.viral_load_ref_date,
                          sub_switch_date.FollowupDate,
                          CASE

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND f_case.follow_up_status = 'Restart medication')
                                  THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND sub_switch_date.FollowupDate IS NOt NULL
                                      )
                                  THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND f_case.pregnancy_status = 'Yes'
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 90)
                                  THEN DATE_ADD(f_case.art_start_date, INTERVAL 91 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) <= 180)
                                  THEN NULL


                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 180)
                                  THEN DATE_ADD(f_case.art_start_date, INTERVAL 181 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.VL_Sent_Date < f_case.follow_up_date)
                                      AND (f_case.follow_up_status = 'Restart medication')
                                  THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.VL_Sent_Date < sub_switch_date.FollowupDate
                                      AND sub_switch_date.FollowupDate IS NOT NULL
                                      )
                                  THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.viral_load_status_inferred = 'U')
                                  THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 91 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND
                                   (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                      AND vlperfdate.routine_viral_load_test_indication in
                                          ('First viral load test at 6 months or longer post ART',
                                           'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                           'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                  THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 91 DAY)

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND
                                   (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                      AND vlperfdate.routine_viral_load_test_indication IS NOT NULL
                                      AND vlperfdate.routine_viral_load_test_indication not in
                                          ('First viral load test at 6 months or longer post ART',
                                           'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                           'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                  THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 181 DAY)


                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL)
                                  THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 365 DAY)

                              ELSE DATE_ADD(END_DATE, INTERVAL 100 YEAR) End AS eligiblityDate,

                          CASE

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND f_case.follow_up_status = 'Restart medication')
                                  THEN 'client restarted ART'

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND sub_switch_date.FollowupDate IS NOt NULL
                                      )
                                  THEN 'Regimen Change'


                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND f_case.pregnancy_status = 'Yes'
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 90)
                                  THEN 'First VL for Pregnant'

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) <= 180)
                                  THEN 'N/A'

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 180)
                                  THEN 'First VL'


                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.VL_Sent_Date < f_case.follow_up_date)
                                      AND (f_case.follow_up_status = 'Restart medication')
                                  THEN 'client restarted ART'

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.VL_Sent_Date < sub_switch_date.FollowupDate
                                      AND sub_switch_date.FollowupDate IS NOT NULL
                                      )
                                  THEN 'Regimen Change'

                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL
                                      AND vlperfdate.viral_load_status_inferred = 'U')
                                  THEN 'Repeat/Confirmatory Viral Load test'

                              WHEN
                                  (vlperfdate.viral_load_status_inferred IS NOT NULL
                                      AND
                                   (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes'))
                                  THEN 'Pregnant/Breastfeeding and needs retesting'


                              WHEN
                                  (vlperfdate.VL_Sent_Date IS NOT NULL)
                                  THEN 'Annual Viral Load Test'

                              ELSE 'Unassigned' End                          AS vl_status_final,
                          CASE

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NULL
                                      AND f_case.follow_up_status = 'Restart medication')
                                  THEN 'client restarted ART'

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NULL
                                      AND sub_switch_date.FollowupDate IS NOt NULL
                                      )
                                  THEN 'Regimen Change'


                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NULL
                                      AND f_case.pregnancy_status = 'Yes'
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 90)
                                  THEN 'First VL for Pregnant'

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) <= 180)
                                  THEN 'N/A'

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NULL
                                      AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                        COALESCE(END_DATE, CURDATE())) > 180)
                                  THEN 'First VL'


                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NOT NULL
                                      AND vlperfdate.viral_load_perform_date < f_case.follow_up_date)
                                      AND (f_case.follow_up_status = 'Restart medication')
                                  THEN 'client restarted ART'

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NOT NULL
                                      AND vlperfdate.viral_load_perform_date < sub_switch_date.FollowupDate
                                      AND sub_switch_date.FollowupDate IS NOT NULL
                                      )
                                  THEN 'Regimen Change'

                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NOT NULL
                                      AND vlperfdate.viral_load_status_inferred = 'U')
                                  THEN 'Repeat/Confirmatory Viral Load test'

                              WHEN
                                  (vlperfdate.viral_load_status_inferred IS NOT NULL
                                      AND
                                   (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes'))
                                  THEN 'Pregnant/Breastfeeding and needs retesting'


                              WHEN
                                  (vlperfdate.viral_load_perform_date IS NOT NULL)
                                  THEN 'Annual Viral Load Test'

                              ELSE 'Unassigned' End                          AS VL_STATUS_COVERAGE


                   FROM FollowUp AS f_case
                            INNER JOIN tmp_2
                                       ON f_case.encounter_id = tmp_2.encounter_id
                            LEFT JOIN tmp_vl_performed_date_3 as vlperfdate
                                      ON vlperfdate.client_id = f_case.client_id
                            Left join vl_sent_date as vlsentdate
                                      ON vlsentdate.client_id = f_case.client_id
                            Left join switch_sub_date as sub_switch_date
                                      ON sub_switch_date.client_id = f_case.client_id),


         vl_eligibility as (select tmp_3.client_id,
                                   vl_status_final as vl_status
                            from tmp_3
                            where NOT EXISTS (select 1 from all_art_not_started_status where all_art_not_started_status.client_id = tmp_3.client_id)
                            union
                            select client_id, art_start_date
                            from all_art_not_started_status),


         dsd_cat as (select client_id, dsd_category, dsd_fdate, assessment_status
                     from (SELECT client_id,
                                  dsd_category,
                                  follow_up_date                                                                              AS dsd_fdate,
                                  assessment_status,
                                  ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY assessment_date DESC, encounter_id DESC) AS row_num
                           FROM FollowUp
                           WHERE follow_up_date <= END_DATE
                             and assessment_date is not null) t
                     where row_num = 1
                       and NOT EXISTS (select 1 from all_art_not_started_status where all_art_not_started_status.client_id = t.client_id)),

         tpt as (select client_id, tpt_status from tpt_gold
                 union select client_id, tpt_status from tpt_silver_bronze_1
                 union select client_id, tpt_status from tpt_bronze_2
                 union select client_id, tpt_status from tpt_bronze_3
                 union select client_id, tpt_status from tpt_bronze_4
                 union select client_id, tpt_status from tpt_bronze_5
                 union select client_id, tpt_status from contraindicated
                 union select client_id, tpt_status from tpt_bronze_5_changed
                 union select client_id, tpt_status from tpt_bronze_6),


         latest_follow_up AS (SELECT fu.client_id,
                                     fu.follow_up_date,
                                     fu.follow_up_status                                                                                 AS final_follow_up_status,
                                     fu.eligible_for_cxca_screening,
                                     fu.reason_for_not_being_eligible,
                                     fu.other_reason_for_not_being_eligible_for_cxca,
                                     fu.screening_status,
                                     fu.hiv_confirmed_date,
                                     fu.art_start_date
                              FROM (select client_id, follow_up_date, follow_up_status, eligible_for_cxca_screening, reason_for_not_being_eligible,
                                           other_reason_for_not_being_eligible_for_cxca, screening_status, hiv_confirmed_date, art_start_date,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS rn
                                    from FollowUp where follow_up_date <= END_DATE) fu
                              WHERE fu.rn = 1),


         prev_screening AS (SELECT sc.client_id,
                                   sc.follow_up_date,
                                   sc.ccs_via_result,
                                   sc.via_date,
                                   sc.ccs_treat_received_date,
                                   sc.date_patient_referred_out,
                                   sc.biopsy_result,
                                   sc.ccs_hpv_result,
                                   sc.hpv_dna_result_received_date,
                                   sc.cytology_result,
                                   sc.cytology_result_date,
                                   sc.colposcopy_exam_finding,
                                   sc.biopsy_result_received_date
                            FROM (select client_id, follow_up_date, ccs_via_result, via_date, ccs_treat_received_date, date_patient_referred_out,
                                         biopsy_result, ccs_hpv_result, hpv_dna_result_received_date, cytology_result, cytology_result_date,
                                         colposcopy_exam_finding, biopsy_result_received_date,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS rn
                                  from FollowUp where follow_up_date <= END_DATE AND screening_status = 'Cervical cancer screening performed') sc
                            WHERE sc.rn = 1),

         cxca_eligibility_base_clients AS (SELECT lf.*,
                                                  ps.follow_up_date AS previous_screening_follow_up_date,
                                                  ps.ccs_via_result,
                                                  ps.via_date,
                                                  ps.ccs_treat_received_date,
                                                  ps.date_patient_referred_out,
                                                  ps.biopsy_result,
                                                  ps.ccs_hpv_result,
                                                  ps.hpv_dna_result_received_date,
                                                  ps.cytology_result,
                                                  ps.cytology_result_date,
                                                  ps.colposcopy_exam_finding,
                                                  ps.biopsy_result_received_date,

                                                  c.sex,
                                                  c.Age,

                                                  -- This CASE statement generates the detailed Eligibility Status
                                                  CASE
                                                      -- TC-02, TC-03, ...: Not eligible by user/form (e.g., Hysterectomy, etc.)
                                                      WHEN ps.client_id IS NULL
                                                          AND lf.eligible_for_cxca_screening = 'No'
                                                          THEN CONCAT('Not Eligible ',
                                                                      COALESCE(lf.reason_for_not_being_eligible,
                                                                               lf.other_reason_for_not_being_eligible_for_cxca))

                                                      -- TC-19: Biopsy confirmed cancer (Red rule source)
                                                      WHEN (ps.biopsy_result = 'Carcinoma in situ'
                                                          OR ps.biopsy_result = 'Invasive cervical cancer'
                                                          OR ps.biopsy_result = 'Other')
                                                          AND (ps.ccs_treat_received_date <= END_DATE
                                                              OR ps.date_patient_referred_out <= END_DATE)
                                                          THEN 'Not Eligible Confirmed Cirvical Cancer'

                                                      -- TC-06: User-Labeled as Eligible
                                                      WHEN ps.client_id IS NULL
                                                          AND
                                                           lf.screening_status != 'Cervical cancer screening performed'
                                                          AND lf.eligible_for_cxca_screening = 'Yes'
                                                          THEN 'Eligible Labeled by User'

                                                      -- TC-07: Never screened/assessed
                                                      WHEN ps.client_id IS NULL
                                                          AND lf.eligible_for_cxca_screening IS NULL
                                                          THEN 'Eligible Never Screened/Assessed'

                                                      -- TC-08: Unknown VIA result
                                                      WHEN ps.ccs_via_result = 'Unknown'
                                                          THEN 'Eligible Unknown VIA Screening Result'

                                                      -- TC-09: VIA negative >2 years ago
                                                      WHEN (TIMESTAMPDIFF(DAY, ps.via_date, END_DATE)) > 730
                                                          AND ps.ccs_via_result = 'VIA negative'
                                                          THEN 'Eligible Needs Re-Screening'

                                                      -- TC-10, TC-11 (VIA Positive logic)
                                                      WHEN ps.ccs_via_result = 'VIA positive: eligible for cryo/thermo-coagula'
                                                          THEN
                                                          CASE
                                                              -- TC-10: Treatment/Referral Given > 1 year (Needs follow-up)
                                                              WHEN
                                                                  ((TIMESTAMPDIFF(DAY, ps.ccs_treat_received_date, END_DATE)) >
                                                                   365
                                                                      OR
                                                                   (TIMESTAMPDIFF(DAY, ps.date_patient_referred_out, END_DATE)) >
                                                                   365)
                                                                      AND ps.biopsy_result IS NULL
                                                                  THEN 'Eligible Post Treatment/Referral Follow-Up'
                                                              -- TC-11: No Treatment/Referral
                                                              WHEN ps.ccs_treat_received_date IS NULL
                                                                  AND ps.date_patient_referred_out IS NULL
                                                                  THEN 'Eligible Treatment Not Received or Not Referred'
                                                              ELSE 'Not Eligible (Screening Up-to-Date)' -- Default if treatment received recently
                                                              END

                                                      -- TC-12: VIA Positive & Not Eligible for Cryo OR Suspected Cancer & NO BIOPSY
                                                      WHEN (ps.ccs_via_result =
                                                            'VIA positive: non-eligible for cryo/thermo-coagula'
                                                          OR ps.ccs_via_result = 'suspected cervical cancer')
                                                          AND ps.biopsy_result IS NULL
                                                          THEN 'Eligible Biopsy Test Not Done'

                                                      -- TC-13: HPV negative >3 years ago
                                                      WHEN ps.ccs_hpv_result = 'Negative result'
                                                          AND
                                                           TIMESTAMPDIFF(DAY, ps.hpv_dna_result_received_date, END_DATE) >
                                                           1095
                                                          THEN 'Eligible Needs Re-Screening'

                                                      -- TC-14: HPV positive, needs VIA triage
                                                      WHEN ps.ccs_via_result IS NULL
                                                          AND ps.ccs_hpv_result = 'Positive'
                                                          THEN 'Eligible Needs VIA Triage'

                                                      -- TC-15: Cytology Negative >3 years ago
                                                      WHEN ps.cytology_result = 'Negative result'
                                                          AND
                                                           TIMESTAMPDIFF(DAY, ps.cytology_result_date, END_DATE) > 1095
                                                          THEN 'Eligible Needs Re-Screening'

                                                      -- TC-16, TC-17, TC-18 (Cytology Positive logic)
                                                      WHEN (ps.cytology_result =
                                                            'ASCUS (Atypical Squamous Cells of Undetermined Significance) on Pap Smear'
                                                          OR ps.cytology_result = '> Ascus')
                                                          THEN
                                                          CASE
                                                              -- TC-16: NO HPV Test
                                                              WHEN ps.hpv_dna_result_received_date IS NULL
                                                                  THEN 'Eligible Needs HPV Triage'
                                                              -- TC-17: HPV Negative > 2 years (Needs Reassessment)
                                                              WHEN ps.ccs_hpv_result = 'Negative result'
                                                                  AND
                                                                   TIMESTAMPDIFF(DAY, ps.hpv_dna_result_received_date, END_DATE) >
                                                                   730
                                                                  THEN 'Eligible Needs Re-Screening'
                                                              -- TC-18: HPV Positive & Needs Colposcopy
                                                              WHEN ps.ccs_hpv_result = 'Positive'
                                                                  AND ps.colposcopy_exam_finding IS NULL
                                                                  THEN 'Eligible Needs Colposcopy Test'
                                                              ELSE 'Not Eligible (Screening Up-to-Date)'
                                                              END

                                                      -- TC-20: Biopsy CIN-1/CIN-2 > 1 year
                                                      WHEN (ps.biopsy_result = 'CIN (1-3)'
                                                          OR ps.biopsy_result = 'CIN-2')
                                                          AND
                                                           TIMESTAMPDIFF(DAY, ps.biopsy_result_received_date, END_DATE) >
                                                           365
                                                          THEN 'Eligible Needs Re-Screening'

                                                      -- DEFAULT (CATCH-ALL): Client is not due for screening / Screening Done (Green rule source)
                                                      ELSE 'Not Eligible (Screening Up-to-Date)'
                                                      END           AS EligibilityStatus
                                           FROM latest_follow_up lf
                                                    LEFT JOIN prev_screening ps
                                                              ON lf.client_id = ps.client_id
                                                    JOIN tmp_address c ON lf.client_id = c.client_id),

         cervical as (SELECT base.*, -- Selects all client info AND the EligibilityStatus

                             -- Calculate Age based on END_DATE
                             age     AS current_age,

                             -- This CASE statement implements the color-coded rules
                             CASE
                                 -- RULE 1: Blue (Not Applicable)
                                 -- Female <25 OR Female >65 OR All Males, Follow-Up Status = TO, DEAD, STOP
                                 WHEN base.sex = 'Male'
                                     OR age < 25
                                     OR age > 65
                                     OR
                                      base.final_follow_up_status IN ('Dead', 'Transferred out', 'Stop all', 'Ran away')
                                     THEN 'Not Applicable (Blue)'

                                 -- RULE 2: Black (ART Not Started)
                                 -- HIV Confirmation Date but no ART START DATE
                                 WHEN base.art_start_date IS NULL
                                     THEN 'ART Not Started (Black)'

                                 -- RULE 3: Red (Confirmed CXCA)
                                 -- Clients with confirmed cancer are excluded from screening eligibility (using the detailed status)
                                 WHEN base.EligibilityStatus = 'Not Eligible Confirmed Cirvical Cancer'
                                     THEN 'Confirmed CXCA (RED)'

                                 -- The remaining rules apply to the active, 25-65 female cohort

                                 -- RULE 4: Green (Previously Screened / Screening Done)
                                 -- Maps to the catch-all status where screening is up-to-date
                                 WHEN base.EligibilityStatus = 'Not Eligible (Screening Up-to-Date)'
                                     THEN 'Previously Screened (Green)'

                                 -- RULE 5: Yellow (Eligible for Screening/RX)
                                 -- Maps to *any* status that requires screening/follow-up action
                                 WHEN base.EligibilityStatus LIKE 'Eligible%'
                                     THEN 'Eligible (Yellow)'

                                 -- RULE 6: White (Not Eligible - Other Reasons)
                                 -- Maps to other "Not Eligible" statuses (e.g., Hysterectomy, etc.)
                                 WHEN base.EligibilityStatus LIKE 'Not Eligible%'
                                     THEN 'Not Eligible (White)'

                                 -- Fallback
                                 ELSE 'Unknown Status'
                                 END AS Cervical_status

                      FROM cxca_eligibility_base_clients AS base),


         asm as (select client_id
                      , assessment_status
                      , dsd_category
                 from dsd_cat
                 union ALL
                 select client_id
                      , ''
                      , 'ART not started'
                 from all_art_not_started_status),

         offer_list as (select client.client_id,
                               client.mrn,
                               client.uan,
                               client.sex,
                               client.patient_uuid,
                               client.patient_name,
                               offer.offered_date,
                               visit_date_ict_offer,
                               priority_criteria,
                               offered,
                               ict_serial_number,
                               offer.yes,
                               offer.no,
                               elicited,
                               high_risk_for_ipv,
                               accepted,
                               accepted_date,
                               linked_to_appropriate_care,
                               specify_other_adverse_event_type,
                               reason_ict_service_not_accepted,
                               adverse_event_type,
                               CASE WHEN all_art_not_started_status.client_id IS NOT NULL THEN 'YES' ELSE 'NO' END AS art_not_started
                        from mamba_flat_encounter_ict_general ict_general
                                 join mamba_flat_encounter_ict_offer offer on ict_general.client_id = offer.client_id
                                 join mamba_dim_client client on ict_general.client_id = client.client_id
                                 join tmp_address on tmp_address.client_id = client.client_id
                        left join all_art_not_started_status on tmp_address.client_id = all_art_not_started_status.client_id
                        where offered_date <= END_DATE),
         offer as (select * from (select *, ROW_NUMBER() over (PARTITION BY client_id ORDER BY offered_date DESC ) as row_num from offer_list) t where row_num = 1)

    select tmp_address.patient_name                                          AS `Patient Name`,
           tmp_address.patient_uuid                                          AS `UUID`,
           tmp_address.mrn,
           CONCAT('''', tmp_address.uan) as uan,
           tmp_address.patientname,
           tmp_address.age,
           tmp_address.sex,
           tmp_address.Adrress,
           tpt.tpt_status,
           cervical.Cervical_status,

           case

               when vl_status_final = 'N/A' THEN 'Not Applicable'
               when eligiblityDate <= COALESCE(END_DATE, CURDATE())
                   THEN 'Eligible for Viral Load'
               when eligiblityDate > COALESCE(END_DATE, CURDATE())
                   THEN 'Viral Load Done (Currently not Eligible)' -- "Viral Load Done"
               when tmp_3.art_start_date is NULL and follow_up_status is null THEN 'Not Started ART'

               Else 'undetermined_VL' end                                    as `Viral Load Eligibility Status`
            ,
           CASE
               WHEN art_not_started = 'YES' THEN 'N/A'
               WHEN offer.offered_date is null and latest_follow_up.final_follow_up_status NOT IN ('Dead', 'Transferred Out')
                   THEN 'Never Screened for ICT'
               WHEN offer.offered_date IS NOT NULL AND
                    DATE_ADD(offer.offered_date, INTERVAL 730 DAY) > COALESCE(END_DATE, CURDATE())
                   THEN 'Screened for ICT Previously (Not Eligible)'
               WHEN offer.offered_date IS NOT NULL AND
                    DATE_ADD(offer.offered_date, INTERVAL 730 DAY) <= COALESCE(END_DATE, CURDATE())
                   THEN 'Currently Eligible for Rescreening'
               WHEN latest_follow_up.final_follow_up_status IN ('Dead', 'Transferred Out')
                   THEN 'Not Applicable' END                                 AS `ICT Eligibility Status`,
           offer.offered_date                                                as `Latest ICT Offer Date GC.`,
           offer.offered_date                                                as `Latest ICT Offer Date EC.`,
           case
               when asm.assessment_status is not null then asm.assessment_status
               Else '' end                                                   as `DSD Assesment Status`
            ,
           case
               when tmp_3.dsd_category is not null then tmp_3.dsd_category
               Else 'Not enrolled to any DSD' end                            as dsd_category
            ,

           CASE tmp_3.follow_up_status
               WHEN 'Alive' THEN 'Alive on ART'
               WHEN 'Restart medication' THEN 'Restart'
               WHEN 'Transferred out' THEN 'TO'
               WHEN 'Stop all' THEN 'Stop'
               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
               WHEN 'Ran away' THEN 'Drop'
               ELSE tmp_3.follow_up_status
               END                                                           as follow_up_status,

           tmp_3.follow_up_date                                              as `Follow Up Date`,
           tmp_3.follow_up_date                                              as `Follow Up Date EC.`,
           tmp_3.art_start_date                                              as `Art Start Date`,
           tmp_3.art_start_date                                              as `Art Start Date EC.`,
           tmp_3.hiv_confirmed_date as `HIV Confirmed Date GC.`,
           tmp_3.hiv_confirmed_date as `HIV Confirmed Date EC.`,
           tmp_3.next_visit_date                                             as `Nex Visit Date`,
           tmp_3.next_visit_date                                             as `Nex Visit Date EC.`,
           timestampdiff(month, tmp_3.art_start_date, tmp_3.next_visit_date) as monthsonART,
           tmp_3.arv_dose                                                    as artdosecode,
           tmp_3.ARVDispendsedDoseCode                                       as regimen,
           tmp_3.weight,
           tmp_3.adherence                                                   AS Adherance,
           tmp_3.nutritional_screening_result                                As NutritionalStatus,
           tmp_3.ns_adult                                                    As Nstatus
    from tmp_address
             left join tpt
                       on tpt.client_id = tmp_address.client_id
             left join vl_eligibility on vl_eligibility.client_id = tmp_address.client_id
             left join asm on asm.client_id = tmp_address.client_id
             left join cervical on cervical.client_id = tmp_address.client_id
             left join tmp_3 on tmp_3.client_id = tmp_address.client_id
             left join offer on offer.client_id = tmp_address.client_id
             left join latest_follow_up on latest_follow_up.client_id = tmp_address.client_id

    where (
        (START_NV_DATE IS NULL OR END_NV_DATE IS NULL)
            OR (tmp_3.next_visit_date BETWEEN START_NV_DATE AND END_NV_DATE)
        )
      AND (
        (TYPE_OF_CLIENT = 'TX_CURR'
            AND tmp_3.follow_up_status IN ('Alive', 'Restart medication')
            AND tmp_3.art_dose_end_date >= END_DATE
            )
            OR TYPE_OF_CLIENT = 'ALL'
        )
    ORDER BY tmp_address.PatientName;

END //
DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_re_test_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_re_test_query;

~
CREATE PROCEDURE sp_fact_line_list_re_test_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH ReTest as (select re_test.encounter_id,
                           re_test.client_id,
                           re_test.date_enrolled_in_care,
                           re_test.date_of_initial_test,
                           re_test.expiration_date,
                           re_test.test_1_expire_date,
                           re_test.test_2_expire_date,
                           re_test.test_3_expire_date,
                           re_test_1.date_of_retesting_for_verification,
                           final_result,
                           action_taken_after_final_test,
                           entry_point,
                           antiretrovirals_started,
                           test_1_result,
                           test_2_result,
                           test_3_result
                    from mamba_flat_encounter_re_test as re_test
                             left join mamba_flat_encounter_re_test_1 as re_test_1
                                       on re_test.encounter_id = re_test_1.encounter_id),
         tmp_re_test as (select *,
                                ROW_NUMBER() over (PARTITION BY client_id ORDER BY date_of_retesting_for_verification DESC , encounter_id DESC) as row_num
                         from ReTest
                         WHERE (date_of_retesting_for_verification BETWEEN REPORT_START_DATE AND REPORT_END_DATE)
                            OR (REPORT_START_DATE IS NULL AND REPORT_END_DATE IS NULL AND
                                date_of_retesting_for_verification <= CURDATE())),
         re_test as (select * from tmp_re_test where row_num = 1)
    select client.patient_name                                                      as `Patient Name`,
           client.patient_uuid                                                      as `UUID`,
           CAST(client.mrn AS CHAR(20)) as mrn,
           CONCAT('''', uan) as uan,
           TIMESTAMPDIFF(YEAR, date_of_birth, COALESCE(REPORT_END_DATE, CURDATE())) as Age,
           sex,
           date_of_initial_test                                                     as `Date initial tested`,
           date_of_retesting_for_verification                                       as `Date retested`,
           final_result                                                             as `Final Result`,
           action_taken_after_final_test                                            as `Action taken`,
           entry_point                                                              as `Entry point`,
           COALESCE(test_3_result, test_2_result, test_1_result)                       `Previous result`,
           date_enrolled_in_care                                                    as `Date Started ART`
    from re_test
             join mamba_dim_client client on re_test.client_id = client.client_id;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_rtt_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_rtt_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_rtt_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             antiretroviral_art_dispensed_dose_i,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             cd4_count,
                             weight_text_,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               cd4_count,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),                         -- Param 1 @start_date
         latest_follow_up_start as (select *
                                    from tmp_latest_follow_up_start
                                    where row_num = 1),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),                                  -- Param 2 @start_date
         interrupted_at_start AS (select latest_follow_up_start.*
                                  from latest_follow_up_start
                                           left join tx_curr_start
                                                     on latest_follow_up_start.client_id = tx_curr_start.client_id
                                  where tx_curr_start.client_id is null
                                    and latest_follow_up_start.follow_up_status != 'Transferred out'),

         -- TX curr
         tmp_latest_follow_up_end AS (SELECT client_id,
                                             follow_up_date,
                                             encounter_id,
                                             follow_up_status,
                                             treatment_end_date,
                                             art_start_date,
                                             cd4_count,
                                             regimen,
                                             weight_text_,
                                             antiretroviral_art_dispensed_dose_i,
                                             adherence,
                                             next_visit_date,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE follow_up_status IS NOT NULL
                                        AND art_start_date IS NOT NULL
                                        AND follow_up_date <= REPORT_END_DATE),                             -- Param 3 @end_date
         -- TX curr
         tmp_restart_follow_up_end AS (SELECT client_id,
                                              follow_up_date                                                                     as restart_follow_up_date,
                                              encounter_id,
                                              follow_up_status                                                                   as restart_status,
                                              treatment_end_date,
                                              art_start_date,
                                              cd4_count                                                                          as restart_cd4_count,
                                              ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                       FROM FollowUp
                                       WHERE follow_up_status IS NOT NULL
                                         AND art_start_date IS NOT NULL
                                         AND follow_up_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE), -- Param 4 and 5 @start_date, @end_date
         tx_curr_end AS (select *
                         from tmp_latest_follow_up_end
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),                                      -- Param 6 @end_date
         restart_follow_up_end as (select tmp_restart_follow_up_end.*
                                   from tmp_restart_follow_up_end
                                            join tx_curr_end
                                                 on tmp_restart_follow_up_end.client_id = tx_curr_end.client_id
                                   where tmp_restart_follow_up_end.row_num = 1),

         tx_rtt as (select tx_curr_end.follow_up_date                                        as latest_follow_up_date,
                           tx_curr_end.encounter_id,
                           CASE tx_curr_end.follow_up_status
                               WHEN 'Alive' THEN 'Alive on ART'
                               WHEN 'Restart medication' THEN 'Restart'
                               WHEN 'Transferred out' THEN 'TO'
                               WHEN 'Stop all' THEN 'Stop'
                               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                               WHEN 'Ran away' THEN 'Drop'
                               END                                                           as latest_follow_up_status,
                           tx_curr_end.treatment_end_date                                    as latest_follow_up_treatment_end_date,
                           tx_curr_end.art_start_date                                        as latest_follow_up_art_start_date,
                           tx_curr_end.cd4_count                                             as latest_follow_up_cd4_count,
                           restart_follow_up_end.restart_cd4_count,

                           CASE restart_follow_up_end.restart_status
                               WHEN 'Alive' THEN 'Alive on ART'
                               WHEN 'Restart medication' THEN 'Restart'
                               WHEN 'Transferred out' THEN 'TO'
                               WHEN 'Stop all' THEN 'Stop'
                               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                               WHEN 'Ran away' THEN 'Drop'
                               END                                                           AS `Restart Status`,
                           restart_follow_up_end.restart_follow_up_date,
                           sex,
                           date_of_birth,
                           mrn,
                           uan,
                           patient_name,
                           patient_uuid,
                           tx_curr_end.regimen,
                           tx_curr_end.weight_text_,
                           tx_curr_end.antiretroviral_art_dispensed_dose_i,
                           tx_curr_end.adherence,
                           tx_curr_end.next_visit_date,
                           (SELECT datim_agegroup
                            from mamba_dim_agegroup
                            where TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) = age) as fine_age_group,   -- Param 7 @end_date
                           (SELECT normal_agegroup
                            from mamba_dim_agegroup
                            where TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) = age) as coarse_age_group, -- Param 8 @end_date
                           interrupted_at_start.follow_up_date                               as interrupted_follow_up_follow_up_date,
                           CASE interrupted_at_start.follow_up_status
                               WHEN 'Alive' THEN 'Alive on ART'
                               WHEN 'Restart medication' THEN 'Restart'
                               WHEN 'Transferred out' THEN 'TO'
                               WHEN 'Stop all' THEN 'Stop'
                               WHEN 'Loss to follow-up (LTFU)' THEN 'Lost'
                               WHEN 'Ran away' THEN 'Drop'
                               END                                                           as interrupted_follow_up_follow_up_status,
                           interrupted_at_start.treatment_end_date                           as interrupted_follow_up_treatment_end_date,
                           CASE
                               WHEN interrupted_at_start.follow_up_status in ('Alive', 'Restart medication')
                                   and interrupted_at_start.treatment_end_date <= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)
                                   THEN -- Param 9 @start_date
                                   TIMESTAMPDIFF(MONTH, interrupted_at_start.treatment_end_date,
                                                 restart_follow_up_end.restart_follow_up_date)
                               ELSE TIMESTAMPDIFF(MONTH, interrupted_at_start.follow_up_date,
                                                  restart_follow_up_end.restart_follow_up_date)
                               END                                                           AS 'interrupted_months'


                    from interrupted_at_start
                             join tx_curr_end
                                  on interrupted_at_start.client_id = tx_curr_end.client_id
                             join mamba_dim_client client on interrupted_at_start.client_id = client.client_id
                             join restart_follow_up_end on tx_curr_end.client_id = restart_follow_up_end.client_id)

    select patient_name                                        as `Patient Name`,
           patient_uuid                                        as `UUID`,
           CAST(mrn AS CHAR(20)) as mrn,
           CONCAT('''', uan) as UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) as Age, -- Param 10 @end_date
           Sex,
           weight_text_                                        as Weight,
           latest_follow_up_art_start_date                     as `ART Start Date`,
           latest_follow_up_art_start_date                     as `ART Start Date EC.`,
           restart_follow_up_date                              as `Date returned to treatment`,
           restart_follow_up_date                              as `Date returned to treatment EC.`,
           interrupted_follow_up_follow_up_status              as `Interrupted Follow-up Status`,
           Regimen,
           antiretroviral_art_dispensed_dose_i                 as `ARV Dose days`,
           adherence                                           as Adherance,
           next_visit_date                                     as `Next Visit Date`,
           next_visit_date                                     as `Last Next Visit Date EC.`,
           latest_follow_up_treatment_end_date                 as `Last TX_Curr Date`,
           latest_follow_up_treatment_end_date                 as `Last TX_Curr Date EC.`,
           latest_follow_up_date                               as `Last Follow-up Date`,
           latest_follow_up_date                               as `Last Follow-up Date EC.`,
           latest_follow_up_status                             as `Last Follow-up Status`,
           interrupted_follow_up_follow_up_date                as `Date excluded from TX_CURR`
    from tx_rtt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tpt_linelist_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tpt_linelist_query;

~
CREATE PROCEDURE sp_fact_line_list_tpt_linelist_query(
    IN REPORT_START_DATE DATE,
    IN REPORT_END_DATE DATE,
    IN REPORT_TYPE VARCHAR(50)
)
BEGIN
    DECLARE treatment_type_condition VARCHAR(200);
    DECLARE tpt_query TEXT;

    IF REPORT_TYPE = 'ALL' THEN
        SET treatment_type_condition =
                ' tmp_tpt.cpt_start_date is not null  or tmp_tpt.fpt_start_date is not null  or tmp_tpt.tpt_start_date is not null';
    ELSEIF REPORT_TYPE = 'CPT' THEN
        SET treatment_type_condition = ' tmp_tpt.cpt_start_date is not null';
    ELSEIF REPORT_TYPE = 'FPT' THEN
        SET treatment_type_condition = ' tmp_tpt.fpt_start_date is not null';
    ELSEIF REPORT_TYPE = 'TPT' THEN
        SET treatment_type_condition = ' tmp_tpt.tpt_start_date is not null';
    END IF;

    SET tpt_query = 'WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             date_of_event                       as hiv_confirmed_date,
                             art_antiretroviral_start_date       as art_start_date,
                             follow_up_date_followup_            as followup_date,
                             weight_text_                        as weight_in_kg,
                             pregnancy_status,
                             regimen,
                             antiretroviral_art_dispensed_dose_i as art_dose_days,
                             follow_up_status,
                             anitiretroviral_adherence_level,
                             next_visit_date,
                             dsd_category,
                             date_started_on_tuberculosis_prophy as tpt_start_date,
                             date_completed_tuberculosis_prophyl as tpt_completed_date,
                             date_discontinued_tuberculosis_prop as tpt_discontinued_date,
                             date_viral_load_results_received    as viral_load_performed_date,
                             viral_load_test_status,
                             treatment_end_date                  as art_end_date,
                             current_who_hiv_stage,
                             cd4_count,
                             cotrimoxazole_prophylaxis_start_dat as cpt_start_date,
                             cotrimoxazole_prophylaxis_stop_date as cpt_stop_date,
                             patient_diagnosed_with_active_tuber as active_tb_dx,
                             diagnosis_date,
                             tuberculosis_drug_treatment_start_d,
                             date_active_tbrx_completed,
                             tb_prophylaxis_type                 AS TB_ProphylaxisType,
                             tb_prophylaxis_type_alternate_      AS TB_ProphylaxisTypeALT,
                             tpt_followup_6h_                       tpt_follow_up_inh,
                             why_eligible_reason_,
                             tb_diagnostic_test_result              tb_specimen_type,
                             fluconazole_start_date              AS fpt_start_date,
                             fluconazole_stop_date               as fpt_stop_date,
                             transfer_in
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),

         tmp_tpt_start as (select encounter_id,
                                  client_id,
                                  tpt_start_date,
                                  ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.tpt_start_date DESC , FollowUp.encounter_id DESC ) AS row_num
                           from FollowUp
                           where tpt_start_date between ? and ?
                            ),
         tmp_tpt_completed as (select encounter_id,
                                      client_id,
                                      tpt_completed_date,
                                      ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.tpt_completed_date DESC , FollowUp.encounter_id DESC ) AS row_num
                               from FollowUp
                               where tpt_completed_date is not null
                            ),
         -- CPT
         tmp_cpt_start as (select encounter_id,
                                  client_id,
                                  cpt_start_date,
                                  ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.cpt_start_date DESC , FollowUp.encounter_id DESC ) AS row_num
                           from FollowUp
                           where cpt_start_date between ? and ?
                             ),
         tmp_cpt_completed as (select encounter_id,
                                      client_id,
                                      cpt_stop_date,
                                      ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.cpt_stop_date DESC , FollowUp.encounter_id DESC ) AS row_num
                               from FollowUp
                               where cpt_stop_date is not null
                             ),

         -- FPT
         tmp_fpt_start as (select encounter_id,
                                  client_id,
                                  fpt_start_date,
                                  ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.fpt_start_date DESC , FollowUp.encounter_id DESC ) AS row_num
                           from FollowUp
                           where fpt_start_date between ? and ?
                             ),
         tmp_fpt_completed as (select encounter_id,
                                      client_id,
                                      fpt_stop_date,
                                      ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.fpt_stop_date DESC , FollowUp.encounter_id DESC ) AS row_num
                               from FollowUp
                               where fpt_stop_date is not null
                               ),


         tmp_latest_follow_up as (SELECT encounter_id,
                                         client_id,
                                         followup_date                                                                                                         AS FollowupDate,
                                         ROW_NUMBER() OVER (PARTITION BY FollowUp.client_id ORDER BY FollowUp.followup_date DESC, FollowUp.encounter_id DESC ) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    and hiv_confirmed_date is not null
                                    AND followup_date <= ?),
         tpt_start as (select * from tmp_tpt_start where row_num = 1),
         tpt_completed as (select * from tmp_tpt_completed where row_num = 1),
         fpt_start as (select * from tmp_fpt_start where row_num = 1),
         fpt_completed as (select * from tmp_fpt_completed where row_num = 1),
         cpt_start as (select * from tmp_cpt_start where row_num = 1),
         cpt_completed as (select * from tmp_cpt_completed where row_num = 1),


         latest_follow_up as (select * from tmp_latest_follow_up where row_num = 1),
         tmp_tpt as (SELECT f_case.encounter_id,
                            f_case.client_id,
                            f_case.weight_in_kg,
                            f_case.hiv_confirmed_date,
                            f_case.art_start_date,
                            f_case.followup_date,
                            f_case.why_eligible_reason_,
                            art_dose_days                       as artdosecode,
                            f_case.next_visit_date,
                            CASE f_case.follow_up_status
                               WHEN ''Alive'' THEN ''Alive on ART''
                               WHEN ''Restart medication'' THEN ''Restart''
                               WHEN ''Transferred out'' THEN ''TO''
                               WHEN ''Stop all'' THEN ''Stop''
                               WHEN ''Loss to follow-up (LTFU)'' THEN ''Lost''
                               WHEN ''Ran away'' THEN ''Drop''
                               END as follow_up_status,
                            f_case.art_end_date,
                            f_case.current_who_hiv_stage        AS WHOStage,
                            cd4_count                              AdultCD4Count,
                            cd4_count                              ChildCD4Count,
                            tb_specimen_type                    AS TB_SpecimenType,
                            active_tb_dx                        As ActiveTBDiagnosed,
                            diagnosis_date                      As ActiveTBDignosedDate,
                            tuberculosis_drug_treatment_start_d As TBTx_StartDate,
                            date_active_tbrx_completed          As TBTx_CompletedDate,
                            tpt_start.tpt_start_date,
                            tpt_completed.tpt_completed_date,
                            fpt_start.fpt_start_date,
                            fpt_completed.fpt_stop_date,
                            cpt_start.cpt_start_date,
                            cpt_completed.cpt_stop_date
                     FROM latest_follow_up
                              INNER JOIN FollowUp f_case ON f_case.encounter_id = latest_follow_up.encounter_id
                              Left join tpt_start on latest_follow_up.client_id = tpt_start.client_id
                              Left join tpt_completed on latest_follow_up.client_id = tpt_completed.client_id
                              Left join cpt_start on latest_follow_up.client_id = cpt_start.client_id
                              Left join cpt_completed on latest_follow_up.client_id = cpt_completed.client_id
                              Left join fpt_start on latest_follow_up.client_id = fpt_start.client_id
                              Left join fpt_completed on latest_follow_up.client_id = fpt_completed.client_id)

    select patient_name                                        as `Patient Name`,
           patient_uuid                                        as `UUID`,
           sex                                                 as Sex,
           tmp_tpt.weight_in_kg                                as Weight,
           CAST(mrn AS CHAR(20)) as mrn,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as Age,
           tmp_tpt.tpt_start_date                            as `TPT Start Date`,
           tmp_tpt.tpt_start_date                            as `TPT Start Date EC.`,
           tmp_tpt.tpt_completed_date                    as `TPT Completed Date`,
           tmp_tpt.tpt_completed_date                    as `TPT Completed Date EC.`,
           TIMESTAMPDIFF(YEAR, tmp_tpt.tpt_start_date, tmp_tpt.tpt_completed_date) as `Days Difference`,
           FollowUp.TB_ProphylaxisType                         as `TPT Type`,
           FollowUp.TB_ProphylaxisTypeALT                      as `TPT Type ALT`,
           tmp_tpt.hiv_confirmed_date                          as `Hiv Confirmed Date`,
           tmp_tpt.hiv_confirmed_date                          as `Hiv Confirmed Date EC.`,
           tmp_tpt.art_start_date                              as `Art Start Date`,
           tmp_tpt.art_start_date                              as `Art Start Date EC.`,
           tmp_tpt.followup_date                               as `Follow Up Date`,
           tmp_tpt.followup_date                               as `Follow Up Date EC.`,
           Transfer_In,
           tmp_tpt.artdosecode                                 as ARTDoseDays,
           tmp_tpt.next_visit_date                             as `Next visit Date`,
           tmp_tpt.next_visit_date                             as `Next visit Date EC.`,
           tmp_tpt.follow_up_status                            as `Follow Up Status`,
           tmp_tpt.art_end_date                                as `ART Dose End Date`,
           tmp_tpt.art_end_date                                as `ART Dose End Date EC.`,
           tmp_tpt.WHOStage                                    as WHOStage,
           AdultCD4Count                                       as `Adult CD4 Count`,
           ChildCD4Count                                       as `Child CD4 Count`,
           tmp_tpt.cpt_start_date                              as `CPT Start Date`,
           tmp_tpt.cpt_start_date                              as `CPT Start Date EC.`,
           tmp_tpt.cpt_stop_date                               as CPT_StopDate,
           tmp_tpt.cpt_stop_date                               as `CPT_StopDate EC.`,
           TB_SpecimenType,
           ActiveTBDiagnosed,
           ActiveTBDignosedDate                                as `Active TB Dignosed Date`,
           ActiveTBDignosedDate                                as `Active TB Dignosed Date EC.`,
           TBTx_StartDate                                      as `TBT Start Date`,
           TBTx_StartDate                                      as `TBT Start Date EC.`,
           TBTx_CompletedDate                                  as `TBT Completed Date`,
           TBTx_CompletedDate                                  as `TBT Completed Date EC.`,
           tmp_tpt.fpt_start_date                              as `Fluconazole Start Date`,
           tmp_tpt.fpt_start_date                              as `Fluconazole Start Date EC.`,
           tmp_tpt.fpt_stop_date                               as `Fluconazole End Date`,
           tmp_tpt.fpt_stop_date                               as `Fluconazole End Date EC.`

    FROM FollowUp
             join tmp_tpt on tmp_tpt.encounter_id = FollowUp.encounter_id
             join mamba_dim_client client on tmp_tpt.client_id = client.client_id where ';

    SET @sql = CONCAT(tpt_query, treatment_type_condition);
    PREPARE stmt FROM @sql;
    SET @start_date = REPORT_START_DATE;
    SET @end_date = REPORT_END_DATE;
    EXECUTE stmt USING  @start_date, @end_date, @start_date, @end_date, @start_date, @end_date, @end_date, @end_date;
    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_curr_analysis_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_curr_analysis_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_curr_analysis_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE,
                                                          IN REPORT_TYPE VARCHAR(50))
BEGIN

    DECLARE tx_curr_base_query TEXT;
    DECLARE final_select_query TEXT;
    DECLARE filter_condition TEXT;
    DECLARE columns_list TEXT;
    SET session group_concat_max_len = 20000;

    -- Determine the WHERE clause filter condition based on REPORT_TYPE.
-- The conditions directly use columns from the f_result CTE instead of relying on a pre-calculated 'factor'.
    IF REPORT_TYPE = 'TX_CURR_THIS_MONTH' THEN
        -- Corresponds to factors: 'NEWLY STARTED', 'RESTART', 'TI', 'TRACED BACK' , 'STILL ON CARE'
        SET filter_condition =
                ' factor in (''NEWLY STARTED'', ''STILL ON CARE'', ''RESTART'',''TO/TI'' ,''TI'', ''TRACED BACK'')';
        SET columns_list = 'patient_name as `Patient Name`, MRN , UAN , TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age, age_out as `Age Out`,
       sex, regimen , follow_up_status_curr as `follow up status` , art_start_date_curr as `art start date`, art_start_date_curr as `art start date EC.` , adherence ,
       CASE WHEN in_prev_period THEN ''Counted'' ELSE '''' END   AS `Previous status`, pregnancy_status as `Pregnancy status`,
       nutritional_status_of_adult as `Nutritional status`, FollowUpDate_curr as `Follow up date`, FollowUpDate_curr as `Follow up date EC.`, next_visit_date as `Appointment date`, next_visit_date as `Appointment date EC.`,
       dsd_category as `Dsd category`';
    ELSEIF REPORT_TYPE = 'TX_CURR_LAST_MONTH' THEN
        -- Clients who were in TX_CURR in the previous reporting period.
        SET filter_condition = ' in_prev_period = 1';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           age_out as `Age Out`,
           sex,
           regimen,
           follow_up_status_prev                                 as `follow up status`,
           art_start_date_prev                                   as `art start date`,
           art_start_date_prev                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_prev                                     as `Follow up date`,
           FollowUpDate_prev                                     as `Follow up date EC.`,
           next_visit_date                                       as `Appointment date`,
           next_visit_date                                       as `Appointment date EC.` ';
    ELSEIF REPORT_TYPE = 'TX_CURR_NEWLY_INCLUDED' THEN
        -- Corresponds to factors: 'NEWLY STARTED', 'RESTART', 'TI', 'TRACED BACK' , 'TO/TI'
        SET filter_condition = ' factor in (''TRACED BACK'', ''RESTART'', ''TI'', ''TO/TI'', ''NEWLY STARTED'')';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           age_out as `Age Out`,
           sex,
           regimen,
           follow_up_status_curr                                 as `follow up status`,
           art_start_date_curr                                   as `art start date`,
           art_start_date_curr                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_curr                                     as `Follow up date`,
           FollowUpDate_curr                                     as `Follow up date EC.`,
           next_visit_date                                       as `Appointment date`,
           next_visit_date                                       as `Appointment date EC.`,
           factor as `Added status` ';
    ELSEIF REPORT_TYPE = 'TX_CURR_EXCLUDED_THIS_MONTH' THEN
        -- Corresponds to factors: 'TO', 'DEAD', 'LOST', 'DROP', 'STOP', 'NOT UPDATED'
        SET filter_condition = ' factor in (''Transferred out'', ''Dead'', ''Loss to follow-up (LTFU)'', ''Ran away'', ''Stop all'', ''NOT UPDATED'')';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           age_out as `Age Out`,
           sex,
           regimen,
           follow_up_status_curr                                 as `follow up status`,
           art_start_date_curr                                   as `art start date`,
           art_start_date_curr                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_curr                                     as `Follow up date`,
           FollowUpDate_curr                                     as `Follow up date EC.`,
           next_visit_date                                       as `Appointment date`,
           next_visit_date                                       as `Appointment date EC.`,
           factor as `Deduct follow up status` ';
    ELSEIF REPORT_TYPE = 'OTHER_OUTCOME' THEN
        -- Corresponds to factors: 'TO', 'DEAD', 'LOST', 'DROP', 'STOP'
        SET filter_condition = ' in_prev_period = 1 AND factor in (''Transferred out'', ''Dead'', ''Loss to follow-up (LTFU)'', ''Ran away'', ''Stop all'')';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           age_out as `Age Out`,
           sex,
           regimen,
           follow_up_status_curr                                 as `follow up status`,
           art_start_date_curr                                   as `art start date`,
           art_start_date_curr                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_curr                                     as `Follow up date`,
           FollowUpDate_curr                                     as `Follow up date EC.`,
           next_visit_date_prev                                       as `Appointment date`,
           next_visit_date_prev                                       as `Appointment date EC.` ';
    ELSEIF REPORT_TYPE = 'NOT_UPDATED' THEN
        -- Corresponds to factor: 'NOT UPDATED'
        SET filter_condition = ' factor in (''NOT UPDATED'') ';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           age_out as `Age Out`,
           sex,
           regimen,
           follow_up_status_curr                                 as `follow up status`,
           art_start_date_curr                                   as `art start date`,
           art_start_date_curr                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_curr                                     as `Follow up date`,
           FollowUpDate_curr                                     as `Follow up date EC.`,
           next_visit_date                                       as `Appointment date`,
           next_visit_date                                       as `Appointment date EC.` ';
    ELSEIF REPORT_TYPE = 'SUMMARY' THEN
        SET columns_list = ' ''Previous Month Tx_Current'' as `Label`,COUNT(*) as `Count` from tx_curr_analysis where in_prev_period=1
            UNION ALL
            select ''TO(-)'',COUNT(*) from tx_curr_analysis where factor in (''Transferred out'')
            UNION ALL
            select ''LOST(-)'',COUNT(*) from tx_curr_analysis where factor = (''Loss to follow-up (LTFU)'')
            UNION ALL
            select ''DROP(-)'',COUNT(*) from tx_curr_analysis where factor = (''Ran away'')
            UNION ALL
            select ''DEAD(-)'',COUNT(*) from tx_curr_analysis where factor = (''Dead'')
            UNION ALL
            select ''STOP(-)'',COUNT(*) from tx_curr_analysis where factor = (''Stop all'')
            UNION ALL
            select ''NOT UPDATED(-)'',COUNT(*) from tx_curr_analysis where factor = (''NOT UPDATED'')
            UNION ALL
            select ''TRACED BACK(+)'',COUNT(*) from tx_curr_analysis where factor = (''TRACED BACK'')
            UNION ALL
            select ''TO/TI(+)'',COUNT(*) from tx_curr_analysis where factor = (''TO/TI'')
            UNION ALL
            select ''RESTART(+)'',COUNT(*) from tx_curr_analysis where factor = (''RESTART'')
            UNION ALL
            select ''TI(+)'',COUNT(*) from tx_curr_analysis where factor = (''TI'')
            UNION ALL
            select ''NEWLY INITIATED(+)'',COUNT(*) from tx_curr_analysis where factor = (''NEWLY STARTED'')
            UNION ALL
            select ''Current Month Tx_Current'',COUNT(*) from tx_curr_analysis where factor in (''NEWLY STARTED'', ''STILL ON CARE'', ''RESTART'', ''TI'', ''TRACED BACK'',''TO/TI'')
            UNION ALL
            select ''Tx_Current net current increment'', (SELECT COUNT(*) FROM tx_curr_analysis WHERE factor IN (''NEWLY STARTED'', ''STILL ON CARE'', ''RESTART'', ''TI'', ''TRACED BACK'',''TO/TI'')) -
                (SELECT COUNT(*) FROM tx_curr_analysis WHERE in_prev_period = 1) ';
    ELSEIF REPORT_TYPE = 'ON_DSD' THEN
        SET filter_condition = ' dsd_category is not null ';
        SET columns_list = ' patient_name as `Patient Name`,
           patient_uuid                             as `UUID`,
           MRN,
           UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
           sex,
           regimen,
           follow_up_status_curr                                 as `follow up status`,
           art_start_date_curr                                   as `art start date`,
           art_start_date_curr                                   as `art start date EC.`,
           adherence,
           visit_type `schedule type`,
           FollowUpDate_curr                                     as `Follow up date`,
           FollowUpDate_curr                                     as `Follow up date EC.`,
           next_visit_date                                       as `Appointment date`,
           next_visit_date                                       as `Appointment date EC.`,
           assessment_date as `enrollment date`,
           assessment_date as `enrollment date EC.`,
           dsd_category as `latest DSD category` ';
    ELSE
        SET filter_condition = ' 1 = 1';
        SET columns_list = '   patient_name as `Patient Name`,
                               patient_uuid                             as `UUID`,
                               MRN,
                               UAN,
                               TIMESTAMPDIFF(YEAR, date_of_birth, ?) as age,
                               sex,
                               FollowUpDate_curr,
                               art_dose_End_curr,
                               follow_up_status_curr,
                               art_start_date_curr,
                               TIStatus_curr,
                               in_prev_period,
                               FollowUpDate_prev,
                               art_dose_End_prev,
                               follow_up_status_prev,
                               in_prev_period,
                               factor ';
    END IF;

    SET tx_curr_base_query = '
        with followup as
         (select follow_up.encounter_id,
                 follow_up_date_followup_ as follow_up_date,
                 follow_up.client_id,
                 follow_up_status,
                 art_antiretroviral_start_date,
                 treatment_end_date,
                 regimen,
                 adherence,
                 next_visit_date,
                 dsd_category,
                 assessment_date,
                 pregnancy_status,
                 nutritional_status_of_adult,
                 cd4_count,
                 visit_type
          FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
     tmp_latest_follow_up as
         (select client_id,
                 encounter_id,
                 follow_up_date,
                 treatment_end_date,
                 follow_up_status,
                 art_antiretroviral_start_date,
                 regimen,
                 adherence,
                 pregnancy_status,
                 nutritional_status_of_adult,
                 next_visit_date,
                 dsd_category,
                 assessment_date,
                 cd4_count,
                 visit_type,
                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC,encounter_id DESC ) AS row_num
          from followup
          where follow_up_date <= ?),                                -- param 1: @end_date
     -- Latest follow up before reporting period
     latest_follow_up as
         (select *,
                 fn_get_ti_status(client_id, ?, ?) AS TIStatus -- param 2: @start_date, param 3: @end_date
          from tmp_latest_follow_up
          where row_num = 1
            and (art_antiretroviral_start_date is not null and
                 art_antiretroviral_start_date <= ?)),               -- param 4: @end_date
     -- Latest curr follow up
     latest_curr_follow_up as (select *
                               from latest_follow_up
                               where follow_up_status in (''Alive'', ''Restart medication'')
                                 and treatment_end_date >= ? -- param 5: @end_date
     ),
     -- Previous follow up before reporting period
     tmp_previous_follow_up as
         (select client_id,
                 encounter_id,
                 follow_up_date,
                 treatment_end_date,
                 follow_up_status,
                 art_antiretroviral_start_date,
                 regimen,
                 adherence,
                 pregnancy_status,
                 nutritional_status_of_adult,
                 next_visit_date,
                 dsd_category,
                 assessment_date,
                 cd4_count,
                 visit_type,
                 ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC,encounter_id DESC ) AS row_num
          from followup
          where follow_up_date <= DATE_ADD(?, INTERVAL -1 DAY) -- param 6: @start_date
            AND follow_up_status IS NOT NULL
            and art_antiretroviral_start_date is not null),
     previous_follow_up as ( select * from tmp_previous_follow_up where row_num=1),
     -- Previous curr follow up before reporting period
     previous_curr_follow_up as
         (select *
          from tmp_previous_follow_up
          where row_num = 1
            and follow_up_status in (''Alive'', ''Restart medication'')
            and art_antiretroviral_start_date <= DATE_ADD(?, INTERVAL -1 DAY) -- param 7: @start_date
            and treatment_end_date >= DATE_ADD(?, INTERVAL -1 DAY)), -- param 8: @start_date
     tx_curr_factor as (select latest_all.client_id,
                               latest_curr.client_id as curr_client,
                               latest_all.follow_up_date                   as FollowUpDate_curr,
                               latest_all.treatment_end_date               as art_dose_End_curr,
                                CASE latest_all.follow_up_status
                               WHEN ''Alive'' THEN ''Alive on ART''
                               WHEN ''Restart medication'' THEN ''Restart''
                               WHEN ''Transferred out'' THEN ''TO''
                               WHEN ''Stop all'' THEN ''Stop''
                               WHEN ''Loss to follow-up (LTFU)'' THEN ''Lost''
                               WHEN ''Ran away'' THEN ''Drop''
                               END                as follow_up_status_curr,
                               latest_all.art_antiretroviral_start_date    as art_start_date_curr,
                               latest_all.TIStatus                         as TIStatus_curr,
                               previous_curr.client_id is not null         as in_prev_period,
                               previous_curr.follow_up_date                as FollowUpDate_prev,
                               previous_curr.treatment_end_date            as art_dose_End_prev,
                               CASE previous_curr.follow_up_status
                               WHEN ''Alive'' THEN ''Alive on ART''
                               WHEN ''Restart medication'' THEN ''Restart''
                               WHEN ''Transferred out'' THEN ''TO''
                               WHEN ''Stop all'' THEN ''Stop''
                               WHEN ''Loss to follow-up (LTFU)'' THEN ''Lost''
                               WHEN ''Ran away'' THEN ''Drop''
                               END             as follow_up_status_prev,
                               previous_curr.next_visit_date               as next_visit_date_prev,
                               previous_curr.art_antiretroviral_start_date as art_start_date_prev,
                               latest_all.regimen,
                               latest_all.adherence,
                               latest_all.pregnancy_status,
                               latest_all.nutritional_status_of_adult,
                               latest_all.next_visit_date,
                               latest_curr.dsd_category,
                               latest_all.assessment_date,
                               latest_all.cd4_count,
                               latest_all.visit_type,
                               case
                                   when
                                       latest_curr.client_id is not null
                                           and
                                       latest_curr.art_antiretroviral_start_date between ? and ? -- param 9: @start_date, param 10: @end_date
                                           and latest_curr.TIStatus = ''NTI''
                                           and latest_curr.follow_up_status in (''Alive'', ''Restart medication'')
                                       then ''NEWLY STARTED''
                                   when
                                       latest_curr.client_id is not null
                                           and latest_curr.follow_up_status in (''Alive'', ''Restart medication'')
                                           and previous_curr.client_id is not null -- also in prev curr
                                       then ''STILL ON CARE''

                                   when latest_curr.client_id is not null
                                       and latest_all.follow_up_status = ''Restart medication''
                                       and previous_curr.client_id is null -- not in prev
                                       then ''RESTART''
                                   when latest_curr.client_id is not null
                                       and latest_curr.follow_up_status in (''Alive'', ''Restart medication'')
                                       and latest_curr.TIStatus = ''TI'' then ''TI''

                                   when latest_curr.client_id is not null
                                       and latest_curr.follow_up_status in (''Alive'', ''Restart medication'')
                                       and previous_all.follow_up_status = ''Transferred out''
                                       then ''TO/TI'' -- TI in curr

                                   when latest_curr.client_id is not null
                                       and latest_curr.follow_up_status in (''Alive'', ''Restart medication'')
                                       then ''TRACED BACK''
-- subtract factor--
                                   when
                                       previous_curr.client_id is not null
                                           and latest_all.treatment_end_date <
                                               ? -- param 11: @end_date
                                           and latest_all.follow_up_status in (''Alive'', ''Restart medication'')
                                       then ''NOT UPDATED''
                                   when previous_curr.client_id is not null then latest_all.follow_up_status
                                   end                                     as factor
                        from latest_follow_up latest_all
                                 left join previous_curr_follow_up previous_curr
                                           on latest_all.client_id = previous_curr.client_id
                                 left join latest_curr_follow_up latest_curr
                                           on latest_all.client_id = latest_curr.client_id
                                 left join previous_follow_up previous_all
                                           on latest_all.client_id = previous_all.client_id
                        ),
     tx_curr_analysis as (select CAST(dim_client.mrn AS CHAR(20)) as MRN,
                                 dim_client.uan as UAN,
                                 dim_client.patient_name,
                                 dim_client.date_of_birth,
                                 patient_uuid,
                                 dim_client.sex,
                                 CASE WHEN (TIMESTAMPDIFF(YEAR, date_of_birth, art_start_date_curr) <= 15) AND
                                           TIMESTAMPDIFF(YEAR, date_of_birth, COALESCE(?,CURDATE())) >= 15 AND
                                           DATE_ADD(date_of_birth, INTERVAL 15 YEAR) BETWEEN ? AND ? THEN ''YES''
                                      ELSE ''NO'' END AS age_out,
                                 r.*
                          from tx_curr_factor r
                                   inner join mamba_dim_client dim_client on r.client_id = dim_client.client_id
                          where r.factor is not null
                          ) ';

    IF REPORT_TYPE = 'SUMMARY' THEN
        SET final_select_query = CONCAT(' SELECT ',
                                        columns_list);
    ELSE
        SET final_select_query = CONCAT(' SELECT ',
                                        columns_list,
                                        ' FROM tx_curr_analysis WHERE ', filter_condition);
    END IF;


    SET @sql = CONCAT(tx_curr_base_query, final_select_query);

    PREPARE stmt FROM @sql;
    SET @end_date = REPORT_END_DATE;
    SET @start_date = REPORT_START_DATE;
    IF REPORT_TYPE = 'SUMMARY' THEN
        EXECUTE stmt USING @end_date, @start_date, @end_date, @end_date, @end_date, @start_date, @start_date, @start_date, @start_date, @end_date, @end_date, @end_date, @start_date, @end_date;
    ELSE
        EXECUTE stmt USING @end_date, @start_date, @end_date, @end_date, @end_date, @start_date, @start_date, @start_date, @start_date, @end_date, @end_date, @end_date, @start_date, @end_date, @end_date;
    END IF;

    DEALLOCATE PREPARE stmt;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_curr_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_curr_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_curr_query(IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id                 AS PatientId,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             assessment_date,
                             treatment_end_date,
                             antiretroviral_art_dispensed_dose_i AS ARTDoseDays,
                             weight_text_                        AS Weight,
                             screening_test_result_tuberculosis  AS TB_SreeningResult,
                             date_of_last_menstrual_period_lmp_     LMP_Date,
                             anitiretroviral_adherence_level     AS AdherenceLevel,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             diagnosis_date                      AS ActiveTBDiagnoseddate,
                             nutritional_status_of_adult,
                             nutritional_supplements_provided,
                             stages_of_disclosure,
                             date_started_on_tuberculosis_prophy,
                             method_of_family_planning,
                             patient_diagnosed_with_active_tuber as ActiveTBDiagnosed,
                             dsd_category,
                             nutritional_screening_result,
                             cd4_count,
                             date_of_event                       as hiv_confirmed_date,
                             date_started_on_tuberculosis_prophy AS inhprophylaxis_started_date,
                             date_completed_tuberculosis_prophyl AS InhprophylaxisCompletedDate,
                             date_active_tbrx_completed,
                             date_of_reported_hiv_viral_load     as viral_load_sent_date,
                             date_viral_load_results_received    AS viral_load_perform_date,
                             viral_load_test_status,
                             CASE visitect_cd4_result WHEN 'VISITECT <=200 copies/ml' THEN 'VISITECT >200 copies/ml' ELSE visitect_cd4_result END AS visitect_cd4_result,
                             visitect_cd4_test_date
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         -- TX curr
         tx_curr_all AS (SELECT PatientId,
                                follow_up_date                                                                            ,
                                encounter_id,
                                follow_up_status,
                                treatment_end_date,
                                art_start_date,
                                Weight,
                                cd4_count,
                                hiv_confirmed_date,
                                regimen,
                                ARTDoseDays,
                                AdherenceLevel,
                                nutritional_screening_result,
                                nutritional_supplements_provided,
                                nutritional_status_of_adult,
                                method_of_family_planning,
                                pregnancy_status,
                                breast_feeding_status,
                                date_active_tbrx_completed,
                                next_visit_date,
                                TB_SreeningResult,
                                dsd_category,
                                visitect_cd4_test_date,
                                ROW_NUMBER() OVER (PARTITION BY PatientId ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                         FROM FollowUp
                         WHERE follow_up_status IS NOT NULL
                           AND art_start_date IS NOT NULL
                           AND follow_up_date <= COALESCE(REPORT_END_DATE,CURDATE())),

         tx_curr AS (select *
                     from tx_curr_all
                     where row_num = 1
                       AND follow_up_status in ('Alive', 'Restart medication')
                       AND treatment_end_date >= COALESCE(REPORT_END_DATE,CURDATE())),
         latestDSD_tmp AS (SELECT FollowUp.PatientId,
                                  assessment_date                                                                              AS latestDsdDate,
                                  FollowUp.encounter_id,
                                  FollowUp.dsd_category,
                                  ROW_NUMBER() OVER (PARTITION BY FollowUp.PatientId ORDER BY assessment_date DESC, FollowUp.follow_up_date desc , FollowUp.encounter_id DESC ) AS row_num
                           FROM FollowUp
                           join tx_curr_all on FollowUp.encounter_id=tx_curr_all.encounter_id
                           WHERE assessment_date IS NOT NULL
                             AND assessment_date <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_tpt_start as (select encounter_id,
                                  PatientId,
                                  inhprophylaxis_started_date                                                                                                          as inhprophylaxis_started_date,
                                  ROW_NUMBER() OVER (PARTITION BY FollowUp.PatientId ORDER BY FollowUp.inhprophylaxis_started_date DESC , FollowUp.encounter_id DESC ) AS row_num
                           from FollowUp
                           where inhprophylaxis_started_date is not null
                             and FollowUp.inhprophylaxis_started_date <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_tpt_completed as (select encounter_id,
                                      PatientId,
                                      InhprophylaxisCompletedDate                                                                                                          as InhprophylaxisCompletedDate,
                                      ROW_NUMBER() OVER (PARTITION BY FollowUp.PatientId ORDER BY FollowUp.InhprophylaxisCompletedDate DESC , FollowUp.encounter_id DESC ) AS row_num
                               from FollowUp
                               where InhprophylaxisCompletedDate is not null
                                 and FollowUp.InhprophylaxisCompletedDate <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_sent_date as (SELECT PatientId,
                                     encounter_id,
                                     viral_load_sent_date                                                                             as VL_Sent_Date,
                                     ROW_NUMBER() over (PARTITION BY PatientId ORDER BY viral_load_sent_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE viral_load_sent_date <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_vl_performed_date as (SELECT PatientId,
                                          encounter_id,
                                          viral_load_perform_date,
                                          viral_load_test_status,
                                          ROW_NUMBER() over (PARTITION BY PatientId ORDER BY viral_load_perform_date DESC, encounter_id DESC) AS row_num
                                   FROM FollowUp
                                   WHERE viral_load_perform_date <= COALESCE(REPORT_END_DATE,CURDATE())),
         tmp_visitect_cd4_result as (SELECT PatientId,
                                          encounter_id,
                                          visitect_cd4_result,
                                          ROW_NUMBER() over (PARTITION BY PatientId ORDER BY visitect_cd4_test_date DESC, encounter_id DESC) AS row_num
                                   FROM FollowUp
                                   WHERE visitect_cd4_test_date is not null and visitect_cd4_test_date <= follow_up_date),
         vl_sent_date as (select * from tmp_vl_sent_date where row_num = 1),
         latestDSD AS (select * from latestDSD_tmp where row_num = 1),
         tpt_start as (select * from tmp_tpt_start where row_num = 1),
         tpt_completed as (select * from tmp_tpt_completed where row_num = 1),
         vl_performed_date as (select * from tmp_vl_performed_date where row_num = 1),
         visitect_cd4_result as ( select * from tmp_visitect_cd4_result where row_num=1)
    select client.patient_name                                                        as 'Patient Name',
           patient_uuid                             as `UUID`,
           CAST(mrn AS CHAR(20)) as mrn,
           CONCAT('''', uan) UAN,
           TIMESTAMPDIFF(YEAR, date_of_birth, art_start_date)                         as 'Age at Enrollment',
           TIMESTAMPDIFF(YEAR, date_of_birth, COALESCE(REPORT_END_DATE,CURDATE()))                        as 'Current Age',
           Sex,
           Weight,
           cd4_count                                                                  as CD4,
           visitect_cd4_result                                                        as `Visit ECT CD4 Result`,
           visitect_cd4_test_date as `Visit ECT CD4 Test Date`,
           visitect_cd4_test_date as `Visit ECT CD4 Test Date EC.`,
           hiv_confirmed_date            as 'HIV Confirmed Date',
           hiv_confirmed_date            as 'HIV Confirmed Date EC.',
           art_start_date                as 'ART Start Date',
           art_start_date                as 'ART Start Date EC.',
           CASE WHEN TB_SreeningResult = 'Negative result' THEN 'Negative' ELSE  TB_SreeningResult END           as 'TB Screening Result',
           follow_up_date                as 'Follow-up Date',
           follow_up_date                as 'Follow-up Date EC.',
           CASE WHEN tx_curr.follow_up_status = 'Restart medication'     THEN 'Restart'
               ELSE tx_curr.follow_up_status
               END       as 'Follow-up Status',
           Regimen,
           ARTDoseDays                                                                as 'ARV Dose Days',
           AdherenceLevel                                                             as Adherence,
           tx_curr.dsd_category                                                     as 'DSD Category',
           CASE WHEN nutritional_status_of_adult = 'Malnutrition of mild degree (Gomez: 75% to Less than 90% of Standard Weight)'    THEN 'Mild Malnutrition'
                WHEN nutritional_status_of_adult = 'Malnutrition of moderate degree (Gomez: 60% to Less than 75% of Standard Weight)'    THEN 'Moderate Malnutrition'
                WHEN nutritional_status_of_adult = 'Severe protein-calorie malnutrition (Gomez: Less than 60% of Standard Weight)'    THEN 'Severe Malnutrition'
                WHEN nutritional_status_of_adult = 'Obese Abdomen' OR nutritional_status_of_adult= 'Overweight'    THEN 'Overweight'
                ELSE nutritional_status_of_adult
              END as 'Nutritional Status',
           nutritional_screening_result                                               as 'Nutritional Screening Result',
           nutritional_supplements_provided                                           as 'Therapeutic/ Supplementary Food',
           CASE WHEN method_of_family_planning = 'Vasectomy'
               THEN 'Vasectomy/tubal ligation'
               ELSE method_of_family_planning
               END as 'Familiy Planning Method',
           pregnancy_status                                                           as 'Pregnant?',
           breast_feeding_status                                                      as 'Breastfeeding?',
           IF(breast_feeding_status = 'Yes' or pregnancy_status = 'Yes', 'Yes', 'No') as 'On PMTCT?',
           tpt_start.inhprophylaxis_started_date                                      as 'TPT Start Date',
           tpt_start.inhprophylaxis_started_date                                      as 'TPT Start Date EC.',
           tpt_completed.InhprophylaxisCompletedDate                                  as 'TPT Completed Date',
           tpt_completed.InhprophylaxisCompletedDate                                  as 'TPT Completed Date EC.',
           date_active_tbrx_completed                                                 as 'TB Treatment Completed Date',
           date_active_tbrx_completed                                                 as 'TB Treatment Completed Date EC.',
           vl_sent_date.VL_Sent_Date                                                  as 'VL Sent Date',
           vl_sent_date.VL_Sent_Date                                                  as 'VL Sent Date EC.',
           vl_performed_date.viral_load_test_status                                   as 'VL Status',
           next_visit_date                                                               'Next Visit Date',
           next_visit_date                                                               'Next Visit Date EC.',
           tx_curr.treatment_end_date                                                    'Last TX_Curr Date',
           tx_curr.treatment_end_date                                                    'Last TX_Curr Date EC.',
           client.mobile_no                                                           as 'Mobile No.'
    from tx_curr
             left join latestDSD on latestDSD.PatientId = tx_curr.PatientId
             left join tpt_start on tx_curr.PatientId = tpt_start.PatientId
             left join tpt_completed on tx_curr.PatientId = tpt_completed.PatientId
             left join vl_sent_date on tx_curr.PatientId = vl_sent_date.PatientId
             left join vl_performed_date on tx_curr.PatientId = vl_performed_date.PatientId
             left join mamba_dim_client client on tx_curr.PatientId = client.client_id
             left join visitect_cd4_result on tx_curr.PatientId = visitect_cd4_result.PatientId
    order by client.patient_name;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_ml_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_ml_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_ml_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             antiretroviral_art_dispensed_dose_i as dose_days,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t AS transferred_in,
                             adherence
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         -- TX curr start
         tmp_latest_follow_up_start AS (SELECT client_id,
                                               follow_up_date,
                                               encounter_id,
                                               follow_up_status,
                                               treatment_end_date,
                                               art_start_date,
                                               regimen,
                                               dose_days,
                                               adherence,
                                               next_visit_date,
                                               ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                        FROM FollowUp
                                        WHERE follow_up_status IS NOT NULL
                                          AND art_start_date IS NOT NULL
                                          AND follow_up_date <= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         tx_curr_start AS (select *
                           from tmp_latest_follow_up_start
                           where row_num = 1
                             AND follow_up_status in ('Alive', 'Restart medication')
                             AND treatment_end_date >= DATE_ADD(REPORT_START_DATE, INTERVAL -1 DAY)),
         -- TX curr
         tmp_latest_follow_up AS (SELECT client_id,
                                         follow_up_date,
                                         encounter_id,
                                         follow_up_status,
                                         treatment_end_date,
                                         art_start_date,
                                         regimen,
                                         dose_days,
                                         adherence,
                                         next_visit_date,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= REPORT_END_DATE),
         latest_follow_up as (select *
                              from tmp_latest_follow_up
                              where row_num = 1),
         tx_curr_end AS (select *
                         from tmp_latest_follow_up
                         where row_num = 1
                           AND follow_up_status in ('Alive', 'Restart medication')
                           AND treatment_end_date >= REPORT_END_DATE),

         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select tmp_latest_follow_up.*
                        from tmp_latest_follow_up
                                 join first_follow_up on tmp_latest_follow_up.client_id = first_follow_up.client_id
                        where art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                          AND first_follow_up.follow_up_status in ('Alive', 'Restart medication')
                          AND tmp_latest_follow_up.row_num = 1),
         tx_new as (select *
                    from tx_new_tmp),

         on_art as (select *
                    from tx_new
                    union ALL
                    select *
                    from tx_curr_start),
         interrupted_art as (select on_art.*,
                                    latest_follow_up.regimen as latest_regimen,
                                    latest_follow_up.dose_days as latest_dose_days,
                                    latest_follow_up.adherence as latest_adherence,
                                    latest_follow_up.next_visit_date as latest_next_visit_date,
                                    client.sex,
                                    client.date_of_birth,
                                    TIMESTAMPDIFF(YEAR, client.date_of_birth, REPORT_END_DATE)        as Age,
                                    patient_name,
                                    patient_uuid,
                                    CAST(client.mrn AS CHAR(20)) as mrn,
                                    uan,
                                    mobile_no,
                                    kebele,
                                    house_number,
                                    city_village,
                                    (SELECT datim_agegroup
                                     from mamba_dim_agegroup
                                     where TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) = age) as fine_age_group,
                                    (SELECT normal_agegroup
                                     from mamba_dim_agegroup
                                     where TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) = age) as coarse_age_group,
                                    latest_follow_up.follow_up_status                                   as latest_follow_up_status,
                                    latest_follow_up.follow_up_date                                     as latest_follow_up_date
                             from on_art
                                      join mamba_dim_client client on on_art.client_id = client.client_id
                                      join latest_follow_up
                                           on on_art.client_id = latest_follow_up.client_id
                             where on_art.client_id not in (select client_id from tx_curr_end))
    select patient_name                                             as `Patient Name`,
           patient_uuid                                             as `UUID`,
           MRN,
           CONCAT('''', uan) as UAN,
           Age,
           Sex,
           art_start_date                                           as `ART Start Date`,
           art_start_date                                           as `ART Start Date EC.`,
           latest_follow_up_date                                      as `Last Follow-up Date`,
           latest_follow_up_date                                      as `Last Follow-up Date in EC.`,
           latest_follow_up_status                                    as `Last Follow-up Status`,
           latest_regimen                                                  as Regimen,
           latest_dose_days                                                as   `ARV Dose Days`,
           latest_Adherence,
           latest_next_visit_date                                          as `Next Visit Date`,
           latest_next_visit_date                                          as `Next Visit Date EC.`,
           treatment_end_date                                       as `Last TX_CURR Date`,
           treatment_end_date                                       as `Last TX_CURR Date EC.`,
           TIMESTAMPDIFF(MONTH, art_start_date, treatment_end_date) as `On Treatment For (in months)`,
           -- `On PMTCT?`,
           mobile_no                                                as `Mobile No.`,
           kebele                                                   as `Sub-City`,
           city_village                                             as   Woreda,
           house_number                                             as   `House No.`
    from interrupted_art;


END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_tx_new_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_tx_new_query;

~
CREATE PROCEDURE sp_fact_line_list_tx_new_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN

    WITH FollowUp AS (select follow_up.encounter_id,
                             follow_up.client_id,
                             follow_up_status,
                             follow_up_date_followup_            AS follow_up_date,
                             art_antiretroviral_start_date       AS art_start_date,
                             treatment_end_date,
                             next_visit_date,
                             regimen,
                             currently_breastfeeding_child          breast_feeding_status,
                             pregnancy_status,
                             transferred_in_check_this_for_all_t as transferred_in,
                             cd4_count,
                             weight_text_                        as weight,
                             current_who_hiv_stage,
                             nutritional_screening_result,
                             screening_test_result_tuberculosis  as TB_SreeningResult,
                             date_of_event                       as hiv_confirmed_date,
                             antiretroviral_art_dispensed_dose_i    ARTDoseDays
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id),
         tmp_first_follow_up as (SELECT client_id,
                                        follow_up_date                                                                     AS FollowupDate,
                                        encounter_id,
                                        transferred_in,
                                        pregnancy_status,
                                        follow_up_status,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date , encounter_id ) AS row_num,
                                        art_start_date,
                                        cd4_count,
                                        weight,
                                        current_who_hiv_stage,
                                        nutritional_screening_result,
                                        TB_SreeningResult,
                                        hiv_confirmed_date,
                                        breast_feeding_status,
                                        ARTDoseDays,
                                        regimen,
                                        next_visit_date,
                                        treatment_end_date
                                 FROM FollowUp
                                 WHERE art_start_date IS NOT NULL),
         first_follow_up as (select * from tmp_first_follow_up where row_num = 1),

         tx_new_tmp as (select first_follow_up.client_id,
                               art_start_date,
                               FollowupDate,
                               transferred_in,
                               pregnancy_status,
                               cd4_count,
                               weight,
                               current_who_hiv_stage,
                               nutritional_screening_result,
                               TB_SreeningResult,
                               COALESCE(intake_a.date_hiv_confirmed,hiv_confirmed_date) as hiv_confirmed_date ,
                               breast_feeding_status,
                               regimen,
                               ARTDoseDays,
                               next_visit_date,
                               treatment_end_date
                        from first_follow_up
                        left join mamba_flat_encounter_intake_a intake_a on first_follow_up.client_id = intake_a.client_id
                        where art_start_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE
                          AND (first_follow_up.transferred_in is null or first_follow_up.transferred_in != 'Yes')
                          AND first_follow_up.follow_up_status in ('Alive', 'Restart medication')),
         tx_new as (select tx_new_tmp.client_id,
                           patient_name,
                           patient_uuid,
                           sex,
                           CAST(mrn AS CHAR(20))                                             as mrn,
                           uan,
                           weight,
                           current_who_hiv_stage,
                           nutritional_screening_result,
                           TB_SreeningResult,
                           hiv_confirmed_date,
                           art_start_date,
                           pregnancy_status,
                           breast_feeding_status,
                           regimen,
                           date_of_birth,
                           ARTDoseDays,
                           next_visit_date,
                           treatment_end_date,
                           mobile_no,
                           TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE)               as age,
                           cd4_count
                    from tx_new_tmp
                             join mamba_dim_client client on tx_new_tmp.client_id = client.client_id)
    select patient_name                                                  AS 'Patient Name',
           patient_uuid                                                  as `UUID`,
           MRN                                                           AS 'MRN',
           CONCAT('''', uan)                                                           AS 'UAN',
           age                                                           AS 'Age',
           sex                                                           AS 'Sex',
           weight                                                        AS 'Weight',
           cd4_count                                                     AS 'CD4',
           current_who_hiv_stage                                         AS 'WHO Stage',
           nutritional_screening_result                                  AS 'Nutritional Status',
           TB_SreeningResult                                             AS 'TB Screening Result',
           hiv_confirmed_date                                            AS 'Enrollment Date',
           hiv_confirmed_date                                            AS 'Enrollment Date EC.',
           hiv_confirmed_date                                            AS 'HIV Confirmed Date',
           hiv_confirmed_date                                            AS 'HIV Confirmed Date EC.',
           tx_new.art_start_date                                         AS 'ART Start Date',
           tx_new.art_start_date                                         AS 'ART Start Date EC.',
           TIMESTAMPDIFF(DAY, hiv_confirmed_date, tx_new.art_start_date) AS 'Days Difference',
           pregnancy_status                                              AS 'Pregnant?',
           breast_feeding_status                                         AS 'Breastfeeding?',
           regimen                                                       AS 'Regimen',
           ARTDoseDays                                                   AS 'ARV Dose Days',
           next_visit_date                                               AS 'Next Visit Date',
           next_visit_date                                               AS 'Next Visit Date EC.',
           treatment_end_date                                            AS 'Last TX_Curr Date',
           treatment_end_date                                            AS 'Last TX_Curr Date EC.',
           mobile_no                                                     AS 'Mobile No.'
    FROM tx_new;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_vl_eligibility_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_vl_eligibility_query;

~
CREATE PROCEDURE sp_fact_line_list_vl_eligibility_query(
    IN REPORT_END_DATE DATE
)
BEGIN

    WITH FollowUp AS (SELECT follow_up.client_id,
                             follow_up.encounter_id,
                             date_viral_load_results_received AS viral_load_perform_date,
                             viral_load_received_,
                             follow_up_status,
                             follow_up_date_followup_         AS follow_up_date,
                             art_antiretroviral_start_date       art_start_date,
                             viral_load_test_status,
                             hiv_viral_load                   AS viral_load_count,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                AS routine_viral_load_test_indication,
                             COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                      suspected_antiretroviral_failure
                             )                                AS targeted_viral_load_test_indication,
                             viral_load_test_indication,
                             pregnancy_status,
                             currently_breastfeeding_child    AS breastfeeding_status,
                             antiretroviral_art_dispensed_dose_i arv_dispensed_dose,
                             regimen,
                             next_visit_date,
                             treatment_end_date,
                             date_of_event                       date_hiv_confirmed,
                             weight_text_                     as weight,
                             date_of_reported_hiv_viral_load  as viral_load_sent_date,
                             regimen_change
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id),


         tmp_all_art_follow_ups as (SELECT encounter_id,
                                           client_id,
                                           follow_up_status,
                                           follow_up_date                                                                             AS FollowUpDate,
                                           ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                    FROM FollowUp
                                    WHERE follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),

         all_art_follow_ups as (select * from tmp_all_art_follow_ups where row_num = 1),

         tmp_vl_sent_date as (SELECT encounter_id,
                                     client_id,
                                     viral_load_sent_date                                                                             AS VL_Sent_Date,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_sent_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE viral_load_sent_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         vl_sent_date as (select * from tmp_vl_sent_date where row_num = 1),

         tmp_switch_sub_date as (SELECT encounter_id,
                                        client_id,
                                        follow_up_date                                                                             AS FollowUpDate,
                                        ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                 FROM FollowUp
                                 WHERE follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())
                                   and regimen_change is not null),
         switch_sub_date as (select * from tmp_switch_sub_date where row_num = 1),

         tmp_vl_performed_date_1 as (SELECT encounter_id,
                                            client_id,
                                            viral_load_perform_date                                                                             AS viral_load_perform_date,
                                            routine_viral_load_test_indication,
                                            viral_load_test_status,
                                            viral_load_count,
                                            ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_perform_date DESC, encounter_id DESC) AS row_num
                                     FROM FollowUp
                                     WHERE art_start_date IS NOT NULL
                                       AND (
                                         (viral_load_perform_date IS NOT NULL AND
                                          viral_load_perform_date <= COALESCE(REPORT_END_DATE, CURDATE())
                                             )
                                             OR
                                         viral_load_perform_date IS NULL
                                         )),
         tmp_vl_performed_date_2 as (select * from tmp_vl_performed_date_1 where row_num = 1),

         tmp_vl_performed_date_3 as (SELECT tmp_vl_performed_date_2.encounter_id,
                                            tmp_vl_performed_date_2.client_id,
                                            vl_sent_date.VL_Sent_Date,
                                            case
                                                when tmp_vl_performed_date_2.viral_load_perform_date <
                                                     vl_sent_date.VL_Sent_Date
                                                    then null
                                                else tmp_vl_performed_date_2.viral_load_perform_date end as viral_load_perform_date,
                                            case
                                                when tmp_vl_performed_date_2.viral_load_perform_date <
                                                     vl_sent_date.VL_Sent_Date
                                                    then null
                                                else tmp_vl_performed_date_2.viral_load_test_status end  as viral_load_status,
                                            CASE
                                                WHEN tmp_vl_performed_date_2.viral_load_count > 0 AND
                                                     tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date
                                                    THEN CAST(tmp_vl_performed_date_2.viral_load_count AS DECIMAL(12, 2))
                                                ELSE NULL END                                            AS viral_load_count,
                                            CASE
                                                WHEN
                                                    viral_load_test_status IS NULL AND
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date
                                                    THEN
                                                    NULL
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date AND
                                                     (viral_load_test_status LIKE 'Det%'
                                                         OR viral_load_test_status LIKE 'Uns%'
                                                         OR viral_load_test_status LIKE 'High VL%'
                                                         OR viral_load_test_status LIKE 'Low Level Viremia%')
                                                    THEN
                                                    'U'
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date >=
                                                     vl_sent_date.VL_Sent_Date AND
                                                     (viral_load_test_status LIKE 'Su%'
                                                         OR viral_load_test_status LIKE 'Undet%')
                                                    THEN
                                                    'S'
                                                WHEN
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date AND
                                                    (ISNULL(viral_load_count) > CAST(50 AS float)
                                                        )
                                                    THEN
                                                    'U'
                                                WHEN
                                                    tmp_vl_performed_date_2.viral_load_perform_date >=
                                                    vl_sent_date.VL_Sent_Date AND
                                                    (ISNULL(viral_load_count) <= CAST(50 AS float)
                                                        )
                                                    THEN
                                                    'S'
                                                ELSE
                                                    NULL
                                                END                                                      AS viral_load_status_inferred,
                                            CASE
                                                WHEN vl_sent_date.VL_Sent_Date IS NOT NULL
                                                    THEN vl_sent_date.VL_Sent_Date
                                                WHEN tmp_vl_performed_date_2.viral_load_perform_date IS NOT NULL
                                                    THEN tmp_vl_performed_date_2.viral_load_perform_date
                                                ELSE NULL END                                            AS viral_load_ref_date,
                                            tmp_vl_performed_date_2.routine_viral_load_test_indication
                                     FROM tmp_vl_performed_date_2
                                              LEFT JOIN vl_sent_date
                                                        ON tmp_vl_performed_date_2.client_id = vl_sent_date.client_id),
         tmp_latest_alive_restart as (SELECT encounter_id,
                                             client_id,
                                             follow_up_date                                                                             AS FollowupDate,
                                             follow_up_status,
                                             ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                      FROM FollowUp
                                      WHERE follow_up_date <= COALESCE(REPORT_END_DATE, CURDATE())),
         latest_alive_restart as (select *
                                  from tmp_latest_alive_restart
                                  where row_num = 1
                                    AND follow_up_status in ('Alive', 'Restart medication')),
         vl_eligibility as (SELECT f_case.art_start_date                                     as art_start_date,
                                   f_case.breastfeeding_status                               as BreastFeeding,
                                   f_case.date_hiv_confirmed                                 as date_hiv_confirmed,
                                   sub_switch_date.FollowupDate                              as date_regimen_change,
                                   all_art_follow_ups.follow_up_status                       as follow_up_status,
                                   f_case.follow_up_date                                     as FollowUpDate,
                                   f_case.pregnancy_status                                   as IsPregnant,
                                   f_case.client_id                                          as PatientId,
                                   vlperfdate.viral_load_count                               as viral_load_count,
                                   vlperfdate.viral_load_perform_date                        as viral_load_perform_date,
                                   vlsentdate.VL_Sent_Date                                   as viral_load_sent_date,
                                   vlperfdate.viral_load_status                              as viral_load_status,
                                   f_case.weight,
                                   arv_dispensed_dose,
                                   f_case.regimen,
                                   f_case.next_visit_date,
                                   f_case.treatment_end_date,
                                   CASE
                                       WHEN vlsentdate.VL_Sent_Date IS NOT NULL
                                           THEN vlsentdate.VL_Sent_Date
                                       WHEN vlperfdate.viral_load_perform_date IS NOT NULL
                                           THEN vlperfdate.viral_load_perform_date
                                       ELSE NULL END                                         AS viral_load_ref_date,
                                   sub_switch_date.FollowupDate                              as switchDate,
                                   vlperfdate.viral_load_status_inferred,

                                   vlperfdate.routine_viral_load_test_indication             as viral_load_indication,

                                   CASE

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND f_case.follow_up_status = 'Restart medication')
                                           THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND sub_switch_date.FollowupDate IS NOt NULL
                                               )
                                           THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND f_case.pregnancy_status = 'Yes'
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 90)
                                           THEN DATE_ADD(f_case.art_start_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) <= 180)
                                           THEN NULL


                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 180)
                                           THEN DATE_ADD(f_case.art_start_date, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.VL_Sent_Date < f_case.follow_up_date)
                                               AND (f_case.follow_up_status = 'Restart medication')
                                           THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.VL_Sent_Date < sub_switch_date.FollowupDate
                                               AND sub_switch_date.FollowupDate IS NOT NULL
                                               )
                                           THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.viral_load_status_inferred = 'U')
                                           THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                               AND vlperfdate.routine_viral_load_test_indication in
                                                   ('First viral load test at 6 months or longer post ART',
                                                    'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                    'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                           THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                               AND vlperfdate.routine_viral_load_test_indication IS NOT NULL
                                               AND vlperfdate.routine_viral_load_test_indication not in
                                                   ('First viral load test at 6 months or longer post ART',
                                                    'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                    'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                           THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 181 DAY)


                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL)
                                           THEN DATE_ADD(vlperfdate.VL_Sent_Date, INTERVAL 365 DAY)

                                       ELSE DATE_ADD(REPORT_END_DATE, INTERVAL 100 YEAR) End AS eligiblityDate,

                                   CASE

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND f_case.follow_up_status = 'Restart medication')
                                           THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND sub_switch_date.FollowupDate IS NOt NULL
                                               )
                                           THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND f_case.pregnancy_status = 'Yes'
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 90)
                                           THEN DATE_ADD(f_case.art_start_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) <= 180)
                                           THEN NULL


                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 180)
                                           THEN DATE_ADD(f_case.art_start_date, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_perform_date < f_case.follow_up_date)
                                               AND (f_case.follow_up_status = 'Restart medication')
                                           THEN DATE_ADD(f_case.follow_up_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_perform_date < sub_switch_date.FollowupDate
                                               AND sub_switch_date.FollowupDate IS NOT NULL
                                               )
                                           THEN DATE_ADD(sub_switch_date.FollowupDate, INTERVAL 181 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_status_inferred = 'U')
                                           THEN DATE_ADD(vlperfdate.viral_load_perform_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                               AND vlperfdate.routine_viral_load_test_indication in
                                                   ('First viral load test at 6 months or longer post ART',
                                                    'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                    'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                           THEN DATE_ADD(vlperfdate.viral_load_perform_date, INTERVAL 91 DAY)

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes')
                                               AND vlperfdate.routine_viral_load_test_indication IS NOT NULL
                                               AND vlperfdate.routine_viral_load_test_indication not in
                                                   ('First viral load test at 6 months or longer post ART',
                                                    'Viral load after EAC: repeat viral load where initial viral load greater than 50 and less than 1000 copies per ml',
                                                    'Viral load after EAC: confirmatory viral load where initial viral load greater than 1000 copies per ml'))
                                           THEN DATE_ADD(vlperfdate.viral_load_perform_date, INTERVAL 181 DAY)


                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL)
                                           THEN DATE_ADD(vlperfdate.viral_load_perform_date, INTERVAL 365 DAY)

                                       ELSE DATE_ADD(REPORT_END_DATE, INTERVAL 100 YEAR) End AS eligiblityDateReceived,


                                   CASE

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND f_case.follow_up_status = 'Restart medication')
                                           THEN 'client restarted ART'

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND sub_switch_date.FollowupDate IS NOt NULL
                                               )
                                           THEN 'Regimen Change'


                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND f_case.pregnancy_status = 'Yes'
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 90)
                                           THEN 'First VL for Pregnant'

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) <= 180)
                                           THEN 'N/A'

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 180)
                                           THEN 'First VL'


                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.VL_Sent_Date < f_case.follow_up_date)
                                               AND (f_case.follow_up_status = 'Restart medication')
                                           THEN 'client restarted ART'

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.VL_Sent_Date < sub_switch_date.FollowupDate
                                               AND sub_switch_date.FollowupDate IS NOT NULL
                                               )
                                           THEN 'Regimen Change'

                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL
                                               AND vlperfdate.viral_load_status_inferred = 'U')
                                           THEN 'Repeat/Confirmatory Viral Load test'

                                       WHEN
                                           (vlperfdate.viral_load_status_inferred IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes'))
                                           THEN 'Pregnant/Breastfeeding and needs retesting'


                                       WHEN
                                           (vlperfdate.VL_Sent_Date IS NOT NULL)
                                           THEN 'Annual Viral Load Test'

                                       ELSE 'Unassigned' End                                 AS vl_status_final,
                                   CASE

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND f_case.follow_up_status = 'Restart medication')
                                           THEN 'client restarted ART'

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND sub_switch_date.FollowupDate IS NOt NULL
                                               )
                                           THEN 'Regimen Change'


                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND f_case.pregnancy_status = 'Yes'
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 90)
                                           THEN 'First VL for Pregnant'

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) <= 180)
                                           THEN 'N/A'

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NULL
                                               AND TIMESTAMPDIFF(DAY, f_case.art_start_date,
                                                                 COALESCE(REPORT_END_DATE, CURDATE())) > 180)
                                           THEN 'First VL'


                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_perform_date < f_case.follow_up_date)
                                               AND (f_case.follow_up_status = 'Restart medication')
                                           THEN 'client restarted ART'

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_perform_date < sub_switch_date.FollowupDate
                                               AND sub_switch_date.FollowupDate IS NOT NULL
                                               )
                                           THEN 'Regimen Change'

                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL
                                               AND vlperfdate.viral_load_status_inferred = 'U')
                                           THEN 'Repeat/Confirmatory Viral Load test'

                                       WHEN
                                           (vlperfdate.viral_load_status_inferred IS NOT NULL
                                               AND
                                            (f_case.pregnancy_status = 'Yes' OR f_case.breastfeeding_status = 'Yes'))
                                           THEN 'Pregnant/Breastfeeding and needs retesting'


                                       WHEN
                                           (vlperfdate.viral_load_perform_date IS NOT NULL)
                                           THEN 'Annual Viral Load Test'

                                       ELSE 'Unassigned' End                                 AS VL_STATUS_COVERAGE

                            FROM FollowUp AS f_case
                                     INNER JOIN latest_alive_restart
                                                ON f_case.encounter_id = latest_alive_restart.encounter_id

                                     LEFT JOIN tmp_vl_performed_date_3 as vlperfdate
                                               ON vlperfdate.client_id = f_case.client_id

                                     Left join vl_sent_date as vlsentdate
                                               ON vlsentdate.client_id = f_case.client_id

                                     Left join switch_sub_date as sub_switch_date
                                               ON sub_switch_date.client_id = f_case.client_id


                                     Left join all_art_follow_ups on f_case.client_id = all_art_follow_ups.client_id

                            where all_art_follow_ups.follow_up_status in ('Alive', 'Restart Medication')),
         eligibility as (select patient_name                                     AS 'Patient Name',
                                patient_uuid                                     as `UUID`,
                                CAST(client.mrn AS CHAR(20))                     as MRN,
                                CONCAT('''', uan)                                              as UniqueArtNumber,
                                TIMESTAMPDIFF(YEAR, date_of_birth, FollowUpDate) as Age,
                                client.sex,
                                Weight,
                                client.phone_no                                  as PNumber,
                                client.mobile_no                                 as Mobile,
                                art_start_date                                   as `ART Start Date`,
                                art_start_date                                   as `ART Start Date EC.`,
                                FollowUpDate                                     as `Follow Up Date`,
                                FollowUpDate                                     as `Follow Up Date EC.`,
                                date_regimen_change                              as `Date Regiment Change`,
                                date_regimen_change                              as `Date Regiment Change EC.`,
                                viral_load_sent_date                             as `Viral Load Sent Date`,
                                viral_load_sent_date                             as `Viral Load Sent Date EC.`,
                                viral_load_perform_date                          as `Viral Load Received Date`,
                                viral_load_perform_date                          as `Viral Load Received Date EC.`,
                                IsPregnant,
                                next_visit_date                                  as `Next Visit Date`,
                                next_visit_date                                  as `Next Visit Date EC.`,
                                follow_up_status                                 as followupstatus,
                                viral_load_ref_date                              as `Viral Load Ref Date`,
                                viral_load_ref_date                              as `Viral Load Ref Date EC.`,
                                treatment_end_date                               as `Art Dose End Date`,
                                treatment_end_date                               as `Art Dose End Date EC.`,
                                viral_load_status                                as vl_status,
                                viral_load_count                                 as VLCount,
                                regimen                                          as artdose,
                                CASE
                                    WHEN IsPregnant = 'Yes' OR BreastFeeding = 'Yes' THEN
                                        'Yes'
                                    ELSE 'No' END                                AS `PMTCT-ART`,
                                date_hiv_confirmed                               as `Hiv Confirmed Date`,
                                date_hiv_confirmed                               as `Hiv Confirmed Date EC.`,
                                t.arv_dispensed_dose                             as ARTDoseDays,
                                CAST(eligiblityDate AS DATE)                     as `Eligiblity Date`,
                                CAST(eligiblityDate AS DATE)                     as `Eligiblity Date EC.`,
                                case

                                    when t.vl_status_final = 'N/A' THEN 'Not Applicable'
                                    when t.eligiblityDate <= COALESCE(REPORT_END_DATE, CURDATE())
                                        THEN 'Eligible for Viral Load'
                                    when t.eligiblityDate > COALESCE(REPORT_END_DATE, CURDATE())
                                        THEN 'Viral Load Done (Currently not Eligible)' -- 'Viral Load Done'
                                    when t.art_start_date is NULL and t.follow_up_status is null THEN 'Not Started ART'
                                    end                                          as `Viral Load Eligibility Status`,
                                CASE

                                    WHEN t.eligiblityDate > COALESCE(REPORT_END_DATE, CURDATE()) THEN 'N/A'
                                    ELSE vl_status_final END                     as `Reason for Viral Load Eligibility`,
                                eligiblityDateReceived                           as 'Viral Load Coverage Eligibility Date',
                                eligiblityDateReceived                           as 'Viral Load Coverage Eligibility Date EC.',
                                case

                                    when t.VL_STATUS_COVERAGE = 'N/A' THEN 'Not Applicable'
                                    when t.eligiblityDateReceived <= COALESCE(REPORT_END_DATE, CURDATE())
                                        THEN 'Eligible for Viral Load'
                                    when t.eligiblityDateReceived > COALESCE(REPORT_END_DATE, CURDATE())
                                        THEN 'Viral Load Done (Currently not Eligible)' -- 'Viral Load Done'
                                    when t.art_start_date is NULL and t.follow_up_status is null THEN 'Not Started ART'
                                    end                                          as `Viral Load Test Coverage`


                         from vl_eligibility t
                                  join mamba_dim_client client on t.PatientId = client_id)
    select *
    from eligibility;
END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_vl_received_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_vl_received_query;

~
CREATE PROCEDURE sp_fact_line_list_vl_received_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT follow_up.client_id,
                             follow_up.encounter_id,
                             date_viral_load_results_received AS viral_load_perform_date,
                             date_of_reported_hiv_viral_load  as viral_load_sent_date,
                             viral_load_received_,
                             follow_up_status,
                             follow_up_date_followup_         AS follow_up_date,
                             art_antiretroviral_start_date       art_start_date,
                             viral_load_test_status,
                             hiv_viral_load                   AS viral_load_count,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                AS routine_viral_load_test_indication,
                             COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                      suspected_antiretroviral_failure
                             )                                AS targeted_viral_load_test_indication,
                             viral_load_test_indication,
                             pregnancy_status,
                             currently_breastfeeding_child    AS breastfeeding_status,
                             antiretroviral_art_dispensed_dose_i arv_dispensed_dose,
                             regimen,
                             next_visit_date,
                             treatment_end_date,
                             date_of_event                       date_hiv_confirmed,
                             weight_text_                     as weight,
                             adherence,
                             cd4_,
                             cd4_count
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id),

         vl_performed_date_tmp AS (SELECT FollowUp.encounter_id,
                                          FollowUp.client_id,
                                          FollowUp.viral_load_perform_date,
                                          FollowUp.viral_load_test_status,
                                          follow_up_date,
                                          viral_load_sent_date,
                                          follow_up_status,
                                          arv_dispensed_dose,
                                          adherence,
                                          regimen,
                                          viral_load_count,
                                          cd4_,
                                          cd4_count,
                                          routine_viral_load_test_indication,
                                          targeted_viral_load_test_indication,
                                          ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_perform_date DESC, encounter_id DESC) AS row_num
                                   FROM FollowUp
                                   WHERE follow_up_status IS NOT NULL
                                     AND art_start_date IS NOT NULL
                                     AND viral_load_perform_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         latest_follow_up_tmp AS (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         arv_dispensed_dose,
                                         adherence,
                                         next_visit_date,
                                         treatment_end_date,
                                         regimen,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= REPORT_END_DATE),
         latest_follow_up AS (select * from latest_follow_up_tmp where row_num = 1),
         vl_performed_date as (select * from vl_performed_date_tmp where row_num = 1),

         vl_test_performed AS (SELECT patient_name                                        as `Patient Name`,
                                      patient_uuid                                        as `UUID`,
                                      MRN,
                                      CONCAT('''', uan) as UAN,
                                      TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) as Age,
                                      Sex,
                                      Weight,
                                      vlperfdate.cd4_count                                     as CD4,
                                      art_start_date                                      as `ART Start Date`,
                                      art_start_date                                      as `ART Start Date EC.`,
                                      vlperfdate.follow_up_date                           as `Follow-up Date`,
                                      vlperfdate.follow_up_date                           as `Follow-up Date EC.`,
                                      vlperfdate.follow_up_status                         as `Follow-up Status`,
                                      vlperfdate.regimen                                  as Regimen,
                                      vlperfdate.arv_dispensed_dose                       as `ARV Dose Days`,
                                      vlperfdate.Adherence,
                                      pregnancy_status                                    as PregnancyStatus,
                                      breastfeeding_status                                as BreastfeedingStatus,
                                      CASE
                                          WHEN pregnancy_status = 'Yes' THEN 'Yes'
                                          WHEN breastfeeding_status = 'Yes' THEN 'Yes'
                                          ELSE 'No' END                                   AS `On PMTCT?`,
                                      vlperfdate.viral_load_sent_date                     as `Viral Load Sent Date`,
                                      vlperfdate.viral_load_sent_date                     as `Viral Load Sent Date EC.`,
                                      vlperfdate.viral_load_perform_date                  as `VL Received Date`,
                                      vlperfdate.viral_load_perform_date                  as `VL Received Date EC.`,
                                      TIMESTAMPDIFF(DAY, vlperfdate.viral_load_sent_date,
                                                    vlperfdate.viral_load_perform_date)      `TAT (in days)`,
                                      vlperfdate.routine_viral_load_test_indication       as `Routine Test type`,
                                      vlperfdate.targeted_viral_load_test_indication      as `Targeted Test Type`,
                                      vlperfdate.viral_load_test_status                   as viral_load_status,
                                      vlperfdate.viral_load_count,
                                      latest_follow_up.FollowupDate                       as `Latest Follow-up Date`,
                                      latest_follow_up.FollowupDate                       as `Latest Follow-up Date EC.`,
                                      latest_follow_up.follow_up_status                   as `Latest Follow-up Status`,
                                      latest_follow_up.regimen                            as `Latest Regimen`,
                                      latest_follow_up.arv_dispensed_dose                 as `Latest ARV Dose Days`,
                                      latest_follow_up.adherence                          as `Latest Adherence`,
                                      latest_follow_up.next_visit_date                    as `Next Visit Date`,
                                      latest_follow_up.next_visit_date                    as `Next Visit Date EC.`,
                                      latest_follow_up.treatment_end_date                 as `Last TX_Curr Date`,
                                      latest_follow_up.treatment_end_date                 as `Last TX_Curr Date EC.`,
                                      mobile_no                                           as `Mobile No.`

                               FROM FollowUp
                                        INNER JOIN vl_performed_date as vlperfdate
                                                   ON vlperfdate.encounter_id = FollowUp.encounter_id
                                        LEFT JOIN mamba_dim_client client ON vlperfdate.client_id = client.client_id
                                        LEFT JOIN latest_follow_up
                                                  ON latest_follow_up.client_id = FollowUp.client_id)
    select *
    from vl_test_performed;

END //

DELIMITER ;


        
-- ---------------------------------------------------------------------------------------------
-- sp_fact_line_list_vl_sent_query
--

DELIMITER //

DROP PROCEDURE IF EXISTS sp_fact_line_list_vl_sent_query;

~
CREATE PROCEDURE sp_fact_line_list_vl_sent_query(IN REPORT_START_DATE DATE, IN REPORT_END_DATE DATE)
BEGIN
    WITH FollowUp AS (SELECT follow_up.client_id,
                             follow_up.encounter_id,
                             date_viral_load_results_received AS viral_load_perform_date,
                             date_of_reported_hiv_viral_load  as viral_load_sent_date,
                             viral_load_received_,
                             follow_up_status,
                             follow_up_date_followup_         AS follow_up_date,
                             art_antiretroviral_start_date       art_start_date,
                             viral_load_test_status,
                             hiv_viral_load                   AS viral_load_count,
                             COALESCE(
                                     at_3436_weeks_of_gestation,
                                     viral_load_after_eac_confirmatory_viral_load_where_initial_v,
                                     viral_load_after_eac_repeat_viral_load_where_initial_viral_l,
                                     every_six_months_until_mtct_ends,
                                     six_months_after_the_first_viral_load_test_at_postnatal_peri,
                                     three_months_after_delivery,
                                     at_the_first_antenatal_care_visit,
                                     annual_viral_load_test,
                                     second_viral_load_test_at_12_months_post_art,
                                     first_viral_load_test_at_6_months_or_longer_post_art,
                                     first_viral_load_test_at_3_months_or_longer_post_art
                             )                                AS routine_viral_load_test_indication,
                             COALESCE(repeat_or_confirmatory_vl_initial_viral_load_greater_than_10,
                                      suspected_antiretroviral_failure
                             )                                AS targeted_viral_load_test_indication,
                             viral_load_test_indication,
                             pregnancy_status,
                             currently_breastfeeding_child    AS breastfeeding_status,
                             antiretroviral_art_dispensed_dose_i arv_dispensed_dose,
                             regimen,
                             next_visit_date,
                             treatment_end_date,
                             date_of_event                       date_hiv_confirmed,
                             weight_text_                     as weight,
                             adherence,
                             cd4_,
                             cd4_count
                      FROM mamba_flat_encounter_follow_up follow_up
                               LEFT JOIN mamba_flat_encounter_follow_up_1 follow_up_1
                                         ON follow_up.encounter_id = follow_up_1.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_2 follow_up_2
                                         ON follow_up.encounter_id = follow_up_2.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_3 follow_up_3
                                         ON follow_up.encounter_id = follow_up_3.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_4 follow_up_4
                                         ON follow_up.encounter_id = follow_up_4.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_5 follow_up_5
                                         ON follow_up.encounter_id = follow_up_5.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_6 follow_up_6
                                         ON follow_up.encounter_id = follow_up_6.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_7 follow_up_7
                                         ON follow_up.encounter_id = follow_up_7.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_8 follow_up_8
                                         ON follow_up.encounter_id = follow_up_8.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_9 follow_up_9
                                         ON follow_up.encounter_id = follow_up_9.encounter_id
                               LEFT JOIN mamba_flat_encounter_follow_up_10 follow_up_10
                                         ON follow_up.encounter_id = follow_up_10.encounter_id
                      ),


         vl_sent_date_tmp AS (SELECT FollowUp.encounter_id,
                                     FollowUp.client_id,
                                     FollowUp.viral_load_perform_date,
                                     FollowUp.viral_load_test_status,
                                     cd4_count,
                                     follow_up_date,
                                     arv_dispensed_dose,
                                     follow_up_status,
                                     Adherence,
                                     viral_load_count,
                                     regimen,
                                     FollowUp.viral_load_sent_date,
                                     routine_viral_load_test_indication,
                                     targeted_viral_load_test_indication,
                                     ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY viral_load_sent_date DESC, encounter_id DESC) AS row_num
                              FROM FollowUp
                              WHERE follow_up_status IS NOT NULL
                                AND art_start_date IS NOT NULL
                                AND viral_load_sent_date BETWEEN REPORT_START_DATE AND REPORT_END_DATE),
         latest_follow_up_tmp AS (SELECT client_id,
                                         follow_up_date                                                                             AS FollowupDate,
                                         encounter_id,
                                         follow_up_status,
                                         arv_dispensed_dose,
                                         adherence,
                                         next_visit_date,
                                         treatment_end_date,
                                         regimen,
                                         ROW_NUMBER() OVER (PARTITION BY client_id ORDER BY follow_up_date DESC, encounter_id DESC) AS row_num
                                  FROM FollowUp
                                  WHERE follow_up_status IS NOT NULL
                                    AND art_start_date IS NOT NULL
                                    AND follow_up_date <= REPORT_END_DATE),
         latest_follow_up AS (select * from latest_follow_up_tmp where row_num = 1),
         vl_sent_date as (select * from vl_sent_date_tmp where row_num = 1),


         vl_test_sent AS (SELECT patient_name                                        as `Patient Name`,
                                 patient_uuid as `UUID`,
                                 MRN,
                                 CONCAT('''', uan) as UAN,
                                 TIMESTAMPDIFF(YEAR, date_of_birth, REPORT_END_DATE) as Age,
                                 Sex,
                                 Weight,
                                 vlsent.cd4_count                                         as CD4,
                                 art_start_date                                      as `ART Start Date`,
                                 art_start_date                                      as `ART Start Date EC.`,
                                 vlsent.follow_up_date                               as `Follow-up Date`,
                                 vlsent.follow_up_date                               as `Follow-up Date EC.`,
                                 vlsent.follow_up_status                             as `Follow-up Status`,
                                 vlsent.regimen                                      as Regimen,
                                 vlsent.arv_dispensed_dose                              `ARV Dose Days`,
                                 vlsent.Adherence,
                                 pregnancy_status                                    as PregnancyStatus,
                                 breastfeeding_status                                as BreastfeedingStatus,
                                 CASE
                                     WHEN pregnancy_status = 'Yes' THEN 'Yes'
                                     WHEN breastfeeding_status = 'Yes' THEN 'Yes'
                                     ELSE 'No' END                                   AS `On PMTCT?`,
                                 vlsent.viral_load_sent_date                         as `Viral Load Sent Date`,
                                 vlsent.viral_load_sent_date                         as `Viral Load Sent Date EC.`,
                                 vlsent.viral_load_perform_date                      as `VL Received Date`,
                                 vlsent.viral_load_perform_date                      as `VL Received Date EC.`,
                                 TIMESTAMPDIFF(DAY, vlsent.viral_load_sent_date,
                                               vlsent.viral_load_perform_date)                         `TAT (in days)`,
                                 vlsent.routine_viral_load_test_indication           as `Routine Test type`,
                                 vlsent.targeted_viral_load_test_indication          as `Targeted Test Type`,
                                 vlsent.viral_load_test_status                       as viral_load_status,
                                 vlsent.viral_load_count,
                                 latest_follow_up.FollowupDate                       as `Latest Follow-up Date`,
                                 latest_follow_up.FollowupDate                       as `Latest Follow-up Date EC.`,
                                 latest_follow_up.follow_up_status                   as `Latest Follow-up Status`,
                                 latest_follow_up.regimen                            as `Latest Regimen`,
                                 latest_follow_up.arv_dispensed_dose                 as `Latest ARV Dose Days`,
                                 latest_follow_up.adherence                          as `Latest Adherence`,
                                 latest_follow_up.next_visit_date                    as `Next Visit Date`,
                                 latest_follow_up.next_visit_date                    as `Next Visit Date EC.`,
                                 latest_follow_up.treatment_end_date                 as `Last TX_Curr Date`,
                                 latest_follow_up.treatment_end_date                 as `Last TX_Curr Date EC.`,
                                 mobile_no                                           as `Mobile No.`

                          FROM FollowUp
                                   INNER JOIN vl_sent_date as vlsent
                                              ON vlsent.encounter_id = FollowUp.encounter_id
                                   LEFT JOIN mamba_dim_client client ON vlsent.client_id = client.client_id
                                   LEFT JOIN latest_follow_up
                                             ON latest_follow_up.encounter_id = FollowUp.encounter_id)
    select *
    from vl_test_sent;

END //

DELIMITER ;


        
