SELECT DISTINCT COUNT(DISTINCT e.patient_id) AS total_active_tpt FROM openmrs.obs o  INNER JOIN openmrs.concept c on o.concept_id = c.concept_id INNER JOIN openmrs.person p on o.person_id = p.person_id INNER JOIN openmrs.encounter e on o.encounter_id = e.encounter_id INNER JOIN openmrs.encounter_type et on e.encounter_type = et.encounter_type_id LEFT JOIN (SELECT DISTINCT e.patient_id,max(value_datetime) date_enrolled FROM openmrs.obs o INNER JOIN openmrs.concept c on o.concept_id = c.concept_id INNER JOIN openmrs.person p on o.person_id = p.person_id INNER JOIN openmrs.encounter e on o.encounter_id = e.encounter_id INNER JOIN openmrs.encounter_type et on e.encounter_type = et.encounter_type_id  WHERE et.uuid = 'dc6ce80c-83f8-4ace-a638-21df78542551' AND o.concept_id =  (SELECT concept_id FROM openmrs.concept WHERE uuid = '162320AAAAAAAAAAAAAAAAAAAAAAAAAAAAAA') GROUP BY e.patient_id) ed ON ed.patient_id = e.patient_id LEFT JOIN(SELECT DISTINCT e.patient_id, max(value_datetime) date_disenrolled FROM openmrs.obs o INNER JOIN openmrs.concept c on o.concept_id = c.concept_id INNER JOIN openmrs.person p on o.person_id = p.person_id INNER JOIN openmrs.encounter e on o.encounter_id = e.encounter_id INNER JOIN openmrs.encounter_type et on e.encounter_type = et.encounter_type_id WHERE et.uuid = 'dc6ce80c-83f8-4ace-a638-21df78542551' AND o.concept_id = (SELECT concept_id FROM openmrs.concept WHERE uuid = '163284AAAAAAAAAAAAAAAAAAAAAAAAAAAAAA') GROUP BY e.patient_id) dd ON dd.patient_id = e.patient_id WHERE et.uuid = 'dc6ce80c-83f8-4ace-a638-21df78542551' AND (dd.date_disenrolled IS NULL OR ed.date_enrolled > dd.date_disenrolled) -- Base query from JSON
LIMIT 0;

-- Select report column names from the temporary table structure
-- Using information_schema might be slightly more robust if CREATE TABLE AS has issues
SELECT GROUP_CONCAT(COLUMN_NAME SEPARATOR ', ')
INTO @column_names
FROM INFORMATION_SCHEMA.COLUMNS
WHERE TABLE_SCHEMA = DATABASE() -- Use current database
  AND TABLE_NAME = 'mamba_report_total_active_tpt';

-- Update Table definition with report column names (optional, depends on your usage)
-- UPDATE mamba_dim_report_definition
-- SET result_column_names = @column_names
-- WHERE report_id='total_active_tpt';

-- Return the column names as a result set
SELECT @column_names AS column_names;

-- Clean up the temporary table
DROP TABLE IF EXISTS mamba_report_total_active_tpt;

END //

DELIMITER ;



-- ---------------------------------------------------------------------------------------------
-- ----------------------------  Setup the MambaETL Scheduler  ---------------------------------
-- ---------------------------------------------------------------------------------------------


-- Enable the event etl_scheduler
SET GLOBAL event_scheduler = ON;

~-~-

-- Drop/Create the Event responsible for firing up the ETL process
DROP EVENT IF EXISTS _mamba_etl_scheduler_event;

~-~-

-- Drop/Create the Event responsible for maintaining event logs at a max. 20 elements
DROP EVENT IF EXISTS _mamba_etl_scheduler_trim_log_event;

~-~-

-- Setup ETL configurations
CALL sp_mamba_etl_setup(?, ?, ?, ?, ?, ?, ?);

-- pass them from the runtime properties file

~-~-

CREATE EVENT IF NOT EXISTS _mamba_etl_scheduler_event
    ON SCHEDULE EVERY ? SECOND
        STARTS CURRENT_TIMESTAMP
    DO CALL sp_mamba_etl_schedule();

~-~-

-- Setup a trigger that trims record off _mamba_etl_schedule to just leave 20 latest records.
-- to avoid the table growing too big

 CREATE EVENT IF NOT EXISTS _mamba_etl_scheduler_trim_log_event
    ON SCHEDULE EVERY 3 HOUR
        STARTS CURRENT_TIMESTAMP
    DO CALL sp_mamba_etl_schedule_trim_log_event();

 ~-~-

USE openmrs;
